    --------------------------------------------------
    -- STATE INTERNAL
    --------------------------------------------------
    local selectedMap    = {}           -- [key] = true/false
    local currentEntries = entries      -- list aktif sekarang

    local function normalizeEntry(e)
        if type(e) == "table" then
            return e.key or e.name, e.name or tostring(e.key)
        else
            return e, tostring(e)
        end
    end

local function norm(s)
    s = tostring(s or ""):lower()
    s = s:gsub("%s+", " ")
    return s
end

local function parsePet(label)
    label = tostring(label or "")

    -- ambil KG
    local kg = tonumber(label:match("([%d%.]+)%s*KG")) or 0

    -- hapus [Mutation]
    label = label:gsub("^%b[]%s*", "")

    -- ambil petType
    local petType = label:match("^(.-)%s*|") or label

    return petType, kg
end

local function filterAndSort(list)
    local result = {}
    local q = norm(searchText)

    for _, e in ipairs(list) do
        local key, label = normalizeEntry(e)

        if q == "" 
            or norm(label):find(q, 1, true)
            or norm(key):find(q, 1, true)
        then
            table.insert(result, e)
        end
    end

    table.sort(result, function(a, b)
        local ak = normalizeEntry(a)
        local bk = normalizeEntry(b)

        local aSel = selectedMap[ak] == true
        local bSel = selectedMap[bk] == true

        if aSel ~= bSel then
            return aSel
        end

        local _, aLabel = normalizeEntry(a)
local _, bLabel = normalizeEntry(b)

local aType, aKg = parsePet(aLabel)
local bType, bKg = parsePet(bLabel)

-- 1. selected tetap di atas (jangan diubah)
-- ini sudah ada di atas, jangan dihapus

-- 2. sort petType
if aType ~= bType then
    return aType < bType
end

-- 3. sort KG (besar dulu)
return aKg < bKg


    end)

    return result
end
    --------------------------------------------------
    -- BUILD BUTTONS
    --------------------------------------------------
    local function buildButtons(listOpt)
        -- kalau dipanggil dengan list baru → update currentEntries
        if listOpt then
            currentEntries = listOpt
        end

        local list = filterAndSort(currentEntries or {})

        -- clear lama
        for _, child in ipairs(container:GetChildren()) do
            if child:IsA("TextButton") then
                child:Destroy()
            end
        end

        for i, e in ipairs(list) do
            local key, labelText = normalizeEntry(e)

            -- kalau belum ada state, lihat dari field entry (selected / on)
            if selectedMap[key] == nil then
                if type(e) == "table" and (e.selected or e.on) then
                    selectedMap[key] = true
                else
                    selectedMap[key] = false
                end
            end

            local btn = Instance.new("TextButton")
            btn.Name = "Item_" .. tostring(key)
            btn.AutoButtonColor = false
            btn.BackgroundColor3 = Color3.fromRGB(22, 22, 22)
            btn.Size = UDim2.new(1, 0, 0, 22)
            btn.Text = "  " .. labelText
            btn.Font = Enum.Font.Gotham
            btn.TextXAlignment = Enum.TextXAlignment.Left
            btn.TextSize = 12
            btn.TextColor3 = Color3.fromRGB(200, 200, 200)
            btn.LayoutOrder = i
            btn.Parent = container
            createCorner(btn, 4)

            local function applyVisual()
                if selectedMap[key] then
                    tweenColor(btn, "BackgroundColor3", COLOR_YELLOW)
                    btn.TextColor3 = Color3.fromRGB(0, 0, 0)
                else
                    tweenColor(btn, "BackgroundColor3", Color3.fromRGB(22, 22, 22))
                    btn.TextColor3 = Color3.fromRGB(200, 200, 200)
                end
            end
            applyVisual()

            btn.MouseButton1Click:Connect(function()
                selectedMap[key] = not selectedMap[key]
                applyVisual()
                buildButtons()
                onItemToggle(key, selectedMap[key], labelText)
            end)
            

        end
    end

    -- build pertama
    buildButtons(currentEntries)
    searchBox:GetPropertyChangedSignal("Text"):Connect(function()
    searchText = searchBox.Text
    buildButtons()
    end)
    --------------------------------------------------
    -- API
    --------------------------------------------------
    local function api(action, payload)
        if action == "setList" or action == "setItems" then
            -- ganti isi list + rebuild
            buildButtons(payload or {})

        elseif action == "setSelected" and type(payload) == "table" then
            -- ganti state selectedMap sesuai payload
            selectedMap = {}
            for k, v in pairs(payload) do
                if v then
                    selectedMap[k] = true
                end
            end
            -- redraw pakai currentEntries
            buildButtons()

        elseif action == "getSelected" then
            local result = {}
            for k, v in pairs(selectedMap) do
                if v then
                    table.insert(result, k)
                end
            end
            return result
        end
    end

    return row, api
end



----------------------------------------------------------
-- ROW: DROPDOWN (single / multi) dgn overlay + search
----------------------------------------------------------
-- opts:
-- {
--   label       = "Target Player",
--   placeholder = "Select...",
--   mode        = "single" / "multi"  (default: "single")
--   getItems    = function() return { "A", "B" } end
--                -- ATAU langsung table: { "A","B" } / { {key="a",name="A"}, ... }
--   initial     =   -- SINGLE: "key" / "name"
--                 -- MULTI : { [key]=true, [key2]=true }
--   onChanged   = function(mode, selected) end
-- }
function MainUI:CreateRowDropdown(parent, opts)
    opts = opts or {}
    local mode        = (opts.mode == "multi") and "multi" or "single"
    local labelText   = opts.label or "Dropdown"
    local placeholder = opts.placeholder or "Select..."

    local api = {}

    -- Sumber item bisa function atau table
    local itemsSource = opts.getItems or {}

    local function getItemsList()
        if type(itemsSource) == "function" then
            local ok, res = pcall(itemsSource)
            if ok and type(res) == "table" then
                return res
            else
                warn("[NodeHubDropdown] getItems() tidak mengembalikan table, pakai {}")
                return {}
            end
        elseif type(itemsSource) == "table" then
            return itemsSource
        else
            warn("[NodeHubDropdown] getItems bukan function/table, pakai {}")
            return {}
        end
    end

    local onChanged   = opts.onChanged
    local onClose     = opts.onClose

    -- state
    local currentItems = {}
    local keyToLabel   = {}

    local selectedKey  = nil
    local selectedMap  = {}

    if mode == "single" then
        if opts.initial ~= nil then
            selectedKey = tostring(opts.initial)
        end
    else
        if type(opts.initial) == "table" then
            for k, v in pairs(opts.initial) do
                if v == true or v == 1 or v == "true" then
                    selectedMap[tostring(k)] = true
                end
            end
        end
    end

    ------------------------------------------------------
    -- ROW + LABEL + BUTTON
    ------------------------------------------------------
    local row = Instance.new("Frame")
    row.Name = "RowDropdown"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, 34)
    row.LayoutOrder = #parent:GetChildren() + 1
    row.Parent = parent

    local label = Instance.new("TextLabel")
    label.Name = "Label"
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 0, 0, 0)
    label.Size = UDim2.new(0.6, 0, 1, 0)
    label.Font = Enum.Font.Gotham
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.TextSize = 12
    label.Text = labelText
    label.Parent = row
    applyRowLabelStyle(label, opts.labelStyle or "default")

    local button = Instance.new("TextButton")
    button.Name = "DropdownButton"
    button.AutoButtonColor = false
    button.BackgroundColor3 = Color3.fromRGB(18,18,18)
    button.Size = UDim2.new(0.4, 0, 1, -8)
    button.Position = UDim2.new(0.60, 0, 0, 3)
    button.Font = Enum.Font.Gotham
    button.TextXAlignment = Enum.TextXAlignment.Center
    button.TextSize = 11
    button.TextColor3 = Color3.fromRGB(230,230,230)
    button.Text = "  " .. placeholder
    button.Parent = row
    createCorner(button, 6)
    createStroke(button, Color3.fromRGB(60,60,60), 1, 0.6)

    local arrow = Instance.new("TextLabel")
    arrow.Name = "Arrow"
    arrow.BackgroundTransparency = 1
    arrow.Size = UDim2.new(0, 16, 1, 0)
    arrow.Position = UDim2.new(1, -18, 0, 0)
    arrow.Font = Enum.Font.GothamBold
    arrow.TextSize = 12
    arrow.TextXAlignment = Enum.TextXAlignment.Center
    arrow.TextColor3 = Color3.fromRGB(200,200,200)
    arrow.Text = "▼"
    arrow.Parent = button

    local function normalizeItem(e)
        if type(e) == "table" then
            local key = e.key or e.name
            local lbl = e.name or tostring(e.key)
            key = tostring(key)
            return key, lbl
        else
            local key = tostring(e)
            return key, key
        end
    end

    local function refreshButtonText()
        if mode == "single" then
            if not selectedKey then
                button.Text = "  " .. placeholder
                return
            end
            local label = keyToLabel[selectedKey] or selectedKey
            button.Text = "  " .. label
            return
        end

        local names = {}
        for k, on in pairs(selectedMap) do
            if on then
                table.insert(names, keyToLabel[k] or k)
            end
        end
        table.sort(names)

        if #names == 0 then
            button.Text = "  " .. placeholder
            return
        end

        local maxChars = 25
        local total = table.concat(names, ", ")
        if #total <= maxChars then
            button.Text = "  " .. total
            return
        end

        local shown, used = {}, 0
        for i, name in ipairs(names) do
            local part = (i == 1) and name or (", " .. name)
            if used + #part > maxChars then break end
            table.insert(shown, name)
            used += #part
        end
        local rest = #names - #shown
        local txt = table.concat(shown, ", ")
        if rest > 0 then
            txt ..= (" +%d"):format(rest)
        end
        button.Text = "  " .. txt
    end

    local function syncItemLabels()
        keyToLabel = {}
        for _, e in ipairs(getItemsList() or {}) do
            local k, lbl = normalizeItem(e)
            keyToLabel[k] = lbl
        end
    end

    local function resolveSelectedKey(key)
        if not key or mode ~= "single" then
            return key
        end
        key = tostring(key)
        if keyToLabel[key] then
            return key
        end
        local lower = key:lower()
        for k, lbl in pairs(keyToLabel) do
            if k:lower() == lower or lbl:lower() == lower then
                return k
            end
        end
        local compact = lower:gsub("[^%w]", "")
        for k, lbl in pairs(keyToLabel) do
            if k:lower():gsub("[^%w]", "") == compact then
                return k
            end
            if lbl:lower():gsub("[^%w]", "") == compact then
                return k
            end
        end
        return key
    end

local function openDropdown()
