    --------------------------------------------------
    -- REBUILD LIST (SAMA KAYAK KODEMU SEBELUMNYA)
    --------------------------------------------------
local function rebuildList()
    currentItems = {}
    keyToLabel   = {}
    local onDeleteItem = opts.onDeleteItem

    -- build items + label map
    local rawItems = getItemsList() or {}
    for _, e in ipairs(rawItems) do
        local k, lbl = normalizeItem(e)
        table.insert(currentItems, { key = k, label = lbl })
        keyToLabel[k] = lbl
    end

    local knownKeys = {}
    for _, info in ipairs(currentItems) do
        knownKeys[info.key] = true
    end
    if mode == "multi" then
        for k, on in pairs(selectedMap) do
            if on and not knownKeys[k] then
                local lbl = keyToLabel[k] or (tostring(k) .. " x 0")
                table.insert(currentItems, { key = k, label = lbl })
                keyToLabel[k] = lbl
                knownKeys[k] = true
            end
        end
    elseif mode == "single" and selectedKey and not knownKeys[selectedKey] then
        local lbl = keyToLabel[selectedKey] or (tostring(selectedKey) .. " x 0")
        table.insert(currentItems, { key = selectedKey, label = lbl })
        keyToLabel[selectedKey] = lbl
    end

    -- clear old list children (buttons/labels/frames)
    for _, c in ipairs(list:GetChildren()) do
        if not c:IsA("UIListLayout") and not c:IsA("UIPadding") then
            c:Destroy()
        end
    end

    local q = (search.Text or ""):lower()

    -- helper: check selected
    local function isSelected(k)
        if mode == "single" then
            return selectedKey == k
        else
            return selectedMap[k] == true
        end
    end

    -- filter + split selected/rest
    local picked, rest = {}, {}
    for _, info in ipairs(currentItems) do
        local lbl = tostring(info.label or "")
        local low = lbl:lower()
        if q == "" or low:find(q, 1, true) then
            if isSelected(info.key) then
                table.insert(picked, info)
            else
                table.insert(rest, info)
            end
        end
    end

    -- optional: sort per group biar rapi
    local function byLabel(a, b)
        return tostring(a.label):lower() < tostring(b.label):lower()
    end
    table.sort(picked, byLabel)
    table.sort(rest, byLabel)

    -- merge: selected dulu
    local ordered = {}
    for _, v in ipairs(picked) do table.insert(ordered, v) end
    for _, v in ipairs(rest)   do table.insert(ordered, v) end

    local idx = 0

    -- render
    for _, info in ipairs(ordered) do
        local k   = info.key
        local lbl = info.label

        idx += 1

        local btnItem = Instance.new("TextButton")
        btnItem.Name = "Item_" .. tostring(k)
        btnItem.AutoButtonColor = false
        btnItem.BackgroundColor3 = Color3.fromRGB(22,22,22)
        btnItem.Size = UDim2.new(1, 0, 0, 22)
        btnItem.Text = ""
        btnItem.Font = Enum.Font.Gotham
        btnItem.TextXAlignment = Enum.TextXAlignment.Center
        btnItem.TextSize = 12
        btnItem.TextColor3 = Color3.fromRGB(220,220,220)
        btnItem.LayoutOrder = idx
        btnItem.ZIndex = 101
        btnItem.Parent = list
        createCorner(btnItem, 4)
        
        local txt = Instance.new("TextLabel")
txt.BackgroundTransparency = 1
txt.Size = onDeleteItem and UDim2.new(1, -30, 1, 0) or UDim2.new(1, 0, 1, 0)
txt.Position = onDeleteItem and UDim2.new(0, 6, 0, 0) or UDim2.new(0, 0, 0, 0)
txt.Font = Enum.Font.Gotham
txt.TextXAlignment = onDeleteItem and Enum.TextXAlignment.Left or Enum.TextXAlignment.Center
txt.TextSize = 12
txt.TextColor3 = Color3.fromRGB(220,220,220)
txt.Text = tostring(lbl)
txt.ZIndex = 102
txt.Parent = btnItem

local deleting = false
if onDeleteItem then
    local del = Instance.new("TextButton")
    del.Name = "DeleteButton"
    del.Size = UDim2.new(0, 20, 0, 20)
    del.Position = UDim2.new(1, -24, 0.5, -10)
    del.BackgroundColor3 = Color3.fromRGB(45, 20, 20)
    del.AutoButtonColor = false
    del.Text = "🗑"
    del.Font = Enum.Font.GothamBold
    del.TextSize = 11
    del.TextColor3 = Color3.fromRGB(255,255,255)
    del.ZIndex = 103
    del.Active = true
    del.Parent = btnItem

    createCorner(del, 5)
    createStroke(del, Color3.fromRGB(255,80,80), 1, 0.3)

del.MouseButton1Click:Connect(function()
    deleting = true

    selectedMap[k] = nil
    if selectedKey == k then
        selectedKey = nil
    end

    if onDeleteItem then
        pcall(function()
            onDeleteItem(k, info)
        end)
    end

    if mode == "single" and not selectedKey then
        for _, e in ipairs(getItemsList() or {}) do
            local kk = normalizeItem(e)
            if kk and kk ~= k then
                selectedKey = kk
                break
            end
        end
        if not selectedKey then
            for _, e in ipairs(getItemsList() or {}) do
                local kk = normalizeItem(e)
                if kk then
                    selectedKey = kk
                    break
                end
            end
        end
    end

    refreshButtonText()
    rebuildList()

    task.defer(function()
        deleting = false
    end)
end)
end

