    --------------------------------------------------
    -- CLOSE HANDLER (X & KLIK DI LUAR PANEL)
    --------------------------------------------------
    local UserInputService = game:GetService("UserInputService")

    local function closeOverlay()
        if api then
            api._rebuildOpenList = nil
        end
        if onClose then
            pcall(onClose)
        end
        if overlay and overlay.Parent then
            overlay:Destroy()
        end
    end

    closeBtn.MouseButton1Click:Connect(closeOverlay)

    overlay.MouseButton1Click:Connect(function()
        local mousePos = UserInputService:GetMouseLocation()
        local pPos = panel.AbsolutePosition
        local pSize = panel.AbsoluteSize

        local x, y = mousePos.X, mousePos.Y
        local insideX = x >= pPos.X and x <= pPos.X + pSize.X
        local insideY = y >= pPos.Y and y <= pPos.Y + pSize.Y

        -- kalau klik di LUAR panel → close, kalau di dalam panel → abaikan
        if not (insideX and insideY) then
            closeOverlay()
        end
    end)

    search.Text = ""
    if api then
        api._rebuildOpenList = rebuildList
    end
    rebuildList()
end




    button.MouseEnter:Connect(function()
        tweenColor(button, "BackgroundColor3", Color3.fromRGB(24,24,24))
    end)
    button.MouseLeave:Connect(function()
        tweenColor(button, "BackgroundColor3", Color3.fromRGB(18,18,18))
    end)
    button.MouseButton1Click:Connect(openDropdown)

    syncItemLabels()
    if mode == "single" and selectedKey then
        selectedKey = resolveSelectedKey(selectedKey)
    end
    refreshButtonText()

    if mode == "multi" and type(onChanged) == "function" and next(selectedMap) then
        task.defer(function()
            local copy = {}
            for k, v in pairs(selectedMap) do
                if v then copy[k] = true end
            end
            if next(copy) then
                onChanged("multi", copy)
            end
        end)
    elseif mode == "single" and type(onChanged) == "function" and selectedKey then
        task.defer(function()
            onChanged("single", selectedKey)
        end)
    end

    function api.getMode()
        return mode
    end

    function api.setMode(newMode)
        if newMode == "multi" then
            mode = "multi"
        else
            mode = "single"
        end
        refreshButtonText()
    end

    function api.setSelected(value)
        if mode == "single" then
            selectedKey = value and tostring(value) or nil
        else
            selectedMap = {}
            if type(value) == "table" then
                for k, v in pairs(value) do
                    if v == true or v == 1 or v == "true" then
                        selectedMap[tostring(k)] = true
                    end
                end
            end
        end
        refreshButtonText()
    end

    function api.getSelected()
        if mode == "single" then
            return selectedKey
        else
            local copy = {}
            for k, v in pairs(selectedMap) do
                if v then copy[k] = true end
            end
            return copy
        end
    end

    function api.refreshLabel()
        refreshButtonText()
    end

    function api.refreshItems()
        syncItemLabels()
        refreshButtonText()
        if type(api._rebuildOpenList) == "function" then
            pcall(api._rebuildOpenList)
        end
    end

    return row, api
end

