        local on = toggleApiGet("__GAG2_CLAIM_SEED_TOGGLE_API")
        if on ~= nil then
            writeClaimSeedState(on)
            applyClaimSeedRuntime(on == true)
        end
    end

    G.__GAG2_READ_CLAIM_SEED = readClaimSeedEnabled
    G.__GAG2_WRITE_CLAIM_SEED = writeClaimSeedState
    G.__GAG2_SYNC_AUTO_CLAIM_SEED = syncAutoClaimSeedAll
