    _G.__GAG2_FLUSH_AUTO_TELE = flushAutoTeleState

    ----------------------------------------------------------------
    -- helpers (shared)
    ----------------------------------------------------------------
    local function cleanSelectedMap(selectedMap)
        local out = {}
        if type(selectedMap) ~= "table" then
            return out
        end
        for k, v in pairs(selectedMap) do
            if v == true then
                out[tostring(k)] = true
            elseif type(k) == "number" and (type(v) == "string" or type(v) == "number") then
                local s = tostring(v)
                if s ~= "" then out[s] = true end
            elseif type(k) == "number" and type(v) == "table" then
                local kk = v.key or v.name or v.id
                if kk then out[tostring(kk)] = true end
            elseif type(k) == "string" and type(v) == "table" then
                out[tostring(k)] = true
            end
        end
        return out
    end

    local function mapToArray(map)
        local arr = {}
        if type(map) == "table" then
            for k, v in pairs(map) do
                if v == true then
                    arr[#arr + 1] = tostring(k)
                end
            end
        end
        table.sort(arr)
        return arr
    end

    local function arrayToMap(arr)
        local m = {}
        if type(arr) == "table" then
            for _, v in ipairs(arr) do
                if v ~= nil and tostring(v) ~= "" then
                    m[tostring(v)] = true
                end
            end
            if next(m) then return m end
            for k, v in pairs(arr) do
                if v == true or v == 1 or v == "true" then
                    m[tostring(k)] = true
                end
            end
        end
        return m
    end

    registerToggleFlush("collect", "collect", "__GAG2_COLLECT_ENABLE_API")
    registerToggleFlush("plant", "plant", "__GAG2_PLANT_ENABLE_API")
    registerToggleFlush("sell", "sell", "__GAG2_SELL_ENABLE_API")
    registerFlush("buy", function()
        local seedOn = toggleApiGet("__GAG2_BUY_SEED_ENABLE_API")
        local gearOn = toggleApiGet("__GAG2_BUY_GEAR_ENABLE_API")
        local propsOn = toggleApiGet("__GAG2_BUY_PROPS_ENABLE_API")
        if seedOn == nil and gearOn == nil and propsOn == nil then return end
        local partial = {}
        if seedOn ~= nil then partial.seed = { enabled = seedOn } end
        if gearOn ~= nil then partial.gear = { enabled = gearOn } end
        if propsOn ~= nil then partial.props = { enabled = propsOn } end
        if type(State) == "table" and type(State.patchAuto) == "function" then
            pcall(State.patchAuto, "buy", partial, { noSync = true })
        end
    end)

    ----------------------------------------------------------------
    -- Auto Buy Pet
    ----------------------------------------------------------------
    if type(G.__GAG2_BUY_PET) ~= "table" then
        G.__GAG2_BUY_PET = {
            enabled = false,
            auto_tame = false,
            max_price_mult = 2,
            selected = {},
        }
    end
    _G.__GAG2_BUY_PET = G.__GAG2_BUY_PET

    local function ensureBuyPetStore()
        local s = G.__GAG2_BUY_PET
        if type(s) ~= "table" then
            s = {
                enabled = false,
                auto_tame = false,
                max_price_mult = 2,
                selected = {},
            }
            G.__GAG2_BUY_PET = s
        end

        s.enabled = (s.enabled == true)
        s.auto_tame = (s.auto_tame == true)
        local mult = tonumber(s.max_price_mult)
        s.max_price_mult = (mult and mult >= 1) and mult or 2
        s.selected = cleanSelectedMap(s.selected or {})

        if not s._hydrated then
            local m = getMainRef()
            if type(m) == "table" and type(m.auto) == "table"
                and type(m.auto.buy) == "table" and type(m.auto.buy.pet) == "table" then
                local pet = m.auto.buy.pet
                s.enabled = (pet.enabled == true)
                s.auto_tame = (pet.auto_tame == true)
                local pm = tonumber(pet.max_price_mult)
                s.max_price_mult = (pm and pm >= 1) and pm or 2
                if type(pet.items) == "table" and next(pet.items) then
                    s.selected = cleanSelectedMap(arrayToMap(pet.items))
                end
            end
            s._hydrated = true
        end

        G.__GAG2_BUY_PET = s
        _G.__GAG2_BUY_PET = s
        return s
    end

    local function writeBuyPetToMain()
        local s = ensureBuyPetStore()
        G.__GAG2_BUY_PET = s
        _G.__GAG2_BUY_PET = s

        G.AUTO_BUY_PET_ENABLED = s.enabled
        _G.AUTO_BUY_PET_ENABLED = s.enabled
        G.AUTO_TAME_PET_ENABLED = s.auto_tame
        _G.AUTO_TAME_PET_ENABLED = s.auto_tame
        G.AUTO_BUY_PET_MAX_PRICE_MULT = s.max_price_mult
        _G.AUTO_BUY_PET_MAX_PRICE_MULT = s.max_price_mult
        G.BUY_PET_SELECTED = s.selected
        _G.BUY_PET_SELECTED = s.selected
        G.GAG2_PET_LIST = mapToArray(s.selected)
        _G.GAG2_PET_LIST = G.GAG2_PET_LIST

        local m = getMainRef()
        if type(m) == "table" then
            m.auto = m.auto or {}
            m.auto.buy = m.auto.buy or {}
            m.auto.buy.pet = {
                enabled = s.enabled,
                auto_tame = s.auto_tame,
                max_price_mult = s.max_price_mult,
                items = mapToArray(s.selected),
            }
            G.MAIN = m
            _G.MAIN = m
        end

        patchAutoOnly("buy", {
            pet = {
                enabled = s.enabled,
                auto_tame = s.auto_tame,
                max_price_mult = s.max_price_mult,
                items = mapToArray(s.selected),
            },
        })

        return s
    end

    local function writeBuyPetState(opts)
        local s = ensureBuyPetStore()
        if type(opts) == "table" then
            if opts.enabled ~= nil then s.enabled = (opts.enabled == true) end
            if opts.auto_tame ~= nil then s.auto_tame = (opts.auto_tame == true) end
            if opts.max_price_mult ~= nil then
                local n = tonumber(opts.max_price_mult) or 2
                s.max_price_mult = (n >= 1) and n or 2
            end
            if opts.selected ~= nil then
                s.selected = cleanSelectedMap(opts.selected)
            end
        end
        return writeBuyPetToMain()
    end

    local function readBuyPetAutoTame()
        local s = ensureBuyPetStore()
        if s.auto_tame == true then return true end

        local m = getMainRef()
        if type(m) == "table" and type(m.auto) == "table"
            and type(m.auto.buy) == "table" and type(m.auto.buy.pet) == "table" then
            if m.auto.buy.pet.auto_tame == true then
                s.auto_tame = true
                G.__GAG2_BUY_PET = s
                _G.__GAG2_BUY_PET = s
                return true
            end
        end

        if G.AUTO_TAME_PET_ENABLED == true or rawget(_G, "AUTO_TAME_PET_ENABLED") == true then
            s.auto_tame = true
            G.__GAG2_BUY_PET = s
            _G.__GAG2_BUY_PET = s
            return true
        end

        return false
    end

    local function readBuyPetEnabled()
        local s = ensureBuyPetStore()
        if s.enabled == true then return true end

        local m = getMainRef()
        if type(m) == "table" and type(m.auto) == "table"
            and type(m.auto.buy) == "table" and type(m.auto.buy.pet) == "table" then
            if m.auto.buy.pet.enabled == true then
                s.enabled = true
                G.__GAG2_BUY_PET = s
                _G.__GAG2_BUY_PET = s
                return true
            end
        end

        if G.AUTO_BUY_PET_ENABLED == true or rawget(_G, "AUTO_BUY_PET_ENABLED") == true then
            s.enabled = true
            G.__GAG2_BUY_PET = s
            _G.__GAG2_BUY_PET = s
            return true
        end

        return false
    end

    local function getAutoBuyPetModule()
        return G.AutoBuyPetModule or G.AutoBuyPet or _G.AutoBuyPetModule or _G.AutoBuyPet
    end

    local function syncBuyPetStoreFromMain()
        local s = ensureBuyPetStore()
        local m = getMainRef()
        if type(m) == "table" and type(m.auto) == "table"
            and type(m.auto.buy) == "table" and type(m.auto.buy.pet) == "table" then
            local pet = m.auto.buy.pet
            if pet.enabled == true then s.enabled = true end
            if pet.auto_tame == true then s.auto_tame = true end
            local pm = tonumber(pet.max_price_mult)
            if pm and pm >= 1 then s.max_price_mult = pm end
            if type(pet.items) == "table" and next(pet.items) then
                local fromMain = cleanSelectedMap(arrayToMap(pet.items))
                if next(fromMain) then
                    if not next(s.selected) then
                        s.selected = fromMain
                    end
                end
            end
        end
        if G.AUTO_BUY_PET_ENABLED == true or rawget(_G, "AUTO_BUY_PET_ENABLED") == true then
            s.enabled = true
        end
        if G.AUTO_TAME_PET_ENABLED == true or rawget(_G, "AUTO_TAME_PET_ENABLED") == true then
            s.auto_tame = true
        end
        local petMap = G.BUY_PET_SELECTED or rawget(_G, "BUY_PET_SELECTED")
        if type(petMap) == "table" and next(petMap) and not next(s.selected) then
            s.selected = cleanSelectedMap(petMap)
        end
        G.__GAG2_BUY_PET = s
        _G.__GAG2_BUY_PET = s
        return s
    end

    local function applyBuyPetRuntime(on)
        syncBuyPetStoreFromMain()
        if on == nil then
            on = readBuyPetEnabled()
        else
            on = (on == true)
        end
        local tameOn = readBuyPetAutoTame()
        local s = ensureBuyPetStore()

        s = writeBuyPetState({
            enabled = on,
            auto_tame = tameOn,
            max_price_mult = s.max_price_mult,
            selected = s.selected,
        })

        local abp = getAutoBuyPetModule()
        if type(abp) ~= "table" then return end

        if type(abp.SetSelected) == "function" then
            pcall(abp.SetSelected, abp, s.selected)
        end
        if type(abp.SetAutoTame) == "function" then
            pcall(abp.SetAutoTame, abp, tameOn == true)
        end
        if type(abp.SetMaxPriceMult) == "function" then
            pcall(abp.SetMaxPriceMult, abp, s.max_price_mult)
        end
        if on then
            if type(abp.ApplyRuntime) == "function" then
                pcall(abp.ApplyRuntime, abp, true)
            elseif type(abp.Start) == "function" then
                pcall(abp.Start, abp)
            end
            if type(abp.EnsureRunning) == "function" then
                pcall(abp.EnsureRunning, abp)
            end
        else
            if type(abp.ApplyRuntime) == "function" then
                pcall(abp.ApplyRuntime, abp, false)
            elseif type(abp.Stop) == "function" then
                pcall(abp.Stop, abp)
            end
        end
    end

    local function flushBuyPetFromUI()
        if G.__GAG2_RESETTING == true then return end
        local opts = {}
        local dd = G.__GAG2_BUY_PET_DROPDOWN_API or rawget(_G, "__GAG2_BUY_PET_DROPDOWN_API")
        if type(dd) == "table" and type(dd.getSelected) == "function" then
            opts.selected = cleanSelectedMap(dd.getSelected())
        end
        local en = G.__GAG2_BUY_PET_ENABLE_API or rawget(_G, "__GAG2_BUY_PET_ENABLE_API")
        if type(en) == "table" and type(en.get) == "function" then
            opts.enabled = en.get() == true
        end
        local tm = G.__GAG2_BUY_PET_TAME_API or rawget(_G, "__GAG2_BUY_PET_TAME_API")
        if type(tm) == "table" and type(tm.get) == "function" then
            opts.auto_tame = tm.get() == true
        end
        local getPrice = G.__GAG2_BUY_PET_PRICE_GET or rawget(_G, "__GAG2_BUY_PET_PRICE_GET")
        if type(getPrice) == "function" then
            local n = tonumber(getPrice())
            if n and n >= 1 then
                opts.max_price_mult = n
            end
        end

        if next(opts) ~= nil then
            writeBuyPetState(opts)
        else
            syncBuyPetStoreFromMain()
            writeBuyPetToMain()
        end
    end

    local function syncAutoBuyPetAll()
        if G.__GAG2_RESETTING == true then
            syncBuyPetStoreFromMain()
            writeBuyPetToMain()
            applyBuyPetRuntime(false)
            return
        end
        flushBuyPetFromUI()
        applyBuyPetRuntime(readBuyPetEnabled())
    end

    local function saveBuyPetNow()
        flushBuyPetFromUI()
        saveNow()
    end

    G.__GAG2_READ_BUY_PET = readBuyPetEnabled
    G.__GAG2_WRITE_BUY_PET = writeBuyPetState
    G.__GAG2_WRITE_BUY_PET_MAIN = writeBuyPetToMain
    G.__GAG2_SYNC_AUTO_BUY_PET = syncAutoBuyPetAll
    G.__GAG2_FLUSH_BUY_PET = flushBuyPetFromUI
    G.__GAG2_SAVE_BUY_PET = saveBuyPetNow
    registerFlush("buyPet", flushBuyPetFromUI)
    _G.__GAG2_READ_BUY_PET = readBuyPetEnabled
    _G.__GAG2_WRITE_BUY_PET = writeBuyPetState
    _G.__GAG2_WRITE_BUY_PET_MAIN = writeBuyPetToMain
    _G.__GAG2_SYNC_AUTO_BUY_PET = syncAutoBuyPetAll
    _G.__GAG2_FLUSH_BUY_PET = flushBuyPetFromUI
    _G.__GAG2_SAVE_BUY_PET = saveBuyPetNow

    ----------------------------------------------------------------
    -- Auto Gift — persist via G.__GAG2_AUTO_GIFT (mailbox categories from game catalog)
    ----------------------------------------------------------------
    local GIFT_LEGACY_ALIASES = { Tools = "Pets", EmptyPots = "DustyPots", InstyPots = "DustyPots" }

    local function migrateLegacyGiftStore(s)
        if type(s) ~= "table" then return end
        s.categories = type(s.categories) == "table" and s.categories or {}
        s.selected = type(s.selected) == "table" and s.selected or {}
        s.send_totals = type(s.send_totals) == "table" and s.send_totals or {}
        for legacy, canon in pairs(GIFT_LEGACY_ALIASES) do
            if s.categories[legacy] == true then
                s.categories[canon] = true
                s.categories[legacy] = false
            end
            if type(s.selected[legacy]) == "table" and next(s.selected[legacy]) then
                s.selected[canon] = s.selected[canon] or {}
                for k, v in pairs(s.selected[legacy]) do
                    if v == true then s.selected[canon][k] = true end
                end
                s.selected[legacy] = {}
            end
            if s.send_totals[legacy] ~= nil and s.send_totals[canon] == nil then
                s.send_totals[canon] = s.send_totals[legacy]
            end
        end
    end

    local function defaultGiftCategoryMap()
        local t = {}
        for _, def in ipairs(buildGiftCatUiDefs()) do
            t[def.key] = false
        end
        local store = G.__GAG2_AUTO_GIFT
        if type(store) == "table" and type(store.categories) == "table" then
            for key in pairs(store.categories) do
                if t[key] == nil then t[key] = false end
            end
        end
        return t
    end

    local function defaultGiftSelectedMap()
        local t = {}
        for _, def in ipairs(buildGiftCatUiDefs()) do
            t[def.key] = {}
        end
        local store = G.__GAG2_AUTO_GIFT
        if type(store) == "table" and type(store.selected) == "table" then
            for key in pairs(store.selected) do
                if t[key] == nil then t[key] = {} end
            end
        end
        return t
    end

    local function defaultGiftSendTotals()
        local t = {}
        for _, def in ipairs(buildGiftCatUiDefs()) do
            t[def.key] = 20
        end
        local store = G.__GAG2_AUTO_GIFT
        if type(store) == "table" and type(store.send_totals) == "table" then
            for key in pairs(store.send_totals) do
                if t[key] == nil then t[key] = 20 end
            end
        end
        return t
    end

    local function buildGiftCatUiDefs()
        local ag = G.AutoGiftModule or G.AutoGift or _G.AutoGiftModule or _G.AutoGift
        if type(ag) ~= "table" then return {} end
        if type(ag.IsCatalogLoaded) == "function" and not ag.IsCatalogLoaded(ag) then
            if type(ag.ReloadCatalog) == "function" then
                pcall(ag.ReloadCatalog, ag)
            end
        end
        if type(ag.GetCategoryDefs) == "function" then
            local ok, defs = pcall(ag.GetCategoryDefs, ag)
            if ok and type(defs) == "table" and #defs > 0 then
                local out = {}
                for _, def in ipairs(defs) do
                    local label = def.label or def.key
                    out[#out + 1] = {
                        key = def.key,
                        label = label,
                        itemLabel = label .. " list",
                        placeholder = "All " .. string.lower(label) .. "...",
                    }
                end
                return out
            end
        end
        return {}
    end

    local function getGiftCatKeys()
        local keys = {}
        for _, def in ipairs(buildGiftCatUiDefs()) do
            keys[#keys + 1] = def.key
        end
        return keys
    end

    if type(G.__GAG2_AUTO_GIFT) ~= "table" then
        G.__GAG2_AUTO_GIFT = {
            enabled = false,
            auto_send = false,
            auto_claim_mail = false,
            auto_accept_gift = false,
            recipient_username = "",
            recipient_user_id = 0,
            recipient_display = "",
            categories = defaultGiftCategoryMap(),
            selected = defaultGiftSelectedMap(),
            skip_equipped = true,
            max_per_batch = 20,
            note = "",
            delay_sec = 1,
            send_totals = defaultGiftSendTotals(),
            category_mode = "single",
            send_list_mode = "loop",
            send_total = 20,
            after_send_mode = "keep",
        }
    end
    _G.__GAG2_AUTO_GIFT = G.__GAG2_AUTO_GIFT

    local function ensureAutoGiftStore()
        local s = G.__GAG2_AUTO_GIFT
        if type(s) ~= "table" then
            s = {
                enabled = false,
                auto_send = false,
                auto_claim_mail = false,
                auto_accept_gift = false,
                recipient_username = "",
                recipient_user_id = 0,
                recipient_display = "",
                categories = defaultGiftCategoryMap(),
                selected = defaultGiftSelectedMap(),
                skip_equipped = true,
                max_per_batch = 20,
                note = "",
                delay_sec = 1,
                send_totals = defaultGiftSendTotals(),
                category_mode = "single",
                send_list_mode = "loop",
                send_total = 20,
                after_send_mode = "keep",
            }
            G.__GAG2_AUTO_GIFT = s
        end

        s.enabled = (s.enabled == true)
        s.auto_send = (s.auto_send == true)
        s.auto_claim_mail = (s.auto_claim_mail == true)
        s.auto_accept_gift = (s.auto_accept_gift == true)
        s.recipient_username = tostring(s.recipient_username or "")
        s.recipient_user_id = math.floor(tonumber(s.recipient_user_id) or 0)
        s.recipient_display = tostring(s.recipient_display or "")
        s.skip_equipped = (s.skip_equipped ~= false)
        s.max_per_batch = math.floor(math.max(1, math.min(20, tonumber(s.max_per_batch) or 20)))
        s.note = tostring(s.note or "")
        s.delay_sec = tonumber(s.delay_sec) or 1
        if s.delay_sec == 3 or s.delay_sec == 6 or s.delay_sec == 8 then s.delay_sec = 1 end
        if s.delay_sec < 1 then s.delay_sec = 1 end

        migrateLegacyGiftStore(s)

        s.categories = type(s.categories) == "table" and s.categories or {}
        for _, key in ipairs(getGiftCatKeys()) do
            s.categories[key] = (s.categories[key] == true)
        end

        s.selected = type(s.selected) == "table" and s.selected or {}
        for _, key in ipairs(getGiftCatKeys()) do
            s.selected[key] = cleanSelectedMap(s.selected[key] or {})
        end

        s.send_totals = type(s.send_totals) == "table" and s.send_totals or {}
        for _, key in ipairs(getGiftCatKeys()) do
            local n = math.floor(tonumber(s.send_totals[key]) or 20)
            if n < 1 then n = 1 end
            s.send_totals[key] = n
        end

        s.category_mode = tostring(s.category_mode or "single"):lower()
        if s.category_mode ~= "multi" then s.category_mode = "single" end
        local slm = tostring(s.send_list_mode or "loop"):lower():gsub("%s+", "")
        if slm == "sendtotal" or slm == "send_total" or slm == "total" then
            s.send_list_mode = "send_total"
        else
            s.send_list_mode = "loop"
        end
        s.send_total = math.floor(tonumber(s.send_total) or 20)
        if s.send_total < 1 then s.send_total = 1 end
        s.after_send_mode = tostring(s.after_send_mode or "keep"):lower()
        if s.after_send_mode ~= "reset" then s.after_send_mode = "keep" end

        local curEpoch = tonumber(G.__GAG2_GIFT_STORE_EPOCH) or tonumber(_G.__GAG2_GIFT_STORE_EPOCH) or 0
        if curEpoch > (tonumber(s._storeEpoch) or 0) then
            s._hydrated = false
            s._storeEpoch = curEpoch
        end

        if not s._hydrated then
            local m = getMainRef()
            if type(m) == "table" and type(m.auto) == "table" and type(m.auto.gift) == "table" then
                local g = m.auto.gift
                s.enabled = (g.enabled == true)
                s.auto_send = (g.auto_send == true)
                s.auto_claim_mail = (g.auto_claim_mail == true)
                s.auto_accept_gift = (g.auto_accept_gift == true)
                s.recipient_username = tostring(g.recipient_username or "")
                s.recipient_user_id = math.floor(tonumber(g.recipient_user_id) or 0)
                s.recipient_display = tostring(g.recipient_display or "")
                s.skip_equipped = (g.skip_equipped ~= false)
                s.max_per_batch = math.floor(math.max(1, math.min(20, tonumber(g.max_per_batch) or 20)))
                s.note = tostring(g.note or "")
                s.delay_sec = tonumber(g.delay_sec) or 1
                if type(g.categories) == "table" then
                    for _, key in ipairs(getGiftCatKeys()) do
                        s.categories[key] = (g.categories[key] == true)
                    end
                end
                if type(g.selected) == "table" then
                    for _, key in ipairs(getGiftCatKeys()) do
                        local arr = g.selected[key]
                        if type(arr) == "table" and next(arr) then
                            s.selected[key] = cleanSelectedMap(arrayToMap(arr))
                        end
                    end
                end
                if type(g.send_totals) == "table" then
                    s.send_totals = s.send_totals or {}
                    for _, key in ipairs(getGiftCatKeys()) do
                        if g.send_totals[key] ~= nil then
                            s.send_totals[key] = math.floor(tonumber(g.send_totals[key]) or 20)
                        end
                    end
                end
            end
            s._hydrated = true
        end

        G.__GAG2_AUTO_GIFT = s
        _G.__GAG2_AUTO_GIFT = s
        return s
    end

    local function giftPayloadFromStore(s)
        s = ensureAutoGiftStore()
        local categories = {}
        local selected = {}
        local send_totals = {}
        for _, key in ipairs(getGiftCatKeys()) do
            categories[key] = (s.categories[key] == true)
            selected[key] = mapToArray(s.selected[key])
            send_totals[key] = math.floor(tonumber(s.send_totals and s.send_totals[key]) or 20)
        end
        return {
            enabled = (s.enabled == true),
            auto_send = (s.auto_send == true),
            auto_claim_mail = (s.auto_claim_mail == true),
            auto_accept_gift = (s.auto_accept_gift == true),
            recipient_username = tostring(s.recipient_username or ""),
            recipient_user_id = math.floor(tonumber(s.recipient_user_id) or 0),
            recipient_display = tostring(s.recipient_display or ""),
            categories = categories,
            selected = selected,
            skip_equipped = (s.skip_equipped == true),
            max_per_batch = math.floor(tonumber(s.max_per_batch) or 20),
            note = tostring(s.note or ""),
            delay_sec = tonumber(s.delay_sec) or 1,
            send_totals = send_totals,
            category_mode = s.category_mode,
            send_list_mode = s.send_list_mode,
            send_total = s.send_total,
            after_send_mode = s.after_send_mode,
        }
    end

    local function giftConfigFromStore(s)
        s = ensureAutoGiftStore()
        local categories = {}
        local selected = {}
        local send_totals = {}
        for _, key in ipairs(getGiftCatKeys()) do
            categories[key] = s.categories[key] == true
            selected[key] = cleanSelectedMap(s.selected[key])
            send_totals[key] = math.floor(tonumber(s.send_totals and s.send_totals[key]) or 20)
        end
        return {
            enabled = s.enabled,
            auto_send = s.auto_send,
            auto_claim_mail = s.auto_claim_mail,
            auto_accept_gift = s.auto_accept_gift,
            recipient_username = s.recipient_username,
            recipient_user_id = s.recipient_user_id,
            recipient_display = s.recipient_display,
            categories = categories,
            selected = selected,
            skip_equipped = s.skip_equipped,
            max_per_batch = s.max_per_batch,
            note = s.note,
            delay_sec = s.delay_sec,
            send_totals = send_totals,
            category_mode = s.category_mode,
            send_list_mode = s.send_list_mode,
            send_total = s.send_total,
            after_send_mode = s.after_send_mode,
        }
    end

    local function giftCategoryModeFromStore(s)
        s = ensureAutoGiftStore()
        local m = tostring(s.category_mode or "single"):lower()
        return (m == "multi") and "multi" or "single"
    end

    local function safeDdGetSelected(api)
        if type(api) ~= "table" then return nil end
        local fn = api.getSelected
        if type(fn) ~= "function" then return nil end
        local ok, sel = pcall(fn, api)
        if ok then return sel end
        ok, sel = pcall(fn)
        if ok then return sel end
        return nil
    end

    local function readGiftDropdownSelected(key)
        return safeDdGetSelected(G[key] or rawget(_G, key))
    end

    local function categoriesMapFromDd(api, categoryMode)
        local sel = safeDdGetSelected(api)
        if sel == nil then return {} end
        if categoryMode == "single" then
            local key = sel
            if type(key) == "table" then
                key = nil
                for k, v in pairs(sel) do
                    if v == true then
                        key = tostring(k)
                        break
                    end
                end
            end
            local cats = {}
            for _, def in ipairs(buildGiftCatUiDefs()) do
                cats[def.key] = (key ~= nil and tostring(key) == def.key)
            end
            return cats
        end
        if type(sel) ~= "table" then
            return {}
        end
        return cleanSelectedMap(sel)
    end

    local function selectedMapFromDd(dd, categoryMode)
        local sel = safeDdGetSelected(dd)
        if sel == nil then return {} end
        if categoryMode == "single" then
            if type(sel) == "table" then
                return cleanSelectedMap(sel)
            end
            if tostring(sel) ~= "" then
                return { [tostring(sel)] = true }
            end
            return {}
        end
        if type(sel) ~= "table" then
            return {}
        end
        return cleanSelectedMap(sel)
    end

    local function readGiftUiValue(key, mode)
        mode = mode or "fn"
        local api = G[key] or rawget(_G, key)
        if mode == "toggle" then
            if type(api) == "table" and type(api.get) == "function" then
                local ok, v = pcall(api.get, api)
                if ok then return v end
            end
            return nil
        end
        if type(api) == "function" then
            local ok, v = pcall(api)
            if ok then return v end
        end
        if type(api) == "table" and type(api.get) == "function" then
            local ok, v = pcall(api.get, api)
            if ok then return v end
        end
        return nil
    end

    local function writeAutoGiftToMain()
        local s = ensureAutoGiftStore()
        G.__GAG2_AUTO_GIFT = s
        _G.__GAG2_AUTO_GIFT = s

        G.AUTO_GIFT_ENABLED = s.enabled
        _G.AUTO_GIFT_ENABLED = s.enabled
        G.AUTO_GIFT_AUTO_SEND = s.auto_send
        _G.AUTO_GIFT_AUTO_SEND = s.auto_send

        local m = getMainRef()
        if type(m) == "table" then
            m.auto = m.auto or {}
            m.auto.gift = giftPayloadFromStore(s)
            G.MAIN = m
            _G.MAIN = m
        end

        local payload = giftPayloadFromStore(s)
        local maps = payload.selected or {}
        local selected = {}
        for _, key in ipairs(getGiftCatKeys()) do
            selected[key] = mapToArray(maps[key] or {})
        end
        payload.selected = selected
        patchAutoOnly("gift", payload)

        return s
    end

    local function writeAutoGiftState(opts)
        local s = ensureAutoGiftStore()
        if type(opts) == "table" then
            if opts.enabled ~= nil then s.enabled = (opts.enabled == true) end
            if opts.auto_send ~= nil then s.auto_send = (opts.auto_send == true) end
            if opts.auto_claim_mail ~= nil then s.auto_claim_mail = (opts.auto_claim_mail == true) end
            if opts.auto_accept_gift ~= nil then s.auto_accept_gift = (opts.auto_accept_gift == true) end
            if opts.recipient_username ~= nil then
                s.recipient_username = tostring(opts.recipient_username or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
            end
            if opts.recipient_user_id ~= nil then
                s.recipient_user_id = math.floor(tonumber(opts.recipient_user_id) or 0)
            end
            if opts.recipient_display ~= nil then
                s.recipient_display = tostring(opts.recipient_display or "")
            end
            if opts.skip_equipped ~= nil then s.skip_equipped = (opts.skip_equipped == true) end
            if opts.max_per_batch ~= nil then
                s.max_per_batch = math.floor(math.max(1, math.min(20, tonumber(opts.max_per_batch) or 20)))
            end
            if opts.note ~= nil then s.note = tostring(opts.note or "") end
            if opts.delay_sec ~= nil then
                local d = tonumber(opts.delay_sec) or 1
                if d == 3 or d == 6 or d == 8 then d = 1 end
                s.delay_sec = (d >= 1) and d or 1
            end
            if type(opts.categories) == "table" then
                for _, key in ipairs(getGiftCatKeys()) do
                    if opts.categories[key] ~= nil then
                        s.categories[key] = (opts.categories[key] == true)
                    end
                end
            end
            if type(opts.selected) == "table" then
                for _, key in ipairs(getGiftCatKeys()) do
                    if opts.selected[key] ~= nil then
                        s.selected[key] = cleanSelectedMap(opts.selected[key])
                    end
                end
            end
            if type(opts.send_totals) == "table" then
                s.send_totals = s.send_totals or {}
                for _, key in ipairs(getGiftCatKeys()) do
                    if opts.send_totals[key] ~= nil then
                        local n = math.floor(tonumber(opts.send_totals[key]) or 20)
                        if n < 1 then n = 1 end
                        s.send_totals[key] = n
                    end
                end
            end
            if opts.category_mode ~= nil then
                local m = tostring(opts.category_mode):lower()
                s.category_mode = (m == "multi") and "multi" or "single"
            end
            if opts.send_list_mode ~= nil then
                local m = tostring(opts.send_list_mode):lower():gsub("%s+", "")
                s.send_list_mode = (m == "sendtotal" or m == "send_total" or m == "total") and "send_total" or "loop"
            end
            if opts.send_total ~= nil then
                local n = math.floor(tonumber(opts.send_total) or 1)
                if n < 1 then n = 1 end
                s.send_total = n
            end
            if opts.after_send_mode ~= nil then
                s.after_send_mode = (tostring(opts.after_send_mode):lower() == "reset") and "reset" or "keep"
            end
        end
        return writeAutoGiftToMain()
    end

    local function patchGift(opts, syncFn)
        writeAutoGiftState(opts)
        if syncFn then pcall(syncFn) end
        saveNow()
    end

    local function syncAutoGiftStoreFromMain()
        local s = ensureAutoGiftStore()
        local m = getMainRef()
        if type(m) == "table" and type(m.auto) == "table" and type(m.auto.gift) == "table" then
            local g = m.auto.gift
            s.enabled = (g.enabled == true)
            s.auto_send = (g.auto_send == true)
            s.auto_claim_mail = (g.auto_claim_mail == true)
            s.auto_accept_gift = (g.auto_accept_gift == true)
            if type(g.recipient_username) == "string" and g.recipient_username ~= "" then
                if s.recipient_username == "" then s.recipient_username = g.recipient_username end
            end
            if (tonumber(g.recipient_user_id) or 0) > 0 then
                if (tonumber(s.recipient_user_id) or 0) <= 0 then
                    s.recipient_user_id = math.floor(tonumber(g.recipient_user_id))
                end
            end
            if type(g.recipient_display) == "string" and g.recipient_display ~= "" then
                if s.recipient_display == "" then s.recipient_display = g.recipient_display end
            end
            if g.note ~= nil and tostring(g.note) ~= "" and tostring(s.note or "") == "" then
                s.note = tostring(g.note)
            end
            if tonumber(g.delay_sec) and (tonumber(s.delay_sec) or 0) <= 0 then
                s.delay_sec = tonumber(g.delay_sec)
            end
            if tonumber(g.max_per_batch) then
                s.max_per_batch = math.floor(tonumber(g.max_per_batch))
            end
            if g.skip_equipped ~= nil then
                s.skip_equipped = (g.skip_equipped == true)
            end
            if type(g.categories) == "table" then
                for _, key in ipairs(getGiftCatKeys()) do
                    s.categories[key] = (g.categories[key] == true) or (s.categories[key] == true)
                end
            end
            if type(g.selected) == "table" then
                for _, key in ipairs(getGiftCatKeys()) do
                    local fromMain = cleanSelectedMap(arrayToMap(g.selected[key]))
                    if next(fromMain) then
                        s.selected[key] = fromMain
                    end
                end
            end
        end
        G.__GAG2_AUTO_GIFT = s
        _G.__GAG2_AUTO_GIFT = s
        return s
    end

    local function readAutoGiftEnabled()
        local s = ensureAutoGiftStore()
        if s.enabled == true then return true end
        syncAutoGiftStoreFromMain()
        return ensureAutoGiftStore().enabled == true
    end

    local function getAutoGiftModule()
        return G.AutoGiftModule or G.AutoGift or _G.AutoGiftModule or _G.AutoGift
    end

    local function flushAutoGiftFromUI()
        if G.__GAG2_RESETTING == true then return end
        if G.__GAG2_AUTO_GIFT_UI_READY ~= true then
            syncAutoGiftStoreFromMain()
            writeAutoGiftToMain()
            return
        end

        local ok, err = pcall(function()
            local opts = {}
            local key = readGiftUiValue("__GAG2_AUTO_GIFT_TARGET_API", "fn")
            if key ~= nil and tostring(key) ~= "" then
                key = tostring(key):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
                opts.recipient_username = key
                for _, p in ipairs(game:GetService("Players"):GetPlayers()) do
                    if p.Name == key then
                        opts.recipient_user_id = p.UserId
                        opts.recipient_display = p.DisplayName
                        break
                    end
                end
                if opts.recipient_user_id == nil then
                    local cur = ensureAutoGiftStore()
                    if cur.recipient_username == key and (tonumber(cur.recipient_user_id) or 0) > 0 then
                        opts.recipient_user_id = cur.recipient_user_id
                        opts.recipient_display = cur.recipient_display
                    end
                end
            end

            local noteVal = readGiftUiValue("__GAG2_AUTO_GIFT_NOTE_API", "fn")
            if noteVal ~= nil then
                opts.note = tostring(noteVal)
            end
            local delayVal = readGiftUiValue("__GAG2_AUTO_GIFT_DELAY_API", "fn")
            if delayVal ~= nil then
                opts.delay_sec = tonumber(delayVal)
            end
            local claimVal = readGiftUiValue("__GAG2_AUTO_GIFT_CLAIM_API", "toggle")
            if claimVal ~= nil then
                opts.auto_claim_mail = claimVal == true
            end
            local acceptVal = readGiftUiValue("__GAG2_AUTO_GIFT_ACCEPT_NORMAL_API", "toggle")
            if acceptVal ~= nil then
                opts.auto_accept_gift = acceptVal == true
            end

            local cats = {}
            local catMode = giftCategoryModeFromStore(ensureAutoGiftStore())
            local catDd = G.__GAG2_AUTO_GIFT_CAT_MULTI or rawget(_G, "__GAG2_AUTO_GIFT_CAT_MULTI")
            if type(catDd) == "table" then
                cats = categoriesMapFromDd(catDd, catMode)
            else
                for _, catKey in ipairs(getGiftCatKeys()) do
                    local api = G["__GAG2_AUTO_GIFT_CAT_" .. catKey] or rawget(_G, "__GAG2_AUTO_GIFT_CAT_" .. catKey)
                    if type(api) == "table" and type(api.get) == "function" then
                        local getOk, on = pcall(api.get, api)
                        if getOk then
                            cats[catKey] = on == true
                        end
                    end
                end
            end
            if next(cats) then opts.categories = cats end

            local sel = {}
            for _, catKey in ipairs(getGiftCatKeys()) do
                local dd = G["__GAG2_AUTO_GIFT_DD_" .. catKey] or rawget(_G, "__GAG2_AUTO_GIFT_DD_" .. catKey)
                if type(dd) == "table" then
                    sel[catKey] = selectedMapFromDd(dd, catMode)
                end
            end
            if next(sel) then opts.selected = sel end

            local catModeSel = readGiftDropdownSelected("__GAG2_AUTO_GIFT_CATEGORY_MODE")
            if catModeSel ~= nil then
                opts.category_mode = tostring(catModeSel)
            end

            local sendModeSel = readGiftDropdownSelected("__GAG2_AUTO_GIFT_SEND_LIST_MODE")
            if sendModeSel ~= nil then
                opts.send_list_mode = tostring(sendModeSel)
            end

            local sendTotalVal = readGiftUiValue("__GAG2_AUTO_GIFT_SEND_TOTAL_GLOBAL", "fn")
            if sendTotalVal ~= nil then
                opts.send_total = tonumber(sendTotalVal)
            end

            local afterSendSel = readGiftDropdownSelected("__GAG2_AUTO_GIFT_AFTER_SEND_MODE")
            if afterSendSel ~= nil then
                opts.after_send_mode = tostring(afterSendSel)
            end

            local autoSendVal = readGiftUiValue("__GAG2_AUTO_GIFT_AUTO_SEND_API", "toggle")
            if autoSendVal ~= nil then
                opts.auto_send = autoSendVal == true
            end

            if next(opts) ~= nil then
                writeAutoGiftState(opts)
            else
                syncAutoGiftStoreFromMain()
                writeAutoGiftToMain()
            end
        end)

        if not ok then
            error(err)
        end

        G.__GAG2_FLUSH_AUTO_GIFT = flushAutoGiftFromUI
        _G.__GAG2_FLUSH_AUTO_GIFT = flushAutoGiftFromUI
    end

    local function applyAutoGiftRuntime(_on)
        local s = ensureAutoGiftStore()
        local cfg = giftConfigFromStore(s)

        local ag = getAutoGiftModule()
        if type(ag) ~= "table" then return end

        if type(ag.ApplyConfig) == "function" then
            pcall(ag.ApplyConfig, ag, cfg)
        end
        if type(ag.ApplyClaimRuntime) == "function" then
            pcall(ag.ApplyClaimRuntime, ag, s.auto_claim_mail == true)
        end
        if type(ag.ApplyAcceptGiftRuntime) == "function" then
            pcall(ag.ApplyAcceptGiftRuntime, ag, s.auto_accept_gift == true)
        end
        if type(ag.ApplyAutoSendRuntime) == "function" then
            local autoOn = (s.auto_send == true) and (s.send_list_mode ~= "send_total")
            pcall(ag.ApplyAutoSendRuntime, ag, autoOn)
        end
    end

    local function sendGiftNow(isOn)
        local flushFn = flushAutoGiftFromUI
            or G.__GAG2_FLUSH_AUTO_GIFT
            or rawget(_G, "__GAG2_FLUSH_AUTO_GIFT")
        if type(flushFn) ~= "function" then
            G.AUTO_GIFT_STATUS = "Gift flush missing — re-execute hub"
            _G.AUTO_GIFT_STATUS = G.AUTO_GIFT_STATUS
            return
        end
        local flushOk, flushErr = pcall(flushFn)
        if not flushOk then
            G.AUTO_GIFT_STATUS = "UI flush error: " .. tostring(flushErr)
            _G.AUTO_GIFT_STATUS = G.AUTO_GIFT_STATUS
            return
        end
        G.AUTO_GIFT_FLUSH_OK = true
        _G.AUTO_GIFT_FLUSH_OK = true
        G.AUTO_GIFT_STATUS = "Ready"
        _G.AUTO_GIFT_STATUS = "Ready"
        applyAutoGiftRuntime(nil)
        local ag = getAutoGiftModule()
        if type(ag) ~= "table" then
            G.AUTO_GIFT_STATUS = "AutoGift module not loaded — re-execute hub"
            _G.AUTO_GIFT_STATUS = G.AUTO_GIFT_STATUS
            return
        end
        if isOn == false then
            if type(ag.StopSendJob) == "function" then
                pcall(ag.StopSendJob, ag)
            end
            return
        end

        local s = ensureAutoGiftStore()
        if (tonumber(s.recipient_user_id) or 0) <= 0 and s.recipient_username ~= "" then
            if type(ag.LookupRecipient) == "function" then
                pcall(ag.LookupRecipient, ag, s.recipient_username)
                pcall(ag.ApplyConfig, ag, giftConfigFromStore(ensureAutoGiftStore()))
            end
        end

        if type(ag.StartSendJob) == "function" then
            if type(ag.IsSendJobRunning) == "function" and ag.IsSendJobRunning(ag) then
                G.AUTO_GIFT_STATUS = "Send job sudah jalan — tunggu atau toggle OFF dulu"
                _G.AUTO_GIFT_STATUS = G.AUTO_GIFT_STATUS
                return
            end
            task.spawn(function()
                local ok, started = pcall(ag.StartSendJob, ag)
                if not ok then
                    G.AUTO_GIFT_STATUS = "Send error: " .. tostring(started)
                    _G.AUTO_GIFT_STATUS = G.AUTO_GIFT_STATUS
                elseif started ~= true then
                    G.AUTO_GIFT_STATUS = "StartSendJob gagal — toggle OFF lalu ON lagi"
                    _G.AUTO_GIFT_STATUS = G.AUTO_GIFT_STATUS
                end
            end)
        else
            G.AUTO_GIFT_STATUS = "StartSendJob missing — upload AutoGift.lua"
            _G.AUTO_GIFT_STATUS = G.AUTO_GIFT_STATUS
        end
    end

    local function refreshGiftItemDropdowns()
        local applyCats = G.__GAG2_GIFT_APPLY_CATEGORY_SELECTION or rawget(_G, "__GAG2_GIFT_APPLY_CATEGORY_SELECTION")
        local catDd = G.__GAG2_AUTO_GIFT_CAT_MULTI or rawget(_G, "__GAG2_AUTO_GIFT_CAT_MULTI")
        if type(applyCats) == "function" and type(catDd) == "table" and type(catDd.getSelected) == "function" then
            pcall(applyCats, catDd.getSelected(), false)
        end
        for _, key in ipairs(getGiftCatKeys()) do
            local dd = G["__GAG2_AUTO_GIFT_DD_" .. key] or rawget(_G, "__GAG2_AUTO_GIFT_DD_" .. key)
            if type(dd) == "table" and type(dd.refreshItems) == "function" then
                pcall(dd.refreshItems, dd)
            end
        end
    end

    local function syncAutoGiftAll()
        local ag = getAutoGiftModule()
        if type(ag) == "table" then
            if type(ag.IsCatalogLoaded) == "function" and not ag.IsCatalogLoaded(ag) then
                if type(ag.ReloadCatalog) == "function" then
                    pcall(ag.ReloadCatalog, ag)
                end
            end
        end
        if G.__GAG2_RESETTING == true then
            syncAutoGiftStoreFromMain()
            writeAutoGiftToMain()
            applyAutoGiftRuntime(nil)
            return
        end
        if G.__GAG2_AUTO_GIFT_UI_READY == true then
            flushAutoGiftFromUI()
            refreshGiftItemDropdowns()
        else
            syncAutoGiftStoreFromMain()
            writeAutoGiftToMain()
        end
        applyAutoGiftRuntime(nil)
    end

    local function patchBuyPet(opts, syncFn)
        writeBuyPetState(opts)
        if syncFn then pcall(syncFn) end
        saveNow()
    end

    local function saveAutoGiftNow()
        if G.__GAG2_AUTO_GIFT_UI_READY == true then
            flushAutoGiftFromUI()
        else
            writeAutoGiftToMain()
        end
        saveNow()
    end

    G.__GAG2_READ_AUTO_GIFT = readAutoGiftEnabled
    G.__GAG2_WRITE_AUTO_GIFT = writeAutoGiftState
    G.__GAG2_WRITE_AUTO_GIFT_MAIN = writeAutoGiftToMain
    G.__GAG2_SYNC_AUTO_GIFT = syncAutoGiftAll
    G.__GAG2_FLUSH_AUTO_GIFT = flushAutoGiftFromUI
    G.__GAG2_SAVE_AUTO_GIFT = saveAutoGiftNow
    registerFlush("gift", flushAutoGiftFromUI)
    _G.__GAG2_READ_AUTO_GIFT = readAutoGiftEnabled
    _G.__GAG2_WRITE_AUTO_GIFT = writeAutoGiftState
    _G.__GAG2_WRITE_AUTO_GIFT_MAIN = writeAutoGiftToMain
    _G.__GAG2_SYNC_AUTO_GIFT = syncAutoGiftAll
    _G.__GAG2_FLUSH_AUTO_GIFT = flushAutoGiftFromUI
    _G.__GAG2_SAVE_AUTO_GIFT = saveAutoGiftNow

    ----------------------------------------------------------------
    -- Normal Gift — nearby send via NormalGift module
    ----------------------------------------------------------------
    if type(G.__GAG2_NORMAL_GIFT) ~= "table" then
        G.__GAG2_NORMAL_GIFT = {
            target_user_id = 0,
            target_name = "",
            category = "Seeds",
            selected = {},
            send_total = 1,
            teleport_to_target = true,
        }
    end
    _G.__GAG2_NORMAL_GIFT = G.__GAG2_NORMAL_GIFT

    local ensureNormalGiftStore

    local function getNormalGiftModule()
        return G.NormalGiftModule or G.NormalGift or _G.NormalGiftModule or _G.NormalGift
    end

    local function buildNormalGiftCatUiDefs()
        local ng = getNormalGiftModule()
        if type(ng) ~= "table" then return {} end
        if type(ng.GetCategoryDefs) == "function" then
            local ok, defs = pcall(ng.GetCategoryDefs)
            if ok and type(defs) == "table" and #defs > 0 then
                local out = {}
                for _, def in ipairs(defs) do
                    local label = def.label or def.key
                    out[#out + 1] = {
                        key = def.key,
                        label = label,
                        itemLabel = label .. " list",
                        placeholder = "Select " .. string.lower(label) .. "...",
                    }
                end
                return out
            end
        end
        return {}
    end

    local function readNormalGiftCategory()
        local active = G.__GAG2_NORMAL_GIFT_ACTIVE_CAT or rawget(_G, "__GAG2_NORMAL_GIFT_ACTIVE_CAT")
        if active ~= nil and tostring(active) ~= "" and tostring(active) ~= "_none" then
            return tostring(active)
        end
        local catDd = G.__GAG2_NORMAL_GIFT_CAT_DD or rawget(_G, "__GAG2_NORMAL_GIFT_CAT_DD")
        if type(catDd) == "table" and type(catDd.getSelected) == "function" then
            local ok, sel = pcall(catDd.getSelected, catDd)
            if not ok then ok, sel = pcall(catDd.getSelected) end
            if ok and sel ~= nil and tostring(sel) ~= "" then
                return tostring(sel)
            end
        end
        return tostring((type(ensureNormalGiftStore) == "function" and ensureNormalGiftStore().category) or "Seeds")
    end

    local function resolveNormalGiftTarget(key)
        key = tostring(key or ""):gsub("^%s+", ""):gsub("%s+$", "")
        if key == "" then return 0, "", nil end

        local PlayersSvc = game:GetService("Players")
        local uid = math.floor(tonumber(key) or 0)
        if uid > 0 then
            local p = PlayersSvc:GetPlayerByUserId(uid)
            if p and p ~= PlayersSvc.LocalPlayer then
                return p.UserId, p.Name, p
            end
        end

        local lower = key:lower():gsub("^@", "")
        for _, p in ipairs(PlayersSvc:GetPlayers()) do
            if p ~= PlayersSvc.LocalPlayer then
                local label = p.DisplayName .. " (@" .. p.Name .. ")"
                if p.Name:lower() == lower
                    or p.DisplayName:lower() == lower
                    or label:lower() == lower
                    or label:lower():find(lower, 1, true)
                    or lower:find(p.Name:lower(), 1, true) then
                    return p.UserId, p.Name, p
                end
            end
        end

        local ng = getNormalGiftModule()
        if type(ng) == "table" and type(ng.ListServerPlayers) == "function" then
            local ok, list = pcall(ng.ListServerPlayers)
            if ok and type(list) == "table" then
                for _, item in ipairs(list) do
                    local itemKey = tostring(item.key or "")
                    if itemKey == key or itemKey:lower() == lower then
                        local pid = math.floor(tonumber(item.userId or itemKey) or 0)
                        if pid > 0 then
                            local p = PlayersSvc:GetPlayerByUserId(pid)
                            if p then return p.UserId, p.Name, p end
                        end
                    end
                    local itemName = tostring(item.name or ""):lower()
                    if itemName == lower or itemName:find(lower, 1, true) then
                        local pid = math.floor(tonumber(item.userId or item.key) or 0)
                        if pid > 0 then
                            local p = PlayersSvc:GetPlayerByUserId(pid)
                            if p then return p.UserId, p.Name, p end
                        end
                    end
                end
            end
        end

        return 0, "", nil
    end

    local function normalGiftTargetReady()
        local ensureFn = ensureNormalGiftStore
            or G.__GAG2_ENSURE_NORMAL_GIFT_STORE
            or rawget(_G, "__GAG2_ENSURE_NORMAL_GIFT_STORE")
        if type(ensureFn) ~= "function" then
            return false, nil
        end
        local s = ensureFn()
        if s.target_user_id > 0 then
            local _, _, p = resolveNormalGiftTarget(tostring(s.target_user_id))
            if p then return true, p end
        end
        if s.target_name ~= "" then
            local _, _, p = resolveNormalGiftTarget(s.target_name)
            if p then return true, p end
        end
        local playerDd = G.__GAG2_NORMAL_GIFT_PLAYER_DD or rawget(_G, "__GAG2_NORMAL_GIFT_PLAYER_DD")
        local sel = safeDdGetSelected(playerDd)
        if sel ~= nil and tostring(sel) ~= "" then
            local _, _, p = resolveNormalGiftTarget(sel)
            if p then return true, p end
        end
        return false, nil
    end

    local function buildNormalGiftItemList(cat)
        cat = tostring(cat or readNormalGiftCategory() or "Seeds")
        if cat == "" then cat = "Seeds" end
        if cat == "_none" then return {} end

        local ng = getNormalGiftModule()
        if type(ng) == "table" and type(ng.GetItemsForCategory) == "function" then
            local ok, items = pcall(ng.GetItemsForCategory, cat)
            if ok and type(items) == "table" then
                if #items == 0 and (cat:lower():find("harvest", 1, true) or cat:lower():find("fruit", 1, true)) then
                    ok, items = pcall(ng.GetItemsForCategory, "HarvestedFruits")
                    if ok and type(items) == "table" and #items > 0 then
                        return items
                    end
                end
                return items
            end
        end

        return {}
    end

    local function countNormalGiftSelected(map)
        map = cleanSelectedMap(map or {})
        local n = 0
        for _, v in pairs(map) do
            if v == true then n = n + 1 end
        end
        return n
    end

    ensureNormalGiftStore = function()
        local s = G.__GAG2_NORMAL_GIFT
        if type(s) ~= "table" then
            s = {
                target_user_id = 0,
                target_name = "",
                category = "Seeds",
                selected = {},
                send_total = 1,
                teleport_to_target = true,
            }
            G.__GAG2_NORMAL_GIFT = s
        end

        s.target_user_id = math.floor(tonumber(s.target_user_id) or 0)
        s.target_name = tostring(s.target_name or "")
        s.category = tostring(s.category or "Seeds")
        if s.category == "" then s.category = "Seeds" end
        s.selected = cleanSelectedMap(s.selected)
        s.send_total = math.floor(math.max(1, math.min(50, tonumber(s.send_total) or 1)))
        if s.teleport_to_target == nil then s.teleport_to_target = true end
        s.teleport_to_target = (s.teleport_to_target == true)

        if not s._hydrated then
            local ngMain = getAuto("normalGift")
            if type(ngMain) == "table" then
                if (tonumber(ngMain.target_user_id) or 0) > 0 then
                    s.target_user_id = math.floor(tonumber(ngMain.target_user_id))
                end
                if ngMain.target_name ~= nil and tostring(ngMain.target_name) ~= "" then
                    s.target_name = tostring(ngMain.target_name)
                end
                if ngMain.category ~= nil and tostring(ngMain.category) ~= "" then
                    s.category = tostring(ngMain.category)
                end
                if type(ngMain.selected) == "table" and next(ngMain.selected) then
                    s.selected = cleanSelectedMap(arrayToMap(ngMain.selected))
                end
                if ngMain.send_total ~= nil then
                    s.send_total = math.floor(math.max(1, math.min(50, tonumber(ngMain.send_total) or 1)))
                end
                if ngMain.teleport_to_target ~= nil then
                    s.teleport_to_target = (ngMain.teleport_to_target == true)
                end
            end
            s._hydrated = true
        end

        G.__GAG2_NORMAL_GIFT = s
        _G.__GAG2_NORMAL_GIFT = s
        return s
    end
    G.__GAG2_ENSURE_NORMAL_GIFT_STORE = ensureNormalGiftStore
    _G.__GAG2_ENSURE_NORMAL_GIFT_STORE = ensureNormalGiftStore

    local function normalGiftPayloadFromStore(s)
        s = ensureNormalGiftStore()
        return {
            target_user_id = s.target_user_id,
            target_name = s.target_name,
            category = s.category,
            selected = mapToArray(s.selected),
            send_total = s.send_total,
            teleport_to_target = s.teleport_to_target == true,
        }
    end

    local function writeNormalGiftToMain()
        local s = ensureNormalGiftStore()
        G.__GAG2_NORMAL_GIFT = s
        _G.__GAG2_NORMAL_GIFT = s
        patchAutoOnly("normalGift", normalGiftPayloadFromStore(s))
        return s
    end

    local function writeNormalGiftState(opts)
        local s = ensureNormalGiftStore()
        if type(opts) == "table" then
            if opts.target_user_id ~= nil then
                s.target_user_id = math.floor(tonumber(opts.target_user_id) or 0)
            end
            if opts.target_name ~= nil then
                s.target_name = tostring(opts.target_name or "")
            end
            if opts.category ~= nil and tostring(opts.category) ~= "" then
                s.category = tostring(opts.category)
            end
            if type(opts.selected) == "table" then
                if opts.selected[1] ~= nil then
                    s.selected = cleanSelectedMap(arrayToMap(opts.selected))
                else
                    s.selected = cleanSelectedMap(opts.selected)
                end
            end
            if opts.send_total ~= nil then
                local n = math.floor(tonumber(opts.send_total) or 1)
                if n < 1 then n = 1 end
                if n > 50 then n = 50 end
                s.send_total = n
            end
            if opts.teleport_to_target ~= nil then
                s.teleport_to_target = (opts.teleport_to_target == true)
            end
        end
        return writeNormalGiftToMain()
    end

    local function patchNormalGift(opts, syncFn)
        writeNormalGiftState(opts)
        if syncFn then pcall(syncFn) end
        saveNow()
    end

    local function applyNormalGiftRuntime()
        local s = ensureNormalGiftStore()
        local ng = getNormalGiftModule()
        if type(ng) ~= "table" then return end
        if type(ng.ApplyConfig) == "function" then
            pcall(function()
                ng.ApplyConfig({
                    target_user_id = s.target_user_id,
                    target_name = s.target_name,
                    category = s.category,
                    selected = s.selected,
                    send_total = s.send_total,
                    teleport_to_target = s.teleport_to_target,
                })
            end)
        end
    end

    local function flushNormalGiftFromUI()
        if G.__GAG2_RESETTING == true then return end
        local opts = {}

        local playerDd = G.__GAG2_NORMAL_GIFT_PLAYER_DD or rawget(_G, "__GAG2_NORMAL_GIFT_PLAYER_DD")
        local playerKey = safeDdGetSelected(playerDd)
        if playerKey ~= nil and tostring(playerKey) ~= "" then
            local uid, name = resolveNormalGiftTarget(playerKey)
            if uid > 0 then opts.target_user_id = uid end
            if name ~= "" then opts.target_name = name end
        end

        local catDd = G.__GAG2_NORMAL_GIFT_CAT_DD or rawget(_G, "__GAG2_NORMAL_GIFT_CAT_DD")
        local catKey = safeDdGetSelected(catDd)
        if catKey ~= nil and tostring(catKey) ~= "" then
            opts.category = tostring(catKey)
        end

        local itemDd = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
        local itemSel = safeDdGetSelected(itemDd)
        if itemSel ~= nil then
            if type(itemSel) == "table" then
                opts.selected = cleanSelectedMap(itemSel)
            elseif tostring(itemSel) ~= "" then
                opts.selected = { [tostring(itemSel)] = true }
            end
        end

        local totalFn = G.__GAG2_NORMAL_GIFT_SEND_TOTAL or rawget(_G, "__GAG2_NORMAL_GIFT_SEND_TOTAL")
        if type(totalFn) == "function" then
            local n = tonumber(totalFn())
            if n and n >= 1 then
                opts.send_total = math.floor(n)
            end
        end

        if next(opts) ~= nil then
            writeNormalGiftState(opts)
        else
            writeNormalGiftToMain()
        end
    end

    local function sendNormalGiftNow(isOn)
        if isOn == false then return end
        flushNormalGiftFromUI()
        applyNormalGiftRuntime()
        local s = ensureNormalGiftStore()
        local itemDd = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
        local itemSel = safeDdGetSelected(itemDd)
        local selMap = (type(itemSel) == "table") and cleanSelectedMap(itemSel) or s.selected
        if countNormalGiftSelected(selMap) < 1 then
            G.NORMAL_GIFT_STATUS = "Select at least 1 item in list"
            _G.NORMAL_GIFT_STATUS = G.NORMAL_GIFT_STATUS
            local api = G.__GAG2_NORMAL_GIFT_SEND_API or rawget(_G, "__GAG2_NORMAL_GIFT_SEND_API")
            if type(api) == "table" and type(api.set) == "function" then
                pcall(api.set, false, true)
            end
            return
        end
        local ng = getNormalGiftModule()
        if type(ng) ~= "table" then
            G.NORMAL_GIFT_STATUS = "NormalGift module not loaded"
            _G.NORMAL_GIFT_STATUS = G.NORMAL_GIFT_STATUS
            return
        end
        if type(ng.GetStats) == "function" then
            local ok, st = pcall(ng.GetStats, ng)
            if ok and type(st) == "table" and st.busy == true then
                G.NORMAL_GIFT_STATUS = "Send already running"
                _G.NORMAL_GIFT_STATUS = G.NORMAL_GIFT_STATUS
                return
            end
        end
        task.spawn(function()
            pcall(ng.SendNow)
        end)
    end

    local function syncNormalGiftAll()
        if G.__GAG2_RESETTING == true then
            writeNormalGiftToMain()
            applyNormalGiftRuntime()
            return
        end
        if G.__GAG2_NORMAL_GIFT_UI_READY == true then
            flushNormalGiftFromUI()
        else
            writeNormalGiftToMain()
        end
        applyNormalGiftRuntime()
    end

    G.__GAG2_SYNC_NORMAL_GIFT = syncNormalGiftAll
    G.__GAG2_FLUSH_NORMAL_GIFT = flushNormalGiftFromUI
    _G.__GAG2_SYNC_NORMAL_GIFT = syncNormalGiftAll
    _G.__GAG2_FLUSH_NORMAL_GIFT = flushNormalGiftFromUI
    registerFlush("normalGift", flushNormalGiftFromUI)

    ----------------------------------------------------------------
    -- Auto Shovel — session only (tidak disimpan ke state/file)
    ----------------------------------------------------------------
    if type(G.__GAG2_SHOVEL) ~= "table" then
        G.__GAG2_SHOVEL = { enabled = false, plants = {} }
    end
    _G.__GAG2_SHOVEL = G.__GAG2_SHOVEL

    local function readShovelEnabled()
        local store = G.__GAG2_SHOVEL or rawget(_G, "__GAG2_SHOVEL")
        return type(store) == "table" and store.enabled == true
    end

    local function readShovelPlantsSelected()
        local store = G.__GAG2_SHOVEL or rawget(_G, "__GAG2_SHOVEL")
        if type(store) == "table" and type(store.plants) == "table" then
            local map = cleanSelectedMap(arrayToMap(store.plants))
            if map._none then map._none = nil end
            return map
        end
        local map = G.AUTO_SHOVEL_PLANTS_SELECTED or rawget(_G, "AUTO_SHOVEL_PLANTS_SELECTED")
        if type(map) == "table" then
            map = cleanSelectedMap(map)
            if map._none then map._none = nil end
            return map
        end
        return {}
    end

    local function countShovelSelected(map)
        map = cleanSelectedMap(map or readShovelPlantsSelected())
        if map._none then map._none = nil end
        local n = 0
        for k, v in pairs(map) do
            if v == true and k ~= "_none" then n = n + 1 end
        end
        return n
    end

    local function writeShovelState(enabled, plantsMap)
        enabled = (enabled == true)
        plantsMap = cleanSelectedMap(plantsMap or readShovelPlantsSelected())

        if type(G.__GAG2_SHOVEL) ~= "table" then
            G.__GAG2_SHOVEL = { enabled = false, plants = {} }
        end
        G.__GAG2_SHOVEL.enabled = enabled
        G.__GAG2_SHOVEL.plants = mapToArray(plantsMap)
        _G.__GAG2_SHOVEL = G.__GAG2_SHOVEL

        AUTO_SHOVEL_ENABLED = enabled
        G.AUTO_SHOVEL_ENABLED = enabled
        _G.AUTO_SHOVEL_ENABLED = enabled
        AUTO_SHOVEL_PLANTS_SELECTED = plantsMap
        G.AUTO_SHOVEL_PLANTS_SELECTED = plantsMap
        _G.AUTO_SHOVEL_PLANTS_SELECTED = plantsMap
    end

    local function applyShovelRuntime(on)
        on = (on == true)
        if on and countShovelSelected() < 1 then
            on = false
        end
        local as = G.AutoShovel or G.AutoShovelModule or rawget(_G, "AutoShovel")
        if type(as) ~= "table" then return on end
        if type(as.ApplyRuntime) == "function" then
            pcall(as.ApplyRuntime, as, on)
        elseif on then
            if type(as.Start) == "function" then pcall(as.Start, as) end
        else
            if type(as.Stop) == "function" then pcall(as.Stop, as) end
        end
        return on
    end

    local function pruneShovelSelection(dropdownApi, toggleApi)
        local AS = G.AutoShovel or G.AutoShovelModule or rawget(_G, "AutoShovel")
        local sel = readShovelPlantsSelected()
        local changed = false
        if type(AS) == "table" and type(AS.PruneSelectionToGarden) == "function" then
            local ok, pruned, didChange = pcall(AS.PruneSelectionToGarden, AS, sel)
            if ok and didChange and type(pruned) == "table" then
                sel = pruned
                changed = true
            end
        end
        if not changed then
            return sel, false
        end

        local on = readShovelEnabled()
        if countShovelSelected(sel) < 1 then
            on = false
        end
        writeShovelState(on, sel)
        applyShovelRuntime(on)

        if dropdownApi and type(dropdownApi.setSelected) == "function" then
            dropdownApi.setSelected(sel)
        end
        if dropdownApi and type(dropdownApi.refreshLabel) == "function" then
            dropdownApi.refreshLabel()
        end
        if not on and toggleApi and type(toggleApi.set) == "function" then
            toggleApi.set(false, true)
        end
        return sel, true
    end

    local function syncAutoShovelAll()
        pruneShovelSelection(nil, nil)
        local on = readShovelEnabled()
        local sel = readShovelPlantsSelected()
        if on and countShovelSelected(sel) < 1 then
            on = false
        end
        writeShovelState(on, sel)
        applyShovelRuntime(on)
    end

    G.__GAG2_READ_SHOVEL = readShovelEnabled
    G.__GAG2_WRITE_SHOVEL = writeShovelState
    G.__GAG2_SYNC_AUTO_SHOVEL = syncAutoShovelAll
    _G.__GAG2_READ_SHOVEL = readShovelEnabled
    _G.__GAG2_WRITE_SHOVEL = writeShovelState
    _G.__GAG2_SYNC_AUTO_SHOVEL = syncAutoShovelAll

    do
        local prevBefore = G.__GAG2_BEFORE_TAB_CHANGE
        G.__GAG2_BEFORE_TAB_CHANGE = function()
            if type(G.__GAG2_SYNC_AUTO_BUY) == "function" then
                pcall(G.__GAG2_SYNC_AUTO_BUY)
            end
            flushBuyPetFromUI()
            flushAutoTeleState()
            if type(prevBefore) == "function" then
                pcall(prevBefore)
            end
            if type(G.__GAG2_FLUSH_TO_MAIN) == "function" then
                pcall(G.__GAG2_FLUSH_TO_MAIN)
            end
            if ui and type(ui.SaveState) == "function" then
                pcall(function() ui:SaveState() end)
            end
        end
        _G.__GAG2_BEFORE_TAB_CHANGE = G.__GAG2_BEFORE_TAB_CHANGE
    end

    local function parseKgRule(txt)
        txt = tostring(txt or ""):gsub("%s+", "")
        if txt == "" then
            return 0, "above"
        end
        local n = tonumber(txt)
        if not n then
            return 0, "above"
        end
        if n < 0 then
            return math.abs(n), "below"
        end
        return n, "above"
    end

    local function normalizeCollectPriority(v)
        local s = tostring(v or "off"):lower():gsub("%s+", "")
        if s == "price" or s == "highestprice" then return "price" end
        if s == "rarity" or s == "highestrarity" then return "rarity" end
        if s == "weight" or s == "heaviest" or s == "heaviestkg" or s == "kg" then return "weight" end
        if s == "off" or s == "normal" or s == "normalscanorder" then return "off" end
        return "off"
    end

    local function applyCollectPriority(mode)
        mode = normalizeCollectPriority(mode)
        if type(State) == "table" and type(State.patchAuto) == "function" then
            pcall(State.patchAuto, "collect", { priority = mode }, { noSync = true })
        else
            local m = rawget(_G, "MAIN") or G.MAIN
            if type(m) == "table" then
                m.auto = m.auto or {}
                m.auto.collect = m.auto.collect or {}
                m.auto.collect.priority = mode
                G.MAIN = m
                _G.MAIN = m
            end
        end
        G.AUTO_COLLECT_PRIORITY = mode
        _G.AUTO_COLLECT_PRIORITY = mode
        return mode
    end

    local function readCollectPriorityFromUi(fallback)
        local api = G.__GAG2_COLLECT_PRIORITY_API or rawget(_G, "__GAG2_COLLECT_PRIORITY_API")
        if type(api) == "table" and type(api.getSelected) == "function" then
            local ok, sel = pcall(api.getSelected, api)
            if not ok then ok, sel = pcall(api.getSelected) end
            if ok and sel ~= nil and tostring(sel) ~= "" then
                return normalizeCollectPriority(sel)
            end
        end
        local pr = G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY")
        if pr ~= nil then
            return normalizeCollectPriority(pr)
        end
        local live = getAuto("collect")
        if type(live) == "table" and live.priority ~= nil then
            return normalizeCollectPriority(live.priority)
        end
        return normalizeCollectPriority(fallback or "off")
    end

    local function flushAutoCollectState()
        applyCollectPriority(readCollectPriorityFromUi())
    end

    G.__GAG2_FLUSH_AUTO_COLLECT = flushAutoCollectState
    _G.__GAG2_FLUSH_AUTO_COLLECT = flushAutoCollectState

    ----------------------------------------------------------------
    -- garden scan (status only)
    ----------------------------------------------------------------
    local function countReadyFruits()
        local ac = G.AutoCollectFruit or G.CollectFruitModule
        if type(ac) == "table" and type(ac.CountReady) == "function" then
            local ok, n = pcall(ac.CountReady, ac)
            if ok and type(n) == "number" then
                return math.max(0, math.floor(n))
            end
        end

        -- fallback: sama seperti game — hanya HarvestPrompt, bukan Age/GrowthReady
        local n = 0
        local CS = game:GetService("CollectionService")
        for _, prompt in ipairs(CS:GetTagged("HarvestPrompt")) do
            if prompt:IsA("ProximityPrompt") and not prompt:GetAttribute("Collected") then
                local fruit = prompt.Parent and prompt.Parent:FindFirstAncestorWhichIsA("Model")
                if fruit and fruit:GetAttribute("PlantId") then
                    n += 1
                end
            end
        end
        return n
    end

    ----------------------------------------------------------------
    -- MAIN TAB: AUTO
    ----------------------------------------------------------------
    ui:RegisterMainTab("auto", "AUTO", 1)

    ----------------------------------------------------------------
    -- SUB TAB: Auto (Collect + Sell)
    ----------------------------------------------------------------
    ui:RegisterSubTab("auto", "auto", "Auto", function()
        local AC_STATE = getAuto("collect")
        local kgSyncToken = 0
        AC_STATE.enabled   = (AC_STATE.enabled == true)
        do
            local d = tonumber(AC_STATE.delay)
            if d == nil then d = 0.1 end
            if d < 0 then d = 0 end
            AC_STATE.delay = d
        end
        AC_STATE.fruits    = type(AC_STATE.fruits) == "table" and AC_STATE.fruits or {}
        AC_STATE.mutations = type(AC_STATE.mutations) == "table" and AC_STATE.mutations or {}
        AC_STATE.kg        = tonumber(AC_STATE.kg) or 0
        AC_STATE.kgMode    = tostring(AC_STATE.kgMode or "above")
        if AC_STATE.kg < 0 then
            AC_STATE.kg = math.abs(AC_STATE.kg)
            AC_STATE.kgMode = "below"
        elseif AC_STATE.kgMode ~= "below" then
            AC_STATE.kgMode = "above"
        end
        do
            local pr = G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY") or AC_STATE.priority
            pr = normalizeCollectPriority(pr)
            AC_STATE.priority = pr
        end

        local function collectDelayDisplay()
            local n = tonumber(AC_STATE.delay)
            return (n ~= nil) and n or 0.1
        end

        local function readCollectDelayFromUi()
            local fn = G.__GAG2_COLLECT_DELAY_API or rawget(_G, "__GAG2_COLLECT_DELAY_API")
            if type(fn) == "function" then
                local ok, v = pcall(fn)
                if ok and v ~= nil then
                    local n = tonumber(v)
                    if n ~= nil then
                        if n < 0 then n = 0 end
                        return n
                    end
                end
            end
            return collectDelayDisplay()
        end

        local function collectSnapshot()
            local on = toggleApiGet("__GAG2_COLLECT_ENABLE_API")
            local priority = readCollectPriorityFromUi(AC_STATE.priority)
            AC_STATE.priority = priority
            return {
                enabled = on ~= nil and on or (AC_STATE.enabled == true),
                delay = readCollectDelayFromUi(),
                fruits = mapToArray(AUTO_COLLECT_FRUITS_SELECTED),
                mutations = mapToArray(AUTO_COLLECT_MUTATIONS_SELECTED),
                kg = tonumber(AC_STATE.kg) or 0,
                kgMode = tostring(AC_STATE.kgMode or "above"),
                kgRule = kgInputText(),
                priority = priority,
            }
        end

        registerFlush("collect", function()
            flushAutoCollectState()
            patchAutoOnly("collect", collectSnapshot())
        end)

        local function kgInputText()
            local kg = tonumber(AC_STATE.kg) or 0
            local mode = tostring(AC_STATE.kgMode or "above")
            if kg <= 0 then
                return "0"
            end
            if mode == "below" then
                return "-" .. tostring(kg)
            end
            return tostring(kg)
        end

        AUTO_COLLECT_FRUITS_SELECTED =
            cleanSelectedMap(arrayToMap(AC_STATE.fruits))
        G.AUTO_COLLECT_FRUITS_SELECTED = AUTO_COLLECT_FRUITS_SELECTED
        _G.AUTO_COLLECT_FRUITS_SELECTED = AUTO_COLLECT_FRUITS_SELECTED

        AUTO_COLLECT_MUTATIONS_SELECTED =
            cleanSelectedMap(arrayToMap(AC_STATE.mutations))
        G.AUTO_COLLECT_MUTATIONS_SELECTED = AUTO_COLLECT_MUTATIONS_SELECTED
        _G.AUTO_COLLECT_MUTATIONS_SELECTED = AUTO_COLLECT_MUTATIONS_SELECTED

        AUTO_COLLECT_FRUIT_ENABLED = AC_STATE.enabled
        G.AUTO_COLLECT_FRUIT_ENABLED = AC_STATE.enabled
        _G.AUTO_COLLECT_FRUIT_ENABLED = AC_STATE.enabled

        G.AUTO_COLLECT_KG = AC_STATE.kg
        _G.AUTO_COLLECT_KG = AC_STATE.kg
        G.AUTO_COLLECT_KG_MODE = AC_STATE.kgMode
        _G.AUTO_COLLECT_KG_MODE = AC_STATE.kgMode
        G.AUTO_COLLECT_KG_RULE = kgInputText()
        _G.AUTO_COLLECT_KG_RULE = G.AUTO_COLLECT_KG_RULE
        G.AUTO_COLLECT_DELAY = AC_STATE.delay
        _G.AUTO_COLLECT_DELAY = AC_STATE.delay
        G.AUTO_COLLECT_PRIORITY = AC_STATE.priority
        _G.AUTO_COLLECT_PRIORITY = AC_STATE.priority

        local COLLECT_PRIORITY_ITEMS = {
            { key = "off",    name = "Normal (scan order)" },
            { key = "price",  name = "Highest Price" },
            { key = "rarity", name = "Highest Rarity" },
            { key = "weight", name = "Heaviest (kg)" },
        }

        local function syncAutoCollectModule()
            G.AUTO_COLLECT_FRUIT_ENABLED = (AC_STATE.enabled == true)
            _G.AUTO_COLLECT_FRUIT_ENABLED = G.AUTO_COLLECT_FRUIT_ENABLED

            G.AUTO_COLLECT_FRUITS_SELECTED = AUTO_COLLECT_FRUITS_SELECTED
            _G.AUTO_COLLECT_FRUITS_SELECTED = AUTO_COLLECT_FRUITS_SELECTED

            G.AUTO_COLLECT_MUTATIONS_SELECTED = AUTO_COLLECT_MUTATIONS_SELECTED
            _G.AUTO_COLLECT_MUTATIONS_SELECTED = AUTO_COLLECT_MUTATIONS_SELECTED

            G.AUTO_COLLECT_KG = tonumber(AC_STATE.kg) or 0
            _G.AUTO_COLLECT_KG = G.AUTO_COLLECT_KG
            if G.AUTO_COLLECT_KG < 0 then
                G.AUTO_COLLECT_KG = math.abs(G.AUTO_COLLECT_KG)
                AC_STATE.kg = G.AUTO_COLLECT_KG
                AC_STATE.kgMode = "below"
            end
            G.AUTO_COLLECT_KG_MODE = tostring(AC_STATE.kgMode or "above")
            if G.AUTO_COLLECT_KG_MODE ~= "below" then
                G.AUTO_COLLECT_KG_MODE = "above"
                AC_STATE.kgMode = G.AUTO_COLLECT_KG_MODE
            end
            _G.AUTO_COLLECT_KG_MODE = G.AUTO_COLLECT_KG_MODE
            G.AUTO_COLLECT_KG_RULE = kgInputText()
            _G.AUTO_COLLECT_KG_RULE = G.AUTO_COLLECT_KG_RULE
            G.AUTO_COLLECT_DELAY = collectDelayDisplay()
            _G.AUTO_COLLECT_DELAY = G.AUTO_COLLECT_DELAY
            G.AUTO_COLLECT_PRIORITY = normalizeCollectPriority(AC_STATE.priority or "off")
            _G.AUTO_COLLECT_PRIORITY = G.AUTO_COLLECT_PRIORITY

            local ac = G.AutoCollectFruit or G.CollectFruitModule
            if type(ac) == "table" then
                local function __call(fn, ...)
                    if type(ac[fn]) == "function" then
                        pcall(ac[fn], ac, ...)
                    end
                end

                __call("SetSelected", G.AUTO_COLLECT_FRUITS_SELECTED)
                __call("SetFruits", G.AUTO_COLLECT_FRUITS_SELECTED)
                __call("setFruits", G.AUTO_COLLECT_FRUITS_SELECTED)
                __call("SetMutations", G.AUTO_COLLECT_MUTATIONS_SELECTED)
                __call("setMutations", G.AUTO_COLLECT_MUTATIONS_SELECTED)
                __call("SetKgFilter", G.AUTO_COLLECT_KG, G.AUTO_COLLECT_KG_MODE)
                __call("setKgFilter", G.AUTO_COLLECT_KG, G.AUTO_COLLECT_KG_MODE)
                __call("SetDelay", G.AUTO_COLLECT_DELAY)
                __call("setDelay", G.AUTO_COLLECT_DELAY)
                __call("SetPriority", G.AUTO_COLLECT_PRIORITY)
                __call("setPriority", G.AUTO_COLLECT_PRIORITY)

                if G.AUTO_COLLECT_FRUIT_ENABLED then
                    __call("Start")
                    __call("start")
                else
                    __call("Stop")
                    __call("stop")
                end
            end
        end

        G.__GAG2_SYNC_AUTO_COLLECT = syncAutoCollectModule

        local body = ui:CreateSection("Auto Collect", false)

        local _, statusTitle = ui:CreateRowLabel(
            body,
            ("Ready to harvest: %d"):format(countReadyFruits()),
            nil,
            nil,
            "muted"
        )

        task.spawn(function()
            while body and body.Parent do
                task.wait(2)
                pcall(function()
                    if statusTitle and statusTitle.Parent then
                        statusTitle.Text = ("Ready to harvest: %d"):format(countReadyFruits())
                    end
                end)
            end
        end)

        ui:CreateRowDropdown(body, {
            label       = "Select Fruit",
            placeholder = "All Fruit...",
            mode        = "multi",
            getItems = function()
                if PlantListView and type(PlantListView.buildFruitItems) == "function" then
                    return PlantListView.buildFruitItems() or {}
                end
                warn("[Collect UI] PlantListView.buildFruitItems tidak ada")
                return {}
            end,
            initial = AUTO_COLLECT_FRUITS_SELECTED,
            onChanged = function(_, selectedMap)
                AUTO_COLLECT_FRUITS_SELECTED = cleanSelectedMap(selectedMap)
                G.AUTO_COLLECT_FRUITS_SELECTED = AUTO_COLLECT_FRUITS_SELECTED
                _G.AUTO_COLLECT_FRUITS_SELECTED = AUTO_COLLECT_FRUITS_SELECTED
                AC_STATE.fruits = mapToArray(AUTO_COLLECT_FRUITS_SELECTED)
                patchAuto("collect", { fruits = AC_STATE.fruits }, syncAutoCollectModule)
            end,
        })

        ui:CreateRowDropdown(body, {
            label       = "Select Mutation",
            placeholder = "All Mutation...",
            mode        = "multi",
            getItems = function()
                if PlantListView and type(PlantListView.listFruitMutations) == "function" then
                    return PlantListView.listFruitMutations() or {}
                end
                warn("[Collect UI] PlantListView.listFruitMutations tidak ada")
                return {}
            end,
            initial = AUTO_COLLECT_MUTATIONS_SELECTED,
            onChanged = function(_, selectedMap)
                AUTO_COLLECT_MUTATIONS_SELECTED = cleanSelectedMap(selectedMap)
                G.AUTO_COLLECT_MUTATIONS_SELECTED = AUTO_COLLECT_MUTATIONS_SELECTED
                _G.AUTO_COLLECT_MUTATIONS_SELECTED = AUTO_COLLECT_MUTATIONS_SELECTED
                AC_STATE.mutations = mapToArray(AUTO_COLLECT_MUTATIONS_SELECTED)
                patchAuto("collect", { mutations = AC_STATE.mutations }, syncAutoCollectModule)
            end,
        })

        ui:CreateRowInput(
            body,
            "KG Filter (- below / + above)",
            kgInputText(),
            function(txt)
                local pending = kgSyncToken + 1
                kgSyncToken = pending
                task.delay(0.4, function()
                    if kgSyncToken ~= pending then return end
                    local kg, mode = parseKgRule(txt)
                    AC_STATE.kg = kg
                    AC_STATE.kgMode = mode
                    G.AUTO_COLLECT_KG = kg
                    _G.AUTO_COLLECT_KG = kg
                    G.AUTO_COLLECT_KG_MODE = mode
                    _G.AUTO_COLLECT_KG_MODE = mode
                    G.AUTO_COLLECT_KG_RULE = txt
                    _G.AUTO_COLLECT_KG_RULE = txt
                    patchAuto("collect", { kg = kg, kgMode = mode, kgRule = txt }, syncAutoCollectModule)
                end)
            end
        )

        _, collectPriorityApi = ui:CreateRowDropdown(body, {
            label       = "Collect Priority",
            placeholder = "Normal (scan order)",
            mode        = "single",
            getItems = function() return COLLECT_PRIORITY_ITEMS end,
            initial = AC_STATE.priority,
            onChanged = function(modeOrKey, selectedKey)
                local key = selectedKey
                if type(key) ~= "string" or key == "" or key == "single" or key == "multi" then
                    key = modeOrKey
                end
                local mode = applyCollectPriority(key)
                AC_STATE.priority = mode
                patchAuto("collect", { priority = mode }, function()
                    local live = getAuto("collect")
                    if type(live) == "table" and live.priority ~= nil then
                        AC_STATE.priority = normalizeCollectPriority(live.priority)
                    end
                    syncAutoCollectModule()
                end)
            end,
        })
        G.__GAG2_COLLECT_PRIORITY_API = collectPriorityApi
        _G.__GAG2_COLLECT_PRIORITY_API = collectPriorityApi

        if type(collectPriorityApi) == "table" and type(collectPriorityApi.setSelected) == "function" then
            pcall(collectPriorityApi.setSelected, AC_STATE.priority)
        end

        local _, collectDelayFn = ui:CreateRowInput(
            body,
            "Collect Delay (sec)",
            tostring(collectDelayDisplay()),
            function(txt)
                local n = tonumber(txt)
                if n == nil then return end
                if n < 0 then n = 0 end
                AC_STATE.delay = n
                G.AUTO_COLLECT_DELAY = n
                _G.AUTO_COLLECT_DELAY = n
                patchAuto("collect", { delay = n }, syncAutoCollectModule)
            end,
            false
        )
        G.__GAG2_COLLECT_DELAY_API = collectDelayFn
        _G.__GAG2_COLLECT_DELAY_API = collectDelayFn

        local _, _, collectEnableApi = ui:CreateRowToggle(
            body,
            "Enable Auto Collect",
            (AC_STATE.enabled == true),
            function(isOn)
                AC_STATE.enabled = (isOn == true)
                patchAuto("collect", { enabled = isOn == true }, syncAutoCollectModule)
            end
        )
        G.__GAG2_COLLECT_ENABLE_API = collectEnableApi
        _G.__GAG2_COLLECT_ENABLE_API = collectEnableApi

        syncAutoCollectModule()

        ----------------------------------------------------------------
        -- Auto Plant (section di bawah Auto Collect)
        ----------------------------------------------------------------
        MAIN.auto.plant = MAIN.auto.plant or {}
        local AP_STATE = getAuto("plant")
        AP_STATE.seeds = type(AP_STATE.seeds) == "table" and AP_STATE.seeds or {}
        AP_STATE.positions = type(AP_STATE.positions) == "table" and AP_STATE.positions or {}
        AP_STATE.mode = tostring(AP_STATE.mode or "random"):lower()
        if AP_STATE.mode ~= "manual" then AP_STATE.mode = "random" end

        local function normalizePlantPositionId(v)
            if v == nil then return nil end
            if type(v) == "table" then
                v = v.id or v.key
            end
            v = tostring(v)
            if v == "" or v:sub(1, 6) == "table:" then return nil end
            return v
        end

        AP_STATE.selectedPosition = normalizePlantPositionId(AP_STATE.selectedPosition)
        if not AP_STATE.selectedPosition and #AP_STATE.positions > 0 then
            local first = AP_STATE.positions[1]
            if type(first) == "table" and first.id then
                AP_STATE.selectedPosition = tostring(first.id)
            end
        end
        AP_STATE.savePosition = false
        if AP_STATE.plantTotal ~= nil then
            AP_STATE.plantTotal = tonumber(AP_STATE.plantTotal)
        end
        if AP_STATE.plantTotal == nil then AP_STATE.plantTotal = 0 end
        if AP_STATE.plantTotal < 0 then AP_STATE.plantTotal = 0 end
        AP_STATE.plantTotal = math.floor(AP_STATE.plantTotal)

        AUTO_PLANT_SEEDS_SELECTED = cleanSelectedMap(arrayToMap(AP_STATE.seeds))
        G.AUTO_PLANT_SEEDS_SELECTED = AUTO_PLANT_SEEDS_SELECTED
        _G.AUTO_PLANT_SEEDS_SELECTED = AUTO_PLANT_SEEDS_SELECTED

        local function plantDelayDisplay()
            local n = tonumber(AP_STATE.delay)
            return (n ~= nil) and n or 0.5
        end

        local function plantTotalDisplay()
            local n = tonumber(AP_STATE.plantTotal)
            return (n ~= nil) and math.floor(n) or 0
        end

        local function buildPositionItems()
            local items = {}
            local positions = AP_STATE.positions
            if type(positions) ~= "table" then return items end
            for i, entry in ipairs(positions) do
                if type(entry) == "table" and entry.id then
                    local x = tonumber(entry.x) or 0
                    local z = tonumber(entry.z) or 0
                    items[#items + 1] = {
                        key = tostring(entry.id),
                        name = ("Pos %d (%.0f, %.0f)"):format(i, x, z),
                    }
                end
            end
            return items
        end

        local function writePlantGlobals()
            local api = G.__GAG2_PLANT_ENABLE_API or rawget(_G, "__GAG2_PLANT_ENABLE_API")
            if type(api) == "table" and type(api.get) == "function" then
                AP_STATE.enabled = (api.get() == true)
            end
            G.AUTO_PLANT_ENABLED = (AP_STATE.enabled == true)
            _G.AUTO_PLANT_ENABLED = G.AUTO_PLANT_ENABLED
            if AP_STATE.delay ~= nil then
                G.AUTO_PLANT_DELAY = tonumber(AP_STATE.delay)
                _G.AUTO_PLANT_DELAY = G.AUTO_PLANT_DELAY
            end
            G.AUTO_PLANT_SEEDS_SELECTED = AUTO_PLANT_SEEDS_SELECTED
            _G.AUTO_PLANT_SEEDS_SELECTED = AUTO_PLANT_SEEDS_SELECTED
            G.AUTO_PLANT_MODE = AP_STATE.mode
            _G.AUTO_PLANT_MODE = AP_STATE.mode
            G.AUTO_PLANT_SELECTED_POSITION = AP_STATE.selectedPosition
            _G.AUTO_PLANT_SELECTED_POSITION = AP_STATE.selectedPosition
            G.AUTO_PLANT_SAVE_POSITION = (AP_STATE.savePosition == true)
            _G.AUTO_PLANT_SAVE_POSITION = G.AUTO_PLANT_SAVE_POSITION
            G.AUTO_PLANT_AUTO_MANUAL = (AP_STATE.autoManual == true)
            _G.AUTO_PLANT_AUTO_MANUAL = G.AUTO_PLANT_AUTO_MANUAL
            G.AUTO_PLANT_TOTAL = plantTotalDisplay()
            _G.AUTO_PLANT_TOTAL = G.AUTO_PLANT_TOTAL
            patchAutoOnly("plant", {
                enabled = (AP_STATE.enabled == true),
                seeds = mapToArray(AUTO_PLANT_SEEDS_SELECTED),
                positions = type(AP_STATE.positions) == "table" and AP_STATE.positions or {},
                mode = AP_STATE.mode,
                delay = AP_STATE.delay,
                autoManual = (AP_STATE.autoManual == true),
                selectedPosition = AP_STATE.selectedPosition,
                savePosition = false,
                plantTotal = plantTotalDisplay(),
            })
        end
        G.__GAG2_PUSH_PLANT = writePlantGlobals
        _G.__GAG2_PUSH_PLANT = writePlantGlobals

        registerFlush("plant", function()
            writePlantGlobals()
        end)

        writePlantGlobals()

        local manualPosRow
        local manualSaveRow
        local manualAutoRow
        local positionDropdownApi
        local setSaveToggle
        local saveToggleApi

        local function setManualRowsVisible(isManual)
            isManual = (isManual == true)
            if manualPosRow then manualPosRow.Visible = isManual end
            if manualSaveRow then manualSaveRow.Visible = isManual end
            if manualAutoRow then manualAutoRow.Visible = isManual end
        end

        local function syncAutoPlantModule()
            writePlantGlobals()

            local ap = G.AutoPlant or G.AutoPlantModule
            if type(ap) ~= "table" then return end

            local function __call(fn, ...)
                if type(ap[fn]) == "function" then
                    pcall(ap[fn], ap, ...)
                end
            end

            __call("SetPlantTotal", G.AUTO_PLANT_TOTAL)

            if G.AUTO_PLANT_ENABLED then
                __call("Start")
            else
                __call("Stop")
            end
        end

        G.__GAG2_SYNC_AUTO_PLANT = syncAutoPlantModule

        G.__GAG2_ON_PLANT_POSITIONS_CHANGED = function()
            local main = G.MAIN or _G.MAIN
            if type(main) == "table" and type(main.auto) == "table" and type(main.auto.plant) == "table" then
                AP_STATE.positions = type(main.auto.plant.positions) == "table" and main.auto.plant.positions or AP_STATE.positions
                AP_STATE.selectedPosition = normalizePlantPositionId(main.auto.plant.selectedPosition)
            end
            writePlantGlobals()
            if positionDropdownApi and type(positionDropdownApi.refreshItems) == "function" then
                positionDropdownApi.refreshItems()
            end
            if positionDropdownApi and type(positionDropdownApi.setSelected) == "function" then
                positionDropdownApi.setSelected(AP_STATE.selectedPosition)
            end
            if positionDropdownApi and type(positionDropdownApi.refreshLabel) == "function" then
                positionDropdownApi.refreshLabel()
            end
            saveNow()
        end

        G.__GAG2_ON_PLANT_SAVE_MODE_CHANGED = function(on)
            AP_STATE.savePosition = (on == true)
            writePlantGlobals()
            if saveToggleApi and type(saveToggleApi.set) == "function" then
                saveToggleApi.set(on, true)
            elseif setSaveToggle then
                setSaveToggle(on, true)
            end
            if not on then
                saveNow()
            end
        end

        G.__GAG2_PLANT_SAVE_TOGGLE_API = nil

        local plantSeedListCache = {}
        local plantSeedPrefetching = false
        local plantSeedDropdownApi = nil

        local function parseSeedItemCount(it)
            if type(it) ~= "table" then return 0 end
            local n = tonumber(it.count) or tonumber(it.right)
            if n then return math.max(0, math.floor(n)) end
            if type(it.name) == "string" then
                local tail = it.name:match("%s+x%s+(.+)$")
                if tail then
                    tail = tail:gsub(",", "")
                    if tail:sub(-1) == "K" then
                        return math.max(0, math.floor((tonumber(tail:sub(1, -2)) or 0) * 1000))
                    end
                    if tail:sub(-1) == "M" then
                        return math.max(0, math.floor((tonumber(tail:sub(1, -2)) or 0) * 1000000))
                    end
                    return math.max(0, math.floor(tonumber(tail) or 0))
                end
            end
            return 0
        end

        local function sumPlantSeedCache()
            local sum = 0
            for _, it in ipairs(plantSeedListCache) do
                sum += parseSeedItemCount(it)
            end
            return sum
        end

        local function plantInventoryTotal()
            return sumPlantSeedCache()
        end

        local function plantSeedStatusText()
            local totalInv = plantInventoryTotal()
            local ap = G.AutoPlant or G.AutoPlantModule
            local enabled = AP_STATE.enabled == true
            local enableApi = G.__GAG2_PLANT_ENABLE_API or rawget(_G, "__GAG2_PLANT_ENABLE_API")
            if type(enableApi) == "table" and type(enableApi.get) == "function" then
                enabled = enableApi.get() == true
            end
            if type(ap) == "table" and type(ap.GetSeedStats) == "function" then
                local ok, s = pcall(ap.GetSeedStats, ap)
                if ok and type(s) == "table" then
                    local planted = math.max(0, math.floor(tonumber(s.planted) or 0))
                    local userLimit = math.max(0, math.floor(tonumber(s.plantTotal) or plantTotalDisplay()))
                    if totalInv <= 0 then
                        totalInv = math.max(0, math.floor(tonumber(s.totalInventory) or tonumber(s.remaining) or 0))
                    end
                    if enabled and userLimit > 0 then
                        return ("Seeds: planted %d / %d (bag: %d)"):format(planted, userLimit, totalInv)
                    end
                    if enabled and planted > 0 then
                        return ("Seeds: planted %d (bag: %d)"):format(planted, totalInv)
                    end
                end
            end
            return ("Seeds in inventory: %d"):format(totalInv)
        end

