                        table.remove(positions, i)
                        removed = true
                    end
                end
                if not removed then return end

                AP_STATE.positions = positions
                if tostring(AP_STATE.selectedPosition) == key then
                    AP_STATE.selectedPosition = nil
                    if #positions > 0 and type(positions[1]) == "table" and positions[1].id then
