            if type(as) ~= "table" then return end

            local function __callSell(fn, ...)
                if type(as[fn]) == "function" then
                    pcall(as[fn], as, ...)
                end
            end

            if G.AUTO_SELL_ENABLED then
                __callSell("Start")
                __callSell("start")
                __callSell("CheckNow")
                __callSell("checkNow")
            else
                __callSell("Stop")
                __callSell("stop")
            end
        end

