        MAIN.auto.buy = MAIN.auto.buy or {}

        local BUY_STATE = getAuto("buy")
        BUY_STATE.seed = type(BUY_STATE.seed) == "table" and BUY_STATE.seed or { enabled = false, items = {} }
        BUY_STATE.gear = type(BUY_STATE.gear) == "table" and BUY_STATE.gear or { enabled = false, items = {} }
        BUY_STATE.props = type(BUY_STATE.props) == "table" and BUY_STATE.props or { enabled = false, items = {} }

        BUY_STATE.seed.enabled = (BUY_STATE.seed.enabled == true)
        BUY_STATE.gear.enabled = (BUY_STATE.gear.enabled == true)
        BUY_STATE.props.enabled = (BUY_STATE.props.enabled == true)
        BUY_STATE.seed.items = type(BUY_STATE.seed.items) == "table" and BUY_STATE.seed.items or {}
        BUY_STATE.gear.items = type(BUY_STATE.gear.items) == "table" and BUY_STATE.gear.items or {}
        BUY_STATE.props.items = type(BUY_STATE.props.items) == "table" and BUY_STATE.props.items or {}

        local BUY_SEED_SELECTED = cleanSelectedMap(arrayToMap(BUY_STATE.seed.items))
        local BUY_GEAR_SELECTED = cleanSelectedMap(arrayToMap(BUY_STATE.gear.items))
        local BUY_PROPS_SELECTED = cleanSelectedMap(arrayToMap(BUY_STATE.props.items))

        local AUTO_BUY_SEED_ENABLED = BUY_STATE.seed.enabled
        local AUTO_BUY_GEAR_ENABLED = BUY_STATE.gear.enabled
        local AUTO_BUY_PROPS_ENABLED = BUY_STATE.props.enabled

        local PET_STORE = syncBuyPetStoreFromMain()
        writeBuyPetToMain()

        local ShopListView = G.ShopListView
        local PetListView = G.PetListView

        local function writeBuyGlobals()
            local seedApi = G.__GAG2_BUY_SEED_ENABLE_API or rawget(_G, "__GAG2_BUY_SEED_ENABLE_API")
            local gearApi = G.__GAG2_BUY_GEAR_ENABLE_API or rawget(_G, "__GAG2_BUY_GEAR_ENABLE_API")
            local propsApi = G.__GAG2_BUY_PROPS_ENABLE_API or rawget(_G, "__GAG2_BUY_PROPS_ENABLE_API")
            if type(seedApi) == "table" and type(seedApi.get) == "function" then
                BUY_STATE.seed.enabled = (seedApi.get() == true)
            end
            if type(gearApi) == "table" and type(gearApi.get) == "function" then
                BUY_STATE.gear.enabled = (gearApi.get() == true)
            end
            if type(propsApi) == "table" and type(propsApi.get) == "function" then
                BUY_STATE.props.enabled = (propsApi.get() == true)
            end

            local main = rawget(_G, "MAIN") or G.MAIN or MAIN
            if type(main) ~= "table" then
                main = {}
                G.MAIN = main
                _G.MAIN = main
            end
            main.auto = main.auto or {}
            main.auto.buy = main.auto.buy or {}
            local buy = main.auto.buy

            buy.seed = type(buy.seed) == "table" and buy.seed or { enabled = false, items = {} }
            buy.gear = type(buy.gear) == "table" and buy.gear or { enabled = false, items = {} }
            buy.props = type(buy.props) == "table" and buy.props or { enabled = false, items = {} }

            buy.seed.enabled = (BUY_STATE.seed.enabled == true)
            buy.gear.enabled = (BUY_STATE.gear.enabled == true)
            buy.props.enabled = (BUY_STATE.props.enabled == true)
            buy.seed.items = mapToArray(BUY_SEED_SELECTED)
            buy.gear.items = mapToArray(BUY_GEAR_SELECTED)
            buy.props.items = mapToArray(BUY_PROPS_SELECTED)

            writeBuyPetToMain()
            buy.pet = type(main.auto.buy.pet) == "table" and main.auto.buy.pet or buy.pet

            patchAutoOnly("buy", {
                seed = { enabled = buy.seed.enabled, items = buy.seed.items },
                gear = { enabled = buy.gear.enabled, items = buy.gear.items },
                props = { enabled = buy.props.enabled, items = buy.props.items },
                pet = {
                    enabled = buy.pet.enabled,
                    auto_tame = buy.pet.auto_tame,
                    max_price_mult = buy.pet.max_price_mult,
                    items = type(buy.pet.items) == "table" and buy.pet.items or {},
                },
            })

            G.AUTO_BUY_SEED_ENABLED = buy.seed.enabled
            _G.AUTO_BUY_SEED_ENABLED = buy.seed.enabled
            G.AUTO_BUY_GEAR_ENABLED = buy.gear.enabled
            _G.AUTO_BUY_GEAR_ENABLED = buy.gear.enabled
            G.AUTO_BUY_PROPS_ENABLED = buy.props.enabled
            _G.AUTO_BUY_PROPS_ENABLED = buy.props.enabled

            G.BUY_SEED_SELECTED = BUY_SEED_SELECTED
            _G.BUY_SEED_SELECTED = BUY_SEED_SELECTED
            G.BUY_GEAR_SELECTED = BUY_GEAR_SELECTED
            _G.BUY_GEAR_SELECTED = BUY_GEAR_SELECTED
            G.BUY_PROPS_SELECTED = BUY_PROPS_SELECTED
            _G.BUY_PROPS_SELECTED = BUY_PROPS_SELECTED

            G.MAIN = main
            _G.MAIN = main
            MAIN = main
            BUY_STATE = buy
        end
        G.__GAG2_PUSH_BUY = writeBuyGlobals
        _G.__GAG2_PUSH_BUY = writeBuyGlobals

        registerFlush("buy", function()
            writeBuyGlobals()
        end)

        writeBuyGlobals()

        local function getAutoBuy()
            return G.AutoBuyModule or G.AutoBuy or _G.AutoBuyModule or _G.AutoBuy
        end

        local function syncAutoBuyModule()
            writeBuyGlobals()

            local ab = getAutoBuy()
            if type(ab) ~= "table" then return end

            local function __call(fn, ...)
                if type(ab[fn]) == "function" then
                    pcall(ab[fn], ab, ...)
                end
            end

            __call("SetSelected", "seed", BUY_SEED_SELECTED)
            __call("SetSelected", "gear", BUY_GEAR_SELECTED)
            __call("SetSelected", "props", BUY_PROPS_SELECTED)

            if BUY_STATE.seed.enabled then
                __call("SetEnabled", "seed", true)
            else
                __call("SetEnabled", "seed", false)
            end
            if BUY_STATE.gear.enabled then
                __call("SetEnabled", "gear", true)
            else
                __call("SetEnabled", "gear", false)
            end
            if BUY_STATE.props.enabled then
                __call("SetEnabled", "props", true)
            else
                __call("SetEnabled", "props", false)
            end

            __call("SyncFromGlobals")

            local anyOn = BUY_STATE.seed.enabled or BUY_STATE.gear.enabled or BUY_STATE.props.enabled
            if anyOn then
                __call("Start")
                __call("start")
            else
                __call("Stop")
                __call("stop")
            end
        end

        G.__GAG2_SYNC_AUTO_BUY = syncAutoBuyModule

        local bodySeed = ui:CreateSection("Auto Buy Seed", true)
        local bodyGear = ui:CreateSection("Auto Buy Gear", false)
        local bodyProps = ui:CreateSection("Auto Buy Props", false)

        ui:CreateRowDropdown(bodySeed, {
            label       = "Select Seed",
            placeholder = "Select Seed...",
            mode        = "multi",
            getItems = function()
                if PlantListView and type(PlantListView.buildSeedItems) == "function" then
                    return PlantListView.buildSeedItems() or {}
                end
                local ab = getAutoBuy()
                if type(ab) == "table" and type(ab.GetLists) == "function" then
                    local ok, seeds = pcall(ab.GetLists, ab)
                    if ok then return seeds or {} end
                end
                return {}
            end,
            initial = BUY_SEED_SELECTED,
            onChanged = function(_, selectedMap)
                BUY_SEED_SELECTED = cleanSelectedMap(selectedMap)
                patchAuto("buy", { seed = { items = mapToArray(BUY_SEED_SELECTED) } }, syncAutoBuyModule)
            end,
        })

        local _, _, seedEnableApi = ui:CreateRowToggle(bodySeed, "Enable Auto Buy Seed", AUTO_BUY_SEED_ENABLED, function(isOn)
            BUY_STATE.seed.enabled = (isOn == true)
            AUTO_BUY_SEED_ENABLED = BUY_STATE.seed.enabled
            patchAuto("buy", { seed = { enabled = isOn == true } }, syncAutoBuyModule)
        end)
        G.__GAG2_BUY_SEED_ENABLE_API = seedEnableApi
        _G.__GAG2_BUY_SEED_ENABLE_API = seedEnableApi

        ui:CreateRowDropdown(bodyGear, {
            label       = "Select Gear",
            placeholder = "Select Gear...",
            mode        = "multi",
            getItems = function()
                if ShopListView and type(ShopListView.buildGearItems) == "function" then
                    return ShopListView.buildGearItems() or {}
                end
                local ab = getAutoBuy()
                if type(ab) == "table" and type(ab.GetLists) == "function" then
                    local ok, _, gears = pcall(ab.GetLists, ab)
                    if ok then return gears or {} end
                end
                return {}
            end,
            initial = BUY_GEAR_SELECTED,
            onChanged = function(_, selectedMap)
                BUY_GEAR_SELECTED = cleanSelectedMap(selectedMap)
                patchAuto("buy", { gear = { items = mapToArray(BUY_GEAR_SELECTED) } }, syncAutoBuyModule)
            end,
        })

        local _, _, gearEnableApi = ui:CreateRowToggle(bodyGear, "Enable Auto Buy Gear", AUTO_BUY_GEAR_ENABLED, function(isOn)
            BUY_STATE.gear.enabled = (isOn == true)
            AUTO_BUY_GEAR_ENABLED = BUY_STATE.gear.enabled
            patchAuto("buy", { gear = { enabled = isOn == true } }, syncAutoBuyModule)
        end)
        G.__GAG2_BUY_GEAR_ENABLE_API = gearEnableApi
        _G.__GAG2_BUY_GEAR_ENABLE_API = gearEnableApi

        ui:CreateRowDropdown(bodyProps, {
            label       = "Select Crate",
            placeholder = "Select Crate...",
            mode        = "multi",
            getItems = function()
                if ShopListView and type(ShopListView.buildPropsItems) == "function" then
                    return ShopListView.buildPropsItems() or {}
                end
                local ab = getAutoBuy()
                if type(ab) == "table" and type(ab.GetLists) == "function" then
                    local ok, _, _, props = pcall(ab.GetLists, ab)
                    if ok then return props or {} end
                end
                return {}
            end,
            initial = BUY_PROPS_SELECTED,
            onChanged = function(_, selectedMap)
                BUY_PROPS_SELECTED = cleanSelectedMap(selectedMap)
                patchAuto("buy", { props = { items = mapToArray(BUY_PROPS_SELECTED) } }, syncAutoBuyModule)
            end,
        })

        local _, _, propsEnableApi = ui:CreateRowToggle(bodyProps, "Enable Auto Buy Props", AUTO_BUY_PROPS_ENABLED, function(isOn)
            BUY_STATE.props.enabled = (isOn == true)
            AUTO_BUY_PROPS_ENABLED = BUY_STATE.props.enabled
            patchAuto("buy", { props = { enabled = isOn == true } }, syncAutoBuyModule)
        end)
        G.__GAG2_BUY_PROPS_ENABLE_API = propsEnableApi
        _G.__GAG2_BUY_PROPS_ENABLE_API = propsEnableApi

        local bodyPet = ui:CreateSection("Auto Buy Pet", false)

        local function petMultText()
            return tostring(PET_STORE.max_price_mult)
        end

        local _, petDropdownApi = ui:CreateRowDropdown(bodyPet, {
            label       = "Select Pet",
            placeholder = "Select Pet...",
            mode        = "multi",
            getItems = function()
                if PetListView and type(PetListView.buildPetItems) == "function" then
                    return PetListView.buildPetItems() or {}
                end
                return {}
            end,
            initial = PET_STORE.selected,
            onChanged = function(_, selectedMap)
                patchBuyPet({ selected = selectedMap }, function() applyBuyPetRuntime(readBuyPetEnabled()) end)
            end,
        })
        G.__GAG2_BUY_PET_DROPDOWN_API = petDropdownApi
        _G.__GAG2_BUY_PET_DROPDOWN_API = petDropdownApi

        do
            local _, _, api = ui:CreateRowToggle(bodyPet, "Enable Auto Buy Pet", PET_STORE.enabled, function(isOn)
                patchBuyPet({ enabled = isOn == true }, function() applyBuyPetRuntime(isOn == true) end)
            end)
            G.__GAG2_BUY_PET_ENABLE_API = api
            _G.__GAG2_BUY_PET_ENABLE_API = api
        end

        do
            local _, _, api = ui:CreateRowToggle(bodyPet, "Auto Tame", PET_STORE.auto_tame, function(isOn)
                patchBuyPet({ auto_tame = isOn == true }, function() applyBuyPetRuntime(readBuyPetEnabled()) end)
            end)
            G.__GAG2_BUY_PET_TAME_API = api
            _G.__GAG2_BUY_PET_TAME_API = api
        end

        do
            local _, getFn = ui:CreateRowInput(bodyPet, "Max Price x", petMultText(), function(txt)
                local n = tonumber(txt)
                if n == nil or n < 1 then return end
                patchBuyPet({ max_price_mult = n }, function() applyBuyPetRuntime(readBuyPetEnabled()) end)
            end)
            G.__GAG2_BUY_PET_PRICE_GET = getFn
            _G.__GAG2_BUY_PET_PRICE_GET = getFn
        end

        if G.__GAG2_BUY_PET_ENABLE_API and type(G.__GAG2_BUY_PET_ENABLE_API.set) == "function" then
            G.__GAG2_BUY_PET_ENABLE_API.set(PET_STORE.enabled == true, true)
        end
        if G.__GAG2_BUY_PET_TAME_API and type(G.__GAG2_BUY_PET_TAME_API.set) == "function" then
            G.__GAG2_BUY_PET_TAME_API.set(PET_STORE.auto_tame == true, true)
        end

        syncAutoBuyModule()
        applyBuyPetRuntime(readBuyPetEnabled())
    end, 2)

    ui:RegisterSubTab("auto", "gift", "Gift", function()
        G.__GAG2_AUTO_GIFT_UI_READY = false
        _G.__GAG2_AUTO_GIFT_UI_READY = false

        local GIFT = ensureAutoGiftStore()
        local lookupToken = 0

        local function resolveGiftTarget(key)
            key = tostring(key or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
            if key == "" then return nil end
            local PlayersSvc = game:GetService("Players")
            for _, p in ipairs(PlayersSvc:GetPlayers()) do
                if p.Name == key or tostring(p.UserId) == key then
                    return p
                end
            end
            return PlayersSvc:FindFirstChild(key)
        end

        local function applyGiftTarget(key)
            key = tostring(key or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
            if key == "" then
                patchGift({
                    recipient_username = "",
                    recipient_user_id = 0,
                    recipient_display = "",
                }, function() applyAutoGiftRuntime(nil) end)
                return
            end

            local p = resolveGiftTarget(key)
            if p then
                patchGift({
                    recipient_username = p.Name,
                    recipient_user_id = p.UserId,
                    recipient_display = p.DisplayName,
                }, function()
                    GIFT = ensureAutoGiftStore()
                    local ag = getAutoGiftModule()
                    if type(ag) == "table" and type(ag.ApplyConfig) == "function" then
                        pcall(ag.ApplyConfig, ag, giftConfigFromStore(GIFT))
                    end
                    G.AUTO_GIFT_STATUS = "Target: " .. p.DisplayName
                    _G.AUTO_GIFT_STATUS = G.AUTO_GIFT_STATUS
                    applyAutoGiftRuntime(nil)
                end)
                return
            end

            lookupToken += 1
            local my = lookupToken
            task.delay(0.5, function()
                if my ~= lookupToken then return end
                local ag = getAutoGiftModule()
                if type(ag) ~= "table" or type(ag.LookupRecipient) ~= "function" then return end
                local okLookup = pcall(ag.LookupRecipient, ag, key)
                local cfg = {}
                if type(ag.GetConfig) == "function" then
                    local okCfg, res = pcall(ag.GetConfig, ag)
                    if okCfg and type(res) == "table" then cfg = res end
                end
                patchGift({
                    recipient_username = key,
                    recipient_user_id = okLookup and (cfg.recipient_user_id or 0) or 0,
                    recipient_display = okLookup and (cfg.recipient_display or "") or "",
                }, function() applyAutoGiftRuntime(nil) end)
            end)
        end

        for _ = 1, 20 do
            local defs = buildGiftCatUiDefs()
            if #defs > 0 then break end
            task.wait(0.25)
        end
        local GIFT_CAT_UI = buildGiftCatUiDefs()

        local function categoriesToMultiMap(cats)
            local out = {}
            cats = type(cats) == "table" and cats or {}
            for _, def in ipairs(buildGiftCatUiDefs()) do
                if cats[def.key] == true then
                    out[def.key] = true
                end
            end
            return out
        end

        local function refreshStatusLabel(lbl)
            if not lbl or not lbl.Parent then return end
            GIFT = ensureAutoGiftStore()
            local ag = getAutoGiftModule()
            local globalStatus = G.AUTO_GIFT_STATUS or rawget(_G, "AUTO_GIFT_STATUS") or ""
            local flushOk = G.AUTO_GIFT_FLUSH_OK == true or rawget(_G, "AUTO_GIFT_FLUSH_OK") == true
            local staleFlush = globalStatus:find("flush error", 1, true)
                or globalStatus:find("UI flush", 1, true)
            local txt = globalStatus ~= "" and globalStatus or "Ready"
            if flushOk and staleFlush then
                txt = "Ready"
            end
            if type(ag) == "table" and type(ag.GetStats) == "function" then
                local ok, st = pcall(ag.GetStats, ag)
                if ok and type(st) == "table" and st.lastStatus and st.lastStatus ~= "" then
                    local ls = tostring(st.lastStatus)
                    if staleFlush and not flushOk then
                        txt = ls .. " | " .. globalStatus
                    elseif globalStatus:find("gagal", 1, true) then
                        txt = ls .. " | " .. globalStatus
                    else
                        txt = ls
                    end
                end
            end
            if GIFT.recipient_display ~= "" and GIFT.recipient_user_id > 0 then
                txt = "Target: " .. GIFT.recipient_display .. " | " .. txt
            elseif GIFT.recipient_username ~= "" then
                txt = "Target: @" .. GIFT.recipient_username .. " | " .. txt
            end
            lbl.Text = "Status: " .. txt
        end

        ----------------------------------------------------------------
        -- Section 1: Gift Mail
        ----------------------------------------------------------------
        local bodyGiftMail = ui:CreateSection("Gift Mail", false)

        local targetInitial = GIFT.recipient_username ~= "" and GIFT.recipient_username or ""
        local _, targetInputFn = ui:CreateRowInput(
            bodyGiftMail,
            "Target",
            targetInitial,
            function(txt)
                applyGiftTarget(txt)
            end,
            false
        )
        G.__GAG2_AUTO_GIFT_TARGET_API = targetInputFn
        _G.__GAG2_AUTO_GIFT_TARGET_API = targetInputFn

        local _, statusLabel = ui:CreateRowLabel(bodyGiftMail, "Status: Ready", nil, nil, "info")
        task.spawn(function()
            while statusLabel and statusLabel.Parent do
                refreshStatusLabel(statusLabel)
                task.wait(1)
            end
        end)

        local itemDropdowns = {}
        local syncingCategoryUi = false
        local sendTotalGlobalRow = nil
        local autoSendRow = nil
        local catModeDd = nil
        local sendListModeDd = nil
        local afterSendModeDd = nil

        local function firstEnabledCategoryKey(categories)
            categories = type(categories) == "table" and categories or {}
            for _, def in ipairs(buildGiftCatUiDefs()) do
                if categories[def.key] == true then
                    return def.key
                end
            end
            return nil
        end

        local function applyGiftCategoryMode(mode, persist)
            mode = (mode == "multi") and "multi" or "single"
            if type(catMultiDd) == "table" and type(catMultiDd.setMode) == "function" then
                catMultiDd.setMode(mode)
            end
            for _, entry in pairs(itemDropdowns) do
                if type(entry) == "table" and type(entry.dd) == "table" and type(entry.dd.setMode) == "function" then
                    entry.dd.setMode(mode)
                end
            end
            if persist then
                patchGift({ category_mode = mode }, function() applyAutoGiftRuntime(nil) end)
            end
        end

        local function applySendListModeUi(mode, persist)
            mode = (mode == "send_total") and "send_total" or "loop"
            if sendTotalGlobalRow then
                sendTotalGlobalRow.Visible = mode == "send_total"
            end
            if autoSendRow then
                autoSendRow.Visible = mode == "loop"
            end
            if persist then
                local patch = { send_list_mode = mode }
                if mode == "send_total" then
                    patch.auto_send = false
                    local autoApi = G.__GAG2_AUTO_GIFT_AUTO_SEND_API or rawget(_G, "__GAG2_AUTO_GIFT_AUTO_SEND_API")
                    if type(autoApi) == "table" and type(autoApi.set) == "function" then
                        pcall(autoApi.set, false, true)
                    end
                end
                patchGift(patch, function() applyAutoGiftRuntime(nil) end)
            end
        end

        local function getGiftSendableMax()
            pcall(flushAutoGiftFromUI)
            applyAutoGiftRuntime(nil)
            local ag = getAutoGiftModule()
            if type(ag) == "table" and type(ag.CountSendableUnits) == "function" then
                local ok, n = pcall(ag.CountSendableUnits, ag)
                if ok and type(n) == "number" then
                    return math.max(0, math.floor(n))
                end
            end
            return 0
        end

        local function applyCategorySelection(selectedMap, persist)
            selectedMap = type(selectedMap) == "table" and selectedMap or {}
            local cats = {}
            for _, def in ipairs(buildGiftCatUiDefs()) do
                cats[def.key] = selectedMap[def.key] == true
            end
            for _, def in ipairs(buildGiftCatUiDefs()) do
                local entry = itemDropdowns[def.key]
                if entry then
                    if entry.row then entry.row.Visible = cats[def.key] == true end
                    if cats[def.key] == true and entry.dd and type(entry.dd.refreshItems) == "function" then
                        pcall(entry.dd.refreshItems, entry.dd)
                    end
                end
            end
            if persist and not syncingCategoryUi then
                patchGift({ categories = cats }, function() applyAutoGiftRuntime(nil) end)
            end
        end

        G.__GAG2_GIFT_APPLY_CATEGORY_SELECTION = applyCategorySelection
        _G.__GAG2_GIFT_APPLY_CATEGORY_SELECTION = applyCategorySelection

        local _, sendListModeDdApi = ui:CreateRowDropdown(bodyGiftMail, {
            label = "Send list mode",
            placeholder = "Loop",
            mode = "single",
            getItems = function()
                return {
                    { key = "loop", name = "Loop" },
                    { key = "send_total", name = "Send total" },
                }
            end,
            initial = (GIFT.send_list_mode == "send_total") and "send_total" or "loop",
            onChanged = function(_, key)
                applySendListModeUi(tostring(key or "loop"), true)
            end,
        })
        sendListModeDd = sendListModeDdApi
        G.__GAG2_AUTO_GIFT_SEND_LIST_MODE = sendListModeDdApi
        _G.__GAG2_AUTO_GIFT_SEND_LIST_MODE = sendListModeDdApi

        autoSendRow, _, G.__GAG2_AUTO_GIFT_AUTO_SEND_API = ui:CreateRowToggle(
            bodyGiftMail,
            "Auto send",
            GIFT.auto_send == true,
            function(isOn)
                patchGift({ auto_send = isOn == true }, function() applyAutoGiftRuntime(nil) end)
            end
        )
        _G.__GAG2_AUTO_GIFT_AUTO_SEND_API = G.__GAG2_AUTO_GIFT_AUTO_SEND_API
        autoSendRow.Visible = GIFT.send_list_mode ~= "send_total"

        sendTotalGlobalRow, G.__GAG2_AUTO_GIFT_SEND_TOTAL_GLOBAL = ui:CreateRowInput(
            bodyGiftMail,
            "Send total",
            tostring(GIFT.send_total or 20),
            function(txt)
                local n = tonumber(txt)
                if n == nil or n < 1 then return end
                local maxN = getGiftSendableMax()
                if maxN > 0 and n > maxN then
                    n = maxN
                end
                patchGift({ send_total = math.floor(n) }, function() applyAutoGiftRuntime(nil) end)
            end,
            false
        )
        _G.__GAG2_AUTO_GIFT_SEND_TOTAL_GLOBAL = G.__GAG2_AUTO_GIFT_SEND_TOTAL_GLOBAL
        sendTotalGlobalRow.Visible = GIFT.send_list_mode == "send_total"

        local _, catModeDdApi = ui:CreateRowDropdown(bodyGiftMail, {
            label = "Category mode",
            placeholder = "Single",
            mode = "single",
            getItems = function()
                return {
                    { key = "single", name = "Single" },
                    { key = "multi", name = "Multi" },
                }
            end,
            initial = giftCategoryModeFromStore(GIFT),
            onChanged = function(_, key)
                applyGiftCategoryMode(tostring(key or "single"), true)
            end,
        })
        catModeDd = catModeDdApi
        G.__GAG2_AUTO_GIFT_CATEGORY_MODE = catModeDdApi
        _G.__GAG2_AUTO_GIFT_CATEGORY_MODE = catModeDdApi

        local catInitMode = giftCategoryModeFromStore(GIFT)
        local _, catMultiDd = ui:CreateRowDropdown(bodyGiftMail, {
            label       = "Categories",
            placeholder = "Select categories...",
            mode        = catInitMode,
            getItems = function()
                local items = {}
                for _, def in ipairs(buildGiftCatUiDefs()) do
                    items[#items + 1] = { key = def.key, name = def.label }
                end
                return items
            end,
            initial = (catInitMode == "single")
