    local function setToggleApi(key, on)
        local api = G[key] or rawget(_G, key)
        if type(api) == "table" and type(api.set) == "function" then
            pcall(api.set, on == true, true)
        end
    end

    local function setInputApi(key, val)
        local fn = G[key] or rawget(_G, key)
        if type(fn) == "function" then
            pcall(fn, val)
        end
    end

    local function clearDropdownApi(key)
        local dd = G[key] or rawget(_G, key)
        if type(dd) == "table" and type(dd.setSelected) == "function" then
            pcall(dd.setSelected, {})
        end
    end

    local function applyAutoUiDefaults()
        local collect = getAuto("collect")
        local plant = getAuto("plant")
        local sell = getAuto("sell")
        local tele = getAuto("autoTele")
        local claim = getAuto("claimSeed")
        local buy = getAuto("buy")
        local gift = getAuto("gift")
        local pet = type(buy.pet) == "table" and buy.pet or {}

        setToggleApi("__GAG2_COLLECT_ENABLE_API", collect.enabled)
        setInputApi("__GAG2_COLLECT_DELAY_API", tostring(collect.delay ~= nil and collect.delay or 0.1))
        do
            local prApi = G.__GAG2_COLLECT_PRIORITY_API or rawget(_G, "__GAG2_COLLECT_PRIORITY_API")
            if type(prApi) == "table" and type(prApi.setSelected) == "function" then
                local pr = G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY") or collect.priority
                pcall(prApi.setSelected, normalizeCollectPriority(pr))
            end
        end
        setToggleApi("__GAG2_PLANT_ENABLE_API", plant.enabled)
        setToggleApi("__GAG2_PLANT_SAVE_TOGGLE_API", plant.savePosition)
        setToggleApi("__GAG2_SELL_ENABLE_API", sell.enabled)
        setToggleApi("__GAG2_TELE_ENABLE_TOGGLE_API", tele.enabled)
        setToggleApi("__GAG2_CLAIM_SEED_TOGGLE_API", claim.enabled)
        setToggleApi("__GAG2_BUY_SEED_ENABLE_API", buy.seed and buy.seed.enabled)
        setToggleApi("__GAG2_BUY_GEAR_ENABLE_API", buy.gear and buy.gear.enabled)
        setToggleApi("__GAG2_BUY_PROPS_ENABLE_API", buy.props and buy.props.enabled)
        setToggleApi("__GAG2_BUY_PET_ENABLE_API", pet.enabled)
        setToggleApi("__GAG2_BUY_PET_TAME_API", pet.auto_tame)
        clearDropdownApi("__GAG2_BUY_PET_DROPDOWN_API")

        setToggleApi("__GAG2_AUTO_GIFT_CLAIM_API", gift.auto_claim_mail)
        setToggleApi("__GAG2_AUTO_GIFT_ACCEPT_NORMAL_API", gift.auto_accept_gift)
        setToggleApi("__GAG2_AUTO_GIFT_AUTO_SEND_API", gift.auto_send)
        setInputApi("__GAG2_AUTO_GIFT_TARGET_API", tostring(gift.recipient_username or ""))
        setInputApi("__GAG2_AUTO_GIFT_SEND_TOTAL_GLOBAL", tostring(gift.send_total or 20))

        local ng = getAuto("normalGift")
        if type(ng) == "table" then
            local playerDd = G.__GAG2_NORMAL_GIFT_PLAYER_DD or rawget(_G, "__GAG2_NORMAL_GIFT_PLAYER_DD")
            if type(playerDd) == "table" and type(playerDd.setSelected) == "function" then
                local uid = math.floor(tonumber(ng.target_user_id) or 0)
                pcall(playerDd.setSelected, uid > 0 and tostring(uid) or nil)
            end
            local catDd = G.__GAG2_NORMAL_GIFT_CAT_DD or rawget(_G, "__GAG2_NORMAL_GIFT_CAT_DD")
            if type(catDd) == "table" and type(catDd.setSelected) == "function" then
                pcall(catDd.setSelected, tostring(ng.category or "Seeds"))
            end
            local itemDd = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
            if type(itemDd) == "table" and type(itemDd.setSelected) == "function" then
                pcall(itemDd.setSelected, cleanSelectedMap(arrayToMap(ng.selected)))
            end
            setInputApi("__GAG2_NORMAL_GIFT_SEND_TOTAL", tostring(ng.send_total or 1))
        end

        for _, key in ipairs(getGiftCatKeys()) do
            clearDropdownApi("__GAG2_AUTO_GIFT_DD_" .. key)
        end

        local catMulti = G.__GAG2_AUTO_GIFT_CAT_MULTI or rawget(_G, "__GAG2_AUTO_GIFT_CAT_MULTI")
        if type(catMulti) == "table" and type(catMulti.setSelected) == "function" then
            local catMap = {}
            if type(gift.categories) == "table" then
                for k, v in pairs(gift.categories) do
                    if v == true then catMap[k] = true end
                end
            end
            pcall(catMulti.setSelected, catMap)
        end

        clearDropdownApi("__GAG2_SHOVEL_DROPDOWN")
    end

    G.__GAG2_AUTO_TAB_CTX = {
        ui               = ui,
        getAuto          = getAuto,
        patchAuto        = patchAuto,
        patchAutoOnly    = patchAutoOnly,
        registerFlush    = registerFlush,
        cleanSelectedMap = cleanSelectedMap,
        arrayToMap       = arrayToMap,
        mapToArray       = mapToArray,
        toggleApiGet     = toggleApiGet,
    }
    _G.__GAG2_AUTO_TAB_CTX = G.__GAG2_AUTO_TAB_CTX

    local prevApplyUiDefaults = G.__GAG2_APPLY_UI_DEFAULTS
    G.__GAG2_APPLY_UI_DEFAULTS = function()
        if type(prevApplyUiDefaults) == "function" then
            pcall(prevApplyUiDefaults)
        end
        applyAutoUiDefaults()
    end
    _G.__GAG2_APPLY_UI_DEFAULTS = G.__GAG2_APPLY_UI_DEFAULTS
end

return M
