    local n = tonumber(txt)
    if not n then
        return 0, "above"
    end
    if n < 0 then
        return math.abs(n), "below"
    end
    return n, "above"
end

local function _liveKgFilter()
    local rule = G.AUTO_COLLECT_KG_RULE or rawget(_G, "AUTO_COLLECT_KG_RULE")
