        return _parseKgRuleInput(rule)
    end
    return _normalizeKgFilter(
        G.AUTO_COLLECT_KG or rawget(_G, "AUTO_COLLECT_KG"),
        G.AUTO_COLLECT_KG_MODE or rawget(_G, "AUTO_COLLECT_KG_MODE")
