    return tostring(kg)
end

local function getACState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local ac = MAIN and MAIN.auto and MAIN.auto.collect
    ac = type(ac) == "table" and ac or {}

    local fruits = _normalizeSet(
        G.AUTO_COLLECT_FRUITS_SELECTED or rawget(_G, "AUTO_COLLECT_FRUITS_SELECTED") or ac.fruits
    )
    local mutations = _normalizeSet(
        G.AUTO_COLLECT_MUTATIONS_SELECTED or rawget(_G, "AUTO_COLLECT_MUTATIONS_SELECTED") or ac.mutations
    )
    local kg, kgMode = _liveKgFilter()

    local rawDelay = G.AUTO_COLLECT_DELAY
    if rawDelay == nil then rawDelay = rawget(_G, "AUTO_COLLECT_DELAY") end
    if rawDelay == nil then rawDelay = ac.delay end
    local delay = _normalizeDelay(rawDelay, 0.1)

    local enabled = (G.AUTO_COLLECT_FRUIT_ENABLED == true)
        or (rawget(_G, "AUTO_COLLECT_FRUIT_ENABLED") == true)
        or (ac.enabled == true)

    local priority = tostring(
        G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY") or ac.priority or "off"
    ):lower()
    if priority ~= "price" and priority ~= "rarity" and priority ~= "weight" then
        priority = "off"
    end

    return {
        enabled = enabled,
        fruits = fruits,
        mutations = mutations,
        kg = kg,
        kgMode = kgMode,
        delay = delay,
        priority = priority,
        anyFruit = _hasAny(fruits),
        anyMut = _hasAny(mutations),
        anyKg = kg > 0,
    }
end

local function _applyLiveFilters(ac)
    if type(ac) ~= "table" then return end

    ac.fruits = _normalizeSet(
        G.AUTO_COLLECT_FRUITS_SELECTED or rawget(_G, "AUTO_COLLECT_FRUITS_SELECTED")
    )
    ac.mutations = _normalizeSet(
        G.AUTO_COLLECT_MUTATIONS_SELECTED or rawget(_G, "AUTO_COLLECT_MUTATIONS_SELECTED")
    )

    local kg, kgMode = _liveKgFilter()
    ac.kg = kg
    ac.kgMode = kgMode
    ac.anyFruit = _hasAny(ac.fruits)
    ac.anyMut = _hasAny(ac.mutations)
    ac.anyKg = kg > 0
end

local function getACStateCached()
    local now = os.clock()
    if cachedAC and (now - cachedACAt) <= AC_CACHE_SEC then
        cachedAC.enabled = (G.AUTO_COLLECT_FRUIT_ENABLED == true)
            or (rawget(_G, "AUTO_COLLECT_FRUIT_ENABLED") == true)
        cachedAC.delay = _liveDelay()
        local pr = G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY")
        if pr then
            pr = tostring(pr):lower()
            if pr == "price" or pr == "rarity" or pr == "weight" then
                cachedAC.priority = pr
            end
        end
        _applyLiveFilters(cachedAC)
        return cachedAC
    end
    cachedAC = getACState()
    cachedAC.delay = _liveDelay()
    cachedACAt = now
    return cachedAC
end

local function _invalidateACCache()
    cachedAC = nil
    cachedACAt = 0
    _clearBatchCaches()
    table.clear(weightCache)
end

local function _writeMainCollect(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.collect = MAIN.auto.collect or {}
    for k, v in pairs(patch) do
        MAIN.auto.collect[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

----------------------------------------------------------------
-- garden + fruit
----------------------------------------------------------------
local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local byId = gardens:FindFirstChild("Plot" .. tostring(plotId))
        if byId then
            cachedPlot = byId
            cachedPlotAt = now
            return byId
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    local byName = gardens:FindFirstChild("Plot" .. LP.Name)
    cachedPlot = byName
    cachedPlotAt = now
    return byName
end

local function _fruitFromPrompt(prompt)
    if not prompt or not prompt.Parent then return nil end
    return prompt.Parent:FindFirstAncestorWhichIsA("Model")
end

local function _getName(model)
    return model:GetAttribute("ConfigPathName")
        or model:GetAttribute("CorePartName")
        or model:GetAttribute("FruitType")
        or model:GetAttribute("FruitName")
        or model:GetAttribute("ItemName")
        or model:GetAttribute("SeedName")
        or model.Name
end

local function _getWeight(model)
    if not model then return 0 end

    local plantId = tostring(model:GetAttribute("PlantId") or "")
    local fruitId = tostring(model:GetAttribute("FruitId") or "")
    if plantId == "" then return 0 end

    local cacheKey = plantId .. "|" .. fruitId
    local now = os.clock()
    local cached = weightCache[cacheKey]
    if cached and (now - cached.at) <= WEIGHT_CACHE_SEC then
        return cached.w
    end

    local w = 0
    if type(FruitSellValue) == "table" and type(FruitSellValue.resolveWeight) == "function" then
        local ok, val = pcall(FruitSellValue.resolveWeight, model)
        if ok and type(val) == "number" then
            w = val
        end
    end

    weightCache[cacheKey] = { w = w, at = now }
    return w
end

local function _parseMutationList(inst)
    local raw = inst and inst:GetAttribute("Mutation")
    if type(raw) ~= "string" or raw == "" then return {} end
    local out = {}
    for token in string.gmatch(raw, "[^%+%,]+") do
        token = tostring(token):match("^%s*(.-)%s*$")
        if token and token ~= "" then out[#out + 1] = token end
    end
    return out
end

local NO_MUTATION_LABEL = "No Mutation"

local function _isNoMutationKey(name)
    local c = _canon(name)
    return c == "nomutation" or c == "none" or tostring(name or "") == NO_MUTATION_LABEL
end

local _mutNameList = nil

local function _getMutationNames()
    if _mutNameList then return _mutNameList end
    _mutNameList = {}
    local PLV = G.PlantListView or _G.PlantListView
    if type(PLV) == "table" and type(PLV.listMutationNames) == "function" then
        local ok, list = pcall(PLV.listMutationNames, PLV)
        if ok and type(list) == "table" then
            for _, n in ipairs(list) do
                if not _isNoMutationKey(n) then
                    _mutNameList[#_mutNameList + 1] = n
                end
            end
        end
    end
    if #_mutNameList == 0 then
        _mutNameList = { "Gold", "Rainbow" }
    end
    return _mutNameList
end

local function _fruitHasMutation(inst)
    if not inst then return false end
    for _, mutName in ipairs(_parseMutationList(inst)) do
        local lower = mutName:lower()
        if lower ~= "none" and lower ~= "normal" and not _isNoMutationKey(mutName) then
            return true
        end
    end
    for _, name in ipairs(_getMutationNames()) do
        if inst:GetAttribute(name) == true then
            return true
        end
    end
    return false
end

local function matchSet(selectedMap, value)
    if not _hasAny(selectedMap) then return true end
    local needle = _canon(value)
    for k, v in pairs(selectedMap) do
        if v == true and _canon(k) == needle then return true end
    end
    return false
end

local function matchMutation(selectedMap, inst)
    if not _hasAny(selectedMap) then return true end
    if not inst then return false end

    if selectedMap[NO_MUTATION_LABEL] == true and not _fruitHasMutation(inst) then
        return true
    end

    for mutName, on in pairs(selectedMap) do
        if on == true and not _isNoMutationKey(mutName) and inst:GetAttribute(mutName) == true then
            return true
        end
    end
    for _, mutName in ipairs(_parseMutationList(inst)) do
        if not _isNoMutationKey(mutName) and matchSet(selectedMap, mutName) then
            return true
        end
    end
    return false
end

local function matchKg(weight, kg, mode)
    kg, mode = _normalizeKgFilter(kg, mode)
    weight = tonumber(weight) or 0
    if kg <= 0 then
        return true
    end
    if mode == "below" then
        return weight > 0 and weight <= kg
    end
    return weight >= kg
end

local function _matchesAllFilters(fruit, ac)
    if ac.anyFruit and not matchSet(ac.fruits, _getName(fruit)) then return false end
    if ac.anyMut and not matchMutation(ac.mutations, fruit) then return false end
    if ac.anyKg and not matchKg(_getWeight(fruit), ac.kg, ac.kgMode) then return false end
    return true
end

local function _allowed(fruit, ac)
    if not fruit or not fruit.Parent then return false end
    if not ac.anyFruit and not ac.anyMut and not ac.anyKg then return true end
    return _matchesAllFilters(fruit, ac)
end

local function _promptCollectable(prompt, ac, applyFilter)
    if not prompt or not prompt.Parent or not prompt:IsA("ProximityPrompt") then return false end
    if prompt:GetAttribute("Collected") then return false end
    local fruit = _fruitFromPrompt(prompt)
    if not fruit or not fruit.Parent then return false end
    local plantId = tostring(fruit:GetAttribute("PlantId") or "")
    if plantId == "" then return false end
    if applyFilter and ac and not _allowed(fruit, ac) then return false end
    return true
end

local function _makeKey(plantId, fruitId)
    return tostring(plantId) .. "|" .. tostring(fruitId or "")
end

----------------------------------------------------------------
-- scan plot (plot-only descendants, refill sekali per batch)
----------------------------------------------------------------
local function _iterPlotHarvestPrompts(plot)
    local out = {}
    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("ProximityPrompt") and CollectionService:HasTag(desc, HARVEST_TAG) then
            out[#out + 1] = desc
        end
    end
    return out
end

local function _scanPlotTargets(ac, applyFilter)
    local plot = getPlayerPlot()
    if not plot then return 0, nil end

    local n = 0
    local seen = {}
    local list = applyFilter and {} or nil
    local needScore = applyFilter and ac.priority ~= "off"

    for _, prompt in ipairs(_iterPlotHarvestPrompts(plot)) do
        if not _promptCollectable(prompt, ac, applyFilter) then continue end

        local fruit = _fruitFromPrompt(prompt)
        local plantId = tostring(fruit:GetAttribute("PlantId") or "")
        local fruitId = tostring(fruit:GetAttribute("FruitId") or "")
        local key = _makeKey(plantId, fruitId)
        if seen[key] then continue end
        seen[key] = true
        n += 1

        if list then
            local score = 0
            if needScore and type(FruitSellValue) == "table" then
                score = FruitSellValue.priorityScore(fruit, ac.priority, fruit)
            end
            list[#list + 1] = {
                plantId = plantId,
                fruitId = fruitId,
                key = key,
                score = score,
            }
        end
    end

    if list and ac.priority ~= "off" and #list > 1 then
        table.sort(list, function(a, b)
            return (a.score or 0) > (b.score or 0)
        end)
    end

    return n, list
end

local function countReadyTargets()
    local now = os.clock()
    if now - _readyCacheAt <= COUNT_CACHE_SEC then
        return _readyCache
    end
    _readyCache = _scanPlotTargets(nil, false)
    _readyCacheAt = now
    return _readyCache
end

local function countFilteredTargets()
    local now = os.clock()
    if now - _filteredCacheAt <= COUNT_CACHE_SEC then
        return _filteredCache
    end
    _filteredCache = _scanPlotTargets(getACStateCached(), true)
    _filteredCacheAt = now
    return _filteredCache
end

----------------------------------------------------------------
-- batch cache + collect
----------------------------------------------------------------
local function _fireCollect(plantId, fruitId)
    plantId = tostring(plantId or "")
    fruitId = tostring(fruitId or "")
    if plantId == "" then return false end
    return pcall(CollectFruit.Fire, CollectFruit, plantId, fruitId)
end

local function _refillBatch(ac)
    batchIdx = 1
    table.clear(batchList)

    local _, list = _scanPlotTargets(ac, true)
    if not list then return 0 end

    for i = 1, #list do
        batchList[i] = list[i]
    end

    batchIdx = 1
    return #batchList
end

local function _batchEmpty()
    return batchIdx > #batchList
end

local function _fireNextFromBatch()
    if _batchEmpty() then return 0 end

    local item = batchList[batchIdx]
    batchIdx += 1

    if not item then return 0 end

    if _fireCollect(item.plantId, item.fruitId) then
        _totalCollected += 1
        _lastTickCollected = 1
        return 1
    end

    _lastTickCollected = 0
    return 0
end

local function collectLoop(myId)
    loopAliveId = myId
    _log("loop start", myId)

    local lastFilterKey = ""

    while running and myId == loopId do
        local ac = getACStateCached()
        local filterKey = _batchFilterKey(ac)
        if filterKey ~= lastFilterKey then
            if lastFilterKey ~= "" then
                _clearBatchCaches()
                table.clear(weightCache)
            end
            lastFilterKey = filterKey
        end

        if not ac.enabled then
            task.wait()
        elseif _batchEmpty() then
            local n = _refillBatch(ac)
            if n == 0 then
                task.wait()
            end
        else
            _fireNextFromBatch()
            _waitAfterFire(ac)
        end
    end

    if loopAliveId == myId then loopAliveId = 0 end
    _log("loop end", myId)
end

----------------------------------------------------------------
-- public API
----------------------------------------------------------------
local function _coerceOn(a, b)
    if type(a) == "table" then return b == true end
    return a == true
end

function M.SetEnabled(a, b)
    local on = _coerceOn(a, b)
    G.AUTO_COLLECT_FRUIT_ENABLED = on
    _G.AUTO_COLLECT_FRUIT_ENABLED = on
    _writeMainCollect({ enabled = on })
    _invalidateACCache()

    if on then
        running = true
        if loopAliveId > 0 and loopAliveId == loopId then return end
        loopId += 1
        local myId = loopId
        task.spawn(function()
            local ok, err = pcall(collectLoop, myId)
            if not ok then
                _warn("loop error:", err)
                if loopAliveId == myId then loopAliveId = 0 end
            end
        end)
    else
        running = false
    end
end

M.setEnabled = M.SetEnabled
M.Start = function() return M.SetEnabled(true) end
M.start = M.Start
M.Stop = function() return M.SetEnabled(false) end
M.stop = M.Stop
M.IsRunning = function() return running == true end
M.isRunning = M.IsRunning

local function _applySet(keyGlobal, keyMain, map)
    map = _normalizeSet(map)
    G[keyGlobal] = map
    _G[keyGlobal] = map
    _writeMainCollect({ [keyMain] = _setToArray(map) })
    _invalidateACCache()
    return map
end

function M.SetFruits(a, b)
    local map = (type(a) == "table" and b ~= nil) and b or a
    return _applySet("AUTO_COLLECT_FRUITS_SELECTED", "fruits", map)
end

M.SetSelected = M.SetFruits
M.setSelected = M.SetFruits
M.setFruits   = M.SetFruits

function M.SetMutations(a, b)
    local map = (type(a) == "table" and b ~= nil) and b or a
    return _applySet("AUTO_COLLECT_MUTATIONS_SELECTED", "mutations", map)
end

M.setMutations = M.SetMutations

function M.SetKgFilter(a, b, c)
    local kg, mode
    if type(a) == "table" then
        kg, mode = b, c
    else
        kg, mode = a, b
    end
    kg, mode = _normalizeKgFilter(kg, mode)
    local rule = _formatKgRule(kg, mode)
    local curRule = G.AUTO_COLLECT_KG_RULE or rawget(_G, "AUTO_COLLECT_KG_RULE")
    if tonumber(G.AUTO_COLLECT_KG or rawget(_G, "AUTO_COLLECT_KG")) == kg
        and tostring(G.AUTO_COLLECT_KG_MODE or rawget(_G, "AUTO_COLLECT_KG_MODE") or "") == mode
        and tostring(curRule or "") == rule then
        return
    end
    G.AUTO_COLLECT_KG = kg
    G.AUTO_COLLECT_KG_MODE = mode
    G.AUTO_COLLECT_KG_RULE = rule
    _G.AUTO_COLLECT_KG = kg
    _G.AUTO_COLLECT_KG_MODE = mode
    _G.AUTO_COLLECT_KG_RULE = rule
    _writeMainCollect({ kg = kg, kgMode = mode, kgRule = rule })
    _invalidateACCache()
end

M.setKgFilter = M.SetKgFilter

function M.SetDelay(a, b)
    local n = _normalizeDelay(type(a) == "table" and b or a, 0.1)
    G.AUTO_COLLECT_DELAY = n
    _G.AUTO_COLLECT_DELAY = n
    _writeMainCollect({ delay = n })
    _invalidateACCache()
end

M.setDelay = M.SetDelay

function M.SetPriority(mode)
    mode = tostring(mode or "off"):lower()
    if mode ~= "price" and mode ~= "rarity" and mode ~= "weight" then
        mode = "off"
    end
    G.AUTO_COLLECT_PRIORITY = mode
    _G.AUTO_COLLECT_PRIORITY = mode
    _writeMainCollect({ priority = mode })
    _invalidateACCache()
    return mode
end

M.setPriority = M.SetPriority

function M.EstimateFruitValue(model)
    if type(FruitSellValue) == "table" and type(FruitSellValue.fromFruit) == "function" then
        return FruitSellValue.fromFruit(model)
    end
    return 0
end

M.estimateFruitValue = M.EstimateFruitValue

function M.SyncFromState()
    local ac = getACState()
    M.SetFruits(ac.fruits)
    M.SetMutations(ac.mutations)
    M.SetKgFilter(ac.kg, ac.kgMode)
    M.SetDelay(ac.delay)
    M.SetPriority(ac.priority)
    M.SetEnabled(ac.enabled)
end

M.syncFromState = M.SyncFromState

function M.SetDebug(on)
    on = (on == true)
    G.AUTO_COLLECT_DEBUG = on
    _G.AUTO_COLLECT_DEBUG = on
    if on then
        _warn("Debug ON — disable for less lag")
    end
    return on
end

M.setDebug = M.SetDebug

function M.GetStats()
    local pending = 0
    if batchIdx <= #batchList then
        pending = #batchList - batchIdx + 1
    end
    return {
        running = running,
        loopId = loopId,
        readyQueue = countReadyTargets(),
        filteredQueue = countFilteredTargets(),
        batchPending = pending,
        lastTickCollected = _lastTickCollected,
        totalCollected = _totalCollected,
        delay = _fireDelaySec(getACStateCached()),
        priority = getACStateCached().priority,
    }
end

function M.DumpState()
    local st = M.GetStats()
    local ac = getACStateCached()
    _warn("========== AUTO COLLECT DUMP ==========")
    _warn("running:", st.running, "| delay:", st.delay)
    _warn("ready:", st.readyQueue, "| filtered:", st.filteredQueue, "| batch:", st.batchPending)
    _warn("last fire:", st.lastTickCollected, "| total fired:", st.totalCollected)
    _warn("filters: fruit=", ac.anyFruit, "mut=", ac.anyMut, "kg=", ac.anyKg,
        "rule=", G.AUTO_COLLECT_KG_RULE or rawget(_G, "AUTO_COLLECT_KG_RULE") or _formatKgRule(ac.kg, ac.kgMode),
        "mode=", ac.kgMode, "kg=", ac.kg)
    _warn("priority:", ac.priority)
    _warn("=======================================")
    return st
end

M.dumpState = M.DumpState

function M.CountReady()
    local ok, n = pcall(countReadyTargets)
    return (ok and type(n) == "number") and n or 0
end

M.countReady = M.CountReady

function M.CountFiltered()
    local ok, n = pcall(countFilteredTargets)
    return (ok and type(n) == "number") and n or 0
end

M.countFiltered = M.CountFiltered

function M.CollectOnce()
    local ac = getACStateCached()
    if _batchEmpty() then
        _refillBatch(ac)
    end
    return _fireNextFromBatch()
end

M.collectOnce = M.CollectOnce

----------------------------------------------------------------
G.AutoCollectFruit   = M
G.CollectFruitModule = M
_G.AutoCollectFruit   = M
_G.CollectFruitModule = M
G.AUTO_COLLECT_BURST = nil
_G.AUTO_COLLECT_BURST = nil

pcall(function() M.SyncFromState() end)

return M
 end,           required = false },
    { key = "AutoSell",        name = "Auto Sell",        factory = function() -- AutoSell.lua — Grow A Garden 2
-- Sell all: Networking.NPCS.PreviewSellAll / SellAll

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local Networking = require(ReplicatedStorage.SharedModules.Networking)

local LOOP_MIN_SEC   = 0.5
local SELL_BUSY_SEC  = 1.5

local running       = false
local loopId        = 0
local busySelling   = false
local lastSellAt    = 0
local attrConn      = nil

----------------------------------------------------------------
local function _dbg()
    return G.AUTO_SELL_DEBUG == true or _G.AUTO_SELL_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-AS]", ...)
end

local function _warn(...)
    warn("[GAG2-AS]", ...)
end

local function _writeMainSell(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.sell = MAIN.auto.sell or {}
    for k, v in pairs(patch) do
        MAIN.auto.sell[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _readSellWhenFull(st)
    -- MAIN.auto.sell = source of truth (UI save)
    if type(st) == "table" then
        if st.sellWhenFull == true then return true end
        if st.sellWhenFull == false then return false end
    end
    if G.AUTO_SELL_WHEN_FULL == true or rawget(_G, "AUTO_SELL_WHEN_FULL") == true then
        return true
    end
    if G.AUTO_SELL_WHEN_FULL == false or rawget(_G, "AUTO_SELL_WHEN_FULL") == false then
        return false
    end
    return true
end

local function getSellState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.sell
    st = type(st) == "table" and st or {}

    local enabled = (G.AUTO_SELL_ENABLED == true)
        or (rawget(_G, "AUTO_SELL_ENABLED") == true)
        or (st.enabled == true)

    local minCount = tonumber(st.minCount)
    if minCount == nil then
        minCount = tonumber(G.AUTO_SELL_MIN_COUNT or rawget(_G, "AUTO_SELL_MIN_COUNT")) or 100
    end
    if minCount < 1 then minCount = 1 end

    local delay = tonumber(st.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_SELL_DELAY or rawget(_G, "AUTO_SELL_DELAY")) or 2
    end
    if delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end

    return {
        enabled      = enabled,
        minCount     = minCount,
        delay        = delay,
        sellWhenFull = _readSellWhenFull(st),
    }
end

----------------------------------------------------------------
local function getPlayerFruitStats()
    local count = tonumber(LP:GetAttribute("FruitCount"))
    local maxCap = tonumber(LP:GetAttribute("MaxFruitCapacity"))
    return count, maxCap
end

local function _isFruitTool(tool)
    if not tool or not tool:IsA("Tool") then return false end
    if tool:GetAttribute("PottedPlant") == true then return false end
    if tool:GetAttribute("Pet") then return false end
    if tool:GetAttribute("FruitName") then return true end
    if tool:GetAttribute("Id") and tool:GetAttribute("SizeMultiplier") then return true end
    return false
end

local function countFruitTools()
    local n = 0
    local function scan(container)
        if not container then return end
        for _, inst in ipairs(container:GetChildren()) do
            if _isFruitTool(inst) then n += 1 end
        end
    end
    scan(LP:FindFirstChild("Backpack"))
    scan(LP.Character)
    return n
end

local function _npcFire(name)
    local npcs = Networking and Networking.NPCS
    local pkt = npcs and npcs[name]
    if not pkt then
        return false, "missing_packet_" .. tostring(name)
    end
    if type(pkt.Fire) ~= "function" then
        return false, "no_fire_" .. tostring(name)
    end
    return pcall(function()
        return pkt:Fire()
    end)
end

local function previewSellAll()
    local ok, res = _npcFire("PreviewSellAll")
    if ok and type(res) == "table" then return res end
    return nil
end

local function getFruitCount()
    local count = select(1, getPlayerFruitStats())
    if type(count) == "number" then return count end

    local preview = previewSellAll()
    if preview and type(preview.FruitCount) == "number" then
        return preview.FruitCount
    end
    return countFruitTools()
end

local function getMaxFruitCapacity()
    local maxCap = select(2, getPlayerFruitStats())
    if type(maxCap) == "number" and maxCap > 0 then return maxCap end
    return nil
end

local function getSellThreshold(st)
    st = st or getSellState()
    if st.sellWhenFull == true then
        local maxCap = getMaxFruitCapacity()
        if maxCap then return maxCap end
    end
    return st.minCount
end

local function _sellSucceeded(res)
    if type(res) ~= "table" then return false end
    if res.Success == true or res.success == true then return true end
    if (tonumber(res.SoldCount) or 0) > 0 then return true end
    return false
end

local function sellAllNow()
    if busySelling then return false, "busy" end
    if os.clock() - lastSellAt < SELL_BUSY_SEC then return false, "cooldown" end

    busySelling = true

    local fruitCount = getFruitCount()
    if fruitCount <= 0 then
        local preview = previewSellAll()
        fruitCount = preview and tonumber(preview.FruitCount) or 0
    end

    if fruitCount <= 0 then
        busySelling = false
        return false, "empty"
    end

    local ok, res = _npcFire("SellAll")
    lastSellAt = os.clock()
    busySelling = false

    if ok and _sellSucceeded(res) then
        _log("sold", res.SoldCount, res.SellPrice)
        return true, res
    end

    _warn("SellAll gagal:", ok, res)
    return false, res
end

local function tryAutoSell()
    local st = getSellState()
    if not st.enabled or busySelling then return end

    local count = getFruitCount()
    local threshold = getSellThreshold(st)
    _log("check", count, ">=", threshold, "full=", st.sellWhenFull)
    if count >= threshold then
        sellAllNow()
    end
end

local function _bindFruitCountWatcher()
    if attrConn then return end
    attrConn = LP:GetAttributeChangedSignal("FruitCount"):Connect(function()
        tryAutoSell()
    end)
end

local function _unbindFruitCountWatcher()
    if attrConn then
        attrConn:Disconnect()
        attrConn = nil
    end
end

local function mainLoop(myId)
    _log("loop start", myId)
    _bindFruitCountWatcher()

    while running and loopId == myId do
        tryAutoSell()
        task.wait(getSellState().delay)
    end

    _unbindFruitCountWatcher()
    _log("loop end", myId)
end

----------------------------------------------------------------
-- public API
----------------------------------------------------------------
local function _coerceOn(a, b)
    if type(a) == "table" then return b == true end
    return a == true
end

function M.SetEnabled(a, b)
    local on = _coerceOn(a, b)

    G.AUTO_SELL_ENABLED = on
    _G.AUTO_SELL_ENABLED = on
    _writeMainSell({ enabled = on })

    if on then
        if not running then
            running = true
            loopId += 1
            local myId = loopId
            task.spawn(function() mainLoop(myId) end)
        end
        task.defer(tryAutoSell)
    else
        running = false
        _unbindFruitCountWatcher()
    end
end

M.setEnabled = M.SetEnabled

function M.Start()
    return M.SetEnabled(true)
end

M.start = M.Start

function M.Stop()
    return M.SetEnabled(false)
end

M.stop = M.Stop

function M.IsRunning()
    return running == true
end

M.isRunning = M.IsRunning

function M.SetMinCount(n)
    n = tonumber(n)
    if n == nil then return end
    if n < 1 then n = 1 end
    G.AUTO_SELL_MIN_COUNT = n
    _G.AUTO_SELL_MIN_COUNT = n
    _writeMainSell({ minCount = n })
    task.defer(tryAutoSell)
end

M.setMinCount = M.SetMinCount

function M.SetDelay(n)
    n = tonumber(n)
    if n == nil then return end
    if n < LOOP_MIN_SEC then n = LOOP_MIN_SEC end
    G.AUTO_SELL_DELAY = n
    _G.AUTO_SELL_DELAY = n
    _writeMainSell({ delay = n })
end

M.setDelay = M.SetDelay

function M.SetSellWhenFull(on)
    on = (on == true)
    G.AUTO_SELL_WHEN_FULL = on
    _G.AUTO_SELL_WHEN_FULL = on
    _writeMainSell({ sellWhenFull = on })
    task.defer(tryAutoSell)
end

M.setSellWhenFull = M.SetSellWhenFull

function M.GetFruitCount()
    return getFruitCount()
end

M.getFruitCount = M.GetFruitCount

function M.GetMaxFruitCapacity()
    return getMaxFruitCapacity()
end

M.getMaxFruitCapacity = M.GetMaxFruitCapacity

function M.GetFruitStats()
    return getFruitCount(), getMaxFruitCapacity()
end

M.getFruitStats = M.GetFruitStats

function M.SellNow()
    return sellAllNow()
end

M.sellNow = M.SellNow

function M.CheckNow()
    tryAutoSell()
end

M.checkNow = M.CheckNow

function M.SyncFromState()
    local st = getSellState()
    M.SetEnabled(st.enabled)
end

M.syncFromState = M.SyncFromState

function M.GetStats()
    local count = getFruitCount()
    local maxCap = getMaxFruitCapacity()
    local st = getSellState()
    return {
        running = running,
        fruitCount = count,
        maxCapacity = maxCap,
        minCount = st.minCount,
        sellWhenFull = st.sellWhenFull,
        threshold = getSellThreshold(st),
        busy = busySelling,
    }
end

----------------------------------------------------------------
G.AutoSellFruit = M
_G.AutoSellFruit = M

-- SyncFromState dipanggil dari MainUI setelah UI builder siap
return M
 end,              required = false },
    { key = "AutoPlant",       name = "Auto Plant",       factory = function() -- AutoPlant.lua — Grow A Garden 2
-- Plant: Networking.Plant.PlantSeed:Fire(position, seedToolId, tool)

local Players            = game:GetService("Players")
local ReplicatedStorage  = game:GetService("ReplicatedStorage")
local CollectionService  = game:GetService("CollectionService")
local UserInputService   = game:GetService("UserInputService")
local GuiService         = game:GetService("GuiService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local Networking = require(ReplicatedStorage.SharedModules.Networking)
local PlantSeed  = Networking.Plant.PlantSeed

local Gardens = workspace:WaitForChild("Gardens")

local LOOP_MIN_SEC     = 0.5
local PLANT_MIN_GAP    = 0.05
local MIN_PLANT_DIST   = 0.45
local RANDOM_MIN_PLANT_DIST = 0.35
local RANDOM_MAX_TRY   = 48
local RANDOM_PART_MARGIN = 0.92
local MANUAL_SLOT_SPACING = MIN_PLANT_DIST * 1.05
local MANUAL_GRID_MAX  = 300
local MANUAL_MAX_TRY_PER_TICK = 48
local PLOT_CACHE_SEC   = 2

local running          = false
local loopId           = 0
local lastPlantAt      = 0
local manualPosIndex   = 1
local manualGridSlot   = 1
local saveInputConn    = nil
local saveEnableAt     = 0
local saveModeActive   = false
local lastClickAt      = 0
local cachedPlot       = nil
local cachedPlotAt     = 0
local randomWarnAt     = 0
local skippedSeedUntil = {}
local seedToolRotate   = 0
local sessionStartTotal = 0
local sessionPlanted    = 0
local sessionUserLimit  = 0

----------------------------------------------------------------
local function _dbg()
    return G.AUTO_PLANT_DEBUG == true or _G.AUTO_PLANT_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-AP]", ...)
end

local function _notifyPositionsChanged()
    if type(G.__GAG2_ON_PLANT_POSITIONS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLANT_POSITIONS_CHANGED)
    end
end

local function _notifySeedStatsChanged()
    if type(G.__GAG2_ON_PLANT_SEED_STATS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLANT_SEED_STATS_CHANGED)
    end
end

local function _writeMainPlant(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}
    for k, v in pairs(patch) do
        MAIN.auto.plant[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _safeStr(v)
    if v == nil then return "" end
    return tostring(v)
end

local function _canon(s)
    return _safeStr(s):lower():gsub("[^%w]+", "")
end

local function _strMatch(a, b)
    a = _canon(a)
    b = _canon(b)
    if a == "" or b == "" then return false end
    if a == b then return true end
    return string.find(a, b, 1, true) ~= nil or string.find(b, a, 1, true) ~= nil
end

local function _normSeedKey(v)
    v = _canon(v)
    if v:sub(-4) == "seed" then
        v = v:sub(1, -5)
    end
    return v
end

local function _getPlantListView()
    return G.PlantListView or rawget(_G, "PlantListView")
end

local function _isMutationSeedTool(tool)
    if not tool then return false end
    if tool:GetAttribute("MutationSeed") == true then return true end

    local seedName = tool:GetAttribute("SeedName") or tool.Name
    local plv = _getPlantListView()
    if plv and type(plv.findBySeedName) == "function" then
        local ok, entry = pcall(plv.findBySeedName, plv, seedName)
        if ok and type(entry) == "table" and entry.MutationSeed == true then
            return true
        end
    end

    local muts = {}
    if plv and type(plv.listMutationNames) == "function" then
        local ok, list = pcall(plv.listMutationNames, plv)
        if ok and type(list) == "table" then
            for _, n in ipairs(list) do
                muts[_normSeedKey(n)] = true
            end
        end
    end

    local key = _normSeedKey(seedName)
    return muts[key] == true
end

local function _isAvatarBlockedError(err)
    err = tostring(err or ""):lower()
    return err:find("avatar", 1, true) ~= nil
        or err:find("equip the", 1, true) ~= nil
end

local function _seedToolId(tool)
    return tostring(tool and tool:GetAttribute("SeedTool") or tool and tool.Name or "")
end

local function _isSeedToolSkipped(tool)
    local id = _seedToolId(tool)
    if id == "" then return false end
    local untilAt = skippedSeedUntil[id]
    if not untilAt then return false end
    if os.clock() >= untilAt then
        skippedSeedUntil[id] = nil
        return false
    end
    return true
end

local function _markSeedToolSkipped(tool, seconds)
    local id = _seedToolId(tool)
    if id == "" then return end
    skippedSeedUntil[id] = os.clock() + (tonumber(seconds) or 90)
end

local function _iterInventoryContainers()
    local out = {}
    local seen = {}

    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end

    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP:FindFirstChild("TasRansel"))
    add(LP.Character)

    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end

    return out
end

local function _normalizePositionId(v)
    if v == nil then return nil end
    if type(v) == "table" then
        v = v.id or v.key
    end
    v = tostring(v)
    if v == "" or v:sub(1, 6) == "table:" then return nil end
    return v
end

local function getPlantState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local ap = MAIN and MAIN.auto and MAIN.auto.plant
    ap = type(ap) == "table" and ap or {}

    local seeds = G.AUTO_PLANT_SEEDS_SELECTED
        or rawget(_G, "AUTO_PLANT_SEEDS_SELECTED")
        or _normalizeSet(ap.seeds)

    local delay = tonumber(ap.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_PLANT_DELAY or rawget(_G, "AUTO_PLANT_DELAY")) or 0.5
    end
    if delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end

    local mode = tostring(ap.mode or G.AUTO_PLANT_MODE or "random"):lower()
    if mode ~= "manual" then mode = "random" end

    local positions = type(ap.positions) == "table" and ap.positions or {}

    local selectedPosition = _normalizePositionId(ap.selectedPosition)
    if selectedPosition == nil then
        selectedPosition = _normalizePositionId(G.AUTO_PLANT_SELECTED_POSITION)
    end

    local enabled = (G.AUTO_PLANT_ENABLED == true)
        or (rawget(_G, "AUTO_PLANT_ENABLED") == true)
        or (ap.enabled == true)

    local savePosition = (G.AUTO_PLANT_SAVE_POSITION == true)
        or (rawget(_G, "AUTO_PLANT_SAVE_POSITION") == true)
        or (ap.savePosition == true)

    local autoManual = (G.AUTO_PLANT_AUTO_MANUAL == true)
        or (rawget(_G, "AUTO_PLANT_AUTO_MANUAL") == true)
        or (ap.autoManual == true)

    local plantTotal = tonumber(ap.plantTotal)
    if plantTotal == nil then
        plantTotal = tonumber(G.AUTO_PLANT_TOTAL or rawget(_G, "AUTO_PLANT_TOTAL")) or 0
    end
    if plantTotal < 0 then plantTotal = 0 end
    plantTotal = math.floor(plantTotal)

    return {
        enabled          = enabled,
        seeds            = _normalizeSet(seeds),
        delay            = delay,
        mode             = mode,
        positions        = positions,
        selectedPosition = selectedPosition,
        savePosition     = savePosition,
        autoManual       = autoManual,
        plantTotal       = plantTotal,
    }
end

----------------------------------------------------------------
----------------------------------------------------------------
local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("OwnerUserId")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    if not Gardens or not Gardens.Parent then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local plot = Gardens:FindFirstChild("Plot" .. tostring(plotId))
        if plot then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    for _, plot in ipairs(Gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    local byName = Gardens:FindFirstChild("Plot" .. LP.Name)
    cachedPlot = byName
    cachedPlotAt = now
    return byName
end

local function isOwnPlot(plot)
    if not plot then return false end
    local myPlot = getPlayerPlot()
    return myPlot ~= nil and plot == myPlot
end

local function collectPlotSurfaces(plot)
    local list = {}
    local seen = {}

    local function add(inst)
        if inst and not seen[inst] then
            seen[inst] = true
            list[#list + 1] = inst
        end
    end

    for _, inst in ipairs(CollectionService:GetTagged("PlantArea")) do
        if inst:IsDescendantOf(plot) then
            add(inst)
        end
    end
    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.Name == "Can_Plant" then
            add(desc)
        end
    end
    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") then
            local n = desc.Name:lower()
            if n:find("soil") or n:find("dirt") or n:find("ground")
                or n:find("farm") or n:find("plot") or n:find("grass") then
                add(desc)
            end
        end
    end
    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.CanQuery ~= false then
            add(desc)
        end
    end
    return list
end

local function createPlantAreaParams(plot)
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    local list = collectPlotSurfaces(plot)
    params.FilterDescendantsInstances = list
    return params, list
end

local function _getPlantGroundXZ(plant)
    if not plant then return nil end

    if plant:IsA("BasePart") then
        local p = plant.Position
        return p.X, p.Z
    end

    local pos = nil
    if plant:IsA("Model") then
        local ok, pivot = pcall(function()
            return plant:GetPivot().Position
        end)
        if ok and typeof(pivot) == "Vector3" then
            pos = pivot
        elseif plant.PrimaryPart then
            pos = plant.PrimaryPart.Position
        end
    end

    if not pos then
        local part = plant:FindFirstChildWhichIsA("BasePart", true)
        if part then pos = part.Position end
    end

    if pos then
        return pos.X, pos.Z
    end
    return nil
end

local function _countPlantsOnPlot(plot)
    plot = plot or getPlayerPlot()
    if not plot then return 0 end
    local plants = plot:FindFirstChild("Plants")
    if not plants then return 0 end
    return #plants:GetChildren()
end

local function isBlockedPlantSpot(pos, minDist, plot)
    minDist = tonumber(minDist) or MIN_PLANT_DIST
    if not pos then return true end

    plot = plot or getPlayerPlot()
    if not plot then return false end

    local plants = plot:FindFirstChild("Plants")
    if not plants then return false end

    local minDist2 = minDist * minDist
    local px, pz = pos.X, pos.Z

    for _, plant in ipairs(plants:GetChildren()) do
        local gx, gz = _getPlantGroundXZ(plant)
        if gx and gz then
            local dx = gx - px
            local dz = gz - pz
            if (dx * dx + dz * dz) < minDist2 then
                return true
            end
        end
    end

    return false
end

local function raycastPlantArea(origin, direction, plot)
    local params, list = createPlantAreaParams(plot)
    if #list == 0 then return nil end

    local filter = params.FilterDescendantsInstances
    for _ = 1, 5 do
        local hit = workspace:Raycast(origin, direction, params)
        if not hit then return nil end
        if hit.Instance.Transparency < 1 then
            return hit
        end
        local idx = table.find(filter, hit.Instance)
        if not idx then return hit end
        table.remove(filter, idx)
        params.FilterDescendantsInstances = filter
        if #filter == 0 then return nil end
    end
    return nil
end

local function vecFromSaved(entry)
    if type(entry) ~= "table" then return nil end
    local x, y, z = tonumber(entry.x), tonumber(entry.y), tonumber(entry.z)
    if x and y and z then return Vector3.new(x, y, z) end
    return nil
end

local function _getStandingPlotPosition(plot)
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp or not plot then return nil end

    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then return nil end

    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = surfaces

    local hit = workspace:Raycast(hrp.Position + Vector3.new(0, 10, 0), Vector3.new(0, -40, 0), params)
    if hit and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end

    for _, part in ipairs(surfaces) do
        if part:IsA("BasePart") then
            local lp = part.CFrame:PointToObjectSpace(hrp.Position)
            local halfX = part.Size.X * 0.55
            local halfZ = part.Size.Z * 0.55
            if math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ then
                return Vector3.new(
                    hrp.Position.X,
                    part.Position.Y + part.Size.Y * 0.5 + 0.05,
                    hrp.Position.Z
                )
            end
        end
    end

    return nil
end

local function seedMatchesTool(tool, selectedSeeds)
    if not tool or not tool:IsA("Tool") then return false end
    local seedAttr = tool:GetAttribute("SeedTool")
    if seedAttr == nil then return false end

    if not next(selectedSeeds) then
        return not _isMutationSeedTool(tool)
    end

    local toolKeys = {
        [_normSeedKey(seedAttr)] = true,
        [_normSeedKey(tool.Name)] = true,
        [_normSeedKey(tool:GetAttribute("SeedName"))] = true,
    }

    for sel, on in pairs(selectedSeeds) do
        if on == true and toolKeys[_normSeedKey(sel)] then
            return true
        end
    end
    return false
end

local function findAllSeedTools(selectedSeeds)
    local found = {}
    local seen = {}

    local function scan(container)
        if not container then return end
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") and seedMatchesTool(inst, selectedSeeds) and not _isSeedToolSkipped(inst) then
                local id = _seedToolId(inst)
                if id ~= "" and not seen[id] then
                    seen[id] = true
                    found[#found + 1] = inst
                end
            end
        end
    end

    for _, container in ipairs(_iterInventoryContainers()) do
        scan(container)
    end
    return found
end

local function _countSeedTools(selectedSeeds)
    return #findAllSeedTools(selectedSeeds)
end

local function _countInventorySeeds(selectedSeeds)
    local cached = G.__GAG2_PLANT_SEED_LIST_CACHE or rawget(_G, "__GAG2_PLANT_SEED_LIST_CACHE")
    if type(cached) == "table" and #cached > 0 then
        local plv = _getPlantListView()
        if plv and type(plv.countOwnedSeeds) == "function" then
            local ok, n = pcall(plv.countOwnedSeeds, plv, selectedSeeds)
            if ok and type(n) == "number" and n > 0 then
                return math.max(0, math.floor(n))
            end
        end
        local sum = 0
        for _, it in ipairs(cached) do
            sum += math.max(0, math.floor(tonumber(it.count) or tonumber(it.right) or 0))
        end
        if sum > 0 then return sum end
    end
    local plv = _getPlantListView()
    if plv and type(plv.countOwnedSeeds) == "function" then
        local ok, n = pcall(plv.countOwnedSeeds, plv, selectedSeeds)
        if ok and type(n) == "number" and n > 0 then
            return math.max(0, math.floor(n))
        end
    end
    return _countSeedTools(selectedSeeds)
end

local function _resetSessionSeedStats(st)
    st = st or getPlantState()
    sessionStartTotal = _countInventorySeeds(st.seeds)
    sessionPlanted = 0
    sessionUserLimit = math.max(0, math.floor(tonumber(st.plantTotal) or 0))
    _notifySeedStatsChanged()
end

local function _canPlantMore()
    if sessionUserLimit > 0 then
        return sessionPlanted < sessionUserLimit
    end
    return true
end

local function _isPlantSessionDone(st)
    st = st or getPlantState()
    if sessionUserLimit > 0 and sessionPlanted >= sessionUserLimit then
        return true, "limit"
    end
    if _countInventorySeeds(st.seeds) == 0 and _countSeedTools(st.seeds) == 0 then
        return true, "empty"
    end
    return false, nil
end

local function _autoStopPlantSession(st, reason)
    st = st or getPlantState()
    if not st.enabled then return end

    M.SetEnabled(false)
    _writeMainPlant({ enabled = false })

    local api = G.__GAG2_PLANT_ENABLE_API or rawget(_G, "__GAG2_PLANT_ENABLE_API")
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    end

    if type(G.__GAG2_SYNC_AUTO_PLANT) == "function" then
        pcall(G.__GAG2_SYNC_AUTO_PLANT)
    end

    if type(G.__GAG2_ON_PLANT_AUTO_FINISHED) == "function" then
        pcall(G.__GAG2_ON_PLANT_AUTO_FINISHED)
    end

    _notifySeedStatsChanged()
end

local function findSeedTool(selectedSeeds)
    local tools = findAllSeedTools(selectedSeeds)
    if #tools == 0 then return nil end
    seedToolRotate = (seedToolRotate % #tools) + 1
    return tools[seedToolRotate]
end

local function equipTool(tool)
    if not tool then return false end
    local char = LP.Character
    local hum = char and char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end
    pcall(function() hum:EquipTool(tool) end)
    return tool.Parent == char
end

local function plantAtPosition(pos, tool)
    if not tool or not tool.Parent then return false, "no_tool" end
    if not _canPlantMore() then return false, "limit" end
    if os.clock() - lastPlantAt < PLANT_MIN_GAP then return false, "cooldown" end

    local seedId = tool:GetAttribute("SeedTool")
    if seedId == nil then return false, "no_seed_attr" end

    local ok, err = pcall(function()
        PlantSeed:Fire(pos, seedId, tool)
    end)
    if ok then
        lastPlantAt = os.clock()
        sessionPlanted += 1
        _notifySeedStatsChanged()
        _log("plant", seedId, pos)
        return true
    end
    return false, err
end

local function tryPlantAt(pos, st, opts)
    st = st or getPlantState()
    opts = type(opts) == "table" and opts or {}
    local plot = getPlayerPlot()
    if not plot then return false, "no_plot" end
    local minDist = tonumber(opts.minDist) or MIN_PLANT_DIST
    if isBlockedPlantSpot(pos, minDist, plot) then return false, "blocked" end

    local tools = findAllSeedTools(st.seeds)
    if #tools == 0 then return false, "no_seed_tool" end

    local lastErr = "plant_fail"
    for i = 1, #tools do
        local tool = tools[((seedToolRotate + i - 2) % #tools) + 1]
        equipTool(tool)
        local ok, err = plantAtPosition(pos, tool)
        if ok then
            seedToolRotate = ((seedToolRotate + i - 2) % #tools) + 1
            return true
        end
        lastErr = err or lastErr
        if _isAvatarBlockedError(err) then
            _markSeedToolSkipped(tool, 90)
            if os.clock() - randomWarnAt > 8 then
                randomWarnAt = os.clock()
                warn("[GAG2-AP] seed mutation butuh avatar khusus — pilih seed biasa (mis. Grape) atau equip avatar yang diminta")
            end
        else
            break
        end
    end
    return false, lastErr
end

local function _snapToPlantSurface(plot, pos)
    if not plot or not pos then return pos end
    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then return pos end

    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = surfaces

    local hit = workspace:Raycast(
        pos + Vector3.new(0, 25, 0),
        Vector3.new(0, -50, 0),
        params
    )
    if hit and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end
    return pos
end

local function randomPlantAreaPart(plot)
    local parts = {}
    for _, inst in ipairs(collectPlotSurfaces(plot)) do
        if inst:IsA("BasePart") then
            parts[#parts + 1] = inst
        end
    end
    if #parts == 0 then return nil end
    return parts[math.random(1, #parts)]
end

local function randomPointOnPart(part)
    local size = part.Size
    local cf = part.CFrame
    local margin = RANDOM_PART_MARGIN
    local rx = (math.random() - 0.5) * size.X * margin
    local rz = (math.random() - 0.5) * size.Z * margin
    return (cf * CFrame.new(rx, size.Y * 0.5, rz)).Position
end

local function tryRandomPlant(st)
    local plot = getPlayerPlot()
    if not plot then
        if os.clock() - randomWarnAt > 8 then
            randomWarnAt = os.clock()
            warn("[GAG2-AP] plot tidak ditemukan (PlotId?)")
        end
        return false
    end

    if next(st.seeds) and _countSeedTools(st.seeds) == 0 then
        return false
    end

    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then
        if os.clock() - randomWarnAt > 8 then
            randomWarnAt = os.clock()
            warn("[GAG2-AP] area tanam tidak ditemukan di plot")
        end
        return false
    end

    for _ = 1, RANDOM_MAX_TRY do
        local part = randomPlantAreaPart(plot)
        if part then
            local pos = randomPointOnPart(part)
            pos = _snapToPlantSurface(plot, pos)
            local ok = tryPlantAt(pos, st, { minDist = RANDOM_MIN_PLANT_DIST })
            if ok then return true end
        end
    end

    if os.clock() - randomWarnAt > 8 then
        randomWarnAt = os.clock()
        local nPlants = _countPlantsOnPlot(plot)
        warn(("[GAG2-AP] tidak ada spot kosong (%d tanaman di plot, jarak min %.2f)"):format(
            nPlants, RANDOM_MIN_PLANT_DIST))
    end
    return false
end

local function _resetManualGrid()
    manualGridSlot = 1
end

-- Spiral dengan jarak antar slot ~MANUAL_SLOT_SPACING (skip titik yang sudah ada tanaman)
local function _offsetForGridSlot(slot)
    if slot <= 1 then
        return Vector3.zero
    end
    local idx = slot - 2
    local golden = 2.399963229728653
    local r = MANUAL_SLOT_SPACING * math.sqrt(idx + 1)
    local angle = idx * golden
    return Vector3.new(math.cos(angle) * r, 0, math.sin(angle) * r)
end

local function _isManualGridExhausted()
    return manualGridSlot > MANUAL_GRID_MAX
end

local function _tryPlantGridAt(center, st)
    if not center then return false end

    local plot = getPlayerPlot()
    if not plot then return false end

    local tried = 0
    while manualGridSlot <= MANUAL_GRID_MAX and tried < MANUAL_MAX_TRY_PER_TICK do
        tried += 1
        local slot = manualGridSlot
        local pos = _snapToPlantSurface(plot, center + _offsetForGridSlot(slot))

        if isBlockedPlantSpot(pos, nil, plot) then
            manualGridSlot = slot + 1
        else
            local ok = tryPlantAt(pos, st)
            if ok then
                manualGridSlot = slot + 1
                return true
            end
            manualGridSlot = slot + 1
        end
    end

    return false
end

local function _resolveManualAnchor(st)
    local positions = st.positions
    if type(positions) ~= "table" or #positions == 0 then return nil end

    if st.autoManual then
        return vecFromSaved(positions[manualPosIndex])
    end

    if st.selectedPosition then
        for _, entry in ipairs(positions) do
            if tostring(entry.id) == tostring(st.selectedPosition) then
                return vecFromSaved(entry)
            end
        end
    end

    return vecFromSaved(positions[1])
end

local manualWarnAt = 0

local function tryManualPlant(st)
    st = st or getPlantState()
    local positions = st.positions
    if type(positions) ~= "table" or #positions == 0 then
        if os.clock() - manualWarnAt > 5 then
            manualWarnAt = os.clock()
            warn("[GAG2] Manual plant: simpan posisi dulu (berdiri di tile → Save Position ON)")
        end
        return false
    end

    if next(st.seeds) and _countSeedTools(st.seeds) == 0 then
        return false
    end

    local plot = getPlayerPlot()
    if not plot then return false end

    local anchor = _resolveManualAnchor(st)
    if not anchor then return false end

    if st.autoManual then
        if _isManualGridExhausted() then
            _resetManualGrid()
            manualPosIndex += 1
            if manualPosIndex > #positions then manualPosIndex = 1 end
            anchor = _resolveManualAnchor(st)
            if not anchor then return false end
        end
        return _tryPlantGridAt(anchor, st)
    end

    return _tryPlantGridAt(anchor, st)
end

local function plantTick(st)
    if not _canPlantMore() then return false end
    st = st or getPlantState()
    if st.mode == "manual" then
        return tryManualPlant(st)
    end
    return tryRandomPlant(st)
end

local function mainLoop(myId)
    _log("loop start", myId)
    while running and loopId == myId do
        local st = getPlantState()
        if st.enabled then
            local done, reason = _isPlantSessionDone(st)
            if done then
                _autoStopPlantSession(st, reason)
            else
                plantTick(st)
                local doneAfter, reasonAfter = _isPlantSessionDone(st)
                if doneAfter then
                    _autoStopPlantSession(st, reasonAfter)
                else
                    _notifySeedStatsChanged()
                end
            end
        end
        task.wait(st.delay)
    end
    _log("loop end", myId)
end

----------------------------------------------------------------
-- save position (klik di PlantArea plot sendiri)
----------------------------------------------------------------
local _bindSaveListener
local _disableSaveMode

local function _isMouseOverBlockingUI()
    local ui = G.__GROWAGARDEN2_UI
    if not ui then return false end

    local loc = UserInputService:GetMouseLocation()
    local inset = GuiService:GetGuiInset()
    local x, y = loc.X, loc.Y - inset.Y

    local function hitsRoot(root)
        if not root or not root.Parent then return false end
        for _, obj in ipairs(GuiService:GetGuiObjectsAtPosition(x, y)) do
            if obj == root or obj:IsDescendantOf(root) then
                return true
            end
        end
        return false
    end

    if hitsRoot(ui.mainFrame) then return true end

    local sg = ui._sg
    if sg then
        for _, desc in ipairs(sg:GetDescendants()) do
            if desc.Name == "NodeHubDropdownOverlay" or desc.Name == "NodeHubModeOverlay" then
                if hitsRoot(desc) then return true end
            end
        end
    end

    return false
end

local function _isTargetOnPlot(target, plot)
    if not target or not plot then return false end
    return target:IsDescendantOf(plot)
end

local function _resolveSaveHit(plot, preferStanding)
    if preferStanding then
        local stand = _getStandingPlotPosition(plot)
        if stand then return stand end
    end

    local cam = workspace.CurrentCamera
    if cam then
        local loc = UserInputService:GetMouseLocation()
        local ray = cam:ViewportPointToRay(loc.X, loc.Y)
        local hit = raycastPlantArea(ray.Origin, ray.Direction * 5000, plot)
        if hit and _isTargetOnPlot(hit.Instance, plot) then
            return hit.Position
        end
    end

    local mouse = LP:GetMouse()
    if mouse and mouse.Target and mouse.Hit and _isTargetOnPlot(mouse.Target, plot) then
        return mouse.Hit.Position
    end

    if not preferStanding then
        return _getStandingPlotPosition(plot)
    end

    return nil
end

local function _commitSavePosition(pos)
    if not pos then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}
    local positions = type(MAIN.auto.plant.positions) == "table" and MAIN.auto.plant.positions or {}

    local id = ("pos_%d"):format(math.floor(os.clock() * 1000))
    positions[#positions + 1] = {
        id = id,
        x = pos.X,
        y = pos.Y,
        z = pos.Z,
    }
    MAIN.auto.plant.positions = positions
    MAIN.auto.plant.selectedPosition = id
    G.MAIN = MAIN
    _G.MAIN = MAIN

    G.AUTO_PLANT_SELECTED_POSITION = id
    _G.AUTO_PLANT_SELECTED_POSITION = id

    _notifyPositionsChanged()
    _resetManualGrid()
    print(("[GAG2] Posisi tanam tersimpan (#%d)"):format(#positions))
    _log("saved pos", id, pos)

    _disableSaveMode()
    return true
end

_disableSaveMode = function()
    saveModeActive = false
    G.AUTO_PLANT_SAVE_POSITION = false
    _G.AUTO_PLANT_SAVE_POSITION = false
    _writeMainPlant({ savePosition = false })
    saveEnableAt = 0

    if type(G.__GAG2_ON_PLANT_SAVE_MODE_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLANT_SAVE_MODE_CHANGED, false)
    end

    local api = G.__GAG2_PLANT_SAVE_TOGGLE_API
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    end
end

local function trySavePositionFromMouse(force)
    if not saveModeActive and not getPlantState().savePosition then return false end
    if not force and os.clock() < saveEnableAt then return false end
    if not force and os.clock() - lastClickAt < 0.15 then return false end
    lastClickAt = os.clock()

    local plot = getPlayerPlot()
    if not plot then
        warn("[GAG2] Save gagal: plot tidak ditemukan")
        return false
    end

    local pos = _resolveSaveHit(plot, force == true)
    if not pos then
        if not force and _isMouseOverBlockingUI() then
            return false
        end
        warn("[GAG2] Save gagal: berdiri di tile plot, lalu tekan Save Position")
        return false
    end

    return _commitSavePosition(pos)
end

_bindSaveListener = function()
    if saveInputConn then return end

    saveInputConn = UserInputService.InputEnded:Connect(function(input)
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        task.defer(trySavePositionFromMouse)
    end)

    UserInputService.InputBegan:Connect(function(input)
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        task.delay(0.05, trySavePositionFromMouse)
    end)
end

local function _scheduleSaveListener()
    saveEnableAt = os.clock() + 0.15
    _bindSaveListener()
end

----------------------------------------------------------------
-- public API
----------------------------------------------------------------
function M.SetEnabled(on)
    on = (on == true)
    local wasRunning = running

    G.AUTO_PLANT_ENABLED = on
    _G.AUTO_PLANT_ENABLED = on
    _writeMainPlant({ enabled = on })

    if on then
        if not wasRunning then
            _resetSessionSeedStats()
        end
        if not running then
            running = true
            loopId += 1
            local myId = loopId
            task.spawn(function() mainLoop(myId) end)
        end
    else
        running = false
        _notifySeedStatsChanged()
    end
end

M.setEnabled = M.SetEnabled
function M.Start() return M.SetEnabled(true) end
M.start = M.Start
function M.Stop() return M.SetEnabled(false) end
M.stop = M.Stop

function M.SetSavePosition(on)
    on = (on == true)
    if not on then
        saveModeActive = false
        G.AUTO_PLANT_SAVE_POSITION = false
        _G.AUTO_PLANT_SAVE_POSITION = false
        _writeMainPlant({ savePosition = false })
        saveEnableAt = 0
        return
    end

    saveModeActive = true
    G.AUTO_PLANT_SAVE_POSITION = true
    _G.AUTO_PLANT_SAVE_POSITION = true
    _writeMainPlant({ savePosition = true })

    local ui = G.__GROWAGARDEN2_UI
    if ui and type(ui.CloseDropdownOverlays) == "function" then
        pcall(ui.CloseDropdownOverlays, ui)
    end

    task.defer(function()
        M.SaveStandingPosition()
    end)
end

M.setSavePosition = M.SetSavePosition

function M.SetAutoManual(on)
    on = (on == true)
    G.AUTO_PLANT_AUTO_MANUAL = on
    _G.AUTO_PLANT_AUTO_MANUAL = on
    _writeMainPlant({ autoManual = on })
end

M.setAutoManual = M.SetAutoManual

function M.SetPlantTotal(a, b)
    local n = tonumber(b)
    if n == nil then n = tonumber(a) end
    if n == nil then return end
    if n < 0 then n = 0 end
    n = math.floor(n)
    G.AUTO_PLANT_TOTAL = n
    _G.AUTO_PLANT_TOTAL = n
    sessionUserLimit = n
    if not running then
        sessionPlanted = 0
    end
    _writeMainPlant({ plantTotal = n })
    _notifySeedStatsChanged()
end

M.setPlantTotal = M.SetPlantTotal

function M.SetMode(mode)
    mode = tostring(mode or "random"):lower()
    if mode ~= "manual" then mode = "random" end
    G.AUTO_PLANT_MODE = mode
    _G.AUTO_PLANT_MODE = mode
    _writeMainPlant({ mode = mode })
end

M.setMode = M.SetMode

function M.SetSelectedPosition(id)
    id = _normalizePositionId(id)
    G.AUTO_PLANT_SELECTED_POSITION = id
    _G.AUTO_PLANT_SELECTED_POSITION = id
    _writeMainPlant({ selectedPosition = id })
    _resetManualGrid()
end

M.setSelectedPosition = M.SetSelectedPosition

function M.SyncFromState()
    local st = getPlantState()
    saveModeActive = false
    if st.savePosition then
        G.AUTO_PLANT_SAVE_POSITION = false
        _G.AUTO_PLANT_SAVE_POSITION = false
        _writeMainPlant({ savePosition = false })
    end
    M.SetEnabled(st.enabled)
end

M.syncFromState = M.SyncFromState

function M.GetPlayerPlot()
    return getPlayerPlot()
end

M.getPlayerPlot = M.GetPlayerPlot

function M.GetState()
    return getPlantState()
end

M.getState = M.GetState

function M.CountSeedTools(selectedSeeds)
    if selectedSeeds == nil then
        return _countInventorySeeds(getPlantState().seeds)
    end
    if type(selectedSeeds) == "table" then
        return _countInventorySeeds(_normalizeSet(selectedSeeds))
    end
    return 0
end

M.countSeedTools = M.CountSeedTools

function M.CountEquippedSeedTools(selectedSeeds)
    if selectedSeeds == nil then
        return _countSeedTools(getPlantState().seeds)
    end
    if type(selectedSeeds) == "table" then
        return _countSeedTools(_normalizeSet(selectedSeeds))
    end
    return 0
end

M.countEquippedSeedTools = M.CountEquippedSeedTools

function M.BuildOwnedSeedItems()
    local cached = G.__GAG2_PLANT_SEED_LIST_CACHE or rawget(_G, "__GAG2_PLANT_SEED_LIST_CACHE")
    if type(cached) == "table" and #cached > 0 then
        return cached
    end
    local plv = _getPlantListView()
    if plv and type(plv.buildPlantSeedItems) == "function" then
        local ok, items = pcall(plv.buildPlantSeedItems, plv)
        if ok and type(items) == "table" and #items > 0 then return items end
    end
    return {}
end

M.buildOwnedSeedItems = M.BuildOwnedSeedItems

function M.GetSeedStats()
    local ok, stats = pcall(function()
        local st = getPlantState()
        local totalInventory = _countInventorySeeds({})
        local remaining = totalInventory
        if next(st.seeds) then
            remaining = _countInventorySeeds(st.seeds)
        end
        local startTotal = sessionStartTotal
        if startTotal <= 0 then
            startTotal = next(st.seeds) and remaining or totalInventory
        end
        local target = sessionUserLimit
        if target <= 0 then
            target = startTotal
        end
        return {
            remaining = remaining,
            totalInventory = totalInventory,
            startTotal = startTotal,
            planted = sessionPlanted,
            total = startTotal,
            plantTotal = sessionUserLimit,
            target = target,
            equippedTools = _countSeedTools(st.seeds),
        }
    end)
    if ok and type(stats) == "table" then
        return stats
    end
    return {
        remaining = 0,
        totalInventory = 0,
        startTotal = 0,
        planted = sessionPlanted,
        total = 0,
        plantTotal = sessionUserLimit,
        target = 0,
        equippedTools = 0,
    }
end

M.getSeedStats = M.GetSeedStats

function M.SaveStandingPosition()
    saveModeActive = true
    G.AUTO_PLANT_SAVE_POSITION = true
    _G.AUTO_PLANT_SAVE_POSITION = true
    saveEnableAt = 0

    local plot = getPlayerPlot()
    if not plot then
        warn("[GAG2] Save gagal: plot tidak ditemukan")
        _disableSaveMode()
        return false
    end

    local pos = _getStandingPlotPosition(plot)
    if not pos then
        warn("[GAG2] Save gagal: berdiri di tile plot dulu, lalu tekan Save Position")
        _disableSaveMode()
        return false
    end

    return _commitSavePosition(pos)
end

M.saveStandingPosition = M.SaveStandingPosition

function M.SavePositionNow()
    saveModeActive = true
    saveEnableAt = 0
    return trySavePositionFromMouse(true) == true
end

M.savePositionNow = M.SavePositionNow

function M.DeletePosition(id)
    id = tostring(id or "")
    if id == "" then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}
    local positions = type(MAIN.auto.plant.positions) == "table" and MAIN.auto.plant.positions or {}

    local removed = false
    for i = #positions, 1, -1 do
        local entry = positions[i]
        if type(entry) == "table" and tostring(entry.id) == id then
            table.remove(positions, i)
            removed = true
        end
    end
    if not removed then return false end

    MAIN.auto.plant.positions = positions
    if tostring(MAIN.auto.plant.selectedPosition) == id then
        local nextId = positions[1] and positions[1].id or nil
        MAIN.auto.plant.selectedPosition = nextId and tostring(nextId) or nil
        G.AUTO_PLANT_SELECTED_POSITION = MAIN.auto.plant.selectedPosition
        _G.AUTO_PLANT_SELECTED_POSITION = MAIN.auto.plant.selectedPosition
    end

    if manualPosIndex > #positions then
        manualPosIndex = math.max(1, #positions)
    end
    _resetManualGrid()

    G.MAIN = MAIN
    _G.MAIN = MAIN
    _notifyPositionsChanged()
    return true
end

M.deletePosition = M.DeletePosition

