G.AutoPlant = M
G.AutoPlantModule = M
_G.AutoPlant = M
_G.AutoPlantModule = M

_bindSaveListener()

return M
 end,             required = false },
    { key = "SprinklerListView", name = "SprinklerListView", factory = function() -- SprinklerListView.lua — Grow A Garden 2
-- List sprinkler dari SharedModules.SprinklerData

local ReplicatedStorage = game:GetService("ReplicatedStorage")
local Players           = game:GetService("Players")

local LP = Players.LocalPlayer
local M = {}

local G = (getgenv and getgenv()) or _G

local _catalogCache = nil

local function _safeRequire(inst)
    if not inst or not inst:IsA("ModuleScript") then return nil end
    local ok, mod = pcall(require, inst)
    if ok and type(mod) == "table" then return mod end
    return nil
end

local function _normalizeEntry(entry, keyHint)
    if type(entry) ~= "table" then return nil end
    local name = entry.SprinklerName or entry.Name or keyHint
    if not name or tostring(name) == "" then return nil end
    return {
        SprinklerName = tostring(name),
        Radius        = tonumber(entry.Radius) or 0,
        Lifetime      = tonumber(entry.Lifetime),
        raw           = entry,
    }
end

local function _loadCatalog()
    if _catalogCache then return _catalogCache end

    local merged = {}
    local root = ReplicatedStorage:FindFirstChild("SharedModules")
    local dataMod = root and root:FindFirstChild("SprinklerData")
    local data = dataMod and _safeRequire(dataMod)

    if type(data) == "table" then
        if #data > 0 then
            for _, entry in ipairs(data) do
                local norm = _normalizeEntry(entry)
                if norm then merged[norm.SprinklerName] = norm end
            end
        else
            for key, entry in pairs(data) do
                if type(entry) == "table" then
                    local norm = _normalizeEntry(entry, key)
                    if norm then merged[norm.SprinklerName] = norm end
                end
            end
        end
    end

    _catalogCache = merged
    return merged
end

function M.refresh()
    _catalogCache = nil
    return _loadCatalog()
end

function M.getCatalogMap()
    return _loadCatalog()
end

function M.findByName(name)
    if not name then return nil end
    return _loadCatalog()[tostring(name)]
end

function M.buildSprinklerItems()
    return M.buildInventorySprinklerItems()
end

local function _iterInventoryContainers()
    local out, seen = {}, {}
    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end
    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP:FindFirstChild("TasRansel"))
    add(LP.Character)
    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end
    return out
end

function M.buildInventorySprinklerItems()
    local counts = {}
    for _, container in ipairs(_iterInventoryContainers()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") then
                local attr = inst:GetAttribute("Sprinkler")
                if attr ~= nil then
                    local name = tostring(attr)
                    if name ~= "" then
                        counts[name] = (counts[name] or 0) + 1
                    end
                end
            end
        end
    end

    local out = {}
    for name, count in pairs(counts) do
        local info = M.findByName(name)
        out[#out + 1] = {
            key   = name,
            name  = name,
            right = ("x%d"):format(count),
            raw   = info or { SprinklerName = name, Radius = 16 },
        }
    end
    table.sort(out, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)
    if #out == 0 then
        return { { key = "_none", name = "(No sprinklers in inventory)" } }
    end
    return out
end

function M.countInventorySprinklers(selected)
    selected = type(selected) == "table" and selected or {}
    local hasFilter = next(selected) ~= nil
    local total = 0
    for _, container in ipairs(_iterInventoryContainers()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") then
                local attr = inst:GetAttribute("Sprinkler")
                if attr ~= nil then
                    local name = tostring(attr)
                    if name ~= "" and (not hasFilter or selected[name] == true) then
                        total += 1
                    end
                end
            end
        end
    end
    return total
end

-- Legacy catalog list (radius lookup still uses SprinklerData)
function M.buildCatalogSprinklerItems()
    local out = {}
    for _, info in pairs(_loadCatalog()) do
        out[#out + 1] = {
            key   = info.SprinklerName,
            name  = info.SprinklerName,
            right = info.Radius and info.Radius > 0 and ("R" .. tostring(info.Radius)) or nil,
            raw   = info,
        }
    end
    table.sort(out, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)
    return out
end

function M.getCoverageRadius(info)
    info = type(info) == "table" and info or M.findByName(info)
    local r = info and tonumber(info.Radius) or 0
    if r <= 0 then return 8 end
    -- SprinklerRadius part pakai Size = Vector3.new(Radius, ..., Radius) → diameter
    return r * 0.5
end

function M.getPlacementSpacing(info)
    info = type(info) == "table" and info or M.findByName(info)
    local r = info and tonumber(info.Radius) or 0
    if r <= 0 then return 16 end
    return r
end

G.SprinklerListView = M
_G.SprinklerListView = M

return M
 end,   required = false },
    { key = "AutoSprinkler",   name = "Auto Sprinkler",   factory = function() -- AutoSprinkler.lua — Grow A Garden 2
-- Place: Networking.Place.PlaceSprinkler:Fire(position, sprinklerName, tool, plotId)

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local CollectionService = game:GetService("CollectionService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local Networking = require(ReplicatedStorage.SharedModules.Networking)
local PlaceSprinkler = Networking.Place and Networking.Place.PlaceSprinkler

local Gardens = workspace:WaitForChild("Gardens")

local sprinklerCatalog = {}
pcall(function()
    local data = require(ReplicatedStorage.SharedModules.SprinklerData)
    if type(data) ~= "table" then return end
    if #data > 0 then
        for _, entry in ipairs(data) do
            if type(entry) == "table" and entry.SprinklerName then
                sprinklerCatalog[entry.SprinklerName] = entry
            end
        end
    else
        for key, entry in pairs(data) do
            if type(entry) == "table" then
                local name = entry.SprinklerName or entry.Name or key
                sprinklerCatalog[tostring(name)] = entry
            end
        end
    end
end)

local LOOP_MIN_SEC       = 0.5
local PLACE_COOLDOWN     = 0.55
local MIN_SPRINKLER_GAP  = 1.0
local PLOT_CACHE_SEC     = 2
local RANDOM_GRID_MARGIN = 0.9

local running     = false
local loopId      = 0
local lastPlaceAt = 0
local cachedPlot  = nil
local cachedPlotAt = 0
local randomGrids = {}
local activeSprinklerType = nil
local typeRoundIndex = 1
local lastRoundSelKey = ""

----------------------------------------------------------------
local lastFailReason = ""

local function _dbg()
    return G.AUTO_SPRINKLER_DEBUG == true or _G.AUTO_SPRINKLER_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-ASpr]", ...)
end

local function _fail(reason, ...)
    lastFailReason = tostring(reason or "")
    if _dbg() then
        if select("#", ...) > 0 then
            warn("[GAG2-ASpr]", reason, ...)
        else
            warn("[GAG2-ASpr]", reason)
        end
    end
    return false, reason
end

local function _writeMain(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.sprinkler = MAIN.auto.sprinkler or {}
    for k, v in pairs(patch) do
        MAIN.auto.sprinkler[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _canon(s)
    s = tostring(s or ""):lower():gsub("[^%w]+", "")
    return s
end

local function _getSLV()
    return G.SprinklerListView or rawget(_G, "SprinklerListView")
end

local function _getShovel()
    return G.AutoShovel or G.AutoShovelModule or rawget(_G, "AutoShovel")
end

local function getSprinklerState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.sprinkler
    st = type(st) == "table" and st or {}

    local sprinklers = G.AUTO_SPRINKLER_SELECTED
        or rawget(_G, "AUTO_SPRINKLER_SELECTED")
        or _normalizeSet(st.sprinklers)

    local plants = G.AUTO_SPRINKLER_PLANTS_SELECTED
        or rawget(_G, "AUTO_SPRINKLER_PLANTS_SELECTED")
        or _normalizeSet(st.plants)

    local delay = tonumber(st.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_SPRINKLER_DELAY or rawget(_G, "AUTO_SPRINKLER_DELAY")) or 1
    end
    if delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end

    local mode = tostring(st.mode or G.AUTO_SPRINKLER_MODE or "random"):lower()
    if mode ~= "near_plant" then mode = "random" end

    local enabled = (G.AUTO_SPRINKLER_ENABLED == true)
        or (rawget(_G, "AUTO_SPRINKLER_ENABLED") == true)
        or (st.enabled == true)

    return {
        enabled    = enabled,
        sprinklers = _normalizeSet(sprinklers),
        plants     = _normalizeSet(plants),
        mode       = mode,
        delay      = delay,
    }
end

----------------------------------------------------------------
local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    if not Gardens or not Gardens.Parent then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local plot = Gardens:FindFirstChild("Plot" .. tostring(plotId))
        if plot then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    for _, plot in ipairs(Gardens:GetChildren()) do
        local owner = plot:GetAttribute("Owner") or plot:GetAttribute("OwnerId") or plot:GetAttribute("OwnerUserId")
        if owner ~= nil then
            if tostring(owner) == LP.Name or tonumber(owner) == LP.UserId then
                cachedPlot = plot
                cachedPlotAt = now
                return plot
            end
        end
    end

    cachedPlot = nil
    cachedPlotAt = now
    return nil
end

local function getPlotId(plot)
    local pid = LP:GetAttribute("PlotId")
    if pid ~= nil then
        local n = tonumber(pid)
        if n then return n end
    end
    if not plot then return nil end
    local n = tonumber(string.match(plot.Name, "%d+"))
    if n then return n end
    return nil
end

local function _describeRemote(remote)
    if typeof(remote) == "Instance" then
        return remote:GetFullName()
    end
    if type(remote) == "table" then
        for _, key in ipairs({ "Remote", "_remote", "remote", "Event", "_event" }) do
            local inner = remote[key]
            if typeof(inner) == "Instance" then
                return inner:GetFullName()
            end
        end
        return "Networking.Place.PlaceSprinkler"
    end
    return "MISSING"
end

local function _unwrapRemoteEvent(remote)
    if typeof(remote) == "Instance" then
        if remote:IsA("RemoteEvent") or remote:IsA("RemoteFunction") then
            return remote
        end
        return remote:FindFirstChildWhichIsA("RemoteEvent", true)
            or remote:FindFirstChildWhichIsA("RemoteFunction", true)
    end
    if type(remote) ~= "table" then return nil end
    for _, key in ipairs({ "Remote", "_remote", "remote", "Event", "_event", "RF", "RE" }) do
        local inner = remote[key]
        if inner then
            local found = _unwrapRemoteEvent(inner)
            if found then return found end
        end
    end
    return nil
end

local function _callPlaceRemote(remote, pos, sprinklerName, tool, plotId)
    if type(remote) ~= "table" and typeof(remote) ~= "Instance" then
        return false
    end

    local function tryFire(fn)
        local ok = pcall(fn)
        return ok
    end

    if type(remote.Fire) == "function" then
        if tryFire(function() remote:Fire(pos, sprinklerName, tool, plotId) end) then
            return true
        end
        if tryFire(function() remote:Fire(pos, sprinklerName, tool) end) then
            return true
        end
    end

    local re = _unwrapRemoteEvent(remote)
    if re and re:IsA("RemoteEvent") then
        if tryFire(function() re:FireServer(pos, sprinklerName, tool, plotId) end) then
            return true
        end
        if tryFire(function() re:FireServer(pos, sprinklerName, tool) end) then
            return true
        end
    end
    if re and re:IsA("RemoteFunction") then
        local ok = pcall(function() re:InvokeServer(pos, sprinklerName, tool, plotId) end)
        if ok then return true end
        ok = pcall(function() re:InvokeServer(pos, sprinklerName, tool) end)
        if ok then return true end
    end
    return false
end

local function _fireToolRemotes(tool, pos, sprinklerName, plotId)
    if not tool then return false end
    local roots = { tool }
    local char = LP.Character
    if char then roots[#roots + 1] = char end

    for _, root in ipairs(roots) do
        for _, desc in ipairs(root:GetDescendants()) do
            if desc:IsA("RemoteEvent") then
                local ok = pcall(function() desc:FireServer(pos, sprinklerName, plotId) end)
                if ok then return true end
                ok = pcall(function() desc:FireServer(pos, sprinklerName, tool, plotId) end)
                if ok then return true end
                ok = pcall(function() desc:FireServer(pos) end)
                if ok then return true end
            end
            if desc:IsA("RemoteFunction") then
                local ok = pcall(function() desc:InvokeServer(pos, sprinklerName, plotId) end)
                if ok then return true end
            end
        end
    end
    return false
end

local function _getPlaceRemote()
    if PlaceSprinkler and type(PlaceSprinkler.Fire) == "function" then
        return PlaceSprinkler
    end
    if type(Networking) == "table" and Networking.Place and Networking.Place.PlaceSprinkler then
        PlaceSprinkler = Networking.Place.PlaceSprinkler
        return PlaceSprinkler
    end
    return nil
end

local function plotIsPlaceable(plot)
    if not plot then return false end
    if plot:GetAttribute("Owner") ~= nil then return true end
    return getPlayerPlot() == plot
end

local function collectPlantAreas(plot)
    local list, seen = {}, {}

    local function add(inst)
        if inst and inst:IsA("BasePart") and not seen[inst] then
            seen[inst] = true
            list[#list + 1] = inst
        end
    end

    if Gardens and Gardens.Parent then
        local ok, parts = pcall(function()
            return Gardens:QueryDescendants("BasePart.PlantArea")
        end)
        if ok and type(parts) == "table" then
            for _, inst in ipairs(parts) do
                if inst:IsDescendantOf(plot) then
                    add(inst)
                end
            end
        end
    end

    if #list > 0 then return list end

    for _, inst in ipairs(CollectionService:GetTagged("PlantArea")) do
        if inst:IsDescendantOf(plot) then
            add(inst)
        end
    end

    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.Name == "Can_Plant" then
            add(desc)
        end
    end

    return list
end

local function createPlantAreaParams(plot)
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = collectPlantAreas(plot)
    return params, params.FilterDescendantsInstances
end

local function snapToPlantArea(plot, pos)
    if not plot or not pos then return nil end
    local params, list = createPlantAreaParams(plot)
    if #list == 0 then return nil end

    local originY = 250
    for _, part in ipairs(list) do
        if part:IsA("BasePart") then
            originY = math.max(originY, part.Position.Y + 80)
        end
    end

    local hit = workspace:Raycast(
        Vector3.new(pos.X, originY, pos.Z),
        Vector3.new(0, -600, 0),
        params
    )
    if hit and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end
    return nil
end

local function isOnPlantArea(plot, pos)
    return snapToPlantArea(plot, pos) ~= nil
end

local function getSprinklerCatalogEntry(name)
    local slv = _getSLV()
    if slv and type(slv.findByName) == "function" then
        local ok, entry = pcall(slv.findByName, slv, name)
        if ok and type(entry) == "table" then return entry end
    end
    return { SprinklerName = tostring(name or ""), Radius = 16 }
end

local function getCoverageRadius(name)
    local slv = _getSLV()
    if slv and type(slv.getCoverageRadius) == "function" then
        local ok, r = pcall(slv.getCoverageRadius, slv, name)
        if ok and type(r) == "number" and r > 0 then return r end
    end
    local entry = getSprinklerCatalogEntry(name)
    local rad = tonumber(entry.Radius) or 16
    return rad * 0.5
end

local function getPlacementSpacing(name)
    local slv = _getSLV()
    if slv and type(slv.getPlacementSpacing) == "function" then
        local ok, s = pcall(slv.getPlacementSpacing, slv, name)
        if ok and type(s) == "number" and s > 0 then return s end
    end
    return tonumber(getSprinklerCatalogEntry(name).Radius) or 16
end

local function listExistingSprinklers(plot)
    local out, seen = {}, {}

    local function addModel(model, name)
        if not model or seen[model] then return end
        seen[model] = true
        local pos = nil
        local ok, pivot = pcall(function()
            return model:GetPivot().Position
        end)
        if ok then pos = pivot end
        if not pos and model.PrimaryPart then
            pos = model.PrimaryPart.Position
        end
        if pos then
            out[#out + 1] = {
                model  = model,
                pos    = pos,
                name   = tostring(name or model.Name),
                radius = getCoverageRadius(name or model.Name),
            }
        end
    end

    if not plot then return out end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("Model") and sprinklerCatalog[desc.Name] then
            addModel(desc, desc.Name)
        end
    end

    local folder = plot:FindFirstChild("Sprinklers")
    if folder then
        for _, model in ipairs(folder:GetChildren()) do
            if model:IsA("Model") then
                addModel(model, model:GetAttribute("SprinklerName") or model.Name)
            end
        end
    end

    return out
end

local function isPosCoveredByExistingSprinklers(pos, existing)
    if not pos or type(existing) ~= "table" then return false end
    for _, s in ipairs(existing) do
        local dx = s.pos.X - pos.X
        local dz = s.pos.Z - pos.Z
        local r = tonumber(s.radius) or 0
        if r > 0 and (dx * dx + dz * dz) <= (r * r) then
            return true
        end
    end
    return false
end

local function isTooCloseToSprinkler(plot, pos)
    if not plot or not pos then return false end

    local function nearModel(model)
        if not model or not model:IsA("Model") then return false end
        local p = nil
        local ok, pivot = pcall(function()
            return model:GetPivot().Position
        end)
        if ok then p = pivot end
        if not p and model.PrimaryPart then
            p = model.PrimaryPart.Position
        end
        if not p then return false end
        local dx = p.X - pos.X
        local dz = p.Z - pos.Z
        return (dx * dx + dz * dz) < (MIN_SPRINKLER_GAP * MIN_SPRINKLER_GAP)
    end

    local folder = plot:FindFirstChild("Sprinklers")
    if folder then
        for _, child in ipairs(folder:GetChildren()) do
            if nearModel(child) then return true end
        end
    end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("Model") then
            local isSpr = sprinklerCatalog[desc.Name]
                or desc:GetAttribute("Sprinkler")
                or desc:GetAttribute("SprinklerName")
            if isSpr and nearModel(desc) then
                return true
            end
        end
    end
    return false
end

local function isPlantCovered(pos, existing, coverageRadius)
    for _, s in ipairs(existing) do
        local dx = s.pos.X - pos.X
        local dz = s.pos.Z - pos.Z
        local maxR = math.max(s.radius, coverageRadius)
        if (dx * dx + dz * dz) <= (maxR * maxR) then
            return true
        end
    end
    return false
end

local function _iterInventoryContainers()
    local out, seen = {}, {}
    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end
    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP:FindFirstChild("TasRansel"))
    add(LP.Character)
    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end
    return out
end

local function sprinklerMatchesTool(tool, selected)
    if not tool or not tool:IsA("Tool") then return false end
    local attr = tool:GetAttribute("Sprinkler")
    if attr == nil then return false end
    attr = tostring(attr)
    if not next(selected) then return true end
    return selected[attr] == true or selected[_canon(attr)] == true
end

local function findSprinklerTools(selected)
    local found = {}
    for _, container in ipairs(_iterInventoryContainers()) do
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") and sprinklerMatchesTool(inst, selected) then
                found[#found + 1] = inst
            end
        end
    end
    return found
end

local function getSprinklerTypeName(tool)
    if not tool or not tool:IsA("Tool") then return nil end
    local attr = tool:GetAttribute("Sprinkler")
    if attr == nil then return nil end
    local name = tostring(attr)
    return (name ~= "") and name or nil
end

local function groupSprinklerToolsByType(selected)
    local groups = {}
    for _, tool in ipairs(findSprinklerTools(selected)) do
        local name = getSprinklerTypeName(tool)
        if name then
            local bucket = groups[name]
            if not bucket then
                bucket = {}
                groups[name] = bucket
            end
            bucket[#bucket + 1] = tool
        end
    end
    return groups
end

local function buildSprinklerTypeOrder(selected)
    local groups = groupSprinklerToolsByType(selected)
    local order, seen = {}, {}

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local arr = type(MAIN) == "table"
        and type(MAIN.auto) == "table"
        and type(MAIN.auto.sprinkler) == "table"
        and MAIN.auto.sprinkler.sprinklers

    if type(arr) == "table" then
        for i = 1, #arr do
            local name = tostring(arr[i] or "")
            if name ~= "" and not seen[name] and groups[name] and #groups[name] > 0 then
                seen[name] = true
                order[#order + 1] = name
            end
        end
        for name, tools in pairs(groups) do
            if not seen[name] and #tools > 0 then
                seen[name] = true
                order[#order + 1] = name
            end
        end
    else
        for name, tools in pairs(groups) do
            if #tools > 0 then
                order[#order + 1] = name
            end
        end
        table.sort(order)
    end

    return order, groups
end

local function resetActiveSprinklerType()
    activeSprinklerType = nil
    typeRoundIndex = 1
    lastRoundSelKey = ""
    randomGrids = {}
end

local function getAvailableSprinklerTypes(selected)
    local order, groups = buildSprinklerTypeOrder(selected)
    local avail = {}
    for _, name in ipairs(order) do
        if groups[name] and #groups[name] > 0 then
            avail[#avail + 1] = name
        end
    end
    return avail, groups, order
end

local function syncRoundRobinSelection(selected)
    local _, _, order = getAvailableSprinklerTypes(selected)
    local selKey = table.concat(order, "\0")
    if selKey ~= lastRoundSelKey then
        lastRoundSelKey = selKey
        typeRoundIndex = 1
    end
end

-- Multi-select: round-robin (1 each type per turn). Single type: keep placing that type.
local function resolveActiveSprinklerType(selected)
    local avail, groups = getAvailableSprinklerTypes(selected)
    if #avail == 0 then
        resetActiveSprinklerType()
        return nil, groups
    end

    syncRoundRobinSelection(selected)

    if #avail == 1 then
        activeSprinklerType = avail[1]
        return avail[1], groups
    end

    if typeRoundIndex > #avail or typeRoundIndex < 1 then
        typeRoundIndex = 1
    end

    local name = avail[typeRoundIndex]
    activeSprinklerType = name
    return name, groups
end

local function advanceSprinklerTypeRound(selected)
    local avail = select(1, getAvailableSprinklerTypes(selected))
    if #avail <= 1 then return end
    typeRoundIndex += 1
    if typeRoundIndex > #avail then
        typeRoundIndex = 1
    end
    _log("next round-robin type", avail[typeRoundIndex], "idx", typeRoundIndex)
end

local function findSprinklerToolOfType(selected, typeName)
    if not typeName then return nil end
    local _, groups = buildSprinklerTypeOrder(selected)
    local tools = groups[typeName]
    if type(tools) ~= "table" or #tools == 0 then return nil end
    return tools[1]
end

local function countSprinklerToolsOfType(selected, typeName)
    if not typeName then return 0 end
    local _, groups = buildSprinklerTypeOrder(selected)
    local tools = groups[typeName]
    return type(tools) == "table" and #tools or 0
end

local function ensureSprinklerEquipped(tool)
    if not tool or not tool:IsA("Tool") then return false end
    local char = LP.Character
    if not char then return false end
    if tool.Parent == char then return true end

    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end

    pcall(function() hum:EquipTool(tool) end)

    local deadline = os.clock() + 0.6
    while os.clock() < deadline do
        if tool.Parent == char then
            task.wait(0.05)
            return tool.Parent == char
        end
        task.wait(0.03)
    end
    return tool.Parent == char
end

local function _sprinklerPlaced(plot, pos, beforeCount)
    if not plot or not pos then return false end
    beforeCount = tonumber(beforeCount) or 0
    local existing = listExistingSprinklers(plot)
    if #existing > beforeCount then return true end
    for _, s in ipairs(existing) do
        local dx = s.pos.X - pos.X
        local dz = s.pos.Z - pos.Z
        if (dx * dx + dz * dz) <= 64 then
            return true
        end
    end
    return false
end

local function placeSprinklerAt(pos, tool, plotId, plot)
    local remote = _getPlaceRemote()
    if not remote then return false, "no_remote" end
    if not tool or not tool.Parent then return false, "no_tool" end
    if os.clock() - lastPlaceAt < PLACE_COOLDOWN then return false, "cooldown" end

    local sprinklerAttr = tool:GetAttribute("Sprinkler")
    if sprinklerAttr == nil then return false, "no_attr" end
    sprinklerAttr = tostring(sprinklerAttr)

    plot = plot or getPlayerPlot()
    plotId = tonumber(plotId) or getPlotId(plot)
    if not plotId then return false, "no_plot_id" end

    if not ensureSprinklerEquipped(tool) then
        return _fail("equip_fail", tool.Name)
    end
    task.wait(0.15)

    local char = LP.Character
    if char then
        local equipped = char:FindFirstChild(tool.Name)
        if equipped and equipped:IsA("Tool") then
            tool = equipped
        end
    end

    local beforeCount = plot and #listExistingSprinklers(plot) or 0
    local firePos = pos + Vector3.new(0, 0.05, 0)

    if not _callPlaceRemote(remote, firePos, sprinklerAttr, tool, plotId) then
        return _fail("fire_failed")
    end

    local function waitPlaced()
        local deadline = os.clock() + 0.5
        while os.clock() < deadline do
            if plot and _sprinklerPlaced(plot, firePos, beforeCount) then
                return true
            end
            if not tool.Parent then
                return true
            end
            task.wait(0.05)
        end
        return false
    end

    if waitPlaced() then
        lastPlaceAt = os.clock()
        lastFailReason = ""
        _log("placed", sprinklerAttr, firePos, plotId)
        return true
    end

    -- retry: beberapa build pakai tool.Name bukan attribute
    if tool.Name ~= sprinklerAttr then
        _callPlaceRemote(remote, firePos, tool.Name, tool, plotId)
        if waitPlaced() then
            lastPlaceAt = os.clock()
            lastFailReason = ""
            _log("placed", tool.Name, firePos, plotId)
            return true
        end
    end

    if _fireToolRemotes(tool, firePos, sprinklerAttr, plotId) and waitPlaced() then
        lastPlaceAt = os.clock()
        lastFailReason = ""
        _log("placed via tool remote", sprinklerAttr, firePos, plotId)
        return true
    end

    return _fail("place_rejected", firePos, "plotId=" .. tostring(plotId))
end

local function countSprinklerTools(selected)
    return #findSprinklerTools(selected)
end

local function tryPlaceAt(plot, pos, st, typeName)
    if not plotIsPlaceable(plot) then
        return _fail("no_owner", plot and plot.Name)
    end

    pos = snapToPlantArea(plot, pos)
    if not pos then
        return _fail("no_surface")
    end
    if isTooCloseToSprinkler(plot, pos) then
        return _fail("too_close", pos)
    end

    local plotId = getPlotId(plot)
    if not plotId then
        return _fail("no_plot_id")
    end

    typeName = typeName or resolveActiveSprinklerType(st.sprinklers)
    if not typeName then
        return _fail("no_type")
    end

    local tool = findSprinklerToolOfType(st.sprinklers, typeName)
    if not tool then
        advanceSprinklerTypeRound(st.sprinklers)
        return _fail("no_tool", typeName)
    end

    local ok, err = placeSprinklerAt(pos, tool, plotId, plot)
    if ok then
        advanceSprinklerTypeRound(st.sprinklers)
        return true
    end
    return false, err or lastFailReason
end

local function getPlantAreasBounds(plot)
    local areas = collectPlantAreas(plot)
    if #areas == 0 then return nil end

    local minX, maxX, minZ, maxZ = math.huge, -math.huge, math.huge, -math.huge
    for _, part in ipairs(areas) do
        if part:IsA("BasePart") then
            local cf, size = part.CFrame, part.Size
            local hx, hz = size.X * 0.5, size.Z * 0.5
            for _, corner in ipairs({
                cf * Vector3.new(-hx, 0, -hz),
                cf * Vector3.new(hx, 0, -hz),
                cf * Vector3.new(-hx, 0, hz),
                cf * Vector3.new(hx, 0, hz),
            }) do
                minX = math.min(minX, corner.X)
                maxX = math.max(maxX, corner.X)
                minZ = math.min(minZ, corner.Z)
                maxZ = math.max(maxZ, corner.Z)
            end
        end
    end

    if minX == math.huge then return nil end
    return minX, maxX, minZ, maxZ
end

local function buildRandomGrid(plot, spacing, existing)
    spacing = tonumber(spacing) or 16
    spacing = math.max(spacing * RANDOM_GRID_MARGIN, MIN_SPRINKLER_GAP + 0.5)
    existing = existing or listExistingSprinklers(plot)

    local minX, maxX, minZ, maxZ = getPlantAreasBounds(plot)
    if not minX then return {} end

    local points = {}
    local z = minZ + spacing * 0.5
    while z <= maxZ do
        local x = minX + spacing * 0.5
        while x <= maxX do
            local pos = snapToPlantArea(plot, Vector3.new(x, 0, z))
            if pos
                and not isTooCloseToSprinkler(plot, pos)
                and not isPosCoveredByExistingSprinklers(pos, existing)
            then
                points[#points + 1] = pos
            end
            x += spacing
        end
        z += spacing
    end
    return points
end

local function getRandomGridState(plot, typeName)
    local existing = listExistingSprinklers(plot)
    local spacing = getPlacementSpacing(typeName)
    local key = plot.Name .. "|" .. typeName .. "|" .. tostring(spacing) .. "|n=" .. tostring(#existing)
    local entry = randomGrids[typeName]
    if not entry or entry.key ~= key then
        entry = {
            key = key,
            points = buildRandomGrid(plot, spacing, existing),
            idx = 1,
        }
        randomGrids[typeName] = entry
    end
    return entry
end

local function getPlantTypeKey(plant)
    local AS = _getShovel()
    if AS and type(AS.GetPlantTypeKey) == "function" then
        local ok, key = pcall(AS.GetPlantTypeKey, AS, plant)
        if ok and key then return tostring(key) end
    end
    return tostring(
        plant:GetAttribute("SeedName")
            or plant:GetAttribute("ConfigPathName")
            or plant:GetAttribute("CorePartName")
            or plant:GetAttribute("FruitType")
            or plant.Name
    )
end

local function getPlantGroundPos(plant)
    if plant:IsA("BasePart") then return plant.Position end
    local ok, pos = pcall(function()
        return plant:GetPivot().Position
    end)
    if ok and typeof(pos) == "Vector3" then return pos end
    local part = plant:FindFirstChildWhichIsA("BasePart", true)
    return part and part.Position or nil
end

local function listTargetPlants(plot, selectedPlants)
    local out = {}
    if not plot or not next(selectedPlants) then return out end
    local folder = plot:FindFirstChild("Plants")
    if not folder then return out end

    for _, plant in ipairs(folder:GetChildren()) do
        local key = getPlantTypeKey(plant)
        if selectedPlants[key] or selectedPlants[_canon(key)] then
            local pos = getPlantGroundPos(plant)
            if pos then
                out[#out + 1] = { plant = plant, key = key, pos = pos }
            end
        end
    end
    return out
end

local function findPlacementNearPlant(plot, plantPos, coverageRadius, existing)
    local candidates = {
        plantPos,
        plantPos + Vector3.new(coverageRadius * 0.5, 0, 0),
        plantPos + Vector3.new(-coverageRadius * 0.5, 0, 0),
        plantPos + Vector3.new(0, 0, coverageRadius * 0.5),
        plantPos + Vector3.new(0, 0, -coverageRadius * 0.5),
    }

    for _, raw in ipairs(candidates) do
        local pos = snapToPlantArea(plot, raw)
        if pos
            and not isTooCloseToSprinkler(plot, pos)
            and not isPosCoveredByExistingSprinklers(pos, existing)
        then
            local covers = false
            local dx = pos.X - plantPos.X
            local dz = pos.Z - plantPos.Z
            if (dx * dx + dz * dz) <= (coverageRadius * coverageRadius) then
                covers = true
            end
            if covers then
                return pos
            end
        end
    end
    return nil
end

local function gardenNeedsSprinkler(plot, st)
    if not plot or not st then return false end

    local name = resolveActiveSprinklerType(st.sprinklers)
    if not name then return false end

    local existing = listExistingSprinklers(plot)

    if st.mode == "near_plant" then
        if not next(st.plants) then return false end
        local coverage = getCoverageRadius(name)
        for _, entry in ipairs(listTargetPlants(plot, st.plants)) do
            if not isPlantCovered(entry.pos, existing, coverage) then
                local pos = findPlacementNearPlant(plot, entry.pos, coverage, existing)
                if pos then return true end
            end
        end
        return false
    end

    local spacing = getPlacementSpacing(name)
    return #buildRandomGrid(plot, spacing, existing) > 0
end

local function tryRandomMode(st, plot)
    if not gardenNeedsSprinkler(plot, st) then
        return false
    end

    local name = resolveActiveSprinklerType(st.sprinklers)
    if not name then
        return false
    end

    local gridState = getRandomGridState(plot, name)
    local randomGrid = gridState.points
    local randomIdx = gridState.idx

    if #randomGrid == 0 then
        return false
    end

    local tried = 0
    while tried < #randomGrid do
        if randomIdx > #randomGrid then randomIdx = 1 end
        local pos = randomGrid[randomIdx]
        randomIdx += 1
        tried += 1

        if not isTooCloseToSprinkler(plot, pos)
            and not isPosCoveredByExistingSprinklers(pos, listExistingSprinklers(plot))
        then
            local ok = tryPlaceAt(plot, pos, st, name)
            if ok then
                table.remove(randomGrid, randomIdx - 1)
                if randomIdx > #randomGrid then randomIdx = 1 end
                gridState.idx = randomIdx
                gridState.points = randomGrid
                return true
            end
        end
    end

    randomGrids[name] = nil
    return false
end

local function tryNearPlantMode(st, plot)
    if not gardenNeedsSprinkler(plot, st) then
        return false
    end

    if not next(st.plants) then
        return false
    end

    local name = resolveActiveSprinklerType(st.sprinklers)
    if not name then
        return false
    end

    local coverage = getCoverageRadius(name)
    local existing = listExistingSprinklers(plot)
    local targets = listTargetPlants(plot, st.plants)

    if #targets == 0 then
        return false
    end

    for _, entry in ipairs(targets) do
        if not isPlantCovered(entry.pos, existing, coverage) then
            local pos = findPlacementNearPlant(plot, entry.pos, coverage, existing)
            if pos then
                local ok = tryPlaceAt(plot, pos, st, name)
                if ok then return true end
            end
        end
    end

    return false
end

local function tick(st)
    st = st or getSprinklerState()

    if countSprinklerTools(st.sprinklers) == 0 then
        return _fail("no_inventory_tools")
    end

    local plot = getPlayerPlot()
    if not plot then
        return _fail("no_plot")
    end

    if not gardenNeedsSprinkler(plot, st) then
        return _fail("garden_full")
    end

    local ok
    if st.mode == "near_plant" then
        ok = tryNearPlantMode(st, plot)
    else
        ok = tryRandomMode(st, plot)
    end
    if not ok and _dbg() and lastFailReason ~= "" then
        warn("[GAG2-ASpr] tick fail:", lastFailReason)
    end
    return ok
end

local function mainLoop(myId)
    _log("loop start", myId)
    while running and loopId == myId do
        local st = getSprinklerState()
        if st.enabled then
            pcall(tick, st)
        end
        task.wait(st.delay)
    end
    _log("loop end", myId)
end

