return M
 end,         required = false },
    { key = "SectionAutoSprinkler", name = "Section Auto Sprinkler", factory = function() -- section_auto_sprinkler.lua — UI section Auto Sprinkler (tab Auto)
-- Dipanggil dari tabs_auto.lua agar file utama tidak membengkak.

local G = (getgenv and getgenv()) or _G
local M = {}

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto       = ctx.getAuto
    local patchAuto     = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush
    local cleanSelectedMap = ctx.cleanSelectedMap
    local arrayToMap    = ctx.arrayToMap
    local mapToArray    = ctx.mapToArray
    local toggleApiGet  = ctx.toggleApiGet

    local G = (getgenv and getgenv()) or _G
    local SprinklerListView = G.SprinklerListView or rawget(_G, "SprinklerListView")

    local SP_STATE = getAuto("sprinkler")
    SP_STATE.sprinklers = type(SP_STATE.sprinklers) == "table" and SP_STATE.sprinklers or {}
    SP_STATE.plants = type(SP_STATE.plants) == "table" and SP_STATE.plants or {}
    SP_STATE.mode = tostring(SP_STATE.mode or "random"):lower()
    if SP_STATE.mode ~= "near_plant" then SP_STATE.mode = "random" end

    local AUTO_SPRINKLER_SELECTED = cleanSelectedMap(arrayToMap(SP_STATE.sprinklers))
    local AUTO_SPRINKLER_PLANTS_SELECTED = cleanSelectedMap(arrayToMap(SP_STATE.plants))

    G.AUTO_SPRINKLER_SELECTED = AUTO_SPRINKLER_SELECTED
    _G.AUTO_SPRINKLER_SELECTED = AUTO_SPRINKLER_SELECTED
    G.AUTO_SPRINKLER_PLANTS_SELECTED = AUTO_SPRINKLER_PLANTS_SELECTED
    _G.AUTO_SPRINKLER_PLANTS_SELECTED = AUTO_SPRINKLER_PLANTS_SELECTED

    local function delayDisplay()
        local n = tonumber(SP_STATE.delay)
        return (n ~= nil) and n or 1
    end

    local function writeSprinklerGlobals()
        local api = G.__GAG2_SPRINKLER_ENABLE_API or rawget(_G, "__GAG2_SPRINKLER_ENABLE_API")
        if type(api) == "table" and type(api.get) == "function" then
            SP_STATE.enabled = (api.get() == true)
        end

        G.AUTO_SPRINKLER_ENABLED = (SP_STATE.enabled == true)
        _G.AUTO_SPRINKLER_ENABLED = G.AUTO_SPRINKLER_ENABLED
        G.AUTO_SPRINKLER_DELAY = tonumber(SP_STATE.delay) or 1
        _G.AUTO_SPRINKLER_DELAY = G.AUTO_SPRINKLER_DELAY
        G.AUTO_SPRINKLER_MODE = SP_STATE.mode
        _G.AUTO_SPRINKLER_MODE = SP_STATE.mode
        G.AUTO_SPRINKLER_SELECTED = AUTO_SPRINKLER_SELECTED
        _G.AUTO_SPRINKLER_SELECTED = AUTO_SPRINKLER_SELECTED
        G.AUTO_SPRINKLER_PLANTS_SELECTED = AUTO_SPRINKLER_PLANTS_SELECTED
        _G.AUTO_SPRINKLER_PLANTS_SELECTED = AUTO_SPRINKLER_PLANTS_SELECTED

        patchAutoOnly("sprinkler", {
            enabled    = (SP_STATE.enabled == true),
            sprinklers = mapToArray(AUTO_SPRINKLER_SELECTED),
            plants     = mapToArray(AUTO_SPRINKLER_PLANTS_SELECTED),
            mode       = SP_STATE.mode,
            delay      = SP_STATE.delay,
        })
    end

    G.__GAG2_PUSH_SPRINKLER = writeSprinklerGlobals
    _G.__GAG2_PUSH_SPRINKLER = writeSprinklerGlobals

    registerFlush("sprinkler", function()
        writeSprinklerGlobals()
    end)

    writeSprinklerGlobals()

    local plantRow
    local plantDropdownApi

    local function setPlantRowVisible(show)
        show = (show == true)
        if plantRow then plantRow.Visible = show end
    end

    local function syncSprinklerModule()
        writeSprinklerGlobals()
        local mod = G.AutoSprinkler or G.AutoSprinklerModule
        if type(mod) ~= "table" then return end

        local function __call(fn, ...)
            if type(mod[fn]) == "function" then
                pcall(mod[fn], mod, ...)
            end
        end

        if G.AUTO_SPRINKLER_ENABLED then
            __call("Start")
        else
            __call("Stop")
        end
    end

    G.__GAG2_SYNC_AUTO_SPRINKLER = syncSprinklerModule
    _G.__GAG2_SYNC_AUTO_SPRINKLER = syncSprinklerModule

    local bodySprinkler = ui:CreateSection("Auto Sprinkler", false)

    ui:CreateRowDropdown(bodySprinkler, {
        label       = "Select Sprinkler",
        placeholder = "From inventory...",
        mode        = "multi",
        getItems = function()
            if SprinklerListView and type(SprinklerListView.buildInventorySprinklerItems) == "function" then
                return SprinklerListView.buildInventorySprinklerItems() or {}
            end
            if SprinklerListView and type(SprinklerListView.buildSprinklerItems) == "function" then
                return SprinklerListView.buildSprinklerItems() or {}
            end
            return { { key = "_none", name = "(No sprinklers in inventory)" } }
        end,
        initial = AUTO_SPRINKLER_SELECTED,
        onChanged = function(_, selectedMap)
            AUTO_SPRINKLER_SELECTED = cleanSelectedMap(selectedMap)
