-- Auto Tele: stop sebelum follow pet, start lagi setelah beli
----------------------------------------------------------------
local function _getAutoTeleMod()
    return G.AutoTele or rawget(_G, "AutoTele")
end

local function _teleIsOn()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" then
        return mod.IsEnabled() == true
    end
    local s = rawget(_G, "__GAG2_AUTO_TELE") or G.__GAG2_AUTO_TELE
    if type(s) == "table" then return s.enabled == true end
    return G.AUTO_TELE_ENABLED == true or rawget(_G, "AUTO_TELE_ENABLED") == true
end

local function _teleWasRunning()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsRunning) == "function" then
        return mod.IsRunning() == true
    end
    return false
end

local function _setBuyBusy(on)
    buyBusy = (on == true)
    G.__GAG2_AUTO_BUY_PET_BUSY = buyBusy
    _G.__GAG2_AUTO_BUY_PET_BUSY = buyBusy
end

local function _teleStopForBuy()
    teleWasOn = _teleIsOn() and _teleWasRunning()
    if not teleWasOn then
        telePaused = false
        return
    end
    telePaused = true
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.Stop) == "function" then
        pcall(mod.Stop, mod)
    end
end

local function _teleResumeNow()
    if not teleWasOn then
        telePaused = false
        return
    end
    telePaused = false
    teleWasOn = false
    G.__GAG2_AUTO_TELE_SUPPRESS = false
    _G.__GAG2_AUTO_TELE_SUPPRESS = false
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" and mod.IsEnabled() then
        if type(mod.Start) == "function" then pcall(mod.Start, mod) end
    end
end

local function _teleKeepPaused()
    if not teleWasOn then return end
    telePaused = true
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
end

