-- Character / pet ref
----------------------------------------------------------------
local function _getHRP()
    local ch = LP.Character
    if not ch then return nil end
    local hrp = ch:FindFirstChild("HumanoidRootPart")
    return hrp and hrp:IsA("BasePart") and hrp or nil
end

local function _refKey(ref) return ref and tostring(ref.Name) or "" end

local function _getWildRefFolder()
    if wildFolder and wildFolder.Parent then return wildFolder end
    local map = workspace:FindFirstChild("Map")
    if not map then return nil end
    local ref = map:FindFirstChild("WildPetRef")
    if ref and ref:IsA("Folder") then wildFolder = ref end
    return wildFolder
end

local function _getTargetPos(ref)
    local suffix = _refKey(ref)
    local spawns = workspace:FindFirstChild("Map") and workspace.Map:FindFirstChild("WildPetSpawns")
    if spawns and suffix ~= "" then
        for _, m in ipairs(spawns:GetChildren()) do
            if m:IsA("Model") and m.Name:sub(-#suffix) == suffix then
                local p = m.PrimaryPart or m:FindFirstChildWhichIsA("BasePart")
                if p then return p.Position end
            end
        end
    end
    return ref.Position
end

local function _tpUnder(ref)
    local h = _getHRP()
    if not h then return end
    local target = _getTargetPos(ref)
    local under = Vector3.new(target.X, target.Y + UNDER_Y, target.Z)
    pcall(function()
        local ch = LP.Character
        local cf = CFrame.new(under, target)
        if ch and ch.PrimaryPart then ch:PivotTo(cf)
        else h.CFrame = cf end
    end)
end

local function _inBuyRange(ref)
    local h = _getHRP()
    if not h or not ref then return false end
    local target = _getTargetPos(ref)
    return (h.Position - target).Magnitude <= BUY_RANGE
end

local function _matchPlotOwner(v)
    if v == nil or not LP then return false end
    return v == LP.UserId or v == LP.Name
        or tostring(v) == tostring(LP.UserId) or tostring(v) == LP.Name
end

local function _getPlayerPlot()
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens or not LP then return nil end

    local plotId = LP:GetAttribute("PlotId")
    local idStr = plotId ~= nil and tostring(plotId) or nil

    if idStr then
        for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
            local plot = gardens:FindFirstChild(name)
            if plot then return plot end
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _matchPlotOwner(plot:GetAttribute("OwnerId"))
            or _matchPlotOwner(plot:GetAttribute("Owner"))
            or _matchPlotOwner(plot:GetAttribute("OwnerUserId"))
            or _matchPlotOwner(plot:GetAttribute("UserId")) then
            return plot
        end
    end

    local myPlot = LP:GetAttribute("Plot") or LP:GetAttribute("PlotName")
        or LP:GetAttribute("GardenPlot") or LP:GetAttribute("PlotId")
    if myPlot then
        for _, name in ipairs({ tostring(myPlot), "Plot" .. tostring(myPlot), "Plot_" .. tostring(myPlot) }) do
            local plot = gardens:FindFirstChild(name)
            if plot then return plot end
        end
    end

    return nil
end

local function _getGardenCFrame()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" then
        local cf = nil
        if type(mod.ResolveTargetCFrame) == "function" then
            cf = mod.ResolveTargetCFrame()
        elseif type(mod.GetGardenCenterCFrame) == "function" then
            cf = mod.GetGardenCenterCFrame()
        end
        if typeof(cf) == "CFrame" then return cf end
    end

    local plot = _getPlayerPlot()
    if not plot then return nil end

    local spawn = plot:FindFirstChild("Spawn", true) or plot:FindFirstChild("SpawnLocation", true)
    if spawn and spawn:IsA("BasePart") then
        return spawn.CFrame + GARDEN_TP_OFFSET
    end

    if plot:IsA("Model") then
        local ok, cf = pcall(function() return plot:GetPivot() end)
        if ok and typeof(cf) == "CFrame" then
            return cf + GARDEN_TP_OFFSET
        end
    end

    return nil
end

local function _tpToGarden()
    local cf = _getGardenCFrame()
    if typeof(cf) ~= "CFrame" then return false end
    local h = _getHRP()
    local ch = LP.Character
    if not h or not ch then return false end
    local ok = pcall(function()
        if ch.PrimaryPart then ch:PivotTo(cf) else h.CFrame = cf end
    end)
    if ok then task.wait(GARDEN_WAIT) end
    return ok
end

local function _getSheckles()
    local v = tonumber(LP:GetAttribute("Sheckles"))
    if v then return v end
    local ls = LP:FindFirstChild("leaderstats")
    if ls then
        for _, n in ipairs({ "Sheckles", "Money", "Cash", "Coins" }) do
            local o = ls:FindFirstChild(n)
            if o and (o:IsA("IntValue") or o:IsA("NumberValue")) then return tonumber(o.Value) end
        end
    end
    return nil
end

local function _getPetTypes()
    if PetTypesCache then return PetTypesCache end
    local sd = ReplicatedStorage:FindFirstChild("SharedData")
    local pt = sd and sd:FindFirstChild("PetTypes")
    if pt and pt:IsA("ModuleScript") then
        local ok, mod = pcall(require, pt)
        if ok and type(mod) == "table" then PetTypesCache = mod end
    end
    return PetTypesCache
end

local function _resolvePetType(raw)
    if raw == nil then return nil end
    if type(raw) == "string" and raw ~= "" then return raw end
    if type(raw) == "number" then
        local petTypes = _getPetTypes()
        if petTypes then
            for name, val in pairs(petTypes) do
                if val == raw then return name end
            end
        end
    end
    return tostring(raw)
end

local function _getPetName(ref)
    if not ref then return nil end
    local n = ref:GetAttribute("PetName")
    if type(n) == "string" and n ~= "" then return n end
    local petType = ref:GetAttribute("PetType")
    if petType ~= nil then
        local resolved = _resolvePetType(petType)
        if type(resolved) == "string" and resolved ~= "" then return resolved end
    end
    for _, attr in ipairs({ "Species", "Pet", "PetId", "Name" }) do
        local v = ref:GetAttribute(attr)
        if type(v) == "string" and v ~= "" then return v end
    end
    return nil
end

local function _getPetData()
    if PetDataCache then return PetDataCache end
    local sd = ReplicatedStorage:FindFirstChild("SharedData")
    local pd = sd and sd:FindFirstChild("PetData")
    if pd and pd:IsA("ModuleScript") then
        local ok, mod = pcall(require, pd)
        if ok and type(mod) == "table" then PetDataCache = mod end
    end
    return PetDataCache
end

local function _getCatalogBasePrice(petName)
    if not petName then return 0 end
    local data = _getPetData()
    if not data then return 0 end
    local entry = data[petName]
    if type(entry) == "table" then
        local p = tonumber(entry.WildPrice or entry.TamePrice or entry.TameBasePrice
            or entry.BasePrice or entry.PurchasePrice or entry.Price)
        if p and p > 0 then return p end
    end
    return 0
end

local function _getPetCatalogEntry(petName)
    petName = tostring(petName or "")
    if petName == "" then return nil, nil end
    local data = _getPetData()
    if not data then return nil, nil end
    local cfg = data[petName]
    if type(cfg) == "table" then return cfg, petName end
    for key, entry in pairs(data) do
        if type(entry) == "table" then
            if entry.DisplayName == petName then return entry, key end
            if type(data.GetSpeciesDisplayName) == "function" then
                local ok, dn = pcall(data.GetSpeciesDisplayName, key)
                if ok and dn == petName then return entry, key end
            end
        end
    end
    return nil, nil
end

local function _getPetDisplayName(petKey)
    petKey = tostring(petKey or "")
    if petKey == "" then return nil end
    local entry = select(1, _getPetCatalogEntry(petKey))
    if entry and type(entry.DisplayName) == "string" and entry.DisplayName ~= "" then
        return entry.DisplayName
    end
    local data = _getPetData()
    if data and type(data.GetSpeciesDisplayName) == "function" then
        local ok, dn = pcall(data.GetSpeciesDisplayName, petKey)
        if ok and type(dn) == "string" and dn ~= "" then return dn end
    end
    return petKey
end

local function _getPetListView()
    return G.PetListView or rawget(_G, "PetListView")
end

local _STATIC_RARITY_RANK = {
    common = 1, uncommon = 2, rare = 3, epic = 4,
    legendary = 5, mythic = 6, divine = 7, secret = 8, super = 9,
}

local function _normRarityKey(s)
    return tostring(s or ""):lower():gsub("%s+", "")
end

local function _getRarityRank(rarity)
    rarity = tostring(rarity or "")
    if rarity == "" then return 0 end
    local plv = _getPetListView()
    if type(plv) == "table" and type(plv.getRarityRank) == "function" then
        local function callRank(name)
            local ok, rank = pcall(plv.getRarityRank, plv, name)
            if not ok then ok, rank = pcall(plv.getRarityRank, name) end
            if ok and type(rank) == "number" and rank > 0 then return rank end
            return 0
        end
        local rank = callRank(rarity)
        if rank > 0 then return rank end
    end
    return _STATIC_RARITY_RANK[_normRarityKey(rarity)] or 0
end

local function _getRareRankThreshold()
    return _STATIC_RARITY_RANK.rare or 3
end

local function _isRarityAboveRare(rarity)
    local rank = _getRarityRank(rarity)
    return rank > _getRareRankThreshold()
end

local function _resolvePetRarity(ref, petKey, petName)
    if ref then
        local attr = ref:GetAttribute("Rarity")
        if attr ~= nil and tostring(attr) ~= "" and tostring(attr) ~= "Unknown" then
            return tostring(attr)
        end
    end
    local data = _getPetData()
    if data and petKey ~= "" then
        local entry = data[petKey]
        if type(entry) == "table" and entry.Rarity then return tostring(entry.Rarity) end
    end
    return nil
end

local function _isStealRef(ref)
    local o = tonumber(ref:GetAttribute("OwnerUserId"))
    return o ~= nil and o ~= 0 and o ~= LP.UserId
end

local function _isFreshSpawn(ref)
    if not ref then return false end
    local o = ref:GetAttribute("OwnerUserId")
    if o == nil then return true end
    local n = tonumber(o)
    return n == nil or n == 0
end

local function _isOwned(ref)
    local o = tonumber(ref:GetAttribute("OwnerUserId"))
    return o ~= nil and o == LP.UserId
end

local function _getBasePrice(ref)
    local key = _refKey(ref)
    if key ~= "" and refBasePrice[key] then return refBasePrice[key] end
    local catalog = _getCatalogBasePrice(_getPetName(ref))
    local price = tonumber(ref:GetAttribute("Price")) or 0
    local base = (catalog > 0) and catalog or price
    if base <= 0 then base = price end
    if key ~= "" then refBasePrice[key] = base end
    return base
end

local function _withinMaxPrice(ref)
    local base = _getBasePrice(ref)
    local price = tonumber(ref:GetAttribute("Price")) or 0
    if base <= 0 or price <= 0 then return true end
    return (price / base) <= _getMaxPriceMult() + 0.001
end

local function _getPriceMult(ref)
    local base = _getBasePrice(ref)
    local price = tonumber(ref:GetAttribute("Price")) or 0
    if base <= 0 or price <= 0 then return 1 end
    return price / base
end

local function _canAfford(ref)
    local price = tonumber(ref:GetAttribute("Price")) or 0
    if price <= 0 then return true end
    local money = _getSheckles()
    return type(money) ~= "number" or money >= price
end

local function _matchesFilter(ref, selected)
    local name = _getPetName(ref)
    if not name or not _hasAnySelected(selected) then return false end
    return selected[name] == true
end

local function _canTarget(ref, selected)
    if not ref or not ref.Parent or not _enabled() then return false end
    if _isOwned(ref) then return false end
    if not _matchesFilter(ref, selected) then return false end
    if not _getPetName(ref) then return false end
    if not _canAfford(ref) then return false end
    if not _withinMaxPrice(ref) then return false end

    if _isStealRef(ref) then
        -- Auto Tame ON: pet milik orang lain → tame/outbid (ikut max price UI)
        if not _autoTameEnabled() then return false end
        local tameable = ref:GetAttribute("Tameable")
        if tameable == false then return false end
        return true
    end

    -- Auto Tame OFF: hanya wild spawn baru (belum ada owner)
    if not _autoTameEnabled() then
        return _isFreshSpawn(ref)
    end

    -- Auto Tame ON + bukan steal: fresh spawn juga boleh dibeli
    return _isFreshSpawn(ref)
end

----------------------------------------------------------------
-- Webhook
----------------------------------------------------------------
local function _webhookDisplayPrice(ref, attrPrice)
    attrPrice = math.floor(tonumber(attrPrice) or 0)
    if attrPrice <= 0 then return 0 end
    if not ref or _isStealRef(ref) then return attrPrice end
    local tameBase = _getCatalogBasePrice(_getPetName(ref))
    if tameBase > 0 and attrPrice >= tameBase * 2 - 1 and attrPrice <= tameBase * 2 + 1 then
        return tameBase
    end
    local owner = tonumber(ref:GetAttribute("OwnerUserId"))
    if (not owner or owner == 0) and attrPrice % 2 == 0 then
        return math.floor(attrPrice / 2)
    end
    return attrPrice
end

local function _readRefForWebhook(ref)
    if not ref then return nil end
    local petKey = _getPetName(ref)
    if not petKey then return nil end
    local petName = _getPetDisplayName(petKey) or petKey
    local key = _refKey(ref)
    local price = tonumber(ref:GetAttribute("Price")) or refLastPrice[key] or 0
    return {
        petKey = petKey,
        petName = petName,
        rarity = _resolvePetRarity(ref, petKey, petName) or "",
        price = _webhookDisplayPrice(ref, price),
        refKey = key,
        at = os.clock(),
    }
end

local function _rememberWebhookTame(ref)
    lastWebhookTame = _readRefForWebhook(ref)
end

local function _notifyPetBuyWebhook(ref)
    local key = ref and _refKey(ref) or ""
    if key ~= "" and webhookSentKeys[key] then return end

    local info = lastWebhookTame
    if ref then
        local fresh = _readRefForWebhook(ref)
        if fresh then info = fresh end
    end
    if not info then return end

    local petName = info.petName or _getPetDisplayName(info.petKey)
    local rarity = _resolvePetRarity(ref, info.petKey, petName) or info.rarity or ""
    rarity = tostring(rarity)
    if rarity == "" or not _isRarityAboveRare(rarity) then return end

    lastWebhookTame = nil
    if key ~= "" then webhookSentKeys[key] = true end

    task.spawn(function()
        local wh = G.WebhookModule or G.Webhook or _G.WebhookModule or _G.Webhook
        if type(wh) ~= "table" or type(wh.SendPetBuy) ~= "function" then return end
        pcall(wh.SendPetBuy, {
            player = LP.Name,
            petName = petName,
            rarity = rarity,
            price = tonumber(info.price) or 0,
        })
    end)
end

local function _markFireAttempt(ref)
    local key = _refKey(ref)
    if key ~= "" then
        refLastPrice[key] = _webhookDisplayPrice(ref, ref:GetAttribute("Price"))
    end
    pcall(_rememberWebhookTame, ref)
end

----------------------------------------------------------------
-- Fire remote
----------------------------------------------------------------
local function _fireTameRemote(ref)
    if not ref or not WildPetTame then return false end
    return pcall(function()
        if type(WildPetTame.Fire) == "function" then
            WildPetTame:Fire(ref)
        else
            WildPetTame:InvokeServer(ref)
        end
    end)
end

local function _fireInterval(ref)
    return _isStealRef(ref) and STEAL_FIRE_SEC or FIRE_SEC
end

----------------------------------------------------------------
-- Core: follow bawah pet → fire sampai beli
----------------------------------------------------------------
local function _pickBest(folder, selected)
    local best, bestScore, bestD = nil, -math.huge, math.huge
    local h = _getHRP()
    if not h then return nil end
    for _, ref in ipairs(folder:GetChildren()) do
        if ref:IsA("BasePart") and _canTarget(ref, selected) then
            local score = _isStealRef(ref) and 1000 or 0
            local d = (_getTargetPos(ref) - h.Position).Magnitude
            if not best or score > bestScore or (score == bestScore and d < bestD) then
                best, bestScore, bestD = ref, score, d
            end
        end
    end
    return best
end

local function _hasMoreTargets(folder, selected)
    return folder and _pickBest(folder, selected) ~= nil
end

local function _followBuyUntilDone(ref, selected)
    if not _canTarget(ref, selected) or not _getHRP() then return false end

    stats.attempts += 1
    _setBuyBusy(true)
    _teleStopForBuy()
    pending[ref] = nil

    -- Sebelum ke pet: garden dulu
    _tpToGarden()

    local lastFire = 0
    local bought = false

    while running and _enabled() and ref.Parent and not _isOwned(ref) do
        if not _canTarget(ref, selected) then break end
        if not _withinMaxPrice(ref) then break end

        _tpUnder(ref)

        -- Hanya pause fire kalau bid kita yang menang (tunggu OwnerUserId update)
        if pending[ref] ~= true then
            local now = os.clock()
            if now - lastFire >= _fireInterval(ref) then
                if _fireTameRemote(ref) then
                    lastFire = now
                    stats.fired += 1
                    _markFireAttempt(ref)
                end
            end
        end

        if _isOwned(ref) then
            bought = true
            break
        end

        task.wait(STICK_SEC)
    end

    if _isOwned(ref) then bought = true end

    if bought then
        stats.ok += 1
        pcall(_notifyPetBuyWebhook, ref)
        _tpToGarden()
        _teleResumeNow()
    else
        stats.fail += 1
        if _hasMoreTargets(_getWildRefFolder(), selected) then
            _teleKeepPaused()
        else
            _teleResumeNow()
        end
    end

    _setBuyBusy(false)
    lastBuyEndAt = os.clock()
    return bought
end

----------------------------------------------------------------
-- Scan / watchers
----------------------------------------------------------------
local function _bindFolder(folder)
    if not folder or boundFolder == folder then return end
    if childConn then childConn:Disconnect(); childConn = nil end
    boundFolder = folder
    childConn = folder.ChildAdded:Connect(function(ref)
        if running and _enabled() and not buyBusy and ref:IsA("BasePart") then
            task.defer(function()
                local sel = _getActiveSelected()
                if running and not buyBusy and ref.Parent and _canTarget(ref, sel) then
                    _followBuyUntilDone(ref, sel)
                end
            end)
        end
    end)
end

local function _ensureWatchers()
    local map = workspace:FindFirstChild("Map")
    if map and not mapConn then
        mapConn = map.ChildAdded:Connect(function(child)
            if child.Name == "WildPetRef" and child:IsA("Folder") then
                wildFolder = child
                _bindFolder(child)
            end
        end)
    end
    local folder = _getWildRefFolder()
    if folder then _bindFolder(folder) end
    return folder
end

local function _scanFolder(folder, selected)
    if not folder or buyBusy or not _enabled() then return 0 end
    if os.clock() - lastBuyEndAt < BUY_GAP then return 0 end
    if not next(selected) then return 0 end

    local target = _pickBest(folder, selected)
    if not target then return 0 end

    return _followBuyUntilDone(target, selected) and 1 or 0
end

local function _mainLoop(myId)
    task.wait()
    local sel = _getActiveSelected()
    while running and loopId == myId do
        if _enabled() then
            local folder = _ensureWatchers()
            if folder then
                pcall(_scanFolder, folder, sel)
                sel = _getActiveSelected()
            end
            task.wait(SCAN_SEC)
        else
            task.wait(0.5)
        end
    end
end

if WildPetTameResult then
    pcall(function()
        WildPetTameResult.OnClientEvent:Connect(function(ref, uid)
            if not ref then return end
            if uid == LP.UserId then
                pending[ref] = true
                pcall(_notifyPetBuyWebhook, ref)
            else
                pending[ref] = nil
            end
        end)
    end)
end

----------------------------------------------------------------
-- Module API
----------------------------------------------------------------
function M.Start()
    if not _enabled() then running = false; return end
    local sel = _selected()
    if next(sel) then activeSelected = sel end
    _ensureWatchers()
    running = true
    loopId += 1
    local myId = loopId
    task.spawn(function() pcall(_mainLoop, myId) end)
    task.defer(function()
        if running and loopId == myId and _enabled() then
            local folder = _getWildRefFolder()
            if folder then pcall(_scanFolder, folder, _getActiveSelected()) end
        end
    end)
end
M.start = M.Start

function M.Stop()
    running = false
    _setBuyBusy(false)
    _teleResumeNow()
    if childConn then childConn:Disconnect(); childConn = nil end
end
M.stop = M.Stop

function M.IsRunning() return running end

function M.TameOnce()
    if not _enabled() then return 0 end
    local folder = _ensureWatchers()
    return folder and _scanFolder(folder, _getActiveSelected()) or 0
end
M.tameOnce = M.TameOnce

function M.SetEnabled(a, b)
    local on = _boolArg(a, b)
    _patchStore({ enabled = on })
    G.AUTO_BUY_PET_ENABLED = on
    _G.AUTO_BUY_PET_ENABLED = on
    if on then M.Start() else M.Stop() end
end
M.setEnabled = M.SetEnabled

function M.ApplyRuntime(a, b)
    local on = (a == nil and b == nil) and _enabled() or _boolArg(a, b)
    M.SetEnabled(on)
    return on
end
M.applyRuntime = M.ApplyRuntime

function M.EnsureRunning()
    if not _enabled() then M.Stop(); return false end
    if not running then M.Start() end
    return running
end
M.ensureRunning = M.EnsureRunning

function M.SetAutoTame(a, b)
    local on = _boolArg(a, b)
    _patchStore({ auto_tame = on })
    G.AUTO_TAME_PET_ENABLED = on
    _G.AUTO_TAME_PET_ENABLED = on
    if on and _enabled() and running then
        task.defer(function()
            if _autoTameEnabled() and _enabled() and running then
                M.TameOnce()
            end
        end)
    end
end
M.setAutoTame = M.SetAutoTame

function M.SetMaxPriceMult(a, b)
    local m = tonumber(_secondArg(a, b)) or 2
    if m < 1 then m = 1 end
    _patchStore({ max_price_mult = m })
    G.AUTO_BUY_PET_MAX_PRICE_MULT = m
    _G.AUTO_BUY_PET_MAX_PRICE_MULT = m
end
M.setMaxPriceMult = M.SetMaxPriceMult

function M.SetSelected(a, b)
    local map = _secondArg(a, b)
    if type(map) ~= "table" then return end
    map = _normalizeSet(map)
    activeSelected = map
    _patchStore({ selected = map })
    G.BUY_PET_SELECTED = map
    _G.BUY_PET_SELECTED = map
    if next(map) then
        G.GAG2_PET_LIST = _setToArray(map)
        _G.GAG2_PET_LIST = G.GAG2_PET_LIST
    end
end
M.setSelected = M.SetSelected

function M.SyncFromGlobals()
    local on = _enabled()
    G.AUTO_BUY_PET_ENABLED = on
    _G.AUTO_BUY_PET_ENABLED = on
    G.AUTO_TAME_PET_ENABLED = _autoTameEnabled()
    _G.AUTO_TAME_PET_ENABLED = G.AUTO_TAME_PET_ENABLED
    G.AUTO_BUY_PET_MAX_PRICE_MULT = _getMaxPriceMult()
    _G.AUTO_BUY_PET_MAX_PRICE_MULT = G.AUTO_BUY_PET_MAX_PRICE_MULT
    local sel = _selected()
    if next(sel) then M.SetSelected(sel) end
    if on then M.Start() else M.Stop() end
end
M.syncFromGlobals = M.SyncFromGlobals
M.SyncFromState = M.SyncFromGlobals
M.syncFromState = M.SyncFromGlobals

function M.GetState()
    local st = getState()
    return {
        enabled = st.enabled,
        autoTame = st.autoTame,
        selected = st.selected,
        selectedList = _setToArray(st.selected),
    }
end
M.getState = M.GetState

function M.GetDiagnostics()
    local folder = _getWildRefFolder()
    local st = getState()
    local selected = st.selected
    local allRefs = {}
    if folder then
        for _, ref in ipairs(folder:GetChildren()) do
            if ref:IsA("BasePart") and _getPetName(ref) then
                allRefs[#allRefs + 1] = {
                    name = ref.Name,
                    petName = _getPetName(ref),
                    price = ref:GetAttribute("Price"),
                    owner = ref:GetAttribute("OwnerUserId"),
                    matched = _matchesFilter(ref, selected),
                    targetable = _canTarget(ref, selected),
                    steal = _isStealRef(ref),
                    fresh = _isFreshSpawn(ref),
                    inRange = _inBuyRange(ref),
                    priceMult = string.format("%.2fx", _getPriceMult(ref)),
                    maxMult = _getMaxPriceMult(),
                }
            end
        end
    end
    return {
        enabled = st.enabled,
        autoTame = st.autoTame,
        running = running,
        buyBusy = buyBusy,
        teleWasOn = teleWasOn,
        maxPriceMult = _getMaxPriceMult(),
        selected = _setToArray(selected),
        wildFolder = folder and folder:GetFullName() or nil,
        stats = stats,
        allRefs = allRefs,
    }
end
M.getDiagnostics = M.GetDiagnostics
M.PrintDiagnostics = M.GetDiagnostics
M.printDiagnostics = M.GetDiagnostics
M.runDiagnostics = M.GetDiagnostics

G.AutoBuyPet = M
G.AutoBuyPetModule = M
_G.AutoBuyPet = M
_G.AutoBuyPetModule = M

task.defer(function()
    _setBuyBusy(false)
    if _enabled() then M.EnsureRunning() end
end)

return M
 end,            required = false },
