            return LP:WaitForChild("PlayerScripts", 8)
        end)
        if ok then ps = child end
    end
    if ps then
        local m = tryKnownPaths(ps)
        if m then return m end
        m = waitMailboxCatalog(ps, 6)
        if m then return m end
    end

    if not sps then
        local ok, child = pcall(function()
            return StarterPlayer:WaitForChild("StarterPlayerScripts", 6)
        end)
        if ok then sps = child end
    end
    if sps then
        local m = waitMailboxCatalog(sps, 6)
        if m then return m end
    end
    local pg = LP:FindFirstChild("PlayerGui")
    if pg then
        local m = pick(pg:FindFirstChild("MailboxItemCatalog", true))
        if m then return m end
    end
    local cm = ReplicatedStorage:FindFirstChild("ClientModules")
    if cm then
        local m = pick(cm:FindFirstChild("MailboxItemCatalog", true))
        if m then return m end
    end
    local shared = ReplicatedStorage:FindFirstChild("SharedModules")
    if shared then
        local m = pick(shared:FindFirstChild("MailboxItemCatalog", true))
        if m then return m end
    end
    return pick(ReplicatedStorage:FindFirstChild("MailboxItemCatalog", true))
end

local function _invokeCatalog(methodName, ...)
    if not MailboxCatalog then return false, nil end
    local fn = MailboxCatalog[methodName]
    if type(fn) ~= "function" then return false, nil end
    local a1, a2, a3, a4 = ...
    local ok, res = pcall(fn, a1, a2, a3, a4)
    if ok then return true, res end
    ok, res = pcall(fn, MailboxCatalog, a1, a2, a3, a4)
    if ok then return true, res end
    return false, nil
end

local function _normalizeCategoryList(cats)
    if type(cats) ~= "table" then return {} end
    if #cats > 0 then
        local out = {}
        for _, key in ipairs(cats) do
            if type(key) == "string" and key ~= "" then
                out[#out + 1] = key
            end
        end
        return out
    end
    local out = {}
    for key, val in pairs(cats) do
        if type(val) == "string" and val ~= "" then
            out[#out + 1] = val
        elseif type(key) == "string" and key ~= "" and (val == true or val == 1) then
            out[#out + 1] = key
        end
    end
    table.sort(out)
    return out
end

local function _catalogIsGiftable(cat)
    if not MailboxCatalog then return false end
    cat = tostring(cat or "")
    for _, key in ipairs(_normalizeCategoryList(MailboxCatalog.Categories)) do
        if key == cat then return true end
    end
    local ok, res = _invokeCatalog("IsGiftable", cat)
    return ok and res == true
end

local function _ensureMailboxCatalog(force)
    if force then
        MailboxCatalog = nil
        catalogLoadedFromGame = false
        catalogModuleInst = nil
    end
    if MailboxCatalog and catalogLoadedFromGame then
        return true
    end
    local modScript = _findCatalogModule()
    if modScript then
        local ok, mod = pcall(require, modScript)
        if ok and type(mod) == "table" and type(mod.Categories) == "table" then
            MailboxCatalog = mod
            catalogLoadedFromGame = true
            return true
        end
    end
    return false
end

local function _catalogCategories()
    if not _ensureMailboxCatalog() then return {} end
    return _normalizeCategoryList(MailboxCatalog.Categories)
end

local function _remoteCallable(remote)
    if remote == nil then return false end
    if type(remote) == "table" then
        return type(remote.Fire) == "function" or type(remote.Invoke) == "function"
    end
    if typeof(remote) == "Instance" then
        return remote:IsA("RemoteFunction") or remote:IsA("RemoteEvent")
    end
    return false
end

local function _callNetworkingRemote(remote, ...)
    if not _remoteCallable(remote) then
        return false, "no_remote"
    end
    local args = table.pack(...)

    local function invoke()
        if type(remote) == "table" then
            if type(remote.Fire) == "function" then
                if args.n > 0 then
                    return remote:Fire(table.unpack(args, 1, args.n))
                end
                return remote:Fire()
            end
            if type(remote.Invoke) == "function" then
                if args.n > 0 then
                    return remote:Invoke(table.unpack(args, 1, args.n))
                end
                return remote:Invoke()
            end
        end
        if typeof(remote) == "Instance" then
            if remote:IsA("RemoteFunction") then
                if args.n > 0 then
                    return remote:InvokeServer(table.unpack(args, 1, args.n))
                end
                return remote:InvokeServer()
            end
            if remote:IsA("RemoteEvent") then
                if args.n > 0 then
                    remote:FireServer(table.unpack(args, 1, args.n))
                else
                    remote:FireServer()
                end
                return nil
            end
        end
        error("networking remote not callable")
    end

    local results = table.pack(pcall(invoke))
    if not results[1] then
        return false, results[2]
    end
    return true, results[2], results[3], results[4], results[5]
end

local function _clearNetworkingCache()
    Networking = nil
    MailboxSendBatch = nil
    MailboxLookup = nil
    MailboxList = nil
    MailboxClaim = nil
    MailboxOpenInbox = nil
    MailboxUpdated = nil
end

local function _ensureNetworking()
    if Networking and _remoteCallable(MailboxSendBatch) then return true end
    local ok, net = pcall(function()
        return require(ReplicatedStorage:WaitForChild("SharedModules"):WaitForChild("Networking"))
    end)
    if ok and type(net) == "table" then
        Networking = net
        if net.Mailbox then
            MailboxSendBatch = net.Mailbox.SendBatch
            MailboxLookup = net.Mailbox.LookupPlayer
            MailboxList = net.Mailbox.List
            MailboxClaim = net.Mailbox.Claim
            MailboxOpenInbox = net.Mailbox.OpenInbox
            MailboxUpdated = net.Mailbox.Updated
        end
    end
    return _remoteCallable(MailboxSendBatch)
end

local function _ensureGiftingNetworking()
    if not _ensureNetworking() then return false end
    if type(Networking) ~= "table" or type(Networking.Gifting) ~= "table" then
        return false
    end
    GiftingPrompted = Networking.Gifting.Prompted
    GiftingResponse = Networking.Gifting.Response
    return GiftingPrompted ~= nil
        and GiftingPrompted.OnClientEvent ~= nil
        and _remoteCallable(GiftingResponse)
end

local function _onNormalGiftPrompted(senderPlayer, _itemName)
    if cfg.auto_accept_gift ~= true then return end
    if typeof(senderPlayer) ~= "Instance" or not senderPlayer:IsA("Player") then return end
    if not senderPlayer.Parent then return end
    if not _ensureGiftingNetworking() then return end

    task.defer(function()
        if cfg.auto_accept_gift ~= true then return end
        if not senderPlayer.Parent then return end
        local ok = _callNetworkingRemote(GiftingResponse, senderPlayer, true)
        if ok then
            stats.acceptedNormalGifts = (stats.acceptedNormalGifts or 0) + 1
            _setStatus("Accepted gift from " .. tostring(senderPlayer.Name))
            _log("accepted normal gift from", senderPlayer.Name, _itemName)
        else
            _log("accept normal gift failed from", senderPlayer.Name)
        end
    end)
end

local function _bindNormalGiftAccept()
    if acceptGiftConn then
        pcall(function() acceptGiftConn:Disconnect() end)
        acceptGiftConn = nil
    end
    if not _ensureGiftingNetworking() then return false end
    acceptGiftConn = GiftingPrompted.OnClientEvent:Connect(_onNormalGiftPrompted)
    return true
end

local function _applyInboxData(data)
    if type(data) ~= "table" then
        table.clear(inboxGifts)
        return
    end

    local box = data.Mailbox
    if type(box) ~= "table" then
        if data.PendingInvites == nil and data.Badge == nil then
            box = data
        else
            return
        end
    end

    table.clear(inboxGifts)
    for giftId, payload in pairs(box) do
        local key = tostring(giftId)
        if key ~= "" and type(payload) == "table" then
            inboxGifts[key] = payload
        end
    end
end

local function _refreshInboxFromServer()
    if not _mailboxUsable() then return false end

    for _ = 1, 4 do
        if not _ensureNetworking() or not _remoteCallable(MailboxOpenInbox) then
            _clearNetworkingCache()
            task.wait(0.25)
            continue
        end

        local ok, data = _callNetworkingRemote(MailboxOpenInbox)
        if ok and type(data) == "table" then
            _applyInboxData(data)
            return true
        end
        break
    end
    return false
end

local function _trackMailboxInbox()
    if inboxConn then return end
    if not _ensureNetworking() then return end

    if MailboxUpdated and MailboxUpdated.OnClientEvent then
        inboxConn = MailboxUpdated.OnClientEvent:Connect(function(data)
            pcall(_applyInboxData, data)
        end)
    end

    task.spawn(function()
        task.wait(2)
        pcall(_refreshInboxFromServer)
    end)
end

local function _ensurePlayerState()
    if PlayerStateClient then return true end
    local function tryRequire(modInst)
        if not modInst then return false end
        local ok, mod = pcall(require, modInst)
        if ok and type(mod) == "table" then
            PlayerStateClient = mod
            return true
        end
        return false
    end
    local cm = ReplicatedStorage:FindFirstChild("ClientModules")
    if cm and tryRequire(cm:FindFirstChild("PlayerStateClient")) then return true end
    local ok = pcall(function()
        return tryRequire(ReplicatedStorage:WaitForChild("ClientModules", 15):WaitForChild("PlayerStateClient"))
    end)
    return ok and PlayerStateClient ~= nil
end

local function _getInventory(waitSec)
    waitSec = tonumber(waitSec) or 0
    if not _ensurePlayerState() then return nil end
    if type(PlayerStateClient.GetLocalReplica) ~= "function" then return nil end
    local replica = PlayerStateClient:GetLocalReplica()
    local deadline = os.clock() + waitSec
    while not replica and os.clock() < deadline do
        task.wait(0.1)
        replica = PlayerStateClient:GetLocalReplica()
    end
    if not replica or type(replica.Data) ~= "table" then return nil end
    local inv = replica.Data.Inventory
    return type(inv) == "table" and inv or nil
end

local function _entryUniqueId(entry, itemKey)
    if type(entry) == "table" then
        local id = entry.Id or entry.UUID or entry.PetId or entry.InstanceId
            or entry.Guid or entry.UniqueId or entry.PetUUID
        if id ~= nil and tostring(id) ~= "" then
            return tostring(id)
        end
    end
    if itemKey ~= nil and tostring(itemKey) ~= "" then
        return tostring(itemKey)
    end
    return nil
end

local function _isUniqueInventoryEntry(entry, itemKey)
    if type(entry) ~= "table" then return false end
    if _entryUniqueId(entry, itemKey) ~= nil then return true end
    return entry.Type ~= nil or entry.PetName ~= nil or entry.PetType ~= nil
        or entry.Name ~= nil or entry.DisplayName ~= nil
end

local function _bagHasEntries(bag)
    if type(bag) ~= "table" then return false end
    local nested = bag.List or bag.Items
    if type(nested) == "table" and #nested > 0 then return true end
    for itemKey in pairs(bag) do
        local keyStr = tostring(itemKey)
        if keyStr:sub(1, 1) ~= "_" then
            return true
        end
    end
    return false
end

local function _eachBagEntry(bag, fn)
    if type(bag) ~= "table" or type(fn) ~= "function" then return end
    local nested = bag.List or bag.Items
    if type(nested) == "table" and (bag.List ~= nil or bag.Items ~= nil) and #nested > 0 then
        for idx, entry in ipairs(nested) do
            fn(_entryUniqueId(entry, idx) or tostring(idx), entry)
        end
        return
    end
    for itemKey, entry in pairs(bag) do
        local keyStr = tostring(itemKey)
        if keyStr:sub(1, 1) == "_" then
            continue
        end
        fn(itemKey, entry)
    end
end

local function _getInventoryBag(inv, category)
    if type(inv) ~= "table" then return nil, "" end
    category = _canonicalCategory(category)
    if category == "" then return nil, category end
    local fallbacks = CATEGORY_BAG_FALLBACKS[category]
    if type(fallbacks) == "table" then
        local emptyBag = nil
        for _, key in ipairs(fallbacks) do
            local bag = inv[key]
            if type(bag) == "table" then
                if _bagHasEntries(bag) then return bag, category end
                if not emptyBag then emptyBag = bag end
            end
        end
        if emptyBag then return emptyBag, category end
    end
    local bag = inv[category]
    if type(bag) == "table" then return bag, category end
    local alt = INVENTORY_BAG_ALIASES[category]
    if alt and type(inv[alt]) == "table" then return inv[alt], category end
    for legacy, canon in pairs(INVENTORY_BAG_ALIASES) do
        if canon == category and type(inv[legacy]) == "table" then
            return inv[legacy], category
        end
    end
    local lower = category:lower()
    for key, bag in pairs(inv) do
        if type(bag) == "table" and tostring(key):lower() == lower then
            return bag, category
        end
    end
    return nil, category
end

local function _isUniqueEntryCategory(cat, bag)
    if type(bag) == "table" then
        for _, entry in pairs(bag) do
            if type(entry) == "table" then return true end
            if tonumber(entry) then return false end
        end
    end
    return false
end

local function _isCountBasedCategory(cat, inv)
    cat = _canonicalCategory(cat)
    if cat == "" then return true end
    inv = inv or _getInventory()
    local bag = inv and _getInventoryBag(inv, cat)
    return not _isUniqueEntryCategory(cat, bag)
end

local function _rebuildCategoryDefs()
    if not _ensureMailboxCatalog() then
        return
    end
    local defs = {}
    local inv = nil
    local okInv, invResult = pcall(_getInventory, 2)
    if okInv then inv = invResult end
    for _, key in ipairs(_catalogCategories()) do
        if _catalogIsGiftable(key) then
            local bag = inv and _getInventoryBag(inv, key)
            defs[#defs + 1] = {
                key = key,
                label = _categoryLabel(key),
                countBased = not _isUniqueEntryCategory(key, bag),
            }
        end
    end
    CATEGORY_DEFS = defs
end

local function _defaultSendTotals()
    local totals = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        totals[def.key] = MAX_BATCH
    end
    return totals
end

local function _ensureCfgCategoryTables()
    cfg.categories = type(cfg.categories) == "table" and cfg.categories or {}
    cfg.selected = type(cfg.selected) == "table" and cfg.selected or {}
    cfg.send_totals = type(cfg.send_totals) == "table" and cfg.send_totals or {}
    for _, def in ipairs(CATEGORY_DEFS) do
        local key = def.key
        if cfg.categories[key] == nil then
            cfg.categories[key] = false
        end
        if type(cfg.selected[key]) ~= "table" then
            cfg.selected[key] = {}
        end
        if cfg.send_totals[key] == nil then
            cfg.send_totals[key] = MAX_BATCH
        end
    end
end

local function _petTypeName(entry, itemKey)
    if type(entry) == "table" then
        return tostring(entry.Type or entry.PetType or entry.PetName or entry.Name or entry.DisplayName or itemKey)
    end
    return tostring(itemKey)
end

local function _resolveDisplayName(category, itemKey, entry)
    if _ensureMailboxCatalog() then
        local ok, name = _invokeCatalog("Resolve", category, itemKey, entry)
        if ok and name ~= nil and tostring(name) ~= "" then
            return tostring(name)
        end
    end
    if PET_LIKE_CATEGORIES[category] or type(entry) == "table" then
        local petName = _petTypeName(entry, itemKey)
        if petName ~= "" and petName ~= tostring(itemKey) then
            return petName
        end
    end
    return tostring(itemKey)
end

local function _mailboxUsable()
    local ok, flags = pcall(function()
        return require(ReplicatedStorage.SharedModules.Flags.MailboxFlags)
    end)
    if ok and type(flags) == "table" and flags.OpenEnabled then
        if type(flags.OpenEnabled.Get) == "function" then
            MailboxOpenEnabled = flags.OpenEnabled
            local okGet, enabled = pcall(flags.OpenEnabled.Get, flags.OpenEnabled)
            if okGet then
                return enabled == true
            end
        elseif type(flags.OpenEnabled) == "function" then
            local okCall, enabled = pcall(flags.OpenEnabled)
            if okCall then
                return enabled == true
            end
        end
    end
    return true
end

local function _isModuleMethodCall(first)
    return type(first) == "table" and type(first.BuildInventoryItems) == "function"
end

local function _categoryArg(first, second)
    if type(second) == "string" then return second end
    if type(first) == "string" then return first end
    return tostring(second or first or "")
end

local function _boolArg(first, second)
    if _isModuleMethodCall(first) then
        return second == true
    end
    return first == true
end

local function _configArg(first, second)
    if _isModuleMethodCall(first) then
        return second
    end
    return first
end

local function _strArg(first, second)
    if type(second) == "string" then return second end
    if type(first) == "string" then return first end
    return tostring(second or first or "")
end

function M.GetInventory(_self)
    return _getInventory(5)
end

function M.GetPlayerStatePath()
    return "ReplicatedStorage.ClientModules.PlayerStateClient -> GetLocalReplica().Data.Inventory"
end

function M.GetCatalogPath()
    if catalogModuleInst and catalogModuleInst.Parent then
        return catalogModuleInst:GetFullName()
    end
    return "StarterPlayer.StarterPlayerScripts.Controllers.MailboxController.MailboxItemCatalog"
end

function M.ReloadCatalog(a, b)
    local force = _boolArg(a, b)
    _ensureMailboxCatalog(force)
    _rebuildCategoryDefs()
    _ensureCfgCategoryTables()
    if not catalogLoadedFromGame then
        _setStatus("MailboxItemCatalog not loaded")
    elseif #CATEGORY_DEFS == 0 then
        _setStatus("Mailbox categories empty")
    end
end

function M.IsCatalogLoaded(_self)
    return catalogLoadedFromGame == true and #CATEGORY_DEFS > 0
end

function M.ListInventoryKeys(_self)
    local inv = _getInventory(5)
    if not inv then return {} end
    local keys = {}
    for key, bag in pairs(inv) do
        if type(bag) == "table" then
            keys[#keys + 1] = tostring(key)
        end
    end
    table.sort(keys)
    return keys
end

local function _categoryEnabled(key)
    key = _canonicalCategory(key)
    if cfg.categories[key] == true then return true end
    for legacy, canon in pairs(SAVE_CATEGORY_ALIASES) do
        if canon == key and cfg.categories[legacy] == true then return true end
    end
    return false
end

local function _categorySelected(key)
    key = _canonicalCategory(key)
    local sel = cfg.selected[key]
    if type(sel) ~= "table" then sel = {} end
    local out = _normalizeSet(sel)
    for legacy, canon in pairs(SAVE_CATEGORY_ALIASES) do
        if canon == key then
            local leg = cfg.selected[legacy]
            if type(leg) == "table" then
                for k, v in pairs(_normalizeSet(leg)) do
                    if v == true then out[k] = true end
                end
            end
        end
    end
    return out
end

local function _enabledCategoryKeys()
    local out = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        if _categoryEnabled(def.key) then
            out[#out + 1] = def.key
        end
    end
    return out
end

local function _matchesSelected(category, name, selectedMap, itemKey, entry)
    if not next(selectedMap) then return true end
    name = tostring(name or "")
    if name ~= "" and selectedMap[name] == true then return true end
    if itemKey ~= nil and selectedMap[tostring(itemKey)] == true then return true end
    local norm = name:lower():gsub("[%s_%-]+", "")
    for k, v in pairs(selectedMap) do
        if v == true and tostring(k):lower():gsub("[%s_%-]+", "") == norm then
            return true
        end
    end
    if entry ~= nil and _ensureMailboxCatalog() then
        local ok, resolved = _invokeCatalog("Resolve", category, itemKey, entry)
        if ok and resolved ~= nil and selectedMap[tostring(resolved)] == true then
            return true
        end
    end
    return false
end

local function _fruitTypeName(entry, itemKey)
    if type(entry) == "table" then
        return tostring(entry.PlantName or entry.FruitName or entry.Type or entry.Name or entry.SeedName or entry.DisplayName or itemKey)
    end
    return tostring(itemKey)
end

local function _isEquippedItemLegacy(itemKey, entry)
    if cfg.skip_equipped ~= true then return false end
    if type(entry) == "table" then
        local id = entry.Id or entry.UUID or entry.PetId or entry.InstanceId
            or entry.Guid or entry.UniqueId or entry.PetUUID
        if id ~= nil and equippedPets[tostring(id)] then return true end
        if entry.Equipped == true then return true end
    end
    if itemKey ~= nil and equippedPets[tostring(itemKey)] then return true end
    return false
end

local function _entryCount(entry)
    if type(entry) == "number" then return entry end
    local n = tonumber(entry)
    if type(n) == "number" then return n end
    if type(entry) == "table" then
        return tonumber(entry.Count or entry.Amount or entry.Quantity or entry.Stack or entry.Qty)
    end
    return nil
end

local function _isOwnedEntry(category, itemKey, entry)
    if type(entry) == "table" then
        if _isUniqueInventoryEntry(entry, itemKey) then
            return true
        end
        local n = _entryCount(entry)
        return type(n) == "number" and n > 0
    end
    local n = tonumber(entry)
    return type(n) == "number" and n > 0
end

local function _isGiftableEntry(category, itemKey, entry)
    category = _canonicalCategory(category)
    if type(entry) == "table" then
        if _isUniqueInventoryEntry(entry, itemKey) then
            if _isEquippedItemLegacy(itemKey, entry) then return false end
            return true
        end
        local n = _entryCount(entry)
        return type(n) == "number" and n > 0
    end
    local n = tonumber(entry)
    return type(n) == "number" and n > 0
end

local function _selectedMapForUi(category)
    local sel = _categorySelected(category)
    if next(sel) then return sel end
    local store = G.__GAG2_AUTO_GIFT or _G.__GAG2_AUTO_GIFT
    if type(store) == "table" and type(store.selected) == "table" then
        local cat = _canonicalCategory(category)
        local raw = store.selected[cat]
        if type(raw) == "table" then
            local out = _normalizeSet(raw)
            if next(out) then return out end
        end
        for legacy, canon in pairs(SAVE_CATEGORY_ALIASES) do
            if canon == cat and type(store.selected[legacy]) == "table" then
                local out = _normalizeSet(store.selected[legacy])
                if next(out) then return out end
            end
        end
    end
    return sel
end

local function _appendSelectedZeroItems(items, category)
    items = type(items) == "table" and items or {}
    local selectedMap = _selectedMapForUi(category)
    if not next(selectedMap) then return items end

    local have = {}
    for _, it in ipairs(items) do
        have[tostring(it.key)] = true
    end
    for selKey, on in pairs(selectedMap) do
        if on == true then
            local sk = tostring(selKey)
            if not have[sk] then
                items[#items + 1] = {
                    key = sk,
                    name = sk .. " x 0",
                    right = "0",
                    count = 0,
                }
            end
        end
    end
    table.sort(items, function(a, b) return a.name < b.name end)
    return items
end

local function _buildInventoryItems(category)
    category = _canonicalCategory(tostring(category or ""))
    if category == "" then return {} end

    local inv = _getInventory(10)
    if not inv then return _appendSelectedZeroItems({}, category) end

    local bag, sendCat = _getInventoryBag(inv, category)
    if type(bag) ~= "table" then return _appendSelectedZeroItems({}, category) end
    sendCat = sendCat or category

    _ensureMailboxCatalog()
    if not _catalogIsGiftable(category) and not next(bag) then
        return _appendSelectedZeroItems({}, category)
    end

    local items = {}
    local countBased = _isCountBasedCategory(sendCat, inv)

    if countBased then
        _eachBagEntry(bag, function(itemKey, count)
            if type(count) == "table" then
                if _isUniqueInventoryEntry(count, itemKey) then
                    if _isOwnedEntry(sendCat, itemKey, count) then
                        local typeName = _resolveDisplayName(sendCat, itemKey, count)
                        items[#items + 1] = {
                            key = typeName,
                            name = typeName .. " x 1",
                            right = "1",
                            count = 1,
                        }
                    end
                    return
                end
                count = _entryCount(count) or 0
            else
                count = tonumber(count) or 0
            end
            if _isOwnedEntry(sendCat, itemKey, count) then
                local key = tostring(itemKey)
                local displayName = _resolveDisplayName(sendCat, itemKey, type(count) == "table" and count or nil)
                items[#items + 1] = {
                    key = key,
                    name = displayName .. " x " .. _formatCount(count),
                    right = _formatCount(count),
                    count = count,
                }
            end
        end)
        table.sort(items, function(a, b) return a.key < b.key end)
        return _appendSelectedZeroItems(items, category)
    end

    local grouped = {}
    _eachBagEntry(bag, function(itemKey, entry)
        if _isOwnedEntry(sendCat, itemKey, entry) then
            local typeName = _resolveDisplayName(sendCat, itemKey, entry)
            grouped[typeName] = (grouped[typeName] or 0) + 1
        end
    end)

    for typeName, count in pairs(grouped) do
        items[#items + 1] = {
            key = typeName,
            name = typeName .. " x " .. _formatCount(count),
            right = _formatCount(count),
            count = count,
        }
    end
    table.sort(items, function(a, b) return a.name < b.name end)
    return _appendSelectedZeroItems(items, category)
end

function M.BuildInventoryItems(a, b)
    return _buildInventoryItems(_categoryArg(a, b))
end

function M.PeekCategory(a, b)
    local category = _canonicalCategory(_categoryArg(a, b))
    _ensureMailboxCatalog()
    local inv = _getInventory(5)
    local bag, sendCat = inv and _getInventoryBag(inv, category)
    print("[AutoGift] peek", category, "bag=", type(bag), "countBased=", inv and _isCountBasedCategory(sendCat, inv))
    if type(bag) == "table" then
        local n = 0
        _eachBagEntry(bag, function(k, e)
            n += 1
            if n <= 5 then
                print("  raw", k, type(e), "giftable=", _isGiftableEntry(sendCat, k, e),
                    "name=", _resolveDisplayName(sendCat, k, e))
            end
        end)
        print("  entries=", n, "ui items=", #_buildInventoryItems(category))
    end
end

M.PackCategory = M.PeekCategory

function M.DebugCategory(a, b)
    local category = _canonicalCategory(_categoryArg(a, b))
    if category == "" then
        warn("[AutoGift] DebugCategory: pass a category name, e.g. DebugCategory(ag, \"Pets\")")
        return
    end
    _ensureMailboxCatalog(true)
    local inv = _getInventory(10)
    local bag, sendCat = inv and _getInventoryBag(inv, category)
    sendCat = sendCat or category
    local lines = {
        "[AutoGift] DebugCategory " .. category,
        "  catalogLoaded=" .. tostring(catalogLoadedFromGame),
        "  giftable=" .. tostring(_catalogIsGiftable(category)),
        "  inventory=" .. tostring(inv ~= nil),
        "  bag=" .. tostring(type(bag)),
        "  bagEntries=" .. tostring(bag and _bagHasEntries(bag)),
        "  countBased=" .. tostring(inv and _isCountBasedCategory(sendCat, inv)),
        "  uiItems=" .. tostring(#_buildInventoryItems(category)),
    }
    if type(bag) == "table" then
        local n = 0
        _eachBagEntry(bag, function(k, e)
            n += 1
            if n <= 8 then
                lines[#lines + 1] = "  [" .. n .. "] " .. tostring(k) .. " type=" .. type(e)
                    .. " owned=" .. tostring(_isOwnedEntry(sendCat, k, e))
                    .. " sendable=" .. tostring(_isGiftableEntry(sendCat, k, e))
                    .. " name=" .. tostring(_resolveDisplayName(sendCat, k, e))
            end
        end)
        lines[#lines + 1] = "  rawCount=" .. tostring(n)
    end
    local out = table.concat(lines, "\n")
    print(out)
    return out
end

local function _collectCandidates()
    local inv = _getInventory(0)
    if not inv then return {} end

    local out = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        local cat = def.key
        if _categoryEnabled(cat) then
            local bag, sendCat = _getInventoryBag(inv, cat)
            local selectedMap = _categorySelected(cat)
            if type(bag) == "table" then
                if _isCountBasedCategory(sendCat, inv) then
                    _eachBagEntry(bag, function(itemKey, count)
                        if type(count) == "table" then
                            count = _entryCount(count) or 0
                        else
                            count = tonumber(count) or 0
                        end
                        local displayName = _resolveDisplayName(sendCat, itemKey, nil)
                        if _isGiftableEntry(sendCat, itemKey, count)
                            and _matchesSelected(sendCat, displayName, selectedMap, itemKey, nil) then
                            out[#out + 1] = {
                                Category = sendCat,
                                ItemKey = tostring(itemKey),
                                Count = count,
                                SortKey = tostring(itemKey),
                            }
                        end
                    end)
                else
                    _eachBagEntry(bag, function(itemKey, entry)
                        if _isGiftableEntry(sendCat, itemKey, entry) then
                            local typeName = _resolveDisplayName(sendCat, itemKey, entry)
                            if _matchesSelected(sendCat, typeName, selectedMap, itemKey, entry) then
                                out[#out + 1] = {
                                    Category = sendCat,
                                    ItemKey = tostring(itemKey),
                                    Count = 1,
                                    SortKey = typeName .. ":" .. tostring(itemKey),
                                }
                            end
                        end
                    end)
                end
            end
        end
    end

    table.sort(out, function(a, b)
        return tostring(a.SortKey) < tostring(b.SortKey)
    end)
    return out
end

local function _sumCandidateUnits(candidates)
    local n = 0
    for _, item in ipairs(candidates) do
        n += math.max(0, math.floor(tonumber(item.Count) or 1))
    end
    return n
end

function M.CountSendableUnits(_self)
    return _sumCandidateUnits(_collectCandidates())
end

local function _buildBatch(candidates, maxItems, totalRemaining)
    maxItems = _clampBatch(maxItems)
    if totalRemaining ~= nil then
        totalRemaining = math.max(0, math.floor(tonumber(totalRemaining) or 0))
        maxItems = math.min(maxItems, totalRemaining)
    end
    if maxItems <= 0 then return {}, 0 end

    local batch = {}
    local used = 0
    local catUsed = {}
    local unitsLeft = totalRemaining

    for _, item in ipairs(candidates) do
        if used >= maxItems then break end
        local cat = item.Category
        local catLimit = _categorySendLimit(cat)
        local cu = catUsed[cat] or 0
        if cu >= catLimit then
            continue
        end

        local count = tonumber(item.Count) or 1
        if _isCountBasedCategory(cat, _getInventory(0)) then
            local room = math.min(maxItems - used, catLimit - cu)
            if unitsLeft ~= nil then
                room = math.min(room, unitsLeft)
            end
            count = math.min(count, room)
            if count > 0 then
                batch[#batch + 1] = {
                    Category = item.Category,
                    ItemKey = item.ItemKey,
                    Count = count,
                }
                used += count
                catUsed[cat] = cu + count
                if unitsLeft ~= nil then
                    unitsLeft -= count
                end
            end
        else
            if used < maxItems and (unitsLeft == nil or unitsLeft > 0) then
                batch[#batch + 1] = {
                    Category = item.Category,
                    ItemKey = item.ItemKey,
                    Count = 1,
                }
                used += 1
                catUsed[cat] = cu + 1
                if unitsLeft ~= nil then
                    unitsLeft -= 1
                end
            end
        end
    end

    return batch, used
end

local function _fireSendBatch(batch, total)
    if #batch == 0 or total <= 0 then
        return false, "empty_batch"
    end

    local note = tostring(cfg.note or "")
    if #note > 100 then note = note:sub(1, 100) end

    local ok, success, msg = _callNetworkingRemote(MailboxSendBatch, cfg.recipient_user_id, batch, note)
    lastSendAt = os.clock()
    stats.lastSendAt = lastSendAt

    if not ok then
        _setStatus("Send error", tostring(success))
        return false, "send_error"
    end
    if success == true then
        stats.sentBatches += 1
        stats.sentItems += total
        local text = (msg and tostring(msg) ~= "") and tostring(msg) or ("Gift sent! (" .. tostring(total) .. " item)")
        _setStatus(text)
        return true, batch
    end

    _setStatus(tostring(msg ~= "" and msg or "Could not send gift"))
    return false, msg
end

function M.LookupRecipient(a, b)
    local username = _cleanUsername(_strArg(a, b))
    if username == "" then
        cfg.recipient_user_id = 0
        cfg.recipient_display = ""
        _setStatus("Enter recipient username")
        return false, "empty_username"
    end

    local now = os.clock()
    if now - lastLookupAt < LOOKUP_COOLDOWN then
        return cfg.recipient_user_id > 0, cfg.recipient_user_id
    end
    lastLookupAt = now

    if not _ensureNetworking() or not _remoteCallable(MailboxLookup) then
        _setStatus("Mailbox remote not ready")
        return false, "no_remote"
    end

    local ok, userId, displayName = _callNetworkingRemote(MailboxLookup, username)
    if not ok then
        _setStatus("Lookup failed")
        return false, "lookup_error"
    end

    userId = tonumber(userId) or 0
    if userId <= 0 or userId == LP.UserId then
        cfg.recipient_user_id = 0
        cfg.recipient_display = ""
        _setStatus("User not found: " .. username)
        return false, "not_found"
    end

    cfg.recipient_username = username
    cfg.recipient_user_id = userId
    cfg.recipient_display = tostring(displayName ~= "" and displayName or username)
    _setStatus("Recipient OK: " .. cfg.recipient_display .. " (" .. tostring(userId) .. ")")
    return true, userId
end

function M._notifySendJobDone(completedOk)
    if cfg.after_send_mode == "reset" and completedOk then
        local fn = G.__GAG2_RESET_GIFT_MAILBOX or _G.__GAG2_RESET_GIFT_MAILBOX
        if type(fn) == "function" then
            pcall(fn)
        end
    end
    local doneFn = G.__GAG2_GIFT_SEND_JOB_DONE or _G.__GAG2_GIFT_SEND_JOB_DONE
    if type(doneFn) == "function" then
        pcall(doneFn, completedOk == true)
    end
end

function M.SendOnceInternal()
    if cfg.recipient_user_id <= 0 then
        local ok = M.LookupRecipient(cfg.recipient_username)
        if not ok then return false, "no_recipient" end
    end
    if not _mailboxUsable() then
        _setStatus("Mailbox disabled on server")
        return false, "mailbox_disabled"
    end
    if not _ensureNetworking() or not MailboxSendBatch then
        _setStatus("SendBatch remote not ready")
        return false, "no_remote"
    end

    local now = os.clock()
    if now - lastSendAt < _sendInterval() then
        return false, "cooldown"
    end

    local candidates = _collectCandidates()
    if #candidates == 0 then
        local cats = _enabledCategoryKeys()
        local hint = (#cats > 0) and table.concat(cats, ", ") or "none"
        _setStatus("No items to send (" .. hint .. ") — check category & inventory")
        return false, "no_items"
    end

    local batch, total = _buildBatch(candidates, cfg.max_per_batch, nil)
    if #batch == 0 then
        return false, "empty_batch"
    end

    return _fireSendBatch(batch, total)
end

function M.SendOnce(_self)
    local ok, res = M.SendOnceInternal()
    if not ok and res == "cooldown" then
        _setStatus("Send cooldown...")
    elseif not ok and res == "no_items" then
        _setStatus("No giftable items")
    end
    return ok, res
end

function M.IsSendJobRunning(_self)
    return sendJobRunning == true
end

function M.StopSendJob(_self)
    sendJobRunning = false
end

function M.StopAutoSend(_self)
    autoSendRunning = false
end

function M.IsAutoSendRunning(_self)
    return autoSendRunning == true
end

local function _autoSendLoop(myId)
    task.wait(0.25)
    while autoSendRunning and autoSendLoopId == myId do
        if cfg.auto_send ~= true or _normalizeSendListMode(cfg.send_list_mode) ~= "loop" then
            task.wait(0.5)
            continue
        end
        if sendJobRunning then
            task.wait(0.2)
            continue
        end

        local ok, reason = M.SendOnceInternal()
        if ok then
            _waitForNextSend()
        elseif reason == "no_items" or reason == "empty_batch" then
            local cats = _enabledCategoryKeys()
            local hint = (#cats > 0) and table.concat(cats, ", ") or "none"
            _setStatus("Auto send: waiting items... (" .. hint .. ")")
            _waitNoItemsRetry()
        elseif reason == "cooldown" then
            _waitForNextSend()
        elseif reason == "no_recipient" then
            _setStatus("Auto send: set target username")
            task.wait(2)
        elseif reason == "mailbox_disabled" or reason == "no_remote" then
            task.wait(2)
        else
            _waitNoItemsRetry()
        end
    end
end

function M.StartAutoSend(_self)
    if autoSendRunning then return false end
    autoSendRunning = true
    autoSendLoopId += 1
    local myId = autoSendLoopId
    task.spawn(function()
        _autoSendLoop(myId)
    end)
    return true
end

function M.ApplyAutoSendRuntime(a, b)
    local on = _boolArg(a, b)
    cfg.auto_send = on
    M.StopAutoSend()
    if on and _normalizeSendListMode(cfg.send_list_mode) == "loop" then
        M.StartAutoSend()
        _setStatus("Auto send ON — looping selected list")
    elseif not on then
        _setStatus("Auto send OFF")
    end
    return on
end

local function _sendJobLoop(myId)
    task.wait(0.05)
    local mode = _normalizeSendListMode(cfg.send_list_mode)

    if mode == "send_total" then
        local target = _clampSendTotalGoal(cfg.send_total)
        cfg.send_total = target
        local available = M.CountSendableUnits(M)
        if available < target then
            _setStatus("Kurang: punya " .. tostring(available) .. ", butuh " .. tostring(target))
            sendJobRunning = false
            M._notifySendJobDone(false)
            return
        end

        local sent = 0
        local noItemsRetries = 0
        while sendJobRunning and sendJobId == myId and sent < target do
            local candidates = _collectCandidates()
            if #candidates == 0 then
                noItemsRetries += 1
                if noItemsRetries < 8 then
                    _waitNoItemsRetry()
                    continue
                end
                break
            end
            noItemsRetries = 0

            local remain = target - sent
            local batch, batchUnits = _buildBatch(candidates, MAX_BATCH, remain)
            if #batch == 0 or batchUnits <= 0 then
                break
            end

            local ok, reason = _fireSendBatch(batch, batchUnits)
            if ok then
                sent += batchUnits
                _setStatus("Mengirim " .. tostring(sent) .. "/" .. tostring(target))
                if sent >= target then
                    break
                end
                _waitForNextSend()
            else
                _waitForNextSend()
            end
        end

        if sent >= target then
            _setStatus("Selesai: kirim " .. tostring(sent) .. " item")
            sendJobRunning = false
            M._notifySendJobDone(true)
        else
            _setStatus("Berhenti: kirim " .. tostring(sent) .. "/" .. tostring(target))
            sendJobRunning = false
            M._notifySendJobDone(false)
        end
        return
    end

    while sendJobRunning and sendJobId == myId do
        local ok, reason = M.SendOnceInternal()
        if not ok then
            if reason == "no_items" or reason == "empty_batch" then
                local cats = _enabledCategoryKeys()
                local hint = (#cats > 0) and table.concat(cats, ", ") or "none"
                _setStatus("Menunggu item... (" .. hint .. ")")
                _waitNoItemsRetry()
            elseif reason == "cooldown" then
                _waitForNextSend()
            elseif reason == "no_recipient" then
                _setStatus("Pilih target / lookup gagal")
                _waitForNextSend()
            elseif reason == "mailbox_disabled" then
                _setStatus("Mailbox disabled on server")
                _waitForNextSend()
            elseif reason == "no_remote" then
                _setStatus("SendBatch remote not ready")
                _waitForNextSend()
            else
                _log("loop skip:", reason)
                _waitNoItemsRetry()
            end
        else
            _waitForNextSend()
        end
    end
end

function M.StartSendJob(_self)
    if sendJobRunning then
        return false, "already_running"
    end
    sendJobRunning = true
    sendJobId += 1
    local myId = sendJobId
    task.spawn(function()
        _sendJobLoop(myId)
    end)
    return true
end

local function _collectInboxGiftIds()
    if not _mailboxUsable() then return {} end
    pcall(_refreshInboxFromServer)

    local ids = {}
    for giftId in pairs(inboxGifts) do
        local key = tostring(giftId)
        if key ~= "" then
            ids[#ids + 1] = key
        end
    end

    if #ids == 0 and _remoteCallable(MailboxList) then
        local ok, data = _callNetworkingRemote(MailboxList)
        if ok and type(data) == "table" then
            if type(data.Inbox) == "table" then
                _applyInboxData({ Mailbox = data.Inbox })
            else
                _applyInboxData(data)
            end
            for giftId in pairs(inboxGifts) do
                ids[#ids + 1] = tostring(giftId)
            end
        end
    end

    table.sort(ids)
    return ids
end

function M.ClaimOnce()
    if not cfg.auto_claim_mail then
        return false, "disabled"
    end
    if not _mailboxUsable() then
        _setStatus("Mailbox disabled — cannot claim")
        return false, "mailbox_disabled"
    end
    if not _ensureNetworking() or not _remoteCallable(MailboxClaim) then
        _setStatus("Mailbox.Claim remote not ready")
        return false, "no_remote"
    end

    local now = os.clock()
    if now - lastClaimAt < MIN_CLAIM_SEC then
        return false, "cooldown"
    end

    local giftIds = _collectInboxGiftIds()
    if #giftIds == 0 then
        return false, "no_gifts"
    end

    local claimed = 0
    for _, giftId in ipairs(giftIds) do
        if pendingClaims[giftId] then
            continue
        end
        pendingClaims[giftId] = true
        local ok, success, msg = _callNetworkingRemote(MailboxClaim, giftId)
        pendingClaims[giftId] = nil
        lastClaimAt = os.clock()

        if ok and success == true then
            claimed += 1
            stats.claimedGifts += 1
            inboxGifts[giftId] = nil
        elseif ok and success ~= true then
            _setStatus(tostring(msg ~= "" and msg or "Could not claim gift"))
        end
        if #giftIds > 1 then
            task.wait(0.08)
        end
    end

    if claimed > 0 then
        _setStatus("Claimed " .. tostring(claimed) .. " gift(s)")
        return true, claimed
    end
    return false, "claim_failed"
end

local function _claimLoop(myId)
    task.wait(0.25)
    while claimRunning and claimLoopId == myId do
        if cfg.auto_claim_mail then
            local ok, res = pcall(M.ClaimOnce)
            if not ok then
                _log("claim error:", res)
            elseif res == "no_gifts" then
                pcall(_refreshInboxFromServer)
            end
            task.wait(CLAIM_LOOP_SEC)
        else
            task.wait(0.5)
        end
    end
end

function M.ApplyConfig(a, b)
    local nextCfg = _configArg(a, b)
    if type(nextCfg) ~= "table" then return end
    if nextCfg.enabled ~= nil then cfg.enabled = (nextCfg.enabled == true) end
    if nextCfg.auto_send ~= nil then cfg.auto_send = (nextCfg.auto_send == true) end
    if nextCfg.auto_claim_mail ~= nil then cfg.auto_claim_mail = (nextCfg.auto_claim_mail == true) end
    if nextCfg.auto_accept_gift ~= nil then cfg.auto_accept_gift = (nextCfg.auto_accept_gift == true) end
    if nextCfg.recipient_username ~= nil then cfg.recipient_username = _cleanUsername(nextCfg.recipient_username) end
    if nextCfg.recipient_user_id ~= nil then cfg.recipient_user_id = tonumber(nextCfg.recipient_user_id) or 0 end
    if nextCfg.recipient_display ~= nil then cfg.recipient_display = tostring(nextCfg.recipient_display or "") end
    if nextCfg.skip_equipped ~= nil then cfg.skip_equipped = (nextCfg.skip_equipped == true) end
    if nextCfg.max_per_batch ~= nil then cfg.max_per_batch = _clampBatch(nextCfg.max_per_batch) end
    if nextCfg.note ~= nil then cfg.note = tostring(nextCfg.note or "") end
    if nextCfg.delay_sec ~= nil then cfg.delay_sec = _clampDelay(nextCfg.delay_sec) end
    if nextCfg.category_mode ~= nil then cfg.category_mode = _normalizeCategoryMode(nextCfg.category_mode) end
    if nextCfg.send_list_mode ~= nil then cfg.send_list_mode = _normalizeSendListMode(nextCfg.send_list_mode) end
    if nextCfg.send_total ~= nil then cfg.send_total = _clampSendTotalGoal(nextCfg.send_total) end
    if nextCfg.after_send_mode ~= nil then cfg.after_send_mode = _normalizeAfterSendMode(nextCfg.after_send_mode) end

    if type(nextCfg.categories) == "table" then
        cfg.categories = {}
        for _, def in ipairs(CATEGORY_DEFS) do
            local key = def.key
            local legacy = nil
            for old, new in pairs(SAVE_CATEGORY_ALIASES) do
                if new == key then legacy = old break end
            end
            local on = (nextCfg.categories[key] == true)
            if not on and legacy and nextCfg.categories[legacy] == true then
                on = true
            end
            cfg.categories[key] = on
        end
    end
    if type(nextCfg.selected) == "table" then
        cfg.selected = type(cfg.selected) == "table" and cfg.selected or {}
        for _, def in ipairs(CATEGORY_DEFS) do
            local key = def.key
            local src = nextCfg.selected[key]
            if src == nil then
                for old, new in pairs(SAVE_CATEGORY_ALIASES) do
                    if new == key and nextCfg.selected[old] ~= nil then
                        src = nextCfg.selected[old]
                        break
                    end
                end
            end
            cfg.selected[key] = _normalizeSet(src)
        end
        for key, src in pairs(nextCfg.selected) do
            if type(key) == "string" and cfg.selected[key] == nil then
                cfg.selected[key] = _normalizeSet(src)
            end
        end
    end
    if type(nextCfg.send_totals) == "table" then
        cfg.send_totals = cfg.send_totals or {}
        for _, def in ipairs(CATEGORY_DEFS) do
            if nextCfg.send_totals[def.key] ~= nil then
                cfg.send_totals[def.key] = _clampSendTotalGoal(nextCfg.send_totals[def.key])
            end
        end
    end
    _ensureCfgCategoryTables()
    if cfg.auto_send == true and _normalizeSendListMode(cfg.send_list_mode) == "loop" then
        if not autoSendRunning then
            M.StartAutoSend()
        end
    elseif autoSendRunning then
        M.StopAutoSend()
    end
end

function M.GetConfig(_self)
    local categories = {}
    local selected = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        categories[def.key] = (cfg.categories[def.key] == true)
        selected[def.key] = _normalizeSet(cfg.selected[def.key])
    end
    return {
        enabled = cfg.enabled,
        auto_send = cfg.auto_send,
        auto_claim_mail = cfg.auto_claim_mail,
        auto_accept_gift = cfg.auto_accept_gift,
        recipient_username = cfg.recipient_username,
        recipient_user_id = cfg.recipient_user_id,
        recipient_display = cfg.recipient_display,
        categories = categories,
        selected = selected,
        skip_equipped = cfg.skip_equipped,
        max_per_batch = cfg.max_per_batch,
        note = cfg.note,
        delay_sec = cfg.delay_sec,
        send_totals = type(cfg.send_totals) == "table" and cfg.send_totals or {},
        category_mode = cfg.category_mode,
        send_list_mode = cfg.send_list_mode,
        send_total = cfg.send_total,
        after_send_mode = cfg.after_send_mode,
    }
end

function M.GetCategoryDefs(_self)
    return CATEGORY_DEFS
end

function M.GetCategoryKeys(_self)
    local keys = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        keys[#keys + 1] = def.key
    end
    return keys
end

function M.GetStats(_self)
    local inboxN = 0
    for _ in pairs(inboxGifts) do inboxN += 1 end
    return {
        lastStatus = stats.lastStatus,
        lastError = stats.lastError,
        sentBatches = stats.sentBatches,
        sentItems = stats.sentItems,
        lastSendAt = stats.lastSendAt,
        claimedGifts = stats.claimedGifts,
        running = running,
        claimRunning = claimRunning,
        inboxGifts = inboxN,
        autoClaimMail = cfg.auto_claim_mail,
        autoAcceptGift = cfg.auto_accept_gift,
        acceptedNormalGifts = stats.acceptedNormalGifts or 0,
    }
end

function M.DebugClaim(_self)
    pcall(_refreshInboxFromServer)
    local ids = _collectInboxGiftIds()
    local report = {
        auto_claim_mail = cfg.auto_claim_mail,
        claimRunning = claimRunning,
        mailboxUsable = _mailboxUsable(),
        claimRemote = _remoteCallable(MailboxClaim),
        inboxCount = #ids,
        giftIds = ids,
    }
    print("[GAG2-Gift] DebugClaim inbox=" .. tostring(#ids)
        .. " auto=" .. tostring(cfg.auto_claim_mail)
        .. " loop=" .. tostring(claimRunning))
    for i = 1, math.min(5, #ids) do
        print("  giftId:", ids[i])
    end
    return report
end

