function M.DebugWhyNot(_self)
    local report = {
        ok = true,
        reasons = {},
        sendable = 0,
        enabledCategories = _enabledCategoryKeys(),
        recipient_user_id = cfg.recipient_user_id,
        recipient_username = cfg.recipient_username,
        catalogLoaded = catalogLoadedFromGame,
        categoryCount = #CATEGORY_DEFS,
        mailboxUsable = _mailboxUsable(),
        networkingReady = _ensureNetworking() and MailboxSendBatch ~= nil,
        sendJobRunning = sendJobRunning,
        lastStatus = stats.lastStatus,
    }

    local function fail(code, msg)
        report.ok = false
        report.reasons[#report.reasons + 1] = code
        if msg then report.reasons[#report.reasons] = code .. ": " .. msg end
    end

    if not catalogLoadedFromGame or #CATEGORY_DEFS == 0 then
        fail("catalog_not_loaded", "ReloadCatalog / re-execute hub")
    end
    if cfg.recipient_user_id <= 0 then
        fail("no_recipient", cfg.recipient_username ~= "" and cfg.recipient_username or "pilih Target")
    end
    if not report.mailboxUsable then
        fail("mailbox_disabled", "MailboxFlags.OpenEnabled = false")
    end
    if not report.networkingReady then
        fail("no_send_remote", "Networking.Mailbox.SendBatch")
    end
    if #report.enabledCategories == 0 then
        fail("no_category", "Category dropdown — pilih Seeds/Fruits/etc")
    end

    report.sendable = M.CountSendableUnits(M)
    if report.sendable <= 0 then
        local cat = report.enabledCategories[1] or ""
        fail("no_sendable_items", cat .. " kosong atau filter item terlalu ketat")
    end

    local lines = { "========== Auto Gift DebugWhyNot ==========" }
    lines[#lines + 1] = "ok: " .. tostring(report.ok)
    lines[#lines + 1] = "sendable: " .. tostring(report.sendable)
    lines[#lines + 1] = "target: " .. tostring(cfg.recipient_display)
        .. " @" .. tostring(cfg.recipient_username) .. " uid=" .. tostring(cfg.recipient_user_id)
    lines[#lines + 1] = "categories: " .. table.concat(report.enabledCategories, ", ")
    lines[#lines + 1] = "catalog: " .. tostring(report.catalogLoaded) .. " defs=" .. tostring(report.categoryCount)
    lines[#lines + 1] = "mailbox: " .. tostring(report.mailboxUsable) .. " remote: " .. tostring(report.networkingReady)
    lines[#lines + 1] = "sendJob: " .. tostring(report.sendJobRunning) .. " status: " .. tostring(report.lastStatus)
    if #report.reasons > 0 then
        lines[#lines + 1] = "reasons:"
        for _, r in ipairs(report.reasons) do
            lines[#lines + 1] = "  - " .. r
        end
    end
    lines[#lines + 1] = "==========================================="
    local out = table.concat(lines, "\n")
    print(out)
    return report
end

