function M.PrintDiagnostics()
    local store = G.__GAG2_AUTO_GIFT or _G.__GAG2_AUTO_GIFT
    local mainGift = nil
    if type(G.MAIN) == "table" and type(G.MAIN.auto) == "table" then
        mainGift = G.MAIN.auto.gift
    end

    print("========== GAG2 Auto Gift ==========")
    print("target:", cfg.recipient_display, "(@" .. cfg.recipient_username .. ")", "uid:", cfg.recipient_user_id)
    print("inventory path:", M.GetPlayerStatePath())
    print("status:", stats.lastStatus, "| sent batches:", stats.sentBatches, "| sent items:", stats.sentItems)

    if type(store) == "table" then
        print("-- store __GAG2_AUTO_GIFT --")
        print("  enabled:", store.enabled, "| auto_send:", store.auto_send)
        print("  target:", store.recipient_username, "uid:", store.recipient_user_id)
        if type(store.categories) == "table" then
            for _, def in ipairs(CATEGORY_DEFS) do
                print("  cat " .. def.key .. ":", store.categories[def.key])
            end
        end
        if type(store.selected) == "table" then
            for _, def in ipairs(CATEGORY_DEFS) do
                print("  sel " .. def.key .. ":", _countSelected(store.selected[def.key]))
            end
        end
        if type(store.send_totals) == "table" then
            for _, def in ipairs(CATEGORY_DEFS) do
                print("  send total " .. def.key .. ":", store.send_totals[def.key])
            end
        end
    else
        print("store: MISSING")
    end

    if type(mainGift) == "table" then
        print("-- MAIN.auto.gift --")
        print("  enabled:", mainGift.enabled, "| auto_send:", mainGift.auto_send)
        print("  target:", mainGift.recipient_username, "uid:", mainGift.recipient_user_id)
    else
        print("MAIN.auto.gift: MISSING")
    end

    if cfg.recipient_user_id <= 0 then
        print("hint: Select a target first (Target dropdown)")
    end
    print("auto claim mail:", cfg.auto_claim_mail, "| claimed gifts:", stats.claimedGifts)
    print("sendable units:", M.CountSendableUnits(M), "| send job:", sendJobRunning)
    print("enabled categories:", table.concat(_enabledCategoryKeys(), ", "))
    print("hint: SetDebug(true) | DebugWhyNot() | DebugCategory(ag, \"Seeds\")")

    local inv = _getInventory()
    if inv then
        for _, def in ipairs(CATEGORY_DEFS) do
            local cat = def.key
            local bag = _getInventoryBag(inv, cat)
            local n = 0
            if type(bag) == "table" then
                if _isCountBasedCategory(cat, inv) then
                    for itemKey, count in pairs(bag) do
                        if type(count) == "table" then
                            count = _entryCount(count) or 0
                        else
                            count = tonumber(count) or 0
                        end
                        if _isGiftableEntry(cat, itemKey, count) then
                            n += 1
                        end
                    end
                else
                    for itemKey, entry in pairs(bag) do
                        if _isGiftableEntry(cat, itemKey, entry) then
                            n += 1
                        end
                    end
                end
            end
            print("inventory giftable " .. cat .. ":", n)
        end
    else
        print("inventory: MISSING (PlayerStateClient not ready)")
    end
end

