function M.StopAcceptGift()
    if acceptGiftConn then
        pcall(function() acceptGiftConn:Disconnect() end)
        acceptGiftConn = nil
    end
end

function M.StartAcceptGift()
    M.StopAcceptGift()
    if _bindNormalGiftAccept() then
        return true
    end
    task.spawn(function()
        for _ = 1, 30 do
            if cfg.auto_accept_gift ~= true then return end
            if _bindNormalGiftAccept() then return end
            task.wait(1)
        end
        if cfg.auto_accept_gift == true then
            _setStatus("Gifting remote not ready")
        end
    end)
    return false
end

function M.ApplyAcceptGiftRuntime(a, b)
    local on = _boolArg(a, b)
    cfg.auto_accept_gift = on
    M.StopAcceptGift()
    if on then
        M.StartAcceptGift()
        if _ensureGiftingNetworking() then
            _setStatus("Auto accept normal gift ON")
        else
            _setStatus("Auto accept ON — waiting for gifting remote")
        end
    else
        _setStatus("Auto accept normal gift OFF")
    end
    return on
end

function M.Start()
    running = false
end

function M.Stop()
    running = false
    M.StopAutoSend()
    M.StopSendJob()
    M.StopAcceptGift()
end

function M.ApplyRuntime(_on)
    M.StopSendJob()
    return false
end

function M.SyncFromGlobals()
    local store = G.__GAG2_AUTO_GIFT or _G.__GAG2_AUTO_GIFT
    if type(store) == "table" then
        M.ApplyConfig(store)
    end
    M.StopSendJob()
    M.ApplyClaimRuntime(cfg.auto_claim_mail == true)
    M.ApplyAcceptGiftRuntime(cfg.auto_accept_gift == true)
    if cfg.auto_send == true and _normalizeSendListMode(cfg.send_list_mode) == "loop" then
        M.ApplyAutoSendRuntime(true)
    else
        M.StopAutoSend()
    end
end

function M.EnsureRunning()
end

local function _trackEquippedPets()
    if not _ensureNetworking() or not Networking.Pets then return end
    for _, conn in ipairs(petEquipConn) do
        pcall(function() conn:Disconnect() end)
    end
    table.clear(petEquipConn)
    table.clear(equippedPets)

    local function mark(id, on)
        id = tostring(id or "")
        if id ~= "" then
            if on then equippedPets[id] = true else equippedPets[id] = nil end
        end
    end

    if Networking.Pets.PetEquipped and Networking.Pets.PetEquipped.OnClientEvent then
        petEquipConn[#petEquipConn + 1] = Networking.Pets.PetEquipped.OnClientEvent:Connect(function(id)
            mark(id, true)
        end)
    end
    if Networking.Pets.PetUnequipped and Networking.Pets.PetUnequipped.OnClientEvent then
        petEquipConn[#petEquipConn + 1] = Networking.Pets.PetUnequipped.OnClientEvent:Connect(function(id)
            mark(id, false)
        end)
    end
    if Networking.Pets.GetEquippedPets then
        task.spawn(function()
            local ok, list = pcall(function()
                return Networking.Pets.GetEquippedPets:Fire()
            end)
            if ok and type(list) == "table" then
                for _, pet in ipairs(list) do
                    if type(pet) == "table" then
                        mark(pet.Id or pet.UUID or pet.PetId, true)
                    elseif pet ~= nil then
                        mark(pet, true)
                    end
                end
            end
        end)
    end
end

