 end,              required = false },
    { key = "NormalGift",      name = "Normal Gift",      factory = function() -- NormalGift.lua — Grow A Garden 2
-- Nearby player gifts via Networking.Gifting.Send (not mailbox).

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local MAX_SEND_DISTANCE = 10
local SEND_DELAY_SEC    = 0.55
local MIN_SEND_GAP      = 0.45
local TP_STAND_DIST     = 6
local TP_Y_OFFSET       = 3
local AFTER_TP_SEC      = 0.1

local GIFT_ATTR_MAP = nil
local GIFT_ATTR_ORDER = nil

local Networking = nil
local GiftingSend = nil
local BackpackGetLayout = nil
local BackpackPromoteFruit = nil
local sendBusy = false

local virtualFruitCache = nil
local virtualFruitCacheAt = 0
local VIRTUAL_FRUIT_CACHE_SEC = 10

local uiItemsCache = {}
local uiItemsCacheAt = {}
local UI_ITEMS_CACHE_SEC = 6

local cfg = {
    target_user_id  = 0,
    target_name     = "",
    category        = "Seeds",
    selected        = {},
    selectedByCat   = {},
    send_total      = 1,
    teleport_to_target = true,
}

local stats = {
    lastStatus = "Ready",
    lastError  = nil,
    sentCount  = 0,
}

local function _setStatus(msg, err)
    stats.lastStatus = tostring(msg or "")
    stats.lastError = err
    G.NORMAL_GIFT_STATUS = stats.lastStatus
    _G.NORMAL_GIFT_STATUS = stats.lastStatus
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

local function _canonicalCategory(cat)
    cat = tostring(cat or "")
    local norm = cat:lower():gsub("[%s_]+", "")
    if norm == "harvestedfruit" or norm == "harvestedfruits" or norm == "harvestedfruid" then
        return "HarvestedFruits"
    end
    return cat
end

local function _isHarvestedFruitsCategory(cat)
    return _canonicalCategory(cat) == "HarvestedFruits"
end

local function _harvestUiKey(uuid)
    uuid = tostring(uuid or "")
    if uuid == "" then return "" end
    return "hf_" .. uuid:gsub("[^%w]", "")
end

local function _registerHarvestKeyMap(uiKey, uuid)
    uiKey = tostring(uiKey or "")
    uuid = tostring(uuid or "")
    if uiKey == "" or uuid == "" then return uiKey end
    local map = G.__GAG2_NORMAL_GIFT_HF_KEYS or {}
    map[uiKey] = uuid
    map[uuid] = uuid
    G.__GAG2_NORMAL_GIFT_HF_KEYS = map
    _G.__GAG2_NORMAL_GIFT_HF_KEYS = map
    return uiKey
end

local function _resolveHarvestSelectionKey(key)
    key = tostring(key or "")
    if key == "" then return key end
    local map = G.__GAG2_NORMAL_GIFT_HF_KEYS or rawget(_G, "__GAG2_NORMAL_GIFT_HF_KEYS")
    if type(map) == "table" and map[key] then
        return tostring(map[key])
    end
    return key
end

local function _expandSelectedMapForHarvest(selectedMap)
    if type(selectedMap) ~= "table" then return selectedMap end
    local map = G.__GAG2_NORMAL_GIFT_HF_KEYS or rawget(_G, "__GAG2_NORMAL_GIFT_HF_KEYS")
    if type(map) ~= "table" then return selectedMap end
    local out = {}
    for k, v in pairs(selectedMap) do
        out[k] = v
        local uuid = map[tostring(k)]
        if v == true and uuid then
            out[tostring(uuid)] = true
            out[_harvestUiKey(uuid)] = true
        end
    end
    return out
end

local function _canonicalGiftType(giftType)
    if _isHarvestedFruitsCategory(giftType) then
        return "HarvestedFruits"
    end
    return tostring(giftType or "")
end

local GIFT_ATTR_KNOWN = {
    Crate = "Crates",
    Gnome = "Gnomes",
    Mushroom = "Mushrooms",
    Sprinkler = "Sprinklers",
    WateringCan = "WateringCans",
    HarvestedFruit = "HarvestedFruits",
    SeedTool = "Seeds",
}

local function _mergeGiftAttrMap(map, order)
    map = type(map) == "table" and map or {}
    order = type(order) == "table" and order or {}
    local seen = {}
    for _, k in ipairs(order) do
        seen[k] = true
    end
    for attr, giftType in pairs(GIFT_ATTR_KNOWN) do
        if map[attr] == nil then
            map[attr] = giftType
            if not seen[attr] then
                order[#order + 1] = attr
                seen[attr] = true
            end
        end
    end
    table.sort(order)
    map.HarvestedFruit = GIFT_ATTR_KNOWN.HarvestedFruit or "HarvestedFruits"
    return map, order
end

local function _scoreGiftAttrMap(t)
    local n = 0
    local hasHF = false
    if type(t) ~= "table" then return 0, false end
    for k, v in pairs(t) do
        if type(k) == "string" and type(v) == "string" then
            n += 1
            if k == "HarvestedFruit" then hasHF = true end
        end
    end
    return n, hasHF
end

local function _tableLooksLikeGiftAttrMap(t)
    if type(t) ~= "table" then return false end
    local seedTool = rawget(t, "SeedTool")
    if type(seedTool) == "string" and seedTool == "Seeds" then
        return true
    end
    local crate = rawget(t, "Crate")
    if type(crate) == "string" and crate == "Crates" then
        return true
    end
    return false
end

local function _cloneGiftAttrMap(src)
    local map, order = {}, {}
    local ok = pcall(function()
        for k, v in pairs(src) do
            if type(k) == "string" and type(v) == "string" then
                map[k] = v
                order[#order + 1] = k
            end
        end
    end)
    if not ok or not next(map) then return nil, nil end
    table.sort(order)
    return map, order
end

local function _extractMapFromFunction(fn)
    if type(fn) ~= "function" or type(debug) ~= "table" or type(debug.getupvalue) ~= "function" then
        return nil
    end
    local best = nil
    local bestScore = 0
    for i = 1, 40 do
        local ok, _, val = pcall(debug.getupvalue, fn, i)
        if not ok or val == nil then break end
        if type(val) == "table" then
            local ok2, isMap = pcall(_tableLooksLikeGiftAttrMap, val)
            if ok2 and isMap then
                local n, hasHF = _scoreGiftAttrMap(val)
                local score = n + (hasHF and 100 or 0)
                if score > bestScore then
                    best = val
                    bestScore = score
                end
            end
        end
    end
    return best
end

local function _waitForControllersStarted(maxSec)
    maxSec = tonumber(maxSec) or 15
    local deadline = os.clock() + maxSec
    while os.clock() < deadline do
        if LP:HasTag("ControllersStarted") then return true end
        task.wait(0.25)
    end
    return LP:HasTag("ControllersStarted")
end

local function _findGiftAttrMapInGc()
    if type(getgc) ~= "function" then return nil end
    local ok, objects = pcall(getgc, true)
    if not ok or type(objects) ~= "table" then return nil end
    local best = nil
    local bestScore = 0
    for _, obj in ipairs(objects) do
        if type(obj) == "table" then
            local ok2, isMap = pcall(_tableLooksLikeGiftAttrMap, obj)
            if ok2 and isMap then
                local n, hasHF = _scoreGiftAttrMap(obj)
                local score = n + (hasHF and 100 or 0)
                if score > bestScore then
                    best = obj
                    bestScore = score
                end
            end
        end
    end
    return best
end

local function _getGiftingControllerScript()
    local ps = LP:FindFirstChild("PlayerScripts")
    if ps then
        local controllers = ps:FindFirstChild("Controllers")
        if controllers then
            local inst = controllers:FindFirstChild("GiftingController")
            if inst then return inst end
        end
    end
    local sps = game:GetService("StarterPlayer"):FindFirstChild("StarterPlayerScripts")
    if sps then
        local controllers = sps:FindFirstChild("Controllers")
        if controllers then
            return controllers:FindFirstChild("GiftingController")
        end
    end
    return nil
end

local function _extractGiftAttrMapFromController(maxWaitSec)
    if type(debug) ~= "table" or type(debug.getupvalue) ~= "function" then
        return nil
    end

    maxWaitSec = tonumber(maxWaitSec) or 0
    if maxWaitSec > 0 then
        _waitForControllersStarted(maxWaitSec)
    elseif not LP:HasTag("ControllersStarted") then
        return nil
    end

    local inst = _getGiftingControllerScript()
    if not inst then return nil end

    local ok, mod = pcall(require, inst)
    if not ok or type(mod) ~= "table" then return nil end

    local fromEquip = _extractMapFromFunction(mod._updateEquippedTool)
    if fromEquip then return fromEquip end

    for _, fn in pairs(mod) do
        local found = _extractMapFromFunction(fn)
        if found then return found end
    end

    return nil
end

local function _loadGiftAttrMapFromGame(maxWaitSec)
    local fromController = _extractGiftAttrMapFromController(maxWaitSec)
    if fromController then return fromController end
    return _findGiftAttrMapInGc()
end

local function _ensureGiftAttrMap(maxWaitSec)
    if GIFT_ATTR_MAP and next(GIFT_ATTR_MAP) then
        if not GIFT_ATTR_MAP.HarvestedFruit then
            GIFT_ATTR_MAP, GIFT_ATTR_ORDER = _mergeGiftAttrMap(GIFT_ATTR_MAP, GIFT_ATTR_ORDER)
            G.__GAG2_GIFTING_ATTR_MAP = GIFT_ATTR_MAP
        end
        return GIFT_ATTR_MAP
    end

    local cached = G.__GAG2_GIFTING_ATTR_MAP
    if type(cached) == "table" then
        local ok, isMap = pcall(_tableLooksLikeGiftAttrMap, cached)
        if ok and isMap then
            local map, order = _cloneGiftAttrMap(cached)
            if map then
                map, order = _mergeGiftAttrMap(map, order)
                GIFT_ATTR_MAP, GIFT_ATTR_ORDER = map, order
                G.__GAG2_GIFTING_ATTR_MAP = GIFT_ATTR_MAP
                return GIFT_ATTR_MAP
            end
        end
    end

    local fromGame = _loadGiftAttrMapFromGame(maxWaitSec)
    if fromGame then
        local map, order = _cloneGiftAttrMap(fromGame)
        if map then
            map, order = _mergeGiftAttrMap(map, order)
            GIFT_ATTR_MAP, GIFT_ATTR_ORDER = map, order
            G.__GAG2_GIFTING_ATTR_MAP = GIFT_ATTR_MAP
            return GIFT_ATTR_MAP
        end
    end

    local map, order = _mergeGiftAttrMap({}, {})
    if next(map) then
        GIFT_ATTR_MAP, GIFT_ATTR_ORDER = map, order
        G.__GAG2_GIFTING_ATTR_MAP = GIFT_ATTR_MAP
        return GIFT_ATTR_MAP
    end

    return nil
end

local function _categoryDef(key)
    key = _canonicalCategory(key)
    if key == "" then key = "Seeds" end
    return { key = key, giftType = key }
end

local function _remoteCallable(remote)
    if remote == nil then return false end
    if type(remote) == "table" then
        return type(remote.Fire) == "function" or type(remote.Invoke) == "function"
    end
    if typeof(remote) == "Instance" then
        return remote:IsA("RemoteFunction") or remote:IsA("RemoteEvent")
    end
    return false
end

local function _callNetworkingRemote(remote, ...)
    if not _remoteCallable(remote) then return false, "no_remote" end
    local args = table.pack(...)
    local function invoke()
        if type(remote) == "table" then
            if type(remote.Fire) == "function" then
                if args.n > 0 then return remote:Fire(table.unpack(args, 1, args.n)) end
                return remote:Fire()
            end
            if type(remote.Invoke) == "function" then
                if args.n > 0 then return remote:Invoke(table.unpack(args, 1, args.n)) end
                return remote:Invoke()
            end
        elseif typeof(remote) == "Instance" then
            if remote:IsA("RemoteFunction") then
                if args.n > 0 then return remote:InvokeServer(table.unpack(args, 1, args.n)) end
                return remote:InvokeServer()
            end
            if remote:IsA("RemoteEvent") then
                if args.n > 0 then remote:FireServer(table.unpack(args, 1, args.n))
                else remote:FireServer() end
                return nil
            end
        end
        error("networking remote not callable")
    end
    local results = table.pack(pcall(invoke))
    if not results[1] then return false, results[2] end
    return true, results[2], results[3], results[4]
end

local function _ensureNetworking()
    if Networking and _remoteCallable(GiftingSend) then return true end
    local ok, net = pcall(function()
        return require(ReplicatedStorage:WaitForChild("SharedModules"):WaitForChild("Networking"))
    end)
    if ok and type(net) == "table" then
        Networking = net
        if type(net.Gifting) == "table" then
            GiftingSend = net.Gifting.Send
        end
        if type(net.Backpack) == "table" then
            BackpackGetLayout = net.Backpack.GetLayout
            BackpackPromoteFruit = net.Backpack.PromoteFruit
        end
    end
    return _remoteCallable(GiftingSend)
end

local function _ensureBackpackNetworking()
    if not _ensureNetworking() then return false end
    return _remoteCallable(BackpackGetLayout) and _remoteCallable(BackpackPromoteFruit)
end

local FRUIT_ID_FIELDS = { "Id", "id", "UUID", "Uuid", "FruitId", "fruitId" }
local FRUIT_NAME_FIELDS = { "FruitName", "Fruit", "Name", "name", "fruitName" }
local FRUIT_WEIGHT_FIELDS = { "Weight", "weight", "Kg", "kg" }
local FRUIT_MUTATION_FIELDS = { "Mutation", "mutation" }

local function _pickFruitField(entry, fields)
    if type(entry) ~= "table" then return nil end
    for _, f in ipairs(fields) do
        local v = entry[f]
        if v ~= nil and tostring(v) ~= "" then return v end
    end
    return nil
end

local function _looksLikeLayoutFruitEntry(entry)
    if type(entry) ~= "table" then return false end
    if entry.SeedTool ~= nil or entry.Pet ~= nil then return false end
    if entry.PottedPlant == true then return false end
    if tostring(entry.MainCategory or "") == "Seed" then return false end

    local id = _pickFruitField(entry, FRUIT_ID_FIELDS)
    if type(id) == "string" and id ~= "" and #id >= 8 then return true end

    local name = _pickFruitField(entry, FRUIT_NAME_FIELDS)
    if name ~= nil and tostring(name) ~= "" then return true end

    if entry.HarvestedFruit == true then return true end
    if entry.FruitProxy == true then return true end

    return false
end

local function _virtualFruitLabel(entry)
    local fruitName = tostring(_pickFruitField(entry, FRUIT_NAME_FIELDS) or "Fruit")
    local weight = tonumber(_pickFruitField(entry, FRUIT_WEIGHT_FIELDS))
    local name = fruitName
    if weight and weight > 0 then
        name = name .. string.format(" [%.2fkg]", weight)
    end
    local mutation = _pickFruitField(entry, FRUIT_MUTATION_FIELDS)
    if mutation ~= nil and tostring(mutation) ~= "" then
        name = name .. " " .. tostring(mutation)
    end
    return name
end

local function _buildVirtualFruitInfo(entry)
    if not _looksLikeLayoutFruitEntry(entry) then return nil end
    local uuid = tostring(_pickFruitField(entry, FRUIT_ID_FIELDS) or "")
    if uuid == "" then return nil end
    return {
        attr = "HarvestedFruit",
        key = _virtualFruitLabel(entry),
        name = tostring(_pickFruitField(entry, FRUIT_NAME_FIELDS) or "Fruit"),
        uuid = uuid,
        giftType = "HarvestedFruits",
        source = "layout",
        raw = entry,
    }
end

local function _collectLayoutFruitEntries(layout, out, depth, seen)
    if depth > 12 or type(layout) ~= "table" then return end
    if seen[layout] then return end
    seen[layout] = true

    if _looksLikeLayoutFruitEntry(layout) then
        out[#out + 1] = layout
        return
    end

    for key, value in pairs(layout) do
        if type(value) == "table" then
            if _looksLikeLayoutFruitEntry(value) then
                out[#out + 1] = value
            else
                _collectLayoutFruitEntries(value, out, depth + 1, seen)
            end
        end
    end
end

local function _mergeFruitInfoLists(primary, secondary)
    local merged = {}
    local byId = {}
    for _, list in ipairs({ primary, secondary }) do
        for _, info in ipairs(list or {}) do
            local uuid = tostring(info.uuid or "")
            if uuid ~= "" and not byId[uuid] then
                byId[uuid] = true
                merged[#merged + 1] = info
            end
        end
    end
    table.sort(merged, function(a, b) return tostring(a.key) < tostring(b.key) end)
    return merged
end

local function _parseBackpackLayoutFruits(layout)
    if type(layout) ~= "table" then return {} end
    local raw = {}
    _collectLayoutFruitEntries(layout, raw, 0, {})
    local fruits = {}
    local byId = {}
    for _, entry in ipairs(raw) do
        local info = _buildVirtualFruitInfo(entry)
        if info and not byId[info.uuid] then
            byId[info.uuid] = true
            fruits[#fruits + 1] = info
        end
    end
    table.sort(fruits, function(a, b) return a.key < b.key end)
    return fruits
end

local function _formatCount(n)
    n = tonumber(n) or 0
    if n >= 1000000 then return string.format("%.1fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fk", n / 1000) end
    return tostring(math.floor(n))
end

local function _getFruitSellValue()
    local fsv = G.FruitSellValue or rawget(_G, "FruitSellValue")
    if type(fsv) == "table" and type(fsv.fromFruit) == "function" then
        return fsv
    end
    return nil
end

local function _formatSellPrice(n)
    n = tonumber(n) or 0
    if n <= 0 then return "" end
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fk", n / 1000) end
    return tostring(math.floor(n))
end

local function _harvestSellPrice(inst)
    if not inst then return 0 end
    local fsv = _getFruitSellValue()
    if not fsv then return 0 end
    local ok, price = pcall(fsv.fromFruit, inst, LP)
    if ok and type(price) == "number" then return price end
    return 0
end

local function _toolStackCount(tool)
    if not tool then return 1 end
    local n = tonumber(tool:GetAttribute("Count") or tool:GetAttribute("Amount")
        or tool:GetAttribute("Stack") or tool:GetAttribute("Qty"))
    if n and n > 0 then return math.floor(n) end
    return 1
end

local function _iterInventoryContainers()
    local out = {}
    local seen = {}

    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end

    local bp = LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack")
    if not bp then
        pcall(function() bp = LP:WaitForChild("Backpack", 2) end)
    end
    add(bp)
    add(LP.Character)

    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            elseif ch ~= bp and ch ~= LP.Character
                and ch.Name ~= "PlayerScripts" and ch.Name ~= "PlayerGui" then
                add(ch)
            end
        end
    end

    return out
end

local function _giftInstanceCanonical(inst)
    if not inst then return nil end
    local cur = inst
    while cur and cur ~= game do
        if cur:IsA("Tool") then return cur end
        if cur == LP then break end
        cur = cur.Parent
    end
    return inst
end

local function _instLooksLikeHarvestedFruit(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return false end
    if inst:GetAttribute("SeedTool") ~= nil then return false end
    if inst:GetAttribute("Pet") ~= nil then return false end
    if inst:GetAttribute("PottedPlant") == true then return false end
    if tostring(inst:GetAttribute("MainCategory") or "") == "Seed" then return false end

    local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
    if fruitName ~= nil and tostring(fruitName) ~= "" then
        return true
    end

    if inst:GetAttribute("FruitProxy") == true then return true end

    local hf = inst:GetAttribute("HarvestedFruit")
    if hf == true then return true end
    if type(hf) == "string" and hf ~= "" then return true end

    return false
end

local function _foreachGiftInstance(callback)
    if type(callback) ~= "function" then return end
    local seen = {}
    local function visit(inst)
        if not inst or seen[inst] then return end
        local canonical = _giftInstanceCanonical(inst)
        if canonical ~= inst then return end
        if inst:IsA("Tool") or _instLooksLikeHarvestedFruit(inst) then
            seen[inst] = true
            callback(inst)
        end
    end
    for _, container in ipairs(_iterInventoryContainers()) do
        visit(container)
        for _, inst in ipairs(container:GetDescendants()) do
            visit(inst)
        end
    end
end

local function _getVirtualFruits(forceRefresh)
    local now = os.clock()
    if not forceRefresh and virtualFruitCache and (now - virtualFruitCacheAt) < VIRTUAL_FRUIT_CACHE_SEC then
        return virtualFruitCache
    end
    local layoutFruits = {}
    if forceRefresh and _ensureBackpackNetworking() then
        local ok, layout = _callNetworkingRemote(BackpackGetLayout)
        if ok and type(layout) == "table" then
            G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT = layout
            _G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT = layout
            layoutFruits = _parseBackpackLayoutFruits(layout)
        end
    end
    virtualFruitCache = _mergeFruitInfoLists(layoutFruits, _collectInstanceFruitInfos())
    virtualFruitCacheAt = now
    return virtualFruitCache
end

local function _invalidateVirtualFruitCache()
    virtualFruitCache = nil
    virtualFruitCacheAt = 0
    uiItemsCache = {}
    uiItemsCacheAt = {}
end

local function _foreachGiftTool(callback)
    _foreachGiftInstance(function(inst)
        if inst:IsA("Tool") then callback(inst) end
    end)
end

local function _attrMatchesGift(attr, attrVal)
    if attrVal == nil then return false end
    if attr == "HarvestedFruit" then
        if attrVal == true then return true end
        if type(attrVal) == "string" and attrVal ~= "" then return true end
        return false
    end
    if type(attrVal) == "boolean" then
        return attrVal == true
    end
    return true
end

local function _harvestedFruitLabel(inst)
    local instName = tostring(inst.Name or "")
    if instName:find("%[.-%]") then
        local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
        if fruitName and instName:find(tostring(fruitName), 1, true) then
            return instName
        end
    end
    local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
    local name = tostring(fruitName or inst.Name or "Fruit")
    local weight = tonumber(inst:GetAttribute("Weight"))
    if weight and weight > 0 then
        name = name .. string.format(" [%.2fkg]", weight)
    end
    local mutation = inst:GetAttribute("Mutation")
    if mutation ~= nil and tostring(mutation) ~= "" then
        return name .. " " .. tostring(mutation)
    end
    return name
end

local function _toolLooksLikeHarvestedFruit(inst)
    return _instLooksLikeHarvestedFruit(inst)
end

local function _buildHarvestedFruitInfo(inst, giftType)
    if not _instLooksLikeHarvestedFruit(inst) then return nil end

    local uuid = inst:GetAttribute("Id")
    if type(uuid) ~= "string" or uuid == "" then
        local harvestedFlag = inst:GetAttribute("HarvestedFruit")
        if type(harvestedFlag) == "string" and harvestedFlag ~= "" then
            uuid = harvestedFlag
        else
            uuid = tostring(inst.Name)
        end
    end

    return {
        attr = "HarvestedFruit",
        key = _harvestedFruitLabel(inst),
        name = inst.Name,
        uuid = tostring(uuid),
        giftType = "HarvestedFruits",
    }
end

local function _buildGiftInfoFromAttr(tool, attr, giftType, attrVal)
    if attr == "HarvestedFruit" or giftType == "HarvestedFruits" then
        return _buildHarvestedFruitInfo(tool, giftType)
    end

    local uuid = tool:GetAttribute("Id")
    if type(uuid) ~= "string" or uuid == "" then
        if type(attrVal) == "string" and attrVal ~= "" then
            uuid = attrVal
        else
            uuid = tool.Name
        end
    end
    local key = type(attrVal) == "string" and attrVal or tostring(attrVal)
    return {
        attr = attr,
        key = key,
        name = tool.Name,
        uuid = tostring(uuid),
        giftType = giftType,
    }
end

local function _toolGiftInfo(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return nil end
    local map = _ensureGiftAttrMap()
    if not map then return nil end

    local hfType = map.HarvestedFruit or "HarvestedFruits"
    local hfInfo = _buildHarvestedFruitInfo(inst, hfType)
    if hfInfo then return hfInfo end

    if not inst:IsA("Tool") then return nil end

    for _, attr in ipairs(GIFT_ATTR_ORDER or {}) do
        local giftType = map[attr]
        local attrVal = inst:GetAttribute(attr)
        if giftType and _attrMatchesGift(attr, attrVal) then
            local info = _buildGiftInfoFromAttr(inst, attr, giftType, attrVal)
            if info then return info end
        end
    end

    for attr, giftType in pairs(map) do
        local attrVal = inst:GetAttribute(attr)
        if _attrMatchesGift(attr, attrVal) then
            local info = _buildGiftInfoFromAttr(inst, attr, giftType, attrVal)
            if info then return info end
        end
    end

    return nil
end

local function _collectInstanceFruitInfos()
    local out = {}
    local byId = {}
    _foreachGiftInstance(function(inst)
        local info = _toolGiftInfo(inst)
        if info and _isHarvestedFruitsCategory(info.giftType) then
            local uuid = tostring(info.uuid or "")
            if uuid ~= "" and not byId[uuid] then
                byId[uuid] = true
                out[#out + 1] = {
                    attr = info.attr,
                    key = info.key,
                    name = info.name,
                    uuid = uuid,
                    giftType = "HarvestedFruits",
                    source = "instance",
                    inst = inst,
                }
            end
        end
    end)
    return out
end

local function _harvestFruitsAsUiItems()
    local items = {}
    for _, info in ipairs(_collectInstanceFruitInfos()) do
        local uuid = tostring(info.uuid or "")
        if uuid ~= "" then
            local uiKey = _registerHarvestKeyMap(_harvestUiKey(uuid), uuid)
            local label = tostring(info.key or info.name or "Fruit")
            local price = _harvestSellPrice(info.inst)
            local priceStr = _formatSellPrice(price)
            local displayName = label
            if priceStr ~= "" then
                displayName = label .. " (" .. priceStr .. ")"
            end
            items[#items + 1] = {
                key = uiKey,
                name = displayName,
                right = priceStr ~= "" and priceStr or "",
                count = 1,
                price = price,
                uuid = uuid,
                giftType = "HarvestedFruits",
            }
        end
    end
    table.sort(items, function(a, b)
        local pa = tonumber(a.price) or 0
        local pb = tonumber(b.price) or 0
        if pa ~= pb then return pa > pb end
        return a.name < b.name
    end)
    return items
end

local function _toolDisplayName(tool)
    if not tool then return "Item" end
    if _instLooksLikeHarvestedFruit(tool) then
        return _harvestedFruitLabel(tool)
    end
    local seedTool = tool:GetAttribute("SeedTool")
    if seedTool then
        local name = tostring(seedTool)
        local lower = string.lower(name)
        if not (string.sub(lower, -5) == " seed" or lower == "seed") then
            name = name .. " Seed"
        end
        return name
    end
    local fruitName = tool:GetAttribute("FruitName") or tool:GetAttribute("Fruit")
    if fruitName then
        local name = tostring(fruitName)
        local mutation = tool:GetAttribute("Mutation")
        if mutation and mutation ~= "" then
            return name .. " " .. tostring(mutation)
        end
        return name
    end
    local info = _toolGiftInfo(tool)
    if info then return tostring(info.key) end
    return tool.Name
end

local function _stripCountSuffix(name)
    return tostring(name or ""):gsub("%s+x%s+[%d%.]+[kKmMbB]?$", "")
end

local function _hasSelection(selectedMap)
    if type(selectedMap) ~= "table" then return false end
    for _, v in pairs(selectedMap) do
        if v == true then return true end
    end
    return false
end

local function _matchesToolSelection(inst, info, selectedMap)
    if not _hasSelection(selectedMap) then return false end
    if info and _isHarvestedFruitsCategory(info.giftType) then
        selectedMap = _expandSelectedMapForHarvest(selectedMap)
    end
    local display = inst and _toolDisplayName(inst) or tostring(info.key or info.uuid or "")
    local base = _stripCountSuffix(display)
    local keys = {
        tostring(info.uuid or ""),
        tostring(info.key or ""),
        display,
        base,
    }
    if inst then
        keys[#keys + 1] = inst.Name
        keys[#keys + 1] = tostring(inst:GetAttribute("FruitName") or "")
        keys[#keys + 1] = tostring(inst:GetAttribute("Fruit") or "")
    else
        keys[#keys + 1] = tostring(info.name or "")
    end
    for _, k in ipairs(keys) do
        if k ~= "" and selectedMap[k] == true then return true end
    end
    local normBase = base:lower():gsub("[%s_%-]+", "")
    for k, v in pairs(selectedMap) do
        if v == true then
            local nk = _stripCountSuffix(tostring(k)):lower():gsub("[%s_%-]+", "")
            if nk ~= "" and nk == normBase then return true end
        end
    end
    return false
end

local function _toolsAsUiItems(catKey)
    catKey = _canonicalCategory(tostring(catKey or ""))
    if catKey == "" then catKey = "Seeds" end
    if not _ensureGiftAttrMap() then return {} end

    local now = os.clock()
    local cachedAt = uiItemsCacheAt[catKey] or 0
    if uiItemsCache[catKey] and (now - cachedAt) < UI_ITEMS_CACHE_SEC then
        return uiItemsCache[catKey]
    end

    if _isHarvestedFruitsCategory(catKey) then
        local items = _harvestFruitsAsUiItems()
        uiItemsCache[catKey] = items
        uiItemsCacheAt[catKey] = now
        return items
    end

    local grouped = {}
    _foreachGiftInstance(function(inst)
        local info = _toolGiftInfo(inst)
        if info and _canonicalGiftType(info.giftType) == catKey then
            local key = tostring(info.key or info.uuid or "")
            if key ~= "" then
                if not grouped[key] then
                    grouped[key] = {
                        key = key,
                        displayName = _toolDisplayName(inst),
                        uuid = info.uuid,
                        giftType = info.giftType,
                        count = 0,
                    }
                end
                grouped[key].count += _toolStackCount(inst)
            end
        end
    end)

    local items = {}
    for _, g in pairs(grouped) do
        items[#items + 1] = {
            key = g.key,
            name = g.displayName .. " x " .. _formatCount(g.count),
            right = _formatCount(g.count),
            count = g.count,
            uuid = g.uuid,
            giftType = g.giftType,
        }
    end
    table.sort(items, function(a, b) return a.name < b.name end)
    uiItemsCache[catKey] = items
    uiItemsCacheAt[catKey] = now
    return items
end

function M.GetCategoryDefs()
    if not _ensureGiftAttrMap() then
        return {}
    end

    local seen = {}
    local withTools = {}
    _foreachGiftInstance(function(inst)
        local info = _toolGiftInfo(inst)
        if info then
            local gt = _canonicalGiftType(info.giftType)
            if gt ~= "" and not seen[gt] then
                seen[gt] = true
                withTools[#withTools + 1] = gt
            end
        end
    end)
    if not seen.HarvestedFruits and #_collectInstanceFruitInfos() > 0 then
        withTools[#withTools + 1] = "HarvestedFruits"
    end
    table.sort(withTools)

    local out = {}
    for _, giftType in ipairs(withTools) do
        out[#out + 1] = {
            key = giftType,
            label = giftType,
            giftType = giftType,
        }
    end

    return out
end

function M.GetItemsForCategory(a, b)
    local catKey = a
    if type(a) == "table" and type(b) == "string" then
        catKey = b
    end
    catKey = _canonicalCategory(tostring(catKey or cfg.category or ""))
    if catKey == "" then catKey = "Seeds" end
    _ensureGiftAttrMap()
    return _toolsAsUiItems(catKey)
end

function M.InvalidateItemCache()
    _invalidateVirtualFruitCache()
end

function M.ListServerPlayers()
    local out = {}
    for _, p in ipairs(Players:GetPlayers()) do
        if p ~= LP then
            out[#out + 1] = {
                key = tostring(p.UserId),
                name = p.DisplayName .. " (@" .. p.Name .. ")",
                userId = p.UserId,
                player = p,
            }
        end
    end
    table.sort(out, function(a, b) return a.name < b.name end)
    return out
end

local function _selectedMapForCategory(catKey)
    catKey = _canonicalCategory(tostring(catKey or cfg.category or ""))
    if type(cfg.selectedByCat) == "table" and type(cfg.selectedByCat[catKey]) == "table" then
        return _normalizeSet(cfg.selectedByCat[catKey])
    end
    if _canonicalCategory(cfg.category) == catKey then
        return _normalizeSet(cfg.selected)
    end
    return {}
end

local function _resolveCategoryFromUi()
    local dd = G.__GAG2_NORMAL_GIFT_CAT_DD or rawget(_G, "__GAG2_NORMAL_GIFT_CAT_DD")
    if type(dd) == "table" and type(dd.getSelected) == "function" then
        local ok, sel = pcall(dd.getSelected, dd)
        if not ok then ok, sel = pcall(dd.getSelected) end
        if ok and sel ~= nil and tostring(sel) ~= "" then
            return _canonicalCategory(sel)
        end
    end
    local store = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
    if type(store) == "table" and store.category ~= nil and tostring(store.category) ~= "" then
        return _canonicalCategory(store.category)
    end
    return _canonicalCategory(cfg.category)
end

local function _resolveSelectedFromUi(catKey)
    catKey = _canonicalCategory(tostring(catKey or cfg.category or ""))
    local dd = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
    if type(dd) == "table" and type(dd.getSelected) == "function" then
        local ok, sel = pcall(dd.getSelected, dd)
        if not ok then ok, sel = pcall(dd.getSelected) end
        if ok and type(sel) == "table" then
            return _normalizeSet(sel)
        end
        if ok and sel ~= nil and tostring(sel) ~= "" then
            return { [tostring(sel)] = true }
        end
    end
    return _selectedMapForCategory(catKey)
end

local function _syncCfgFromUi()
    local catKey = _resolveCategoryFromUi()
    if catKey ~= "" then
        cfg.category = catKey
    end
    local selectedMap = _resolveSelectedFromUi(catKey)
    cfg.selected = selectedMap
    cfg.selectedByCat = type(cfg.selectedByCat) == "table" and cfg.selectedByCat or {}
    if catKey ~= "" then
        cfg.selectedByCat[catKey] = selectedMap
    end
end

local function _resolvePlayerFromKey(key)
    key = tostring(key or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if key == "" then return nil end

    local uid = math.floor(tonumber(key) or 0)
    if uid > 0 then
        local p = Players:GetPlayerByUserId(uid)
        if p and p ~= LP then return p end
    end

    local lower = key:lower():gsub("^@", "")
    for _, p in ipairs(Players:GetPlayers()) do
        if p ~= LP then
            local label = p.DisplayName .. " (@" .. p.Name .. ")"
            if p.Name:lower() == lower
                or p.DisplayName:lower() == lower
                or label:lower() == lower
                or label:lower():find(lower, 1, true)
                or lower:find(p.Name:lower(), 1, true) then
                return p
            end
        end
    end

    for _, item in ipairs(M.ListServerPlayers()) do
        if tostring(item.key or "") == key then
            local pid = math.floor(tonumber(item.userId or item.key) or 0)
            if pid > 0 then
                local p = Players:GetPlayerByUserId(pid)
                if p then return p end
            end
        end
        local itemName = tostring(item.name or ""):lower()
        if itemName == lower or itemName:find(lower, 1, true) then
            local pid = math.floor(tonumber(item.userId or item.key) or 0)
            if pid > 0 then
                local p = Players:GetPlayerByUserId(pid)
                if p then return p end
            end
        end
    end

    return nil
end

local function _syncTargetCfgFromPlayer(p)
    if not p then return false end
    cfg.target_user_id = p.UserId
    cfg.target_name = p.Name
    return true
end

local function _resolveTarget()
    local uid = math.floor(tonumber(cfg.target_user_id) or 0)
    if uid > 0 then
        local p = Players:GetPlayerByUserId(uid)
        if p then return p end
    end

    local p = _resolvePlayerFromKey(cfg.target_name)
    if p then
        _syncTargetCfgFromPlayer(p)
        return p
    end

    local store = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
    if type(store) == "table" then
        uid = math.floor(tonumber(store.target_user_id) or 0)
        if uid > 0 then
            p = Players:GetPlayerByUserId(uid)
            if p then
                _syncTargetCfgFromPlayer(p)
                return p
            end
        end
        p = _resolvePlayerFromKey(store.target_name)
        if p then
            _syncTargetCfgFromPlayer(p)
            return p
        end
    end

    local dd = G.__GAG2_NORMAL_GIFT_PLAYER_DD or rawget(_G, "__GAG2_NORMAL_GIFT_PLAYER_DD")
    if type(dd) == "table" and type(dd.getSelected) == "function" then
        local ok, sel = pcall(dd.getSelected, dd)
        if not ok then ok, sel = pcall(dd.getSelected) end
        if ok and sel ~= nil and tostring(sel) ~= "" then
            p = _resolvePlayerFromKey(sel)
            if p then
                _syncTargetCfgFromPlayer(p)
                return p
            end
        end
    end

    return nil
end

local function _distanceToPlayer(target)
    local char = LP.Character
    local tchar = target and target.Character
    if not char or not tchar then return math.huge end
    local hrp = char:FindFirstChild("HumanoidRootPart")
    local thrp = tchar:FindFirstChild("HumanoidRootPart")
    if not hrp or not thrp then return math.huge end
    return (hrp.Position - thrp.Position).Magnitude
end

local function _teleport(cf)
    if typeof(cf) ~= "CFrame" then return false end
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not char or not hrp then return false end
    local ok = pcall(function()
        if char.PrimaryPart then
            char:PivotTo(cf)
        else
            hrp.CFrame = cf
        end
    end)
    if ok then task.wait(AFTER_TP_SEC) end
    return ok
end

local function _teleportNearTarget(target)
    local tchar = target and target.Character
    local thrp = tchar and tchar:FindFirstChild("HumanoidRootPart")
    if not thrp then return false end

    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp then return false end

    local toUs = hrp.Position - thrp.Position
    local dir = toUs.Magnitude > 1 and toUs.Unit or -thrp.CFrame.LookVector
    local flat = Vector3.new(dir.X, 0, dir.Z)
    if flat.Magnitude < 0.05 then
        flat = Vector3.new(0, 0, -1)
    else
        flat = flat.Unit
    end

    local standDist = math.min(TP_STAND_DIST, math.max(3, MAX_SEND_DISTANCE - 1))
    local pos = thrp.Position + flat * standDist + Vector3.new(0, TP_Y_OFFSET, 0)
    local cf = CFrame.new(pos, thrp.Position)
    return _teleport(cf)
end

local function _ensureNearTarget(target)
    if _distanceToPlayer(target) <= MAX_SEND_DISTANCE then
        return true
    end
    if cfg.teleport_to_target ~= true then
        return false, "too_far"
    end
    if not _teleportNearTarget(target) then
        return false, "tp_fail"
    end
    return _distanceToPlayer(target) <= MAX_SEND_DISTANCE + 2
end

function M.TeleportToTarget(targetOrKey)
    local target = targetOrKey
    if typeof(targetOrKey) ~= "Instance" or not targetOrKey:IsA("Player") then
        target = _resolveTarget()
    end
    if not target then
        _setStatus("Select a player in this server")
        return false, "no_target"
    end
    if _teleportNearTarget(target) then
        _setStatus(string.format("Teleported near %s", target.Name))
        return true
    end
    _setStatus("Teleport failed")
    return false, "tp_fail"
end

local function _getEquippedGiftInfo()
    local char = LP.Character
    if not char then return nil end
    local tool = char:FindFirstChildWhichIsA("Tool")
    if not tool then return nil end
    return _toolGiftInfo(tool), tool
end

local function _equipTool(tool)
    if not tool or not tool:IsA("Tool") then return false end
    local char = LP.Character
    local hum = char and char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end
    local bp = LP:FindFirstChildOfClass("Backpack")
    if bp and tool.Parent == bp then
        pcall(function() hum:UnequipTools() end)
        tool.Parent = char
        return true
    end
    pcall(function() hum:EquipTool(tool) end)
    return true
end

local function _findToolByFruitId(id)
    id = tostring(id or "")
    if id == "" then return nil end
    local found
    _foreachGiftInstance(function(inst)
        if found then return end
        if not inst.Parent then return end
        if tostring(inst:GetAttribute("Id") or "") ~= id then return end
        if inst:IsA("Tool") then
            found = inst
            return
        end
        local cur = inst
        while cur and cur ~= LP and cur ~= game do
            if cur:IsA("Tool") then
                found = cur
                return
            end
            cur = cur.Parent
        end
    end)
    return found
end

local function _promoteFruitForSend(fruitId)
    fruitId = tostring(fruitId or "")
    if fruitId == "" then return nil end

    local existing = _findToolByFruitId(fruitId)
    if existing and existing.Parent then return existing end

    if not _ensureBackpackNetworking() then return nil end
    local ok = _callNetworkingRemote(BackpackPromoteFruit, fruitId)
    if not ok then return nil end

    _invalidateVirtualFruitCache()
    for _ = 1, 20 do
        task.wait(0.1)
        existing = _findToolByFruitId(fruitId)
        if existing and existing.Parent then return existing end
    end
    return nil
end

local function _resolveSendTool(inst, info)
    if inst and inst:IsA("Tool") and inst.Parent then return inst end
    if inst and inst.Parent then
        local cur = inst.Parent
        while cur and cur ~= LP and cur ~= game do
            if cur:IsA("Tool") and cur.Parent then return cur end
            cur = cur.Parent
        end
    end
    if info and info.uuid then
        return _findToolByFruitId(info.uuid)
    end
    return nil
end

local function _collectSendCandidates(catKey, selectedMap)
    catKey = _canonicalCategory(tostring(catKey or cfg.category or "Seeds"))
    if catKey == "" then catKey = "Seeds" end
    if _isHarvestedFruitsCategory(catKey) then
        selectedMap = _expandSelectedMapForHarvest(selectedMap)
    end
    local candidates = {}

    _foreachGiftInstance(function(inst)
        if inst.Parent then
            local info = _toolGiftInfo(inst)
            if info and _canonicalGiftType(info.giftType) == catKey
                and _matchesToolSelection(inst, info, selectedMap) then
                candidates[#candidates + 1] = {
                    inst = inst,
                    virtual = false,
                    tool = _resolveSendTool(inst, info),
                    giftType = _canonicalGiftType(info.giftType),
                    uuid = info.uuid,
                    key = info.key,
                    name = _toolDisplayName(inst),
                }
            end
        end
    end)

    if _isHarvestedFruitsCategory(catKey) then
        local seenUuid = {}
        for _, c in ipairs(candidates) do
            if c.uuid then seenUuid[tostring(c.uuid)] = true end
        end
        for _, info in ipairs(_collectInstanceFruitInfos()) do
            local uuid = tostring(info.uuid or "")
            if uuid ~= "" and not seenUuid[uuid] and _matchesToolSelection(nil, info, selectedMap) then
                seenUuid[uuid] = true
                candidates[#candidates + 1] = {
                    inst = info.inst,
                    virtual = true,
                    tool = _findToolByFruitId(uuid),
                    giftType = "HarvestedFruits",
                    uuid = info.uuid,
                    key = info.key,
                    name = tostring(info.key or info.name or "Fruit"),
                }
            end
        end
    end

    return candidates
end

local function _looksLikeConfigPatch(t)
    if type(t) ~= "table" then return false end
    return t.target_user_id ~= nil
        or t.target_name ~= nil
        or t.category ~= nil
        or t.selected ~= nil
        or t.selectedByCat ~= nil
        or t.send_total ~= nil
        or t.teleport_to_target ~= nil
end

function M.SendNow(a, b)
    if sendBusy then
        _setStatus("Send already running")
        return false, "busy"
    end
    if _looksLikeConfigPatch(a) and b == nil then
        M.ApplyConfig(a)
    else
        M.SyncFromGlobals()
        _syncCfgFromUi()
    end

    if not _ensureNetworking() then
        _setStatus("Gifting remote not ready")
        return false, "no_remote"
    end

    if not _ensureGiftAttrMap() then
        _setStatus("GiftingController map not ready — wait/rejoin")
        return false, "no_gift_map"
    end

    local target = _resolveTarget()
    if not target then
        _setStatus("Select a player in this server")
        return false, "no_target"
    end

    local dist = _distanceToPlayer(target)
    if dist > MAX_SEND_DISTANCE then
        if cfg.teleport_to_target == true then
            local nearOk, nearErr = _ensureNearTarget(target)
            if not nearOk then
                if nearErr == "tp_fail" then
                    _setStatus("Teleport to target failed")
                    return false, "tp_fail"
                end
                _setStatus(string.format("Too far (%.0f studs) — enable teleport to target", dist))
                return false, "too_far"
            end
        else
            _setStatus(string.format("Too far (%.0f studs) — move within %d studs or enable teleport", dist, MAX_SEND_DISTANCE))
            return false, "too_far"
        end
    end

    local catKey = _canonicalCategory(tostring(cfg.category or "Seeds"))
    if catKey == "" then catKey = "Seeds" end
    local selectedMap = _selectedMapForCategory(catKey)
    if not _hasSelection(selectedMap) then
        _setStatus("Select at least 1 item in list")
        return false, "no_selection"
    end
    local allCandidates = _collectSendCandidates(catKey, selectedMap)
    if #allCandidates == 0 then
        _setStatus("No matching giftable items for selected category")
        return false, "no_items"
    end

    local total = math.floor(math.max(1, math.min(50, tonumber(cfg.send_total) or 1)))
    sendBusy = true
    local sent = 0

    task.spawn(function()
        for n = 1, total do
            if cfg.teleport_to_target == true and _distanceToPlayer(target) > MAX_SEND_DISTANCE then
                _teleportNearTarget(target)
            end

            local candidates = _collectSendCandidates(catKey, selectedMap)
            if #candidates == 0 then break end

            local item = candidates[((n - 1) % #candidates) + 1]
            if not item then break end

            local tool = item.tool
            if item.giftType == "HarvestedFruits" and (not tool or not tool.Parent) then
                tool = _promoteFruitForSend(item.uuid)
                item.tool = tool
            end
            if tool and tool.Parent then
                _equipTool(tool)
                task.wait(0.15)
            elseif item.giftType == "HarvestedFruits" then
                task.wait(0.05)
            else
                task.wait(0.05)
            end

            local sendType = item.giftType
            local sendUuid = item.uuid
            local equippedInfo = select(1, _getEquippedGiftInfo())
            if equippedInfo then
                sendType = equippedInfo.giftType
                sendUuid = equippedInfo.uuid
            end

            if item.giftType == "HarvestedFruits" and not equippedInfo and not tool then
                -- PromoteFruit failed; skip this round
            else
                local ok = _callNetworkingRemote(GiftingSend, target.UserId, sendType, sendUuid)
                if ok then
                    sent += 1
                    stats.sentCount += 1
                    _invalidateVirtualFruitCache()
                end
            end
            task.wait(math.max(SEND_DELAY_SEC, MIN_SEND_GAP))
        end

        sendBusy = false
        if sent > 0 then
            _setStatus(string.format("Sent %d gift(s) to %s", sent, target.Name))
        elseif catKey == "HarvestedFruits" then
            _setStatus("Send failed — PromoteFruit/hotbar issue")
        else
            _setStatus("Send failed — check distance & item")
        end

        local done = G.__GAG2_NORMAL_GIFT_SEND_DONE or rawget(_G, "__GAG2_NORMAL_GIFT_SEND_DONE")
        if type(done) == "function" then
            pcall(done, sent > 0)
        end
    end)

    return true, "started"
end

function M.ApplyConfig(nextCfg)
    if not _looksLikeConfigPatch(nextCfg) then return end
    if nextCfg.target_user_id ~= nil then
        cfg.target_user_id = math.floor(tonumber(nextCfg.target_user_id) or 0)
    end
    if nextCfg.target_name ~= nil then
        cfg.target_name = tostring(nextCfg.target_name or "")
    end
    if nextCfg.category ~= nil and tostring(nextCfg.category) ~= "" then
        cfg.category = _canonicalCategory(nextCfg.category)
    end
    if type(nextCfg.selectedByCat) == "table" then
        cfg.selectedByCat = {}
        for cat, sel in pairs(nextCfg.selectedByCat) do
            local ck = _canonicalCategory(cat)
            if ck ~= "" then
                cfg.selectedByCat[ck] = _normalizeSet(sel)
            end
        end
    end
    if type(nextCfg.selected) == "table" then
        local cur = _canonicalCategory(nextCfg.category or cfg.category)
        cfg.selected = _normalizeSet(nextCfg.selected)
        cfg.selectedByCat = type(cfg.selectedByCat) == "table" and cfg.selectedByCat or {}
        if cur ~= "" then
            cfg.selectedByCat[cur] = cfg.selected
        end
    elseif cfg.category ~= "" and type(cfg.selectedByCat) == "table" then
        local cur = _canonicalCategory(cfg.category)
        if type(cfg.selectedByCat[cur]) == "table" then
            cfg.selected = _normalizeSet(cfg.selectedByCat[cur])
        end
    end
    if nextCfg.send_total ~= nil then
        local n = math.floor(tonumber(nextCfg.send_total) or 1)
        if n < 1 then n = 1 end
        if n > 50 then n = 50 end
        cfg.send_total = n
    end
    if nextCfg.teleport_to_target ~= nil then
        cfg.teleport_to_target = (nextCfg.teleport_to_target == true)
    end
    if _resolveTarget() then
        _setStatus("Ready")
    end
    G.__GAG2_NORMAL_GIFT = M.GetConfig()
    _G.__GAG2_NORMAL_GIFT = G.__GAG2_NORMAL_GIFT
end

function M.GetConfig()
    local catKey = _canonicalCategory(cfg.category)
    return {
        target_user_id = cfg.target_user_id,
        target_name = cfg.target_name,
        category = catKey,
        selected = _normalizeSet(cfg.selected),
        selectedByCat = type(cfg.selectedByCat) == "table" and cfg.selectedByCat or {},
        send_total = cfg.send_total,
        teleport_to_target = cfg.teleport_to_target == true,
    }
end

function M.GetStats()
    return {
        lastStatus = stats.lastStatus,
        lastError = stats.lastError,
        sentCount = stats.sentCount,
        busy = sendBusy,
    }
end

local function _listToolAttributeLines(tool)
    local lines = {}
    pcall(function()
        for name, val in pairs(tool:GetAttributes()) do
            lines[#lines + 1] = tostring(name) .. "=" .. tostring(val)
        end
    end)
    table.sort(lines)
    return lines
end

function M.PrintDebug(catKey)
    catKey = _canonicalCategory(tostring(catKey or cfg.category or "Seeds"))
    if catKey == "" then catKey = "Seeds" end

    local lines = {}
    local function line(msg)
        msg = tostring(msg or "")
        lines[#lines + 1] = msg
        print("[NormalGift] " .. msg)
    end

    line("=== NormalGift Debug ===")
    line("category=" .. catKey)
    line("ControllersStarted=" .. tostring(LP:HasTag("ControllersStarted")))

    local map = _ensureGiftAttrMap(5)
    if map then
        line("gift attr map: loaded")
        for _, attr in ipairs(GIFT_ATTR_ORDER or {}) do
            line("  " .. attr .. " -> " .. tostring(map[attr]))
        end
    else
        line("gift attr map: NOT loaded (wait/rejoin)")
    end

    local toolCount = 0
    local instCount = 0
    local giftableCount = 0
    _foreachGiftInstance(function(inst)
        instCount += 1
        if inst:IsA("Tool") then toolCount += 1 end
        local parentName = inst.Parent and inst.Parent.Name or "?"
        local attrText = table.concat(_listToolAttributeLines(inst), ", ")
        local info = _toolGiftInfo(inst)
        if info then
            giftableCount += 1
            line(string.format(
                "INST #%d parent=%s class=%s name=%s giftType=%s key=%s uuid=%s attrs=[%s]",
                instCount, parentName, inst.ClassName, inst.Name, info.giftType, info.key, info.uuid, attrText
            ))
        else
            line(string.format(
                "INST #%d parent=%s class=%s name=%s NOT giftable attrs=[%s]",
                instCount, parentName, inst.ClassName, inst.Name, attrText
            ))
        end
    end)
    line("instances=" .. instCount .. " tools=" .. toolCount .. " giftable=" .. giftableCount)

    local items = _toolsAsUiItems(catKey)
    line("UI items for " .. catKey .. ": " .. #items)
    for i = 1, math.min(#items, 25) do
        local it = items[i]
        line("  item[" .. i .. "] key=" .. tostring(it.key) .. " name=" .. tostring(it.name))
    end

    local sel = _selectedMapForCategory(catKey)
    local selCount = 0
    for _, v in pairs(sel) do
        if v == true then selCount += 1 end
    end
    line("selected count=" .. selCount)
    line("=== end debug ===")

    return table.concat(lines, "\n")
end

local PlayerStateClient = nil

local function _ensurePlayerState()
    if PlayerStateClient then return true end
    local function tryRequire(modInst)
        if not modInst then return false end
        local ok, mod = pcall(require, modInst)
        if ok and type(mod) == "table" then
            PlayerStateClient = mod
            return true
        end
        return false
    end
    local cm = ReplicatedStorage:FindFirstChild("ClientModules")
    if cm and tryRequire(cm:FindFirstChild("PlayerStateClient")) then return true end
    local ok = pcall(function()
        return tryRequire(ReplicatedStorage:WaitForChild("ClientModules", 5):WaitForChild("PlayerStateClient"))
    end)
    return ok and PlayerStateClient ~= nil
end

local function _getPlayerStateInventory(waitSec)
    waitSec = tonumber(waitSec) or 2
    if not _ensurePlayerState() then return nil end
    if type(PlayerStateClient.GetLocalReplica) ~= "function" then return nil end
    local replica = PlayerStateClient:GetLocalReplica()
    local deadline = os.clock() + waitSec
    while not replica and os.clock() < deadline do
        task.wait(0.1)
        replica = PlayerStateClient:GetLocalReplica()
    end
    if not replica or type(replica.Data) ~= "table" then return nil end
    local inv = replica.Data.Inventory
    return type(inv) == "table" and inv or nil
end

local function _countBagEntries(bag)
    if type(bag) ~= "table" then return 0 end
    local nested = bag.List or bag.Items
    if type(nested) == "table" and #nested > 0 then return #nested end
    local n = 0
    for k, v in pairs(bag) do
        if tostring(k):sub(1, 1) ~= "_" then
            n += 1
        end
    end
    return n
end

local function _summarizeBagEntry(entry, itemKey)
    itemKey = tostring(itemKey or "")
    if type(entry) == "table" then
        local parts = {}
        for _, field in ipairs({ "Id", "UUID", "Name", "DisplayName", "Type", "Count", "Amount", "Qty" }) do
            local val = entry[field]
            if val ~= nil and tostring(val) ~= "" then
                parts[#parts + 1] = field .. "=" .. tostring(val)
            end
        end
        if #parts > 0 then return table.concat(parts, ", ") end
        return "table"
    end
    return "count=" .. tostring(entry)
end

function M.PrintInventoryDebug()
    local lines = {}
    local function line(msg)
        msg = tostring(msg or "")
        lines[#lines + 1] = msg
        print("[NormalGift-Inv] " .. msg)
    end

    line("=== Inventory Debug (Normal Gift vs PlayerState) ===")
    line("Normal Gift source = Tool di Backpack/Character (BUKAN inventory virtual)")
    line("ControllersStarted=" .. tostring(LP:HasTag("ControllersStarted")))

    local map = _ensureGiftAttrMap(5)
    if map then
        line("gift attr map: loaded")
        for _, attr in ipairs(GIFT_ATTR_ORDER or {}) do
            line("  " .. attr .. " -> " .. tostring(map[attr]))
        end
    else
        line("gift attr map: NOT loaded")
    end

    line("")
    line("--- A) GIFT INSTANCES (Backpack/Character/player folders) ---")
    local instCount = 0
    local toolCount = 0
    local giftableByType = {}
    _foreachGiftInstance(function(inst)
        instCount += 1
        if inst:IsA("Tool") then toolCount += 1 end
        local parentName = inst.Parent and inst.Parent.Name or "?"
        local attrText = table.concat(_listToolAttributeLines(inst), ", ")
        local info = _toolGiftInfo(inst)
        if info then
            giftableByType[info.giftType] = (giftableByType[info.giftType] or 0) + 1
            line(string.format(
                "INST parent=%s class=%s name=%s giftType=%s key=%s uuid=%s attrs=[%s]",
                parentName, inst.ClassName, inst.Name, info.giftType, info.key, info.uuid, attrText
            ))
        else
            line(string.format(
                "INST parent=%s class=%s name=%s NOT giftable attrs=[%s]",
                parentName, inst.ClassName, inst.Name, attrText
            ))
        end
    end)
    line("instances total=" .. instCount .. " tools=" .. toolCount)
    line("player FruitCount=" .. tostring(LP:GetAttribute("FruitCount"))
        .. " MaxFruitCapacity=" .. tostring(LP:GetAttribute("MaxFruitCapacity")))
    line("Backpack.GetLayout fruits=" .. #_getVirtualFruits(true))
    local cats = M.GetCategoryDefs()
    line("giftable categories from tools=" .. #cats)
    for _, def in ipairs(cats) do
        line("  cat " .. def.key .. " tools=" .. tostring(giftableByType[def.key] or 0))
    end

    line("")
    line("--- B) PLAYERSTATE INVENTORY (virtual, untuk Gift Mail) ---")
    local inv = _getPlayerStateInventory(3)
    if not inv then
        line("PlayerState inventory: NOT available")
    else
        local bagKeys = {}
        for key in pairs(inv) do
            if type(inv[key]) == "table" then
                bagKeys[#bagKeys + 1] = tostring(key)
            end
        end
        table.sort(bagKeys)
        line("inventory bags=" .. #bagKeys)
        for _, bagKey in ipairs(bagKeys) do
            local bag = inv[bagKey]
            local entryCount = _countBagEntries(bag)
            line("  bag[" .. bagKey .. "] entries=" .. entryCount)
            local shown = 0
            if type(bag) == "table" then
                local nested = bag.List or bag.Items
                if type(nested) == "table" and #nested > 0 then
                    for idx, entry in ipairs(nested) do
                        shown += 1
                        if shown <= 8 then
                            line("    [" .. idx .. "] " .. _summarizeBagEntry(entry, idx))
                        end
                    end
                else
                    for itemKey, entry in pairs(bag) do
                        if tostring(itemKey):sub(1, 1) ~= "_" then
                            shown += 1
                            if shown <= 8 then
                                line("    [" .. tostring(itemKey) .. "] " .. _summarizeBagEntry(entry, itemKey))
                            end
                        end
                    end
                end
                if shown > 8 then
                    line("    ... +" .. (shown - 8) .. " more")
                end
            end
        end
    end

    line("")
    line("--- C) UI preview per category ---")
    for _, def in ipairs(cats) do
        local items = _toolsAsUiItems(def.key)
        line("  " .. def.key .. " uiItems=" .. #items)
    end
    line("=== end inventory debug ===")

    return table.concat(lines, "\n")
end

local function _harvestRejectReason(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return "invalid instance" end
    if inst:GetAttribute("SeedTool") ~= nil then return "has SeedTool (seed pack)" end
    if inst:GetAttribute("Pet") ~= nil then return "has Pet attribute" end
    if inst:GetAttribute("PottedPlant") == true then return "PottedPlant=true" end
    if tostring(inst:GetAttribute("MainCategory") or "") == "Seed" then return "MainCategory=Seed" end

    local hf = inst:GetAttribute("HarvestedFruit")
    local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
    local parts = {
        "class=" .. inst.ClassName,
        "FruitName=" .. tostring(fruitName),
        "FruitProxy=" .. tostring(inst:GetAttribute("FruitProxy")),
        "Id=" .. tostring(inst:GetAttribute("Id")),
        "HarvestedFruit=" .. tostring(hf),
        "Mutation=" .. tostring(inst:GetAttribute("Mutation")),
        "SizeMultiplier=" .. tostring(inst:GetAttribute("SizeMultiplier")),
    }
    return "bukan harvest fruit (perlu FruitName/FruitProxy/HarvestedFruit) | " .. table.concat(parts, " ")
end

function M.PrintHarvestDebug()
    local lines = {}
    local function line(msg)
        msg = tostring(msg or "")
        lines[#lines + 1] = msg
        print("[NormalGift-Harvest] " .. msg)
    end

    line("=== HarvestedFruit Debug ===")
    line("Sumber: Backpack.GetLayout (virtual) + Tool di hotbar")
    line("Kirim: Backpack.PromoteFruit(Id) -> equip Tool -> Gifting.Send(userId, type, Id)")
    line("Gifting.Send = (userId, giftType, uuid) per Networking decompile")

    local map = _ensureGiftAttrMap(5)
    if map then
        line("map HarvestedFruit -> " .. tostring(map.HarvestedFruit or "MISSING"))
    else
        line("gift map NOT loaded")
    end

    line("Backpack API ready=" .. tostring(_ensureBackpackNetworking()))
    line("player FruitCount=" .. tostring(LP:GetAttribute("FruitCount"))
        .. " MaxFruitCapacity=" .. tostring(LP:GetAttribute("MaxFruitCapacity")))

    local virtualFruits = _getVirtualFruits(true)
    local layoutOnly = 0
    local instanceOnly = 0
    for _, info in ipairs(virtualFruits) do
        if info.source == "layout" then layoutOnly += 1
        elseif info.source == "instance" then instanceOnly += 1 end
    end
    line("Backpack.GetLayout fruits=" .. #virtualFruits
        .. " (layout=" .. layoutOnly .. " instance=" .. instanceOnly .. ")")
    if #virtualFruits == 0 and _ensureBackpackNetworking() then
        local layout = G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT or rawget(_G, "__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT")
        if type(layout) == "table" then
            local keys = {}
            for k in pairs(layout) do keys[#keys + 1] = tostring(k) end
            table.sort(keys)
            line("layout top-level keys: " .. table.concat(keys, ", "))
        end
    end
    for i = 1, math.min(#virtualFruits, 12) do
        local info = virtualFruits[i]
        line(string.format(
            "LAYOUT #%d uuid=%s key=%s hasTool=%s",
            i, tostring(info.uuid), tostring(info.key),
            tostring(_findToolByFruitId(info.uuid) ~= nil)
        ))
    end

    local fruitLike = 0
    local giftable = 0
    local withTool = 0
    _foreachGiftInstance(function(inst)
        local parentName = inst.Parent and inst.Parent.Name or "?"
        local attrs = table.concat(_listToolAttributeLines(inst), ", ")
        if _instLooksLikeHarvestedFruit(inst) then
            fruitLike += 1
            local info = _toolGiftInfo(inst)
            local sendTool = info and _resolveSendTool(inst, info)
            if sendTool then withTool += 1 end
            if info and info.giftType == "HarvestedFruits" then
                giftable += 1
                line(string.format(
                    "OK parent=%s class=%s name=%s key=%s uuid=%s hasTool=%s attrs=[%s]",
                    parentName, inst.ClassName, inst.Name, info.key, info.uuid,
                    tostring(sendTool ~= nil), attrs
                ))
            else
                line(string.format(
                    "FRUIT-LIKE but not giftable parent=%s class=%s name=%s attrs=[%s]",
                    parentName, inst.ClassName, inst.Name, attrs
                ))
            end
        end
    end)

    line("fruit-like instances=" .. fruitLike .. " giftable HarvestedFruits=" .. giftable
        .. " with sendable Tool=" .. withTool)
    line("category HarvestedFruits uiItems=" .. #_toolsAsUiItems("HarvestedFruits"))

    if fruitLike == 0 and #virtualFruits == 0 then
        line("")
        line("Tidak ada buah di Backpack.GetLayout maupun Tool client.")
        line("Harvest/collect buah dulu, lalu debug lagi.")
        line("")
        line("Sample non-fruit instances (max 5):")
        local shown = 0
        _foreachGiftInstance(function(inst)
            if shown >= 5 then return end
            if not _instLooksLikeHarvestedFruit(inst) then
                shown += 1
                local parentName = inst.Parent and inst.Parent.Name or "?"
                line("  " .. parentName .. "/" .. inst.Name .. " (" .. inst.ClassName .. ") | " .. _harvestRejectReason(inst))
            end
        end)
    elseif withTool == 0 and #virtualFruits > 0 then
        line("")
        line("Buah ada di layout — Normal Gift akan PromoteFruit otomatis saat Send.")
    end

    local inv = _getPlayerStateInventory(2)
    if inv then
        line("")
        line("PlayerState bags dengan 'fruit' di nama:")
        local found = false
        for key, bag in pairs(inv) do
            if type(bag) == "table" and tostring(key):lower():find("fruit", 1, true) then
                found = true
                line("  bag[" .. tostring(key) .. "] entries=" .. _countBagEntries(bag))
            end
        end
        if not found then
            line("  (tidak ada — harvest fruit memang bukan virtual bag)")
        end
    end

    line("=== end harvest debug ===")
    return table.concat(lines, "\n")
end

function M.SyncFromGlobals()
    local uiReady = G.__GAG2_NORMAL_GIFT_UI_READY == true
        or rawget(_G, "__GAG2_NORMAL_GIFT_UI_READY") == true

    if uiReady then
        _syncCfgFromUi()
        local store = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
        if type(store) == "table" then
            if store.target_user_id ~= nil or store.target_name ~= nil then
                M.ApplyConfig({
                    target_user_id = store.target_user_id,
                    target_name = store.target_name,
                    send_total = store.send_total,
                    teleport_to_target = store.teleport_to_target,
                })
            end
        end
        return
    end

    local store = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
    if type(store) == "table" then
        M.ApplyConfig(store)
    end
    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.auto) == "table" and type(main.auto.normalGift) == "table" then
        local ngMain = main.auto.normalGift
        local patch = {
            target_user_id = ngMain.target_user_id,
            target_name = ngMain.target_name,
            category = ngMain.category,
            send_total = ngMain.send_total,
            teleport_to_target = ngMain.teleport_to_target,
        }
        if type(ngMain.selectedByCat) == "table" then
            patch.selectedByCat = ngMain.selectedByCat
        end
        if type(ngMain.selected) == "table" then
            patch.selected = ngMain.selected
        end
        M.ApplyConfig(patch)
    end
end

G.NormalGift = M
G.NormalGiftModule = M
G.NormalGiftDebug = M.PrintDebug
G.NormalGiftInventoryDebug = M.PrintInventoryDebug
G.NormalGiftHarvestDebug = M.PrintHarvestDebug
_G.NormalGift = M
_G.NormalGiftModule = M
_G.NormalGiftDebug = M.PrintDebug
_G.NormalGiftInventoryDebug = M.PrintInventoryDebug
_G.NormalGiftHarvestDebug = M.PrintHarvestDebug

task.defer(function()
    for _ = 1, 20 do
        if _ensureNetworking() then break end
        task.wait(0.5)
    end
    _waitForControllersStarted(20)
    for _ = 1, 30 do
        if _ensureGiftAttrMap(0) then break end
        task.wait(0.5)
    end
    if _ensureBackpackNetworking() then
        pcall(_getVirtualFruits, true)
    end
    M.SyncFromGlobals()
    if stats.lastStatus == "Ready" then
        _setStatus("Ready")
    end
    local refresh = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
    if type(refresh) == "table" and type(refresh.refreshItems) == "function" then
        pcall(refresh.refreshItems, refresh)
    end
    refresh = G.__GAG2_NORMAL_GIFT_CAT_DD or rawget(_G, "__GAG2_NORMAL_GIFT_CAT_DD")
    if type(refresh) == "table" and type(refresh.refreshItems) == "function" then
        pcall(refresh.refreshItems, refresh)
    end
end)

return M
 end,            required = false },
    { key = "AutoShovel",      name = "Auto Shovel",      factory = function() -- AutoShovel.lua - Grow A Garden 2
-- Equip shovel -> Networking.Shovel.UseShovel:Fire(plantId, fruitId, shovelType, tool)

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService        = game:GetService("RunService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local UseShovel     = nil
local remotesReady  = false
local LOOP_SEC      = 0.72
local SHOVEL_CD     = 0.68

local running       = false
local loopId        = 0
local shovelBusy    = false
local lastShovelAt  = 0
local plantsConn    = nil
local plotConn      = nil

local stats = {
    attempts = 0,
    ok = 0,
    skipped = {},
    lastError = nil,
    lastPlantId = nil,
    lastSkip = nil,
}

local function _dbg()
    return G.AUTO_SHOVEL_DEBUG == true or _G.AUTO_SHOVEL_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-AS]", ...)
end

local function _enabled()
    local store = G.__GAG2_SHOVEL or rawget(_G, "__GAG2_SHOVEL")
    if type(store) == "table" and store.enabled == true then return true end
    return G.AUTO_SHOVEL_ENABLED == true or rawget(_G, "AUTO_SHOVEL_ENABLED") == true
end

local function _selectedMap()
    local map = G.AUTO_SHOVEL_PLANTS_SELECTED or rawget(_G, "AUTO_SHOVEL_PLANTS_SELECTED")
    if type(map) == "table" then
        if map._none then map._none = nil end
        return map
    end
    local store = G.__GAG2_SHOVEL or rawget(_G, "__GAG2_SHOVEL")
    if type(store) == "table" and type(store.plants) == "table" then
        map = {}
        for _, id in ipairs(store.plants) do
            if id ~= nil and tostring(id) ~= "" and tostring(id) ~= "_none" then
                map[tostring(id)] = true
            end
        end
        return map
    end
    return {}
end

local function _selectedCount()
    local n = 0
    for k, v in pairs(_selectedMap()) do
        if v == true and k ~= "_none" then n = n + 1 end
    end
    return n
end

local function _canRun()
    return _enabled() and _selectedCount() >= 1
end

function M.GetSelectedCount()
    return _selectedCount()
end
M.getSelectedCount = M.GetSelectedCount

function M.HasSelection()
    return _selectedCount() >= 1
end
M.hasSelection = M.HasSelection

function M.CanRun()
    return _canRun()
end
M.canRun = M.CanRun

local function _initRemotes()
    if remotesReady then return end
    remotesReady = true
    local ok, Networking = pcall(function()
        return require(ReplicatedStorage.SharedModules.Networking)
    end)
    if not ok or type(Networking) ~= "table" then
        stats.lastError = "Networking require gagal"
        return
    end
    local ShovelNet = Networking.Shovel
    if type(ShovelNet) == "table" and type(ShovelNet.UseShovel) == "table"
        and type(ShovelNet.UseShovel.Fire) == "function" then
        UseShovel = ShovelNet.UseShovel
    end
    if not UseShovel then
        stats.lastError = "UseShovel MISSING"
        warn("[GAG2-AS] UseShovel remote tidak ditemukan")
    end
end

local function _getPlot()
    local plotId = LP and LP:GetAttribute("PlotId")
    if not plotId then return nil end
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return nil end
    return gardens:FindFirstChild("Plot" .. tostring(plotId))
end

local function _getPlantsFolder()
    local plot = _getPlot()
    return plot and plot:FindFirstChild("Plants") or nil
end

function M.GetPlantDisplayName(plant)
    if not plant then return "?" end
    return plant:GetAttribute("SeedName")
        or plant:GetAttribute("ConfigPathName")
        or plant:GetAttribute("CorePartName")
        or plant:GetAttribute("FruitType")
        or plant:GetAttribute("ItemName")
        or plant.Name
end
M.getPlantDisplayName = M.GetPlantDisplayName

local function _mutationNamesFallback()
    local PLV = G.PlantListView or rawget(_G, "PlantListView")
    if type(PLV) == "table" and type(PLV.listMutationNames) == "function" then
        local ok, list = pcall(PLV.listMutationNames, PLV)
        if ok and type(list) == "table" and #list > 0 then return list end
    end
    return { "Gold", "Rainbow" }
end

-- Dex: plant punya attribute string "Mutation" = "Gold" / "Rainbow" / ...
function M.GetPlantMutation(plant)
    if not plant then return nil end
    local mut = plant:GetAttribute("Mutation")
    if type(mut) == "string" then
        mut = mut:gsub("^%s+", ""):gsub("%s+$", "")
        if mut ~= "" and mut:lower() ~= "none" and mut:lower() ~= "normal" then
            return mut
        end
    end
    for _, name in ipairs(_mutationNamesFallback()) do
        if plant:GetAttribute(name) == true then
            return name
        end
    end
    return nil
end
M.getPlantMutation = M.GetPlantMutation

function M.GetPlantTypeKey(plant)
    local name = M.GetPlantDisplayName(plant)
    name = tostring(name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name == "" then name = plant and plant.Name or "Unknown" end
    local mut = M.GetPlantMutation(plant)
    if mut then
        return mut .. " " .. name
    end
    return name
end
M.getPlantTypeKey = M.GetPlantTypeKey

local function _plantMatchesSelection(plant, sel)
    if not plant or type(sel) ~= "table" then return false end
    local typeKey = M.GetPlantTypeKey(plant)
    if sel[typeKey] then return true end
    -- backward compat: save lama pakai instance Name
    if sel[plant.Name] then return true end
    return false
end

function M.BuildGardenPlantItems()
    local items = {}
    local folder = _getPlantsFolder()
    if not folder then return items end

    local groups = {}
    for _, plant in ipairs(folder:GetChildren()) do
        local typeKey = M.GetPlantTypeKey(plant)
        local g = groups[typeKey]
        if not g then
            g = { key = typeKey, name = typeKey, count = 0 }
            groups[typeKey] = g
        end
        g.count = g.count + 1
    end

    for _, g in pairs(groups) do
        items[#items + 1] = {
            key = g.key,
            name = string.format("%s x %d", g.name, g.count),
            count = g.count,
        }
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)
    return items
end
M.buildGardenPlantItems = M.BuildGardenPlantItems

function M.GetActiveTypeKeys()
    local out = {}
    for _, item in ipairs(M.BuildGardenPlantItems()) do
        local k = item and item.key
        if k and k ~= "" and k ~= "_none" then
            out[tostring(k)] = true
        end
    end
    return out
end
M.getActiveTypeKeys = M.GetActiveTypeKeys

-- Buang tipe dari selection kalau sudah tidak ada di garden
function M.PruneSelectionToGarden(sel)
    sel = type(sel) == "table" and sel or _selectedMap()
    local active = M.GetActiveTypeKeys()
    local out = {}
    local removed = {}
    for k, v in pairs(sel) do
        if v == true and k ~= "_none" then
            if active[k] then
                out[k] = true
            else
                removed[#removed + 1] = k
            end
        end
    end
    return out, #removed > 0, removed
end
M.pruneSelectionToGarden = M.PruneSelectionToGarden

local function _notifyPlantsChanged()
    local fn = G.__GAG2_ON_SHOVEL_PLANTS_CHANGED or rawget(_G, "__GAG2_ON_SHOVEL_PLANTS_CHANGED")
    if type(fn) == "function" then
        pcall(fn)
    end
end

local function _unbindPlantsWatch()
    if plantsConn then plantsConn:Disconnect() plantsConn = nil end
    if plotConn then plotConn:Disconnect() plotConn = nil end
end

local function _bindPlantsWatch(folder)
    _unbindPlantsWatch()
    if not folder then return end
    plantsConn = folder.ChildAdded:Connect(function()
        task.defer(_notifyPlantsChanged)
    end)
    folder.ChildRemoved:Connect(function()
        task.defer(_notifyPlantsChanged)
    end)
    local plot = folder.Parent
    if plot then
        plotConn = plot.ChildAdded:Connect(function(ch)
            if ch.Name == "Plants" then
                _bindPlantsWatch(ch)
                _notifyPlantsChanged()
            end
        end)
    end
end

local function _getEquippedShovel()
    local char = LP and LP.Character
    if not char then return nil end
    for _, ch in ipairs(char:GetChildren()) do
        if ch:IsA("Tool") and ch:GetAttribute("Shovel") then
            return ch
        end
    end
    return nil
end

local function _equipShovel()
    if _getEquippedShovel() then return true end
    local char = LP and LP.Character
    local hum = char and char:FindFirstChildOfClass("Humanoid")
    local bp = LP and LP:FindFirstChild("Backpack")
    if not hum or not bp then return false end
    for _, tool in ipairs(bp:GetChildren()) do
        if tool:IsA("Tool") and tool:GetAttribute("Shovel") then
            local ok = pcall(function() hum:EquipTool(tool) end)
            if ok and _getEquippedShovel() then return true end
        end
    end
    return false
end

local function _shovelPlantInst(plant)
    _initRemotes()
    if not UseShovel or not plant or not plant.Parent then return false, "no_plant" end

    if os.clock() - lastShovelAt < SHOVEL_CD then
        return false, "cooldown"
    end

    if not _equipShovel() then
        stats.lastError = "shovel_not_equipped"
        return false, "no_tool"
    end

    local tool = _getEquippedShovel()
    if not tool then return false, "no_tool" end

    local shovelType = tool:GetAttribute("Shovel")
    if shovelType == nil then return false, "no_shovel_attr" end

    local plantId = plant.Name
    local ok, err = pcall(function()
        UseShovel:Fire(plantId, "", shovelType, tool)
    end)
    lastShovelAt = os.clock()
    stats.attempts = stats.attempts + 1
    stats.lastPlantId = plantId

    if ok then
        stats.ok = stats.ok + 1
        _log("UseShovel", plantId, M.GetPlantTypeKey(plant))
        return true, plantId
    end

    stats.lastError = tostring(err)
    return false, "fire_fail"
end

local function _tick()
    if not _canRun() then return end
    if shovelBusy then return end

    local folder = _getPlantsFolder()
    if not folder then return end

    local sel = _selectedMap()
    shovelBusy = true
    pcall(function()
        for _, plant in ipairs(folder:GetChildren()) do
            if _plantMatchesSelection(plant, sel) then
                local ok = _shovelPlantInst(plant)
                if ok then break end
                task.wait(0.05)
            end
        end
    end)
    shovelBusy = false
end

local function shovelLoop(myId)
    _initRemotes()
    _bindPlantsWatch(_getPlantsFolder())
    _log("loop start")

    while running and loopId == myId do
        local ok, err = pcall(_tick)
        if not ok then
            stats.lastError = tostring(err)
            warn("[GAG2-AS] loop error:", err)
        end
        if _canRun() then
            RunService.Heartbeat:Wait()
            task.wait(LOOP_SEC)
        elseif _enabled() then
            task.wait(0.5)
        else
            task.wait(0.5)
        end
    end
    _unbindPlantsWatch()
    _log("loop stop")
end

function M.Start()
    _initRemotes()
    if running then return end
    running = true
    loopId = loopId + 1
    local myId = loopId
    task.spawn(function() shovelLoop(myId) end)
end
M.start = M.Start

function M.Stop()
    running = false
    _unbindPlantsWatch()
end
M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.SetEnabled(on)
    on = (on == true)
    if type(G.__GAG2_SHOVEL) ~= "table" then G.__GAG2_SHOVEL = {} end
    G.__GAG2_SHOVEL.enabled = on
    _G.__GAG2_SHOVEL = G.__GAG2_SHOVEL
    G.AUTO_SHOVEL_ENABLED = on
    _G.AUTO_SHOVEL_ENABLED = on
    if on then
        M.ApplyRuntime(true)
    else
        M.Stop()
    end
    return on
end
M.setEnabled = M.SetEnabled

function M.ApplyRuntime(on)
    if on == true and not M.HasSelection() then
        M.Stop()
        stats.lastSkip = "no_selection"
        return false
    end
    if on then M.Start() else M.Stop() end
    return on == true
end
M.applyRuntime = M.ApplyRuntime

function M.SyncFromGlobals()
    M.SetEnabled(_enabled())
end
M.syncFromGlobals = M.SyncFromGlobals
M.SyncFromState = M.SyncFromGlobals
M.syncFromState = M.SyncFromGlobals

function M.ShovelOnce()
    if not _canRun() then return 0 end
    local n = 0
    local sel = _selectedMap()
    local folder = _getPlantsFolder()
    if not folder then return 0 end
    for _, plant in ipairs(folder:GetChildren()) do
        if _plantMatchesSelection(plant, sel) then
            local ok = _shovelPlantInst(plant)
            if ok then n = n + 1 break end
        end
    end
    return n
end
M.shovelOnce = M.ShovelOnce

function M.GetDiagnostics()
    _initRemotes()
    local folder = _getPlantsFolder()
    local active = M.BuildGardenPlantItems()
    local sel = _selectedMap()
    local selCount = 0
    for _ in pairs(sel) do selCount = selCount + 1 end
    return {
        enabled = _enabled(),
        running = running,
        remote = UseShovel ~= nil,
        plantsFolder = folder and folder:GetFullName() or nil,
        plantCount = #active,
        selectedCount = selCount,
        hasSelection = selCount >= 1,
        canRun = _canRun(),
        hasShovel = _getEquippedShovel() ~= nil,
        stats = stats,
    }
end
M.getDiagnostics = M.GetDiagnostics

function M.PrintDiagnostics()
    if _enabled() and not running then M.Start() end
    local d = M.GetDiagnostics()
    print("========== GAG2 Auto Shovel ==========")
    print("enabled:", d.enabled, "| running:", d.running)
    print("remote UseShovel:", d.remote and "OK" or "MISSING")
    print("types:", d.plantCount, "| selected:", d.selectedCount, "| canRun:", d.canRun)
    print("folder:", d.plantsFolder or "MISSING (PlotId?)")
    print("shovel equipped:", d.hasShovel)
    print("stats ok=", stats.ok, " attempts=", stats.attempts)
    if stats.lastError then print("lastError:", stats.lastError) end
    local sel = _selectedMap()
    for _, item in ipairs(M.BuildGardenPlantItems()) do
        local mark = sel[item.key] and "[x]" or "[ ]"
        print(" ", mark, item.name)
    end
    print("======================================")
    return d
end
M.printDiagnostics = M.PrintDiagnostics

G.AutoShovel = M
G.AutoShovelModule = M
_G.AutoShovel = M
_G.AutoShovelModule = M

return M
 end,            required = false },
    { key = "AutoTele",        name = "Auto Tele",        factory = function() -- AutoTele.lua — Grow A Garden 2
-- Runtime: persistent loop (same pattern as AutoClaimSeed)

local Players           = game:GetService("Players")
local CollectionService = game:GetService("CollectionService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local MIN_DELAY      = 10
local DEFAULT_DELAY  = 50
local TP_OFFSET      = Vector3.new(0, 3, 0)
local GARDEN_STEP_WAIT = 0.15
local STAND_RADIUS   = 7
local Y_TOLERANCE    = 4   -- cek tinggi juga (Buy Pet stick mode bisa tinggalkan player di bawah tanah)

local running        = false
local loopId         = 0
local cachedPlot     = nil
local cachedGardenCf = nil

local function _truthy(v)
    return (v == true) or (v == 1) or (v == "true") or (v == "1")
