        end
    end
    return type(s) == "table" and s or nil
end

local function _enabled()
    local store = _store()
    if type(store) == "table" then
        return store.enabled == true
    end

    if G.AUTO_TELE_ENABLED == false or rawget(_G, "AUTO_TELE_ENABLED") == false then
        return false
    end

    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" and type(MAIN.auto) == "table"
        and type(MAIN.auto.autoTele) == "table" then
        return MAIN.auto.autoTele.enabled == true
    end

    return G.AUTO_TELE_ENABLED == true or rawget(_G, "AUTO_TELE_ENABLED") == true
end

local function _writeEnabled(on)
    on = (on == true)
    local store = _store()
    if type(store) ~= "table" then
        store = { enabled = on, delay = DEFAULT_DELAY, selectedLocation = "center" }
        G.__GAG2_AUTO_TELE = store
    end
    store.enabled = on
    G.__GAG2_AUTO_TELE = store
    _G.__GAG2_AUTO_TELE = store
    G.AUTO_TELE_ENABLED = on
    _G.AUTO_TELE_ENABLED = on

    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" then
        MAIN.auto = MAIN.auto or {}
        MAIN.auto.autoTele = MAIN.auto.autoTele or {}
        MAIN.auto.autoTele.enabled = on
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end
    return on
end

local function _cfg()
    local s = _store()
    local delay = nil
    local loc = "center"

    if type(s) == "table" then
        delay = tonumber(s.delay)
        loc = tostring(s.selectedLocation or "center")
    end

    if not delay or delay <= 0 then
        local MAIN = G.MAIN or rawget(_G, "MAIN")
        if type(MAIN) == "table" and type(MAIN.auto) == "table"
            and type(MAIN.auto.autoTele) == "table" then
            delay = tonumber(MAIN.auto.autoTele.delay)
            if MAIN.auto.autoTele.selectedLocation then
                loc = tostring(MAIN.auto.autoTele.selectedLocation)
            end
        end
    end

    if not delay or delay <= 0 then delay = DEFAULT_DELAY end
    if delay < MIN_DELAY then delay = MIN_DELAY end
    if loc ~= "spawn" then loc = "center" end

    if type(s) == "table" then
        s.delay = delay
        s.selectedLocation = loc
        G.__GAG2_AUTO_TELE = s
        _G.__GAG2_AUTO_TELE = s
    end

    return {
        enabled = _enabled(),
        delay = delay,
        selectedLocation = loc,
    }
end

local function _hrp()
    local char = LP and LP.Character
    return char and char:FindFirstChild("HumanoidRootPart") or nil
end

local function _matchOwner(v)
    if v == nil or not LP then return false end
    return v == LP.UserId or v == LP.Name
        or tostring(v) == tostring(LP.UserId) or tostring(v) == LP.Name
end

local function _plotOwnedByLocal(plot)
    if not plot then return false end
    if _matchOwner(plot:GetAttribute("OwnerId")) then return true end
    if _matchOwner(plot:GetAttribute("Owner")) then return true end
    if _matchOwner(plot:GetAttribute("OwnerUserId")) then return true end
    if _matchOwner(plot:GetAttribute("UserId")) then return true end

    for _, child in ipairs(plot:GetChildren()) do
        if child:IsA("ValueBase") then
            local n = child.Name:lower()
            if n:find("owner") or n:find("userid") or n:find("player") then
                if _matchOwner(child.Value) then return true end
            end
        end
    end

    local myPlot = LP:GetAttribute("Plot") or LP:GetAttribute("PlotName")
        or LP:GetAttribute("GardenPlot") or LP:GetAttribute("PlotId")
    if myPlot and plot.Name == tostring(myPlot) then return true end
    if myPlot and plot.Name == ("Plot" .. tostring(myPlot)) then return true end

    return false
end

function M.GetPlayerPlot()
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens or not LP then return nil end

    local plotId = LP:GetAttribute("PlotId")
    local idStr = plotId ~= nil and tostring(plotId) or nil

    if cachedPlot and cachedPlot.Parent then
        if idStr then
            for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
                local expected = gardens:FindFirstChild(name)
                if expected and cachedPlot == expected then
                    return cachedPlot
                end
            end
        elseif _plotOwnedByLocal(cachedPlot) then
            return cachedPlot
        end
        cachedPlot = nil
        cachedGardenCf = nil
    end

    if idStr then
        for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
            local plot = gardens:FindFirstChild(name)
            if plot then
                cachedPlot = plot
                return plot
            end
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            return plot
        end
    end

    local hrp = _hrp()
    if hrp then
        local params = RaycastParams.new()
        params.FilterType = Enum.RaycastFilterType.Include
        params.FilterDescendantsInstances = { gardens }
        local hit = workspace:Raycast(hrp.Position + Vector3.new(0, 6, 0), Vector3.new(0, -40, 0), params)
        if hit then
            for _, plot in ipairs(gardens:GetChildren()) do
                if hit.Instance:IsDescendantOf(plot) and _plotOwnedByLocal(plot) then
                    cachedPlot = plot
                    return plot
                end
            end
        end
    end

    return nil
end

local function _collectPlotSurfaces(plot)
    local list, seen = {}, {}
    local function add(inst)
        if inst and not seen[inst] then
            seen[inst] = true
            list[#list + 1] = inst
        end
    end
    for _, inst in ipairs(CollectionService:GetTagged("PlantArea")) do
        if inst:IsDescendantOf(plot) then add(inst) end
    end
    if #list > 0 then return list end
    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") then
            local n = desc.Name:lower()
            if n:find("soil") or n:find("dirt") or n:find("ground")
                or n:find("farm") or n:find("plot") or n:find("grass") then
                add(desc)
            end
        end
    end
    if #list > 0 then return list end
    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.CanQuery ~= false then
            add(desc)
        end
    end
    return list
end

function M.GetGardenPlotCFrame(plot)
    plot = plot or M.GetPlayerPlot()
    if not plot then return nil end

    local spawn = plot:FindFirstChild("Spawn", true) or plot:FindFirstChild("SpawnLocation", true)
    if spawn and spawn:IsA("BasePart") then
        return spawn.CFrame + TP_OFFSET
    end

    if plot:IsA("Model") then
        local ok, cf = pcall(function() return plot:GetPivot() end)
        if ok and typeof(cf) == "CFrame" then
            return cf + TP_OFFSET
        end
    end

    return nil
end

function M.GetGardenCenterCFrame(plot)
    plot = plot or M.GetPlayerPlot()

    if plot then
        local areas = _collectPlotSurfaces(plot)
        if #areas > 0 then
            local sx, sy, sz, n = 0, 0, 0, 0
            for _, part in ipairs(areas) do
                if part:IsA("BasePart") then
                    local p = part.Position
                    sx = sx + p.X
                    sy = sy + p.Y + part.Size.Y * 0.5
                    sz = sz + p.Z
                    n = n + 1
                end
            end
            if n > 0 then
                cachedGardenCf = CFrame.new(sx / n, sy / n, sz / n) + TP_OFFSET
                return cachedGardenCf
            end
        end

        local spawn = plot:FindFirstChild("Spawn", true) or plot:FindFirstChild("SpawnLocation", true)
        if spawn and spawn:IsA("BasePart") then
            cachedGardenCf = spawn.CFrame + TP_OFFSET
            return cachedGardenCf
        end

        if plot:IsA("Model") then
            local okBB, cf, size = pcall(function() return plot:GetBoundingBox() end)
            if okBB and typeof(cf) == "CFrame" and typeof(size) == "Vector3" then
                cachedGardenCf = cf + Vector3.new(0, size.Y * 0.5, 0) + TP_OFFSET
                return cachedGardenCf
            end
            local ok, cf = pcall(function() return plot:GetPivot() end)
            if ok and typeof(cf) == "CFrame" then
                cachedGardenCf = cf + TP_OFFSET
                return cachedGardenCf
            end
        end
    end

    return cachedGardenCf
end

function M.GetGardenSpawnCFrame(plot)
    plot = plot or M.GetPlayerPlot()
    if plot then
        local spawn = plot:FindFirstChild("Spawn", true) or plot:FindFirstChild("SpawnLocation", true)
        if spawn and spawn:IsA("BasePart") then
            return spawn.CFrame + TP_OFFSET
        end
    end
    return M.GetGardenCenterCFrame(plot)
end

local function _flatDist(a, b)
    if not a or not b then return nil end
    local dx, dz = a.X - b.X, a.Z - b.Z
    return math.sqrt(dx * dx + dz * dz)
end

local function _needsTeleport(hrpPos, targetPos)
    if not hrpPos or not targetPos then return true end
    local flat = _flatDist(hrpPos, targetPos) or 999
    if flat > STAND_RADIUS then return true end
    if math.abs(hrpPos.Y - targetPos.Y) > Y_TOLERANCE then return true end
    return false
end

function M.ResolveTargetCFrame()
    local cfg = _cfg()

    if cfg.selectedLocation == "spawn" then
        local cf = M.GetGardenSpawnCFrame()
        if cf then return cf end
        return cachedGardenCf
    end

    local cf = M.GetGardenCenterCFrame()
    if cf then return cf end
    return cachedGardenCf
end

local function _teleport(cf)
    if typeof(cf) ~= "CFrame" then return false end
    local char = LP and LP.Character
    local hrp = _hrp()
    if not char or not hrp then return false end

    local ok = pcall(function()
        if char.PrimaryPart then
            char:PivotTo(cf)
        else
            hrp.CFrame = cf
        end
    end)
    if ok then return true end

    ok = pcall(function()
        hrp.CFrame = cf
    end)
    return ok
end

local function _buyPetBusy()
    return G.__GAG2_AUTO_BUY_PET_BUSY == true
        or rawget(_G, "__GAG2_AUTO_BUY_PET_BUSY") == true
end

local function _suppressed()
    if _buyPetBusy() then return true end
    return G.__GAG2_AUTO_TELE_SUPPRESS == true
        or rawget(_G, "__GAG2_AUTO_TELE_SUPPRESS") == true
end

function M.ClearSuppress()
    G.__GAG2_AUTO_TELE_SUPPRESS = false
    _G.__GAG2_AUTO_TELE_SUPPRESS = false
end
M.clearSuppress = M.ClearSuppress

local function _tick()
    if not _enabled() or _suppressed() then return false end

    local hrp = _hrp()
    if not hrp then return false end

    local target = M.ResolveTargetCFrame()
    if not target then return false end

    -- Sudah di tujuan (center/spawn)? tidak perlu TP lagi sampai jauh
    if not _needsTeleport(hrp.Position, target.Position) then
        return false
    end

    local plotCf = M.GetGardenPlotCFrame()
    local didTp = false

    -- Masih jauh dari tujuan: lewat plot/garden dulu (kecuali tujuan = plot yang sama)
    if plotCf and _needsTeleport(hrp.Position, plotCf.Position) then
        local skipPlot = (target.Position - plotCf.Position).Magnitude < 1
        if not skipPlot and _teleport(plotCf) then
            didTp = true
            task.wait(GARDEN_STEP_WAIT)
            hrp = _hrp()
        end
    end

    if not hrp then return didTp end

    if _needsTeleport(hrp.Position, target.Position) and _teleport(target) then
        didTp = true
    end

    return didTp
end

local function _loop(myId)
    while running and loopId == myId do
        local ok = pcall(function()
            if _enabled() and not _suppressed() then
                _tick()
                task.wait(_cfg().delay)
            else
                task.wait(0.5)
            end
        end)
        if not ok then
            task.wait(0.5)
        end
    end
end

function M.EnsureRunning()
    if not _enabled() then return end
    if not running then
        M.Start()
    end
end

function M.GetDelay()
    return _cfg().delay
end
M.getDelay = M.GetDelay

function M.SetDelay(sec)
    local d = tonumber(sec)
    if not d or d <= 0 then d = DEFAULT_DELAY end
    if d < MIN_DELAY then d = MIN_DELAY end

    local store = _store()
    if type(store) ~= "table" then
        store = { enabled = _enabled(), delay = d, selectedLocation = "center" }
    else
        store.delay = d
    end
    G.__GAG2_AUTO_TELE = store
    _G.__GAG2_AUTO_TELE = store

    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" then
        MAIN.auto = MAIN.auto or {}
        MAIN.auto.autoTele = MAIN.auto.autoTele or {}
        MAIN.auto.autoTele.delay = d
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end
    return d
end
M.setDelay = M.SetDelay

function M.InvalidateCache()
    cachedPlot = nil
    cachedGardenCf = nil
end
M.invalidateCache = M.InvalidateCache

function M.Start()
    if not _enabled() then return end
    if running then return end
    running = true
    loopId = loopId + 1
    local myId = loopId
    task.spawn(_loop, myId)
    -- cek sekali saat nyala (skip kalau baru selesai buy pet — sudah di garden)
    task.defer(function()
        if G.__GAG2_TELE_SKIP_FIRST_TICK == true or rawget(_G, "__GAG2_TELE_SKIP_FIRST_TICK") == true then
            return
        end
        if running and loopId == myId and _enabled() and not _suppressed() then
            pcall(_tick)
        end
    end)
end
M.start = M.Start

function M.Stop()
    running = false
    loopId = loopId + 1
end
M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.IsEnabled()
    return _enabled()
end
M.isEnabled = M.IsEnabled

function M.ApplyRuntime(on)
    if on == nil then on = _enabled() end
    on = _truthy(on)
    _writeEnabled(on)
    if on then
        M.ClearSuppress()
        M.Start()
    else
        M.Stop()
        M.ClearSuppress()
    end
    return on
end
M.applyRuntime = M.ApplyRuntime

function M.SetEnabled(on)
    return M.ApplyRuntime(on)
end
M.setEnabled = M.SetEnabled

function M.TeleportNow()
    if _suppressed() then return false end
    return _tick()
end

function M.SyncFromState()
    M.EnsureRunning()
end

M.SyncFromGlobals = M.SyncFromState

-- watchdog: hanya hidupkan loop kalau mati (tidak bypass delay UI)
task.defer(function()
    while true do
        task.wait(1.5)
        if _enabled() and not running and not _suppressed() and not _buyPetBusy() then
            M.Start()
        end
    end
end)

G.AutoTele = M
G.AutoTeleModule = M
_G.AutoTele = M
_G.AutoTeleModule = M

if LP then
    pcall(function()
        LP:GetAttributeChangedSignal("PlotId"):Connect(function()
            cachedPlot = nil
            cachedGardenCf = nil
        end)
    end)
end

task.defer(function()
    if _enabled() then
        M.EnsureRunning()
    end
end)

return M
 end,              required = false },
    { key = "AutoClaimSeed",   name = "Auto Claim Seed",  factory = function() -- AutoClaimSeed.lua - Grow A Garden 2
-- Alur: stop Auto Tele -> TP bawah seed (Y-7) -> follow claim sampai sukses
--       -> seed lain masih ada? lanjut : resume Auto Tele

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService        = game:GetService("RunService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local ClickPack       = nil
local SeedPackFX      = nil
local remotesReady    = false
local remotePath      = nil

local SCAN_SEC        = 0
local CLAIM_COOLDOWN  = 0.05
local ATTR_WAIT_SEC   = 0.18
local ATTR_POLL_SEC   = 0.005

local UNDER_Y         = -7
local FOLLOW_FIRE_SEC = 0.12
local MAX_FOLLOW_SEC  = 90
local TP_STAND_DIST   = 2
local CLAIM_RANGE     = 18
local PREFIRE_MAX_DIST = 99999
local TP_OFFSET       = Vector3.new(0, 3, 0)
local AFTER_TP_SEC    = 0.05
local VERIFY_WAIT     = 0.2
local VERIFY_WAIT_FAST = 0.08
local CLAIM_COMPLETE_WAIT = 14
local CLAIM_VERDICT_WAIT  = 0.75
local CLAIM_POLL_SEC      = 0.04
local OPEN_UI_WAIT    = 0.18
local OPEN_UI_POLL    = 0.008
local OPEN_PROMPT_FIND_WAIT = 0.05
local OPEN_PROMPT_RETRY_SEC = 0.14
local OPEN_PROMPT_RETRIES   = 4
local VERIFY_POLL     = 0.004
local CLICK_NEAR_DIST = 50
local BURST_FIRE_GAP  = 0
local LOST_CLAIM_COOLDOWN = 2.5

local running       = false
local loopId        = 0
local claimBusy     = false
local spawnFolder   = nil
local childConn     = nil
local attrConns     = {}
local mapConn       = nil
local fxConn        = nil
local claimedConn   = nil
local claimCooldown = {}
local savedGardenCf = nil
local lastScanInfo  = { count = 0, ready = 0, at = 0 }
local lastFxAt      = 0
local lastFxPos     = nil
local lastClaimedAt = 0
local lastClaimedId = nil
local lastClaimedByUs = false
local claimAttemptStartedAt = 0
local inFlightClaims = {}
local seedPackEffectMod = nil
local teleWasOn = false
local telePaused = false

local stats = {
    attempts = 0,
    fired = 0,
    remoteOk = 0,
    teleports = 0,
    clickOk = 0,
    prefire = 0,
    skipped = {},
    lastResult = nil,
    lastSkip = nil,
    lastError = nil,
    lastClaimId = nil,
    lastMethod = nil,
    falseOk = 0,
    lastMs = nil,
}

local function _skip(reason)
    stats.lastSkip = reason
    stats.skipped[reason] = (stats.skipped[reason] or 0) + 1
end

local function _getLP()
    local lp = LP or Players.LocalPlayer
    if lp then LP = lp end
    return lp
end

local function _isLocalPlayerClaim(id)
    local lp = _getLP()
    if not lp or id == nil then return false end
    local s = tostring(id)
    if s == lp.Name then return true end
    if s == tostring(lp.UserId) then return true end
    local n = tonumber(s)
    return n ~= nil and n == lp.UserId
end

local function _getHRP()
    local lp = _getLP()
    if not lp then return nil end
    local char = lp.Character
    if not char then return nil end
    local hrp = char:FindFirstChild("HumanoidRootPart")
    if hrp and hrp:IsA("BasePart") then return hrp end
    return nil
end

local function _enabled()
    local store = G.__GAG2_CLAIM_SEED or rawget(_G, "__GAG2_CLAIM_SEED")
    if type(store) == "table" and store.enabled == true then return true end
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" and type(MAIN.auto) == "table"
        and type(MAIN.auto.claimSeed) == "table" and MAIN.auto.claimSeed.enabled == true then
        return true
    end
    return G.AUTO_CLAIM_SEED_ENABLED == true or rawget(_G, "AUTO_CLAIM_SEED_ENABLED") == true
end

local function _writeEnabled(on)
    on = (on == true)
    if type(G.__GAG2_CLAIM_SEED) ~= "table" then G.__GAG2_CLAIM_SEED = {} end
    G.__GAG2_CLAIM_SEED.enabled = on
    _G.__GAG2_CLAIM_SEED = G.__GAG2_CLAIM_SEED
    G.AUTO_CLAIM_SEED_ENABLED = on
    _G.AUTO_CLAIM_SEED_ENABLED = on
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" then
        MAIN.auto = MAIN.auto or {}
        MAIN.auto.claimSeed = MAIN.auto.claimSeed or {}
        MAIN.auto.claimSeed.enabled = on
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end
    return on
end

local function _findRemote(net, names)
    if type(net) ~= "table" then return nil end
    for _, name in ipairs(names) do
        local r = net[name]
        if r then
            if type(r.Fire) == "function" or type(r.FireServer) == "function"
                or type(r.InvokeServer) == "function" then
                return r, name
            end
        end
    end
    return nil
end

local function _initRemotes()
    if remotesReady then return end
    remotesReady = true
    local ok, Networking = pcall(function()
        return require(ReplicatedStorage.SharedModules.Networking)
    end)
    if not ok or type(Networking) ~= "table" then
        stats.lastError = "Networking require gagal"
        return
    end
    local SeedNet = Networking.SeedPack or Networking.Seedpack or Networking.SeedPacks
    ClickPack, remotePath = _findRemote(SeedNet, { "ClickPack", "ClickSeedPack", "Click" })
    if not ClickPack then
        ClickPack, remotePath = _findRemote(Networking, { "ClickSeedPack", "ClickPack" })
        if ClickPack then remotePath = "Networking." .. tostring(remotePath) end
    else
        remotePath = "Networking.SeedPack." .. tostring(remotePath)
    end
    local SpawnNet = Networking.SeedPackSpawn or Networking.SeedpackSpawn
    if type(SpawnNet) == "table" then
        SeedPackFX = SpawnNet.FX
        if not claimedConn and SpawnNet.Claimed and SpawnNet.Claimed.OnClientEvent then
            claimedConn = SpawnNet.Claimed.OnClientEvent:Connect(function(id, seedName)
                lastClaimedAt = os.clock()
                lastClaimedId = id ~= nil and tostring(id) or nil
                lastClaimedByUs = _isLocalPlayerClaim(id)
            end)
        end
    end
    if not ClickPack then
        stats.lastError = "ClickPack MISSING"
    end
end

local function _getMap()
    return workspace:FindFirstChild("Map")
end

local function _getSpawnFolder()
    if spawnFolder and spawnFolder.Parent then return spawnFolder end
    local map = _getMap()
    if not map then return nil end
    spawnFolder = map:FindFirstChild("SeedPackSpawnServerLocations")
        or map:WaitForChild("SeedPackSpawnServerLocations", 2)
    return spawnFolder
end

local function _truthy(v)
    return v == true or v == 1 or v == "true" or v == "1"
end

local function _getSpawnAttr(inst, name)
    if not inst then return nil end
    local v = inst:GetAttribute(name)
    if v ~= nil then return v end
    return nil
end

local function _spawnHasAttrs(inst)
    if not inst or not inst.Parent then return false end
    local packName = _getSpawnAttr(inst, "SeedPack")
    if type(packName) == "string" and packName ~= "" then return true end
    if _truthy(_getSpawnAttr(inst, "RainbowSeed")) then return true end
    if _truthy(_getSpawnAttr(inst, "GoldSeed")) then return true end
    return false
end

local function _waitSpawnReady(inst)
    if not inst or not inst.Parent then return false end
    if _spawnHasAttrs(inst) then return true end
    local deadline = os.clock() + ATTR_WAIT_SEC
    while inst.Parent and os.clock() < deadline do
        if _spawnHasAttrs(inst) then return true end
        local woke = false
        for _, attr in ipairs({ "SeedPack", "GoldSeed", "RainbowSeed" }) do
            local ok = pcall(function()
                inst:GetAttributeChangedSignal(attr):Wait()
            end)
            if ok then woke = true break end
        end
        if not woke then task.wait(ATTR_POLL_SEC) end
    end
    return _spawnHasAttrs(inst)
end

local function _partCFrame(inst)
    if not inst then return nil end
    if inst:IsA("BasePart") then return inst.CFrame end
    if inst:IsA("Model") then
        local ok, cf = pcall(function() return inst:GetPivot() end)
        if ok and typeof(cf) == "CFrame" then return cf end
        local part = inst:FindFirstChildWhichIsA("BasePart", true)
        if part then return part.CFrame end
    end
    return nil
end

local function _spawnPosition(inst)
    local cf = _partCFrame(inst)
    return cf and cf.Position or nil
end

local function _childWorldPos(obj)
    if not obj then return nil end
    if obj:IsA("BasePart") then return obj.Position end
    if obj:IsA("Model") then
        local pp = obj.PrimaryPart or obj:FindFirstChildWhichIsA("BasePart", true)
        if pp then return pp.Position end
    end
    return nil
end

local function _spawnLabel(inst)
    if not inst then return "unknown" end
    if _truthy(_getSpawnAttr(inst, "RainbowSeed")) then return "Rainbow Seed" end
    if _truthy(_getSpawnAttr(inst, "GoldSeed")) then return "Gold Seed" end
    local pack = _getSpawnAttr(inst, "SeedPack")
    if type(pack) == "string" and pack ~= "" then return pack end
    return inst.Name or "unknown"
end

local function _folderSpawnRoot(inst)
    local folder = _getSpawnFolder()
    if not folder or not inst then return inst end
    local node = inst
    while node and node.Parent and node.Parent ~= folder do
        node = node.Parent
    end
    if node and node.Parent == folder then return node end
    return inst
end

local function _globalSpawnIndex(inst)
    local folder = _getSpawnFolder()
    if not folder then return nil end
    local root = _folderSpawnRoot(inst)
    for i, ch in ipairs(folder:GetChildren()) do
        if ch == root then return tostring(i) end
    end
    return nil
end

local function _findClientSpawnNear(inst)
    local pos = _spawnPosition(inst)
    if not pos then return nil end
    local map = _getMap()
    local client = map and map:FindFirstChild("SeedPackSpawnClient")
    if not client then return nil end
    local best, bestD = nil, 10
    for _, ch in ipairs(client:GetChildren()) do
        local p = _childWorldPos(ch)
        if p then
            local d = (p - pos).Magnitude
            if d < bestD then
                best = ch
                bestD = d
            end
        end
    end
    return best
end

local function _getClaimIds(inst)
    local out = {}
    local seen = {}
    local function add(v)
        if v == nil then return end
        v = tostring(v)
        if v == "" or seen[v] then return end
        if v == "Part" or v == "Model" then return end
        seen[v] = true
        out[#out + 1] = v
    end

    -- Slot index di SeedPackSpawnServerLocations (paling umum di GAG2)
    add(_globalSpawnIndex(inst))

    add(_getSpawnAttr(inst, "SpawnId"))
    add(_getSpawnAttr(inst, "Id"))
    add(_getSpawnAttr(inst, "UUID"))
    add(_getSpawnAttr(inst, "Slot"))
    add(_getSpawnAttr(inst, "SlotId"))
    add(_getSpawnAttr(inst, "Index"))

    if inst and inst.Parent then
        for i, ch in ipairs(inst.Parent:GetChildren()) do
            if ch == inst then add(tostring(i)) break end
        end
    end

    if inst and inst.Name ~= "Part" and inst.Name ~= "Model" then
        add(inst.Name)
    end

    return out
end

local function _primaryClaimId(inst)
    local ids = _getClaimIds(inst)
    return ids[1]
end

local function _distToSpawn(inst)
    local hrp = _getHRP()
    local pos = _spawnPosition(inst)
    if not hrp or not pos then return nil end
    return (hrp.Position - pos).Magnitude
end

local function _spawnTrackKey(inst)
    if not inst then return nil end
    local id = _getSpawnAttr(inst, "SpawnId") or _getSpawnAttr(inst, "Id")
        or _getSpawnAttr(inst, "UUID") or _getSpawnAttr(inst, "SlotId")
    if id ~= nil then return "id:" .. tostring(id) end
    local gidx = _globalSpawnIndex(inst)
    if gidx then return "slot:" .. gidx end
    local pos = _spawnPosition(inst)
    if pos then
        return string.format("p:%.1f,%.1f,%.1f", pos.X, pos.Y, pos.Z)
    end
    return tostring(inst)
end

local function _claimedDuringAttempt()
    return lastClaimedAt >= claimAttemptStartedAt - 0.02
end

local function _weWonClaim()
    return lastClaimedByUs and _claimedDuringAttempt()
end

local function _otherWonClaim()
    return not lastClaimedByUs and _claimedDuringAttempt()
end

local function _waitClaimVerdict(maxWait)
    maxWait = tonumber(maxWait) or 0.1
    local deadline = os.clock() + maxWait
    while os.clock() < deadline do
        if _weWonClaim() then return true, "claimed_event" end
        if _otherWonClaim() then return false, "lost_to_other" end
        task.wait(VERIFY_POLL)
    end
    if _weWonClaim() then return true, "claimed_event" end
    if _otherWonClaim() then return false, "lost_to_other" end
    return nil, nil
end

local function _claimLock(inst)
    local key = _spawnTrackKey(inst)
    if not key or inFlightClaims[key] then return false, key end
    inFlightClaims[key] = true
    return true, key
end

local function _claimUnlock(key)
    if key then inFlightClaims[key] = nil end
end

local function _shouldPrefire(dist)
    return dist == nil or dist <= PREFIRE_MAX_DIST
end

local function _getGardenCFrame()
    local lp = _getLP()
    if not lp then return nil end

    local plotId = lp:GetAttribute("PlotId")
    local gardens = workspace:FindFirstChild("Gardens")
    if gardens and plotId ~= nil then
        for _, name in ipairs({ "Plot" .. tostring(plotId), tostring(plotId), "Plot_" .. tostring(plotId) }) do
            local plot = gardens:FindFirstChild(name)
            if plot then
                local spawn = plot:FindFirstChild("SpawnPoint", true)
                    or plot:FindFirstChild("Spawn", true)
                    or plot:FindFirstChild("SpawnLocation", true)
                if spawn and spawn:IsA("BasePart") then
                    return spawn.CFrame + TP_OFFSET
                end
                if plot:IsA("Model") then
                    local ok, cf = pcall(function() return plot:GetPivot() end)
                    if ok and typeof(cf) == "CFrame" then return cf + TP_OFFSET end
                end
            end
        end
    end

    if not gardens then return nil end
    for _, plot in ipairs(gardens:GetChildren()) do
        local owner = plot:GetAttribute("Owner") or plot:GetAttribute("OwnerId") or plot:GetAttribute("OwnerUserId")
        if owner ~= nil and (tostring(owner) == lp.Name or tonumber(owner) == lp.UserId) then
            local spawn = plot:FindFirstChild("SpawnPoint", true)
                or plot:FindFirstChild("Spawn", true)
                or plot:FindFirstChild("SpawnLocation", true)
            if spawn and spawn:IsA("BasePart") then return spawn.CFrame + TP_OFFSET end
            if plot:IsA("Model") then
                local ok, cf = pcall(function() return plot:GetPivot() end)
                if ok and typeof(cf) == "CFrame" then return cf + TP_OFFSET end
            end
        end
    end
    return nil
end

local function _teleport(cf)
    if typeof(cf) ~= "CFrame" then return false end
    local lp = _getLP()
    local char = lp and lp.Character
    local hrp = _getHRP()
    if not char or not hrp then return false end
    local ok = pcall(function()
        if char.PrimaryPart then char:PivotTo(cf) else hrp.CFrame = cf end
    end)
    if ok then stats.teleports = stats.teleports + 1 end
    return ok
end

----------------------------------------------------------------
-- Auto Tele: stop dulu, resume kalau tidak ada seed lagi
----------------------------------------------------------------
local function _getAutoTeleMod()
    return G.AutoTele or rawget(_G, "AutoTele")
end

local function _teleIsOn()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" then
        return mod.IsEnabled() == true
    end
    local s = rawget(_G, "__GAG2_AUTO_TELE") or G.__GAG2_AUTO_TELE
    if type(s) == "table" then return s.enabled == true end
    return G.AUTO_TELE_ENABLED == true or rawget(_G, "AUTO_TELE_ENABLED") == true
end

local function _teleWasRunning()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsRunning) == "function" then
        return mod.IsRunning() == true
    end
    return false
end

local function _teleStopForClaim()
    teleWasOn = _teleIsOn() and _teleWasRunning()
    if not teleWasOn then
        telePaused = false
        return
    end
    telePaused = true
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.Stop) == "function" then
        pcall(mod.Stop, mod)
    end
end

local function _teleResumeNow()
    if not teleWasOn then
        telePaused = false
        return
    end
    telePaused = false
    teleWasOn = false
    G.__GAG2_AUTO_TELE_SUPPRESS = false
    _G.__GAG2_AUTO_TELE_SUPPRESS = false
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" and mod.IsEnabled() then
        if type(mod.Start) == "function" then pcall(mod.Start, mod) end
    end
end

local function _teleKeepPaused()
    if not teleWasOn then return end
    telePaused = true
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
end

local function _tpUnderSeed(inst)
    local pos = _partWorldPos(inst)
    if not pos then return false end
    local under = Vector3.new(pos.X, pos.Y + UNDER_Y, pos.Z)
    return _teleport(CFrame.new(under, pos))
end

local function _standCFrame(inst)
    local cf = _partCFrame(inst)
    if not cf then return nil end
    local seedPos = cf.Position
    local standPos = seedPos
    if TP_STAND_DIST > 0.05 then
        local hrp = _getHRP()
        local flat = Vector3.new(0, 0, -1)
        if hrp then
            flat = seedPos - hrp.Position
            flat = Vector3.new(flat.X, 0, flat.Z)
        end
        if flat.Magnitude < 0.05 then
            flat = Vector3.new(0, 0, -1)
        else
            flat = flat.Unit
        end
        standPos = seedPos - flat * TP_STAND_DIST
    end
    standPos = standPos + Vector3.new(0, TP_OFFSET.Y, 0)
    return CFrame.new(standPos, seedPos)
end

local function _canClaim(inst)
    local untilAt = claimCooldown[inst]
    return not (untilAt and os.clock() < untilAt)
end

local function _markClaimed(inst, sec)
    claimCooldown[inst] = os.clock() + (tonumber(sec) or CLAIM_COOLDOWN)
end

local function _getClickFn()
    if type(fireclickdetector) == "function" then return fireclickdetector end
    if type(rawget(_G, "fireclickdetector")) == "function" then return rawget(_G, "fireclickdetector") end
    return nil
end

local function _getPromptFn()
    if type(fireproximityprompt) == "function" then return fireproximityprompt end
    if type(rawget(_G, "fireproximityprompt")) == "function" then return rawget(_G, "fireproximityprompt") end
    return nil
end

local function _getSeedPackEffect()
    if seedPackEffectMod == false then return nil end
    if seedPackEffectMod then return seedPackEffectMod end
    local lp = _getLP()
    local controllers = lp and lp:FindFirstChild("PlayerScripts")
    controllers = controllers and controllers:FindFirstChild("Controllers")
    if not controllers then seedPackEffectMod = false return nil end

    local tryPaths = {
        { "SeedPackController", "SeedPackEffect" },
        { "SeedPackController", "SeedPackOpen" },
    }
    for _, path in ipairs(tryPaths) do
        local node = controllers
        for _, name in ipairs(path) do
            node = node and node:FindFirstChild(name)
        end
        if node then
            local ok, mod = pcall(require, node)
            if ok and type(mod) == "table" and type(mod.Open) == "function" then
                seedPackEffectMod = mod
                return mod
            end
        end
    end
    seedPackEffectMod = false
    return nil
end

local function _triggerGameOpen(inst)
    local effect = _getSeedPackEffect()
    if not effect then return false end
    local hrp = _getHRP()
    local spawnCf = _partCFrame(inst)
    if not hrp or not spawnCf then return false end

    local packName = _getSpawnAttr(inst, "SeedPack")
    if type(packName) ~= "string" or packName == "" then
        if _truthy(_getSpawnAttr(inst, "RainbowSeed")) then packName = "Rainbow"
        elseif _truthy(_getSpawnAttr(inst, "GoldSeed")) then packName = "Gold"
        else packName = "Normal" end
    end

    local ok = pcall(function()
        effect.Open(inst.Name, packName, _spawnLabel(inst), hrp.Position, spawnCf)
    end)
    return ok
end

local function _partWorldPos(inst)
    local pos = _spawnPosition(inst)
    if pos then return pos end
    if inst and inst:IsA("BasePart") then return inst.Position end
    return nil
end

local function _findClickDetectorNear(nearPos)
    if not nearPos then return nil end
    local roots = {}
    local temp = workspace:FindFirstChild("Temporary")
    if temp then roots[#roots + 1] = temp end
    local map = _getMap()
    if map then
        local client = map:FindFirstChild("SeedPackSpawnClient")
        if client then roots[#roots + 1] = client end
    end

    local best, bestDist = nil, CLICK_NEAR_DIST
    for _, root in ipairs(roots) do
        for _, obj in ipairs(root:GetDescendants()) do
            if obj:IsA("ClickDetector") then
                local pos = _childWorldPos(obj.Parent) or _childWorldPos(obj:FindFirstAncestorOfClass("Model"))
                if pos then
                    local d = (pos - nearPos).Magnitude
                    if d <= bestDist then
                        best = obj
                        bestDist = d
                    end
                end
            end
        end
    end
    return best
end

local function _findProximityPromptNear(nearPos)
    if not nearPos then return nil end
    local roots = {}
    local map = _getMap()
    if map then
        local client = map:FindFirstChild("SeedPackSpawnClient")
        if client then roots[#roots + 1] = client end
    end
    local folder = _getSpawnFolder()
    if folder then roots[#roots + 1] = folder end

    local best, bestDist = nil, CLICK_NEAR_DIST
    for _, root in ipairs(roots) do
        for _, obj in ipairs(root:GetDescendants()) do
            if obj:IsA("ProximityPrompt") then
                local pos = _childWorldPos(obj.Parent)
                if pos then
                    local d = (pos - nearPos).Magnitude
                    if d <= bestDist then
                        best = obj
                        bestDist = d
                    end
                end
            end
        end
    end
    return best
end

local function _fireClickDetector(cd)
    if not cd then return false end
    local lp = _getLP()
    local fn = _getClickFn()
    local ok = false
    if fn and lp then
        ok = pcall(fn, cd, 0, lp)
        if ok then
            stats.clickOk = stats.clickOk + 1
            stats.lastMethod = "ClickDetector"
        end
    end
    return ok
end

local function _fireProximityPrompt(pp)
    if not pp then return false end
    local fn = _getPromptFn()
    if not fn then return false end
    local ok = pcall(fn, pp)
    if ok then stats.lastMethod = "ProximityPrompt" end
    return ok
end

local function _waitOpenUiClickDetector(inst, onPoll)
    local pos = _partWorldPos(inst)
    if not pos then return nil end
    local deadline = os.clock() + OPEN_UI_WAIT
    while inst.Parent and os.clock() < deadline do
        local cd = _findClickDetectorNear(pos)
        if cd then return cd end
        if type(onPoll) == "function" then onPoll() end
        task.wait(OPEN_UI_POLL)
    end
    return _findClickDetectorNear(pos)
end

local function _fxNearSpawn(inst)
    if not lastFxPos or lastFxAt < claimAttemptStartedAt - 0.05 then return false end
    local pos = _spawnPosition(inst)
    if not pos then return false end
    return (lastFxPos - pos).Magnitude <= 12
end

local function _packStillActive(inst)
    if not inst or not inst.Parent then return false end
    local folder = _getSpawnFolder()
    if folder and inst.Parent ~= folder then return false end
    return _spawnHasAttrs(inst)
end

local function _resetClaimAttempt()
    claimAttemptStartedAt = os.clock()
    lastClaimedByUs = false
end

local function _waitForClaimComplete(inst, maxWait)
    maxWait = tonumber(maxWait) or CLAIM_COMPLETE_WAIT
    local deadline = os.clock() + maxWait
    local lastFire = 0

    while running and _enabled() and os.clock() < deadline do
        if _weWonClaim() then return true, "claimed_event" end
        if _otherWonClaim() then return false, "lost_to_other" end

        local stillActive = inst and inst.Parent and _packStillActive(inst) and _spawnHasAttrs(inst)
        if not stillActive then
            local ok, reason = _waitClaimVerdict(CLAIM_VERDICT_WAIT)
            if ok == true then return true, reason or "spawn_cleared" end
            if ok == false then return false, reason end
            if _weWonClaim() then return true, "claimed_event_late" end
            if _otherWonClaim() then return false, "lost_to_other" end
            task.wait(CLAIM_POLL_SEC)
        else
            if os.clock() - lastFire >= FOLLOW_FIRE_SEC then
                _teleKeepPaused()
                _tpUnderSeed(inst)
                _fireClickPackBurst(inst, "wait_complete")
                lastFire = os.clock()
            end
            task.wait(CLAIM_POLL_SEC)
        end
    end

    if _weWonClaim() then return true, "claimed_event_timeout" end
    if _otherWonClaim() then return false, "lost_to_other" end
    return false, "claim_timeout"
end

local function _verifyClaimed(inst, nearPos, tag, maxWait)
    maxWait = tonumber(maxWait) or VERIFY_WAIT
    local deadline = os.clock() + maxWait
    while os.clock() < deadline do
        if _weWonClaim() then return true, "claimed_event" end
        if _otherWonClaim() then return false, "lost_to_other" end
        if _fxNearSpawn(inst) then
            local ok, reason = _waitClaimVerdict(0.35)
            if ok == true then return true, "fx_event" end
            if ok == false then return false, reason end
        end
        if not _packStillActive(inst) then
            local ok, reason = _waitClaimVerdict(math.max(maxWait, 0.35))
            if ok == true then return true, reason end
            if ok == false then return false, reason end
            return false, "spawn_gone_pending"
        end
        task.wait(VERIFY_POLL)
    end
    if _weWonClaim() then return true, "claimed_event" end
    if _otherWonClaim() then return false, "lost_to_other" end
    if _fxNearSpawn(inst) then
        local ok, reason = _waitClaimVerdict(0.3)
        if ok == true then return true, "fx_event" end
        if ok == false then return false, reason end
    end
    if not _packStillActive(inst) then
        local ok, reason = _waitClaimVerdict(0.35)
        if ok == true then return true, reason end
        if ok == false then return false, reason end
        return false, "spawn_gone_pending"
    end
    return false, nil
end

local function _fireClickPackOne(id, tag)
    if not ClickPack or id == nil then return false, nil end
    if typeof(id) == "Instance" then return false, nil end
    local label = tostring(id)
    if label == "" or label == "Part" or label == "Model" then return false, nil end

    local ok = false
    local err = nil

    if type(ClickPack.Fire) == "function" then
        ok, err = pcall(function() ClickPack:Fire(label) end)
    end
    if not ok and type(ClickPack.FireServer) == "function" then
        ok, err = pcall(function() ClickPack:FireServer(label) end)
    end
    if not ok and type(ClickPack.InvokeServer) == "function" then
        ok, err = pcall(function() ClickPack:InvokeServer(label) end)
    end

    if ok then
        stats.remoteOk = stats.remoteOk + 1
        stats.lastClaimId = label
        return true, label
    end
    stats.lastError = tostring(err)
    return false, nil
end

local function _fireClickPackBurst(inst, tag)
    if not ClickPack or not inst then return {}, 0 end
    local firedIds = {}
    local seen = {}

    local function fireOne(id)
        if id == nil then return end
        local key = tostring(id)
        if seen[key] then return end
        seen[key] = true
        local ok, label = _fireClickPackOne(id, tag)
        if ok then firedIds[#firedIds + 1] = label end
    end

    local primary = _primaryClaimId(inst)
    fireOne(primary)
    for _, id in ipairs(_getClaimIds(inst)) do
        fireOne(id)
    end
    return firedIds, #firedIds
end

local function _prefireRemote(inst, tag)
    _initRemotes()
    if not ClickPack or not inst then return end
    stats.prefire = stats.prefire + 1
    _fireClickPackBurst(inst, tag or "prefire")
end

local function _claimSucceeded(inst, nearPos, method, maxWait)
    local ok, reason = _verifyClaimed(inst, nearPos, method, maxWait)
    if ok then
        stats.lastMethod = method .. ":" .. reason
        return true, method
    end
    if reason == "lost_to_other" then
        stats.lastMethod = method .. ":lost_to_other"
    end
    return false, reason
end

local function _tryOpenPromptClaim(inst, nearPos, tag)
    tag = tag or "open"
    _triggerGameOpen(inst)
    _fireClickPackBurst(inst, tag .. "_burst")

    local pp = nil
    local findDeadline = os.clock() + OPEN_PROMPT_FIND_WAIT
    while not pp and inst.Parent and os.clock() < findDeadline do
        pp = _findProximityPromptNear(nearPos)
        if not pp then task.wait(OPEN_UI_POLL) end
    end
    if not pp then pp = _findProximityPromptNear(nearPos) end
    if not pp then return false end

    local retryDeadline = os.clock() + OPEN_PROMPT_RETRY_SEC
    local attempt = 0
    while inst.Parent and os.clock() < retryDeadline and attempt < OPEN_PROMPT_RETRIES do
        attempt = attempt + 1
        _fireClickPackBurst(inst, tag .. "_r" .. attempt)
        if not _fireProximityPrompt(pp) then
            task.wait(OPEN_UI_POLL)
        else
            stats.lastClaimId = _primaryClaimId(inst)
            local remain = retryDeadline - os.clock()
            local maxW = (remain > VERIFY_WAIT_FAST + 0.01) and VERIFY_WAIT_FAST or math.min(VERIFY_WAIT, remain)
            local ok, reason = _claimSucceeded(inst, nearPos, "open_prompt", maxW)
            if ok then return true, "open_prompt" end
            if reason == "lost_to_other" then return false, "lost_to_other" end
        end
    end
    return false
end

local function _performClaim(inst)
    _initRemotes()
    if not inst then return false, nil, {} end

    local nearPos = _partWorldPos(inst)
    local t0 = os.clock()
    local steps = {}

    local function step(name, fn)
        local ts = os.clock()
        local ok, a, b = fn()
        steps[#steps + 1] = {
            step = name,
            ok = ok,
            ms = math.floor((os.clock() - ts) * 1000),
            extra = b or a,
        }
        return ok, a, b
    end

    step("prompt_fast", function()
        local pp = _findProximityPromptNear(nearPos)
        if not pp then return false end
        _fireClickPackBurst(inst, "prompt_fast")
        if not _fireProximityPrompt(pp) then return false end
        stats.lastClaimId = _primaryClaimId(inst)
        local ok, reason = _claimSucceeded(inst, nearPos, "prompt_fast", VERIFY_WAIT_FAST)
        if not ok and reason == "lost_to_other" then return false, "lost_to_other" end
        return ok
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end
    if steps[#steps].extra == "lost_to_other" then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return false, stats.lastMethod, steps
    end

    step("burst", function()
        local ids, n = _fireClickPackBurst(inst, "burst")
        if n <= 0 then return false end
        local ok, reason = _claimSucceeded(inst, nearPos, "burst", VERIFY_WAIT_FAST)
        if not ok and reason == "lost_to_other" then return false, "lost_to_other" end
        return ok
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end
    if steps[#steps].extra == "lost_to_other" then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return false, stats.lastMethod, steps
    end

    step("open_prompt", function()
        local ok, extra = _tryOpenPromptClaim(inst, nearPos, "fast")
        if not ok and extra == "lost_to_other" then return false, "lost_to_other" end
        return ok
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end
    if steps[#steps].extra == "lost_to_other" then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return false, stats.lastMethod, steps
    end

    step("burst_retry", function()
        local ids, n = _fireClickPackBurst(inst, "burst_retry")
        if n <= 0 then return false end
        local ok, reason = _claimSucceeded(inst, nearPos, "burst_retry")
        if not ok and reason == "lost_to_other" then return false, "lost_to_other" end
        return ok
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end
    if steps[#steps].extra == "lost_to_other" then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return false, stats.lastMethod, steps
    end

    step("clickdet", function()
        local cd = _findClickDetectorNear(nearPos)
        if not cd then
            cd = _waitOpenUiClickDetector(inst, function()
                _fireClickPackBurst(inst, "poll_burst")
            end)
        end
        if cd and _fireClickDetector(cd) then
            stats.lastClaimId = _primaryClaimId(inst)
            return _claimSucceeded(inst, nearPos, "ClickDetector")
        end
        return false
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end

    step("prompt_retry", function()
        local pp = _findProximityPromptNear(nearPos)
        if pp and _fireProximityPrompt(pp) then
            return _claimSucceeded(inst, nearPos, "ProximityPrompt")
        end
        return false
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end

    step("burst_final", function()
        _fireClickPackBurst(inst, "burst_final")
        return _claimSucceeded(inst, nearPos, "burst_final")
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end

    stats.lastMs = math.floor((os.clock() - t0) * 1000)
    return false, nil, steps
end

local function _collectSpawnEntries(folder)
    local out = {}
    if not folder then return out end
    for _, child in ipairs(folder:GetChildren()) do
        out[#out + 1] = child
    end
    return out
end

local function _countReadySpawns(folder)
    if not folder then return 0 end
    local n = 0
    for _, inst in ipairs(_collectSpawnEntries(folder)) do
        if _spawnHasAttrs(inst) and _canClaim(inst) then
            n += 1
        end
    end
    return n
end

local function _collectReadySpawns(folder)
    local out = {}
    if not folder then return out end
    for _, inst in ipairs(_collectSpawnEntries(folder)) do
        if _spawnHasAttrs(inst) and _canClaim(inst) then
            out[#out + 1] = inst
        end
    end
    return out
end

local function _pickNextReadySpawn(batch)
    if type(batch) ~= "table" or #batch == 0 then return nil end
    local best, bestD = batch[1], _distToSpawn(batch[1])
    if bestD == nil then bestD = math.huge end
    for i = 2, #batch do
        local inst = batch[i]
        local d = _distToSpawn(inst)
        if d == nil then
            if bestD == math.huge then best = inst end
        elseif d < bestD then
            best = inst
            bestD = d
        end
    end
    return best
end

local function _followClaimSeed(inst)
    if not inst or not inst.Parent or not _spawnHasAttrs(inst) then
        return false
    end

    local locked, lockKey = _claimLock(inst)
    if not locked then
        _skip("in_flight", inst.Name)
        return false
    end

    stats.attempts += 1
    _resetClaimAttempt()
    local label = _spawnLabel(inst)
    local success = false
    local t0 = os.clock()

    local okRun, errRun = pcall(function()
        _teleKeepPaused()
        _tpUnderSeed(inst)
        if AFTER_TP_SEC > 0 then task.wait(AFTER_TP_SEC) end

        while running and _enabled() and inst.Parent and os.clock() - t0 < MAX_FOLLOW_SEC do
            _teleKeepPaused()

            if _otherWonClaim() then
                break
            end

            if not _spawnHasAttrs(inst) or not _packStillActive(inst) then
                local ok, reason = _waitForClaimComplete(inst, CLAIM_VERDICT_WAIT + 1)
                if ok then
                    success = true
                    stats.lastResult = label .. " / " .. tostring(reason or "cleared")
                    stats.lastMethod = reason
                end
                break
            end

            _tpUnderSeed(inst)

            local nearPos = _partWorldPos(inst)
            if nearPos and _distToSpawn(inst) ~= nil and _distToSpawn(inst) > CLAIM_RANGE then
                _prefireRemote(inst, "follow_far")
            end

            _performClaim(inst)

            local okClaim, reason = _waitForClaimComplete(inst, CLAIM_COMPLETE_WAIT)
            if okClaim then
                success = true
                stats.lastResult = label .. " / " .. tostring(reason or "follow")
                stats.lastMethod = reason
                break
            end
            if reason == "lost_to_other" or _otherWonClaim() then
                break
            end

            if not _spawnHasAttrs(inst) or not _packStillActive(inst) then
                local okLate, reasonLate = _waitForClaimComplete(inst, CLAIM_VERDICT_WAIT + 1)
                if okLate then
                    success = true
                    stats.lastResult = label .. " / " .. tostring(reasonLate or "cleared_late")
                    stats.lastMethod = reasonLate
                end
                break
            end

            task.wait(FOLLOW_FIRE_SEC)
        end

        if not success and os.clock() - t0 >= MAX_FOLLOW_SEC then
            _skip("follow_timeout")
        end
    end)

    _claimUnlock(lockKey)
    if not okRun then
        stats.lastError = tostring(errRun)
    end
    return success
end

local function _processClaimSession(folder)
    if not folder or not _enabled() or claimBusy then
        return 0
    end
    if _countReadySpawns(folder) <= 0 then
        return 0
    end

    claimBusy = true
    G.__GAG2_AUTO_CLAIM_SEED_BUSY = true
    _G.__GAG2_AUTO_CLAIM_SEED_BUSY = true
    _teleStopForClaim()

    local claimed = 0

    while running and _enabled() and _countReadySpawns(folder) > 0 do
        local batch = _collectReadySpawns(folder)
        if #batch == 0 then break end

        local inst = _pickNextReadySpawn(batch)
        if not inst or not inst.Parent or not _spawnHasAttrs(inst) or not _canClaim(inst) then
            break
        end

        if _followClaimSeed(inst) then
            claimed += 1
            stats.fired += 1
            _markClaimed(inst, CLAIM_COOLDOWN)
        else
            local lost = _otherWonClaim()
            if lost then
                _markClaimed(inst, LOST_CLAIM_COOLDOWN)
                _skip("lost_to_other")
            elseif inst.Parent and _spawnHasAttrs(inst) and _packStillActive(inst) then
                _skip("claim_retry_same")
                task.wait(FOLLOW_FIRE_SEC)
            else
                _markClaimed(inst, 1.2)
                _skip("claim_fail")
            end
        end
    end

    _teleResumeNow()
    claimBusy = false
    G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
    _G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
    return claimed
end

local function _queueClaimSession(_source)
    if claimBusy or not _enabled() then return false end
    local folder = _getSpawnFolder() or spawnFolder
    if not folder then
        _skip("no_spawn_folder")
        return false
    end
    task.spawn(function()
        _processClaimSession(folder)
    end)
    return true
end

local function _scanFolder(folder)
    if not folder then _skip("no_spawn_folder") return 0 end
    local entries = _collectSpawnEntries(folder)
    local readyList = {}
    for _, inst in ipairs(entries) do
        if _spawnHasAttrs(inst) then readyList[#readyList + 1] = inst end
    end
    lastScanInfo.count = #entries
    lastScanInfo.ready = #readyList
    lastScanInfo.at = os.clock()

    if #readyList == 0 then return 0 end
    if claimBusy then return 0 end
    return _processClaimSession(folder)
end

local function _unbindAttrWatchers()
    for inst, conns in pairs(attrConns) do
        if type(conns) == "table" then
            for _, conn in ipairs(conns) do
                if conn and conn.Disconnect then conn:Disconnect() end
            end
        end
        attrConns[inst] = nil
    end
end

local function _bindSpawnInst(inst)
    if not inst or not inst.Parent or attrConns[inst] then return end
    local conns = {}
    for _, attr in ipairs({ "SeedPack", "GoldSeed", "RainbowSeed" }) do
        local ok, sig = pcall(function() return inst:GetAttributeChangedSignal(attr) end)
        if ok and sig and type(sig.Connect) == "function" then
            conns[#conns + 1] = sig:Connect(function()
                pcall(function()
                    if _enabled() and inst.Parent and _spawnHasAttrs(inst) then
                        task.spawn(function() _prefireRemote(inst, "attr_" .. attr) end)
                        _queueClaimSession("attr:" .. attr)
                    end
                end)
            end)
        end
    end
    if #conns > 0 then attrConns[inst] = conns end
end

local function _bindFolder(folder)
    if not folder then return end
    if childConn then childConn:Disconnect() childConn = nil end
    _unbindAttrWatchers()
    for _, child in ipairs(folder:GetChildren()) do _bindSpawnInst(child) end
    childConn = folder.ChildAdded:Connect(function(child)
        if not child then return end
        _bindSpawnInst(child)
        task.spawn(function()
            if _spawnHasAttrs(child) then
                _prefireRemote(child, "child_prefire")
                _queueClaimSession("child")
                return
            end
            local deadline = os.clock() + ATTR_WAIT_SEC
            while child.Parent and os.clock() < deadline do
                if _spawnHasAttrs(child) then
                    _prefireRemote(child, "child_wait")
                    _queueClaimSession("child-wait")
                    return
                end
                task.wait(ATTR_POLL_SEC)
            end
        end)
    end)
end

local function _ensureMapWatch()
    if mapConn then return end
    local map = _getMap()
    if not map then
        mapConn = workspace.ChildAdded:Connect(function(child)
            if child.Name == "Map" then
                spawnFolder = nil
                _ensureWatchers()
            end
        end)
        return
    end
    mapConn = map.ChildAdded:Connect(function(child)
        if child.Name == "SeedPackSpawnServerLocations" then
            spawnFolder = child
            _bindFolder(child)
        end
    end)
end

local function _ensureWatchers()
    _ensureMapWatch()
    local folder = _getSpawnFolder()
    if folder and folder ~= spawnFolder then
        spawnFolder = folder
        _bindFolder(folder)
    end
    return folder
end

local function _bindFx()
    if fxConn then return end
    _initRemotes()
    if not SeedPackFX or not SeedPackFX.OnClientEvent then return end
    fxConn = SeedPackFX.OnClientEvent:Connect(function(pos)
        lastFxAt = os.clock()
        if typeof(pos) == "Vector3" then lastFxPos = pos end
    end)
end

local function claimLoop(myId)
    _initRemotes()
    _bindFx()
    while running and loopId == myId do
        local ok, err = pcall(function()
            if not _enabled() then
                running = false
                return
            end
            if not savedGardenCf then savedGardenCf = _getGardenCFrame() end
            _scanFolder(_ensureWatchers())
            if SCAN_SEC <= 0 then RunService.Heartbeat:Wait() else task.wait(SCAN_SEC) end
        end)
        if not ok then
            stats.lastError = tostring(err)
            task.wait(0.5)
        end
    end
    if loopId == myId then
        running = false
    end
end

function M.ClaimOnce()
    if not _enabled() then return 0 end
    return _scanFolder(_ensureWatchers())
end
M.claimOnce = M.ClaimOnce

function M.Start()
    _initRemotes()
    if not _enabled() then
        running = false
        return
    end
    if running then return end
    running = true
    loopId = loopId + 1
    local myId = loopId
    savedGardenCf = savedGardenCf or _getGardenCFrame()
    _ensureWatchers()
    _bindFx()
    task.spawn(function() claimLoop(myId) end)
end
M.start = M.Start

function M.Stop()
    running = false
    if claimBusy then
        _teleResumeNow()
        claimBusy = false
        G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
        _G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
    end
    if childConn then childConn:Disconnect() childConn = nil end
    _unbindAttrWatchers()
end
M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.ApplyRuntime(on)
    if on then M.Start() else M.Stop() end
end
M.applyRuntime = M.ApplyRuntime

function M.SyncFromGlobals()
    M.SetEnabled(_enabled())
end
M.syncFromGlobals = M.SyncFromGlobals
M.SyncFromState = M.SyncFromGlobals
M.syncFromState = M.SyncFromGlobals

function M.SetEnabled(on)
    on = _writeEnabled(on == true)
    if on then
        M.Start()
    else
        M.Stop()
    end
end
M.setEnabled = M.SetEnabled

function M.GetDiagnostics()
    _initRemotes()
    local folder = _getSpawnFolder()
    local active = {}
    if folder then
        for _, inst in ipairs(_collectSpawnEntries(folder)) do
            local ok, row = pcall(function()
                return {
                    name = inst.Name,
                    class = inst.ClassName,
                    claimId = _primaryClaimId(inst),
                    claimIds = table.concat(_getClaimIds(inst), ", "),
                    label = _spawnLabel(inst),
                    ready = _spawnHasAttrs(inst),
                    pack = _getSpawnAttr(inst, "SeedPack"),
                    rainbow = _truthy(_getSpawnAttr(inst, "RainbowSeed")),
                    gold = _truthy(_getSpawnAttr(inst, "GoldSeed")),
                    dist = _distToSpawn(inst),
                    attrs = (function()
                        local parts = {}
                        for n, v in pairs(inst:GetAttributes()) do
                            parts[#parts + 1] = n .. "=" .. tostring(v)
                        end
                        table.sort(parts)
                        return table.concat(parts, ", ")
                    end)(),
                }
            end)
            if ok and type(row) == "table" then active[#active + 1] = row end
        end
    end
    return {
        enabled = _enabled(),
        running = running,
        remote = ClickPack ~= nil,
        remotePath = remotePath or "Networking.SeedPack.ClickPack",
        spawnFolder = folder and folder:GetFullName() or nil,
        activeSpawns = active,
        activeCount = #active,
        readyToClaim = folder and _countReadySpawns(folder) or 0,
        claimBusy = claimBusy,
        telePaused = telePaused,
        underY = UNDER_Y,
        lastScan = lastScanInfo,
        stats = stats,
        storeEnabled = type(G.__GAG2_CLAIM_SEED) == "table" and G.__GAG2_CLAIM_SEED.enabled or nil,
    }
end
M.getDiagnostics = M.GetDiagnostics

local function _formatSkipCounts(skipped)
    if type(skipped) ~= "table" or next(skipped) == nil then
        return "(none)"
    end
    local parts = {}
    for reason, count in pairs(skipped) do
        parts[#parts + 1] = tostring(reason) .. "=" .. tostring(count)
    end
    table.sort(parts)
    return table.concat(parts, ", ")
end

local function _formatValue(v)
    if v == nil then return "nil" end
    local t = type(v)
    if t == "string" or t == "number" or t == "boolean" then
        return tostring(v)
    end
    if t == "table" then
        local parts = {}
        for k, val in pairs(v) do
            parts[#parts + 1] = tostring(k) .. "=" .. _formatValue(val)
        end
        table.sort(parts)
        if #parts == 0 then return "{}" end
        return "{" .. table.concat(parts, ", ") .. "}"
    end
    return tostring(v)
end

function M.DebugWhyNot(_self)
    local d = M.GetDiagnostics()
    local report = {
        ok = true,
        reasons = {},
        enabled = d.enabled == true,
        running = d.running == true,
        remote = d.remote == true,
        spawnFolder = d.spawnFolder,
        readyToClaim = d.readyToClaim or 0,
        activeCount = d.activeCount or 0,
        claimBusy = d.claimBusy == true,
        telePaused = d.telePaused == true,
        lastError = d.stats and d.stats.lastError or nil,
        lastSkip = d.stats and d.stats.lastSkip or nil,
        lastResult = d.stats and d.stats.lastResult or nil,
    }

    local function fail(code, msg)
        report.ok = false
        report.reasons[#report.reasons + 1] = msg and (code .. ": " .. msg) or code
    end

    if not report.enabled then
        fail("disabled", "Enable Auto Claim Seed di tab AUTO")
    end
    if not report.remote then
        fail("no_remote", "Networking.SeedPack.ClickPack belum ready — re-execute hub")
    end
    if not report.spawnFolder then
        fail("no_spawn_folder", "Map.SeedPackSpawnServerLocations tidak ditemukan")
    end
    if report.readyToClaim <= 0 then
        fail("no_ready_seed", "Tidak ada seed pack siap claim di map")
    end
    if report.claimBusy then
        fail("busy", "Sedang proses claim — tunggu sebentar")
    end

    local lines = { "========== Auto Claim Seed DebugWhyNot ==========" }
    lines[#lines + 1] = "ok: " .. tostring(report.ok)
    lines[#lines + 1] = "enabled: " .. tostring(report.enabled)
        .. " | running: " .. tostring(report.running)
        .. " | remote: " .. tostring(report.remote)
    lines[#lines + 1] = "spawn folder: " .. tostring(report.spawnFolder or "MISSING")
    lines[#lines + 1] = "ready to claim: " .. tostring(report.readyToClaim)
        .. " | active spawns: " .. tostring(report.activeCount)
    lines[#lines + 1] = "claim busy: " .. tostring(report.claimBusy)
        .. " | tele paused: " .. tostring(report.telePaused)
    if report.lastError and tostring(report.lastError) ~= "" then
        lines[#lines + 1] = "last error: " .. tostring(report.lastError)
    end
    if report.lastSkip and tostring(report.lastSkip) ~= "" then
        lines[#lines + 1] = "last skip: " .. tostring(report.lastSkip)
    end
    if report.lastResult ~= nil then
        lines[#lines + 1] = "last result: " .. _formatValue(report.lastResult)
    end
    if #report.reasons > 0 then
        lines[#lines + 1] = "reasons:"
        for _, r in ipairs(report.reasons) do
            lines[#lines + 1] = "  - " .. r
        end
    end
    lines[#lines + 1] = "hint: PrintDiagnostics() | ClaimOnce()"
    lines[#lines + 1] = "================================================="
    local out = table.concat(lines, "\n")
    print(out)
    return report
end
M.debugWhyNot = M.DebugWhyNot

function M.PrintDiagnostics(_self)
    local d = M.GetDiagnostics()
    local st = type(d.stats) == "table" and d.stats or {}

    print("========== GAG2 Auto Claim Seed ==========")
    print("enabled:", d.enabled, "| running:", d.running, "| store:", d.storeEnabled)
    if d.enabled ~= true and d.running == true then
        print("warn: running=true tapi enabled=false — toggle OFF lalu ON, atau re-execute hub")
    end
    print("remote:", d.remote, "| path:", tostring(d.remotePath or "MISSING"))
    print("spawn folder:", tostring(d.spawnFolder or "MISSING"))
    print("active spawns:", tostring(d.activeCount or 0), "| ready to claim:", tostring(d.readyToClaim or 0))
    print("claim busy:", d.claimBusy, "| tele paused:", d.telePaused, "| under Y:", d.underY)
    if type(d.lastScan) == "table" then
        print("last scan: total=", d.lastScan.count, "ready=", d.lastScan.ready)
    end

    print("-- stats --")
    print("  attempts:", st.attempts, "| fired:", st.fired, "| remoteOk:", st.remoteOk)
    print("  teleports:", st.teleports, "| clickOk:", st.clickOk, "| prefire:", st.prefire)
    print("  lastMethod:", tostring(st.lastMethod or "-"))
    print("  lastClaimId:", tostring(st.lastClaimId or "-"))
    print("  lastResult:", _formatValue(st.lastResult))
    print("  lastSkip:", tostring(st.lastSkip or "-"))
    print("  lastError:", tostring(st.lastError or "-"))
    print("  lastMs:", tostring(st.lastMs or "-"))
    print("  skipped:", _formatSkipCounts(st.skipped))

    if type(d.activeSpawns) == "table" and #d.activeSpawns > 0 then
        print("-- active spawns (max 8) --")
        for i = 1, math.min(8, #d.activeSpawns) do
            local row = d.activeSpawns[i]
            if type(row) == "table" then
                print(string.format(
                    "  [%d] %s | %s | ready=%s | dist=%s | claimId=%s",
                    i,
                    tostring(row.label or row.name or "?"),
                    tostring(row.class or "?"),
                    tostring(row.ready),
                    tostring(row.dist),
                    tostring(row.claimId or "-")
                ))
                if row.attrs and tostring(row.attrs) ~= "" then
                    print("       attrs:", row.attrs)
                end
            end
        end
        if #d.activeSpawns > 8 then
            print("  ... +" .. tostring(#d.activeSpawns - 8) .. " more")
        end
    else
        print("-- active spawns: (none) --")
    end

    print("hint: DebugWhyNot() | ClaimOnce() | SetEnabled(true)")
    print("========================================")
    return d
end
M.printDiagnostics = M.PrintDiagnostics
M.Debug = M.PrintDiagnostics
M.debug = M.PrintDiagnostics

G.AutoClaimSeed = M
G.AutoClaimSeedModule = M
_G.AutoClaimSeed = M
_G.AutoClaimSeedModule = M

return M
 end,         required = false },
    { key = "AutoHopServer",   name = "Auto Hop Server",  factory = function() -- AutoHopServer.lua — Grow A Garden 2
-- Adapted from auto_snipe_hop (NodeHub Market)
-- ✅ 1 Hop Session (serial attempts, no storm)
-- ✅ Anti IsTeleporting spam (lock window)
-- ✅ If target dead/full -> mark & try next candidate
-- ✅ TeleportData confirm -> push visited (persist)
-- ✅ PRE-HOP: mark current server JobId to visited BEFORE building candidates (STATE + FILE)
-- ✅ Candidates filter uses visited from STATE + FILE cache
-- ✅ If visited reached diffServers -> clear visited (STATE + FILE) + invalidate cache ts
-- ✅ Cache candidates to FILE per (placeId,targetPlayers,diffServers) to reduce 429
-- ✅ 429 backoff -> stop scan and rely on cache
-- ✅ Works with PSReconnect:HopToServer (keeps QTP gating). Fallback to TeleportToPlaceInstance if needed.

local M = {}

----------------------------------------------------------------
-- Services
----------------------------------------------------------------
local Players         = game:GetService("Players")
local TeleportService = game:GetService("TeleportService")
local HttpService     = game:GetService("HttpService")

local LP = Players.LocalPlayer

local function getLP()
    return Players.LocalPlayer or LP
end

----------------------------------------------------------------
-- Runtime status (for UI)
----------------------------------------------------------------
local _lastStatus = "idle"
local _lastSessionErr = nil
local _lastScanPages = 0
local _lastScanServers = 0
local _debug = false
local function dprint(...)
    if not _debug then return end
    print("[GAG2-AutoHop]", ...)
end

local function now() return os.clock() end
local function low(s) return string.lower(tostring(s or "")) end

----------------------------------------------------------------
-- Utils
----------------------------------------------------------------
local function clampNum(v, minv, maxv, fallback)
    local n = tonumber(v)
    if n == nil then return fallback end
    if minv ~= nil and n < minv then n = minv end
    if maxv ~= nil and n > maxv then n = maxv end
    return n
end

local function isArray(t)
    return type(t) == "table" and rawget(t, 1) ~= nil
end

local function ensureArray(t)
    if type(t) ~= "table" then return {} end
    if isArray(t) then return t end
    return {}
end

local SORT_SPLIT_TARGET = 4
local GAME_SERVER_MAX   = 8
local HOP_CURRENT_PLAYER_MIN     = 2
local HOP_CURRENT_PLAYER_DEFAULT = 2
local HOP_TELEPORT_DELAY_DEFAULT = 60

local function clampCurrentPlayers(v)
    return clampNum(v, HOP_CURRENT_PLAYER_MIN, 100, HOP_CURRENT_PLAYER_DEFAULT)
end

-- Auto-adapt: bandingkan Current Player Max vs Target Server
-- current > target  -> server ramai, cari lebih sepi (Asc)
-- current < target  -> server sepi, cari lebih ramai (Desc)
local function getHopMode(currentPlayers, targetPlayers)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    if currentPlayers > targetPlayers then
        return "leave_crowded"
    end
    if currentPlayers < targetPlayers then
        return "leave_quiet"
    end
    return "balanced"
end

local function getSortOrdersForHop(currentPlayers, targetPlayers)
    local mode = getHopMode(currentPlayers, targetPlayers)
    if mode == "leave_crowded" then
        return "Asc", "Desc"
    elseif mode == "leave_quiet" then
        return "Desc", "Asc"
    end
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    if targetPlayers <= SORT_SPLIT_TARGET then
        return "Asc", "Desc"
    end
    return "Desc", "Asc"
end

local function preferHigherPlaying(currentPlayers, targetPlayers)
    return getHopMode(currentPlayers, targetPlayers) == "leave_quiet"
end

local function getScanPagesForHop(currentPlayers, targetPlayers, isFallback)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    local gap = math.abs(currentPlayers - targetPlayers)
    local base
    if getHopMode(currentPlayers, targetPlayers) == "leave_crowded" and targetPlayers <= SORT_SPLIT_TARGET then
        base = isFallback and 6 or 10
    else
        base = isFallback and 8 or 12
    end
    if gap >= 5 then
        base += isFallback and 2 or 4
    end
    return base
end

local function getHopTriggerHint(currentPlayers, targetPlayers)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    local mode = getHopMode(currentPlayers, targetPlayers)
    if mode == "leave_crowded" then
        return "Hop when players >= " .. currentPlayers .. " (target ~" .. targetPlayers .. ")"
    elseif mode == "leave_quiet" then
        return "Hop when players <= " .. currentPlayers .. " (target ~" .. targetPlayers .. ")"
    end
    return "Hop when players >= " .. currentPlayers
end

----------------------------------------------------------------
-- FILE CACHE (reduce 429)
----------------------------------------------------------------
local FS_OK = (type(readfile)=="function" and type(writefile)=="function" and type(isfile)=="function")

local function ensureFolder(path)
    if type(makefolder) ~= "function" then return end
    if type(isfolder) == "function" and isfolder(path) then return end
    local parts = {}
    for seg in tostring(path):gmatch("[^/]+") do
        parts[#parts+1] = seg
        local p = table.concat(parts, "/")
        if type(isfolder) ~= "function" or not isfolder(p) then
            pcall(function() makefolder(p) end)
        end
    end
end

local CACHE_DIR  = "growagarden2"
local CACHE_FILE = CACHE_DIR .. "/autohop_cache.json"

local function safeJsonDecode(s)
    local ok, t = pcall(function() return HttpService:JSONDecode(s) end)
    if ok and type(t) == "table" then return t end
    return nil
end

local function safeJsonEncode(t)
    local ok, s = pcall(function() return HttpService:JSONEncode(t) end)
    if ok and type(s) == "string" then return s end
    return nil
end

local function readCacheRoot()
    if not FS_OK then return {} end
    if not isfile(CACHE_FILE) then return {} end
    local ok, content = pcall(function() return readfile(CACHE_FILE) end)
    if not ok or type(content) ~= "string" then return {} end
    return safeJsonDecode(content) or {}
end

local function writeCacheRoot(root)
    if not FS_OK then return end
    ensureFolder(CACHE_DIR)
    local s = safeJsonEncode(root)
    if not s then return end
    pcall(function() writefile(CACHE_FILE, s) end)
end

local function makeCacheKey(placeId, currentPlayers, targetPlayers, diffServers)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    diffServers = clampNum(diffServers, 1, 200, 5)
    local primary = select(1, getSortOrdersForHop(currentPlayers, targetPlayers))
    return tostring(placeId)
        .. "|cur=" .. tostring(currentPlayers)
        .. "|tp=" .. tostring(targetPlayers)
        .. "|diff=" .. tostring(diffServers)
        .. "|sort=" .. primary
end

-- root[key] = { ts=os.time(), candidates={...}, visited={...} }
local function cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local root = readCacheRoot()
    local key  = makeCacheKey(placeId, currentPlayers, targetPlayers, diffServers)
    local rec  = (type(root[key])=="table") and root[key] or {}
    return root, key, rec
end

local function cacheSave(placeId, currentPlayers, targetPlayers, diffServers, patch)
    local root, key, rec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    rec = (type(rec)=="table") and rec or {}
    patch = (type(patch)=="table") and patch or {}
    for k,v in pairs(patch) do rec[k] = v end
    root[key] = rec
    writeCacheRoot(root)
end

local function cacheGetCandidates(placeId, currentPlayers, targetPlayers, diffServers, maxAgeSec)
    maxAgeSec = tonumber(maxAgeSec) or 900
    local _, _, rec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local ts  = tonumber(rec.ts) or 0
    local arr = rec.candidates
    if type(arr) ~= "table" then return nil, "no_cache" end
    local age = os.time() - ts
    if age > maxAgeSec then
        return ensureArray(arr), "stale_cache"
    end
    return ensureArray(arr), "fresh_cache"
end

local function cacheSetCandidates(placeId, currentPlayers, targetPlayers, diffServers, candidates)
    candidates = ensureArray(candidates)
    cacheSave(placeId, currentPlayers, targetPlayers, diffServers, {
        ts = os.time(),
        candidates = candidates,
    })
end

local function cacheGetVisited(placeId, currentPlayers, targetPlayers, diffServers)
    local _, _, rec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local v = rec.visited
    if type(v) ~= "table" then return {} end
    return ensureArray(v)
end

local function cacheSetVisited(placeId, currentPlayers, targetPlayers, diffServers, visitedArr)
    visitedArr = ensureArray(visitedArr)
    cacheSave(placeId, currentPlayers, targetPlayers, diffServers, {
        visited = visitedArr,
    })
end

----------------------------------------------------------------
-- State read
----------------------------------------------------------------
local function _persistState()
    local G = (getgenv and getgenv()) or _G
    if G.__GAG2_RESETTING == true then return end

    local saveVisited = G.__GAG2_SAVE_AUTO_HOP_VISITED or rawget(_G, "__GAG2_SAVE_AUTO_HOP_VISITED")
    if type(saveVisited) == "function" then
        local visited = {}
        local main = G.MAIN or rawget(_G, "MAIN")
        if type(main) == "table" and type(main.misc) == "table"
            and type(main.misc.rejoin) == "table"
            and type(main.misc.rejoin.auto_hop) == "table"
            and type(main.misc.rejoin.auto_hop.visited) == "table" then
            visited = main.misc.rejoin.auto_hop.visited
        end
        task.defer(function()
            pcall(saveVisited, visited)
        end)
        return
    end

    if type(G.__GAG2_AUTO_SAVE) == "function" then
        task.defer(function() pcall(G.__GAG2_AUTO_SAVE) end)
    end
end

----------------------------------------------------------------
-- State read (GAG2 — MAIN.misc.rejoin.auto_hop)
----------------------------------------------------------------
local function _getState()
    local G = (getgenv and getgenv()) or _G
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    MAIN = (type(MAIN) == "table") and MAIN or {}
    MAIN.misc = (type(MAIN.misc) == "table") and MAIN.misc or {}
    MAIN.misc.rejoin = (type(MAIN.misc.rejoin) == "table") and MAIN.misc.rejoin or {}
    MAIN.misc.rejoin.auto_hop = (type(MAIN.misc.rejoin.auto_hop) == "table") and MAIN.misc.rejoin.auto_hop or {}

    local AH = MAIN.misc.rejoin.auto_hop
    local saved = type(G.__AUTO_HOP_SAVED) == "table" and G.__AUTO_HOP_SAVED

    if AH.enabled == nil then
        if saved and saved.enabled ~= nil then
            AH.enabled = (saved.enabled == true)
        else
            AH.enabled = (G.AUTO_HOP_ENABLED == true)
        end
    end
    if tonumber(AH.current_player) == nil then
        AH.current_player = (saved and tonumber(saved.current))
            or tonumber(G.AUTO_HOP_CURRENT_PLAYER)
            or HOP_CURRENT_PLAYER_DEFAULT
    end
    if tonumber(AH.max_player) == nil then
        AH.max_player = (saved and tonumber(saved.max))
            or tonumber(G.AUTO_HOP_MAX_PLAYER)
            or 1
    end
    if tonumber(AH.teleport_delay) == nil then
        AH.teleport_delay = (saved and tonumber(saved.delay))
            or tonumber(G.AUTO_HOP_TELEPORT_DELAY)
            or HOP_TELEPORT_DELAY_DEFAULT
    end
    if tonumber(AH.minutes) == nil then AH.minutes = 8 end
    if tonumber(AH.diff_servers) == nil then AH.diff_servers = 5 end
    AH.visited = ensureArray(AH.visited)

    AH.current_player = clampCurrentPlayers(AH.current_player)
    AH.max_player   = clampNum(AH.max_player, 1, 100, 1)
    AH.teleport_delay = clampNum(AH.teleport_delay, 0, 600, HOP_TELEPORT_DELAY_DEFAULT)
    AH.minutes      = clampNum(AH.minutes, 1, 1440, 8)
    AH.diff_servers = clampNum(AH.diff_servers, 1, 200, 5)

    G.MAIN = MAIN
    _G.MAIN = MAIN

    local STATE = G.STATE or rawget(_G, "STATE")
    if type(STATE) == "table" then
        STATE.rejoin = STATE.rejoin or {}
        STATE.rejoin.auto_hop = AH
    end

    return MAIN, AH
end

local function getCfg()
    local MAIN, AH = _getState()

    local target = clampNum(AH.max_player, 1, 100, 1)

    return {
        enabled        = (AH.enabled == true),
        minutes        = clampNum(AH.minutes, 1, 1440, 8),
        diffServers    = clampNum(AH.diff_servers, 1, 200, 5),
        currentPlayers = clampCurrentPlayers(AH.current_player),
        targetPlayers  = target,
        teleportDelay  = clampNum(AH.teleport_delay, 0, 600, HOP_TELEPORT_DELAY_DEFAULT),
        AH = AH,
        MAIN = MAIN,
    }
end

local function getLocalPlayerCount()
    local n = 0
    pcall(function()
        n = #Players:GetPlayers()
    end)
    return n
end

----------------------------------------------------------------
-- visited helpers (STATE + FILE)
----------------------------------------------------------------
local function buildSetFromArray(arr)
    local set = {}
    arr = ensureArray(arr)
    for _, v in ipairs(arr) do
        local s = tostring(v or "")
        if s ~= "" then set[s] = true end
    end
    return set
end

local function resetVisitedIfNeeded(placeId, currentPlayers, targetPlayers, diffServers, AH)
    local limit = tonumber(AH and AH.diff_servers) or diffServers or 5
    AH.visited = ensureArray(AH and AH.visited)

    if #AH.visited >= limit then
        AH.visited = {}
        dprint("visited reset limit", limit)

        cacheSetVisited(placeId, currentPlayers, targetPlayers, diffServers, AH.visited)
        cacheSave(placeId, currentPlayers, targetPlayers, diffServers, { ts = 0, scanCursor = {} })
        _persistState()
        return true
    end
    return false
end

-- ✅ PRE-HOP: always mark current server to visited (STATE + FILE)
local function pushVisitedPreHop(jobId)
    local cfg = getCfg()
    local placeId = game.PlaceId

    jobId = tostring(jobId or "")
    if jobId == "" then return false end

    local AH = cfg.AH
    AH.visited = ensureArray(AH.visited)

    for _, v in ipairs(AH.visited) do
        if tostring(v) == jobId then
            return false
        end
    end

    table.insert(AH.visited, jobId)
    dprint("visited prehop +1", jobId, "count", #AH.visited)

    cacheSetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH.visited)
    resetVisitedIfNeeded(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH)
    _persistState()

    return true
end

local function pushVisitedConfirmed(jobId)
    local cfg = getCfg()
    local placeId = game.PlaceId

    jobId = tostring(jobId or "")
    if jobId == "" then return end

    local AH = cfg.AH
    AH.visited = ensureArray(AH.visited)
    for _, v in ipairs(AH.visited) do
        if tostring(v) == jobId then return end
    end

    table.insert(AH.visited, jobId)
    dprint("visited confirmed +1", jobId, "count", #AH.visited)

    cacheSetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH.visited)
    resetVisitedIfNeeded(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH)
    _persistState()
end

----------------------------------------------------------------
-- Local avoid/recent/dead trackers
----------------------------------------------------------------
local AVOID_TTL_SEC    = 240
local AVOID_TTL_DEAD   = 900
local AVOID_TTL_FULL   = 240
local RECENT_TRIED_TTL = 240

local _avoidUntil  = {}
local _recentTried = {}
local _deadUntil   = {}

local function ttlAlive(map, jobId)
    jobId = tostring(jobId or "")
    if jobId == "" then return false end
    local untilT = map[jobId]
    if not untilT then return false end
    if now() >= untilT then
        map[jobId] = nil
        return false
    end
    return true
end

local function isAvoided(jobId) return ttlAlive(_avoidUntil, jobId) end
local function isRecent(jobId)  return ttlAlive(_recentTried, jobId) end
local function isDead(jobId)    return ttlAlive(_deadUntil, jobId) end

local function markAvoid(jobId, sec)
    jobId = tostring(jobId or "")
    if jobId == "" then return end
    sec = tonumber(sec) or AVOID_TTL_SEC
    _avoidUntil[jobId] = now() + sec
end

local function markRecent(jobId, sec)
    jobId = tostring(jobId or "")
    if jobId == "" then return end
    sec = tonumber(sec) or RECENT_TRIED_TTL
    _recentTried[jobId] = now() + sec
end

local function markDead(jobId, sec)
    jobId = tostring(jobId or "")
    if jobId == "" then return end
    sec = tonumber(sec) or AVOID_TTL_DEAD
    _deadUntil[jobId] = now() + sec
end

----------------------------------------------------------------
-- Roblox API backoff (429)
----------------------------------------------------------------
local _apiBlockedUntil = 0
local _api429WinStart  = 0
local _api429Count     = 0

local function apiBackoff(sec, why)
    sec = tonumber(sec) or 30
    local jitter = math.random(0, 8)
    _apiBlockedUntil = now() + sec + jitter
    dprint("API_BACKOFF", math.floor(sec + jitter), "sec", tostring(why or ""))
end

local function httpGet(url)
    if now() < (_apiBlockedUntil or 0) then
        return false, "rate_limited_local", 429
    end

    local req =
        (syn and syn.request) or
        (http and http.request) or
        http_request or
        request or
        (fluxus and fluxus.request)

    if type(req) == "function" then
        local res = req({ Url = url, Method = "GET" })
        local body = res and (res.Body or res.body)
        local code = tonumber(res and (res.StatusCode or res.status_code)) or 0

        if _debug then dprint("http", code, url) end

        if code == 429 then
            local t = now()
            if (t - _api429WinStart) > 60 then
                _api429WinStart = t
                _api429Count = 0
            end
            _api429Count += 1

            local base = 30
            if _api429Count >= 2 then base = 45 end
            if _api429Count >= 4 then base = 75 end
            apiBackoff(base, "http_429")
            return false, "http_429", 429
        end

        if type(body) == "string" and body ~= "" then
            return true, body, code
        end
        return false, "request_failed", code
    end

    local ok, body = pcall(function()
        return HttpService:GetAsync(url)
    end)
    if ok and type(body) == "string" and body ~= "" then
        return true, body, 200
    end

    ok, body = pcall(function()
        return game:HttpGet(url)
    end)
    if not ok then
        return false, body, 0
    end
    return true, body, 200
end

local API_PAGE_LIMIT    = 50   -- limit=100 sering return kosong / cursor null (bug Roblox API)
local API_PAGE_DELAY    = 0.22 -- jeda antar page biar tidak kena 429
local SCAN_EARLY_EXIT   = 22   -- cukup kandidat bagus -> stop scan (hemat API)

local function isServerJoinable(playing, maxPlayers)
    playing = tonumber(playing) or 0
    maxPlayers = tonumber(maxPlayers) or 0
    if maxPlayers <= 0 then return true end
    return playing < maxPlayers
end

-- Target 8 + max server 8 => full (8/8) tidak bisa join; aim ke 7/8
local function scoreTargetForServer(targetPlayers, maxPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    maxPlayers = tonumber(maxPlayers) or 0
    if maxPlayers <= 0 then
        maxPlayers = GAME_SERVER_MAX
    end
    if targetPlayers >= maxPlayers then
        return maxPlayers - 1
    end
    return targetPlayers
end

local function popScore(playing, targetPlayers, maxPlayers)
    local aim = scoreTargetForServer(targetPlayers, maxPlayers)
    return math.abs((tonumber(playing) or 0) - aim)
end

local function getExcludeFullForTarget(targetPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    return targetPlayers >= (GAME_SERVER_MAX - 1)
end

local function fetchServers(placeId, cursor, sortOrder, opts)
    opts = type(opts) == "table" and opts or {}
    local limit = clampNum(opts.limit, 10, 100, API_PAGE_LIMIT)
    local excludeFull = opts.excludeFullGames
    if excludeFull == nil then
        excludeFull = getExcludeFullForTarget(opts.targetPlayers or 1)
    end

    sortOrder = (tostring(sortOrder or "Asc") == "Desc") and "Desc" or "Asc"
    local url = ("https://games.roblox.com/v1/games/%d/servers/Public?sortOrder=%s&limit=%d"):format(
        placeId, sortOrder, limit
    )
    if excludeFull then
        url = url .. "&excludeFullGames=true"
    end
    if cursor and cursor ~= "" then
        url = url .. "&cursor=" .. HttpService:UrlEncode(tostring(cursor))
    end

    local ok, body, code = httpGet(url)
    if not ok then
        return nil, nil, ("http_failed:" .. tostring(body) .. "|code=" .. tostring(code))
    end

    local decoded
    local ok2 = pcall(function()
        decoded = HttpService:JSONDecode(body)
    end)
    if not ok2 or type(decoded) ~= "table" then
        return nil, nil, "json_decode_failed"
    end

    local data = decoded.data
    local nextCursor = decoded.nextPageCursor
    if type(data) ~= "table" then data = {} end

    -- Bug Roblox: limit=100 kadang data=[] + cursor null padahal masih ada server
    if #data == 0 and limit >= 100 and not opts._retriedSmaller then
        dprint("empty page limit=100 -> retry limit=50")
        return fetchServers(placeId, cursor, sortOrder, {
            limit = 50,
            excludeFullGames = excludeFull,
            targetPlayers = opts.targetPlayers,
            _retriedSmaller = true,
        })
    end

    return data, nextCursor, nil
end

local function filterCandidates(list, visitedSet, avoidJobId, targetPlayers, currentPlayers)
    local out = {}
    list = ensureArray(list)
    visitedSet = visitedSet or {}
    avoidJobId = tostring(avoidJobId or "")
    targetPlayers = tonumber(targetPlayers) or 1
    currentPlayers = clampCurrentPlayers(currentPlayers)
    local preferHigh = preferHigherPlaying(currentPlayers, targetPlayers)

    for _, rec in ipairs(list) do
        local id = tostring(rec.id or "")
        local playing = tonumber(rec.playing) or 0
        local maxPlayers = tonumber(rec.maxPlayers) or 0

        if id ~= ""
            and id ~= avoidJobId
            and not visitedSet[id]
            and not isDead(id)
            and not isAvoided(id)
            and not isRecent(id)
        then
            if isServerJoinable(playing, maxPlayers) then
                out[#out+1] = {
                    id = id,
                    playing = playing,
                    maxPlayers = maxPlayers,
                    score = popScore(playing, targetPlayers, maxPlayers),
                }
            end
        end
    end

    table.sort(out, function(a, b)
        if a.score ~= b.score then return a.score < b.score end
        if preferHigh then
            return a.playing > b.playing
        end
        return a.playing < b.playing
    end)

    local trimmed = {}
    for i = 1, math.min(#out, 28) do
        local rec = out[i]
        trimmed[#trimmed+1] = { id=rec.id, playing=rec.playing, maxPlayers=rec.maxPlayers }
    end
    return trimmed
end

----------------------------------------------------------------
-- Build candidates (cache-first, scan-later)
----------------------------------------------------------------
local function buildCandidates(placeId, currentPlayers, targetPlayers, diffServers, visitedSet, avoidJobId)
    visitedSet = visitedSet or {}
    avoidJobId = tostring(avoidJobId or "")
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)

    -- ✅ merge visited from file (persist)
    do
        local vfile = cacheGetVisited(placeId, currentPlayers, targetPlayers, diffServers)
        for _, jid in ipairs(ensureArray(vfile)) do
            visitedSet[tostring(jid)] = true
        end
    end

    -- 1) cache first (fresh)
    local cached, cacheState = cacheGetCandidates(placeId, currentPlayers, targetPlayers, diffServers, 900)
    if type(cached) == "table" and #cached > 0 and cacheState == "fresh_cache" then
        local filtered = filterCandidates(cached, visitedSet, avoidJobId, targetPlayers, currentPlayers)
        if #filtered > 0 then
            dprint("use cache candidates (fresh)", #filtered, "from", #cached)
            return filtered, nil, 0, cacheState
        end
        dprint("cache fresh exhausted by filters -> scan")
    end

    -- 2) if blocked -> stale cache only
    if now() < (_apiBlockedUntil or 0) then
        if type(cached) == "table" and #cached > 0 then
            local filtered = filterCandidates(cached, visitedSet, avoidJobId, targetPlayers, currentPlayers)
            if #filtered > 0 then
                dprint("use cache candidates (blocked)", #filtered, cacheState)
                return filtered, nil, 0, cacheState
            end
            dprint("blocked + cache exhausted by filters")
        end
        return nil, "api_blocked_no_cache", 0, cacheState
    end

    -- 3) scan (primary sort, fallback sort if needed)
    local primarySort, fallbackSort = getSortOrdersForHop(currentPlayers, targetPlayers)
    local scanned = 0
    local pagesTotal = 0
    local poolAbove, poolBelow = {}, {}
    local scanErr = nil
    local preferHigh = preferHigherPlaying(currentPlayers, targetPlayers)

    local _, _, cacheRec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local scanCursor = (type(cacheRec.scanCursor) == "table") and cacheRec.scanCursor or {}

    local function pushPool(pool, rec, maxN)
        pool[#pool+1] = rec
        if #pool > maxN then
            local worstI, worstS = 1, pool[1].score
            for i = 2, #pool do
                if pool[i].score > worstS then
                    worstS = pool[i].score
                    worstI = i
                end
            end
            table.remove(pool, worstI)
        end
    end

    local function poolCount()
        return #poolAbove + #poolBelow
    end

    local function scanWithSort(sortOrder, maxPages)
        local cursor = scanCursor[sortOrder]
        if cursor == "" then cursor = nil end
        local pagesScanned = 0
        local lastErr = nil

        for page = 1, maxPages do
            local servers, nextCursor, err = fetchServers(placeId, cursor, sortOrder, {
                targetPlayers = targetPlayers,
            })
            if not servers then
                lastErr = err
                break
            end

            pagesScanned += 1
            scanned += #servers

            for _, s in ipairs(servers) do
                local id = tostring(s.id or "")
                local playing = tonumber(s.playing) or 0
                local maxPlayers = tonumber(s.maxPlayers) or 0

                if id ~= ""
                    and id ~= avoidJobId
                    and not visitedSet[id]
                    and not isDead(id)
                    and not isAvoided(id)
                    and not isRecent(id)
                    and isServerJoinable(playing, maxPlayers)
                then
                    local score = popScore(playing, targetPlayers, maxPlayers)
                    local rec = { id=id, playing=playing, maxPlayers=maxPlayers, score=score }
                    local aim = scoreTargetForServer(targetPlayers, maxPlayers)
                    if playing >= aim then
                        pushPool(poolAbove, rec, 14)
                    else
                        pushPool(poolBelow, rec, 14)
                    end
                end
            end

            cursor = nextCursor
            scanCursor[sortOrder] = cursor or ""

            if poolCount() >= SCAN_EARLY_EXIT then
                dprint("scan early exit", sortOrder, "page", pagesScanned, "pool=", poolCount())
                break
            end

            if not nextCursor or nextCursor == "" then
                scanCursor[sortOrder] = ""
                break
            end

            if page < maxPages then
                task.wait(API_PAGE_DELAY)
            end
        end

        return pagesScanned, lastErr
    end

    local p1, errPrimary = scanWithSort(primarySort, getScanPagesForHop(currentPlayers, targetPlayers, false))
    pagesTotal += p1 or 0
    scanErr = errPrimary

    if poolCount() <= 0 then
        local p2, errFallback = scanWithSort(fallbackSort, getScanPagesForHop(currentPlayers, targetPlayers, true))
        pagesTotal += p2 or 0
        if errFallback and not scanErr then
            scanErr = errFallback
        end
        dprint("fallback sort", fallbackSort, "candidates=", poolCount())
    end

    _lastScanPages = pagesTotal
    _lastScanServers = scanned
    cacheSave(placeId, currentPlayers, targetPlayers, diffServers, { scanCursor = scanCursor })

    if poolCount() <= 0 then
        if tostring(scanErr or ""):find("429") or tostring(scanErr or ""):find("code=429") then
            if type(cached) == "table" and #cached > 0 then
                local filtered = filterCandidates(cached, visitedSet, avoidJobId, targetPlayers, currentPlayers)
                if #filtered > 0 then
                    dprint("scan failed 429 -> fallback cache(filtered)", #filtered, cacheState)
                    return filtered, nil, scanned, cacheState
                end
            end
        end
        if scanErr and poolCount() <= 0 then
            return nil, scanErr, scanned, cacheState
        end
    end

    dprint("scan sort primary=", primarySort, "fallback=", fallbackSort,
        "current=", currentPlayers, "target=", targetPlayers,
        "pages=", pagesTotal, "servers=", scanned)

    local candidates = {}
    local function sortPool(pool)
        table.sort(pool, function(a, b)
            if a.score ~= b.score then return a.score < b.score end
            if preferHigh then
                return a.playing > b.playing
            end
            return a.playing < b.playing
        end)
    end
    if #poolAbove > 0 then
        sortPool(poolAbove)
        for _, rec in ipairs(poolAbove) do
            candidates[#candidates+1] = { id=rec.id, playing=rec.playing, maxPlayers=rec.maxPlayers }
        end
    end
    if #poolBelow > 0 then
        sortPool(poolBelow)
        for _, rec in ipairs(poolBelow) do
            candidates[#candidates+1] = { id=rec.id, playing=rec.playing, maxPlayers=rec.maxPlayers }
        end
    end

    if #candidates > 0 then
        cacheSetCandidates(placeId, currentPlayers, targetPlayers, diffServers, candidates)
    end

    dprint("SCAN done scanned=", scanned, "candidates=", #candidates, "target=", targetPlayers)
    return candidates, nil, scanned, cacheState
end

----------------------------------------------------------------
-- Teleport wrappers
----------------------------------------------------------------
local function teleportToJob(placeId, jobId, teleportData)
    placeId = tonumber(placeId) or game.PlaceId
    jobId = tostring(jobId or "")
    if jobId == "" then return false, "jobId_empty" end

    local opts = Instance.new("TeleportOptions")
    if type(teleportData) == "table" then
        pcall(function() opts:SetTeleportData(teleportData) end)
    end
    pcall(function() opts.ServerInstanceId = jobId end)

    local okAsync, errAsync = pcall(function()
        TeleportService:TeleportAsync(placeId, { getLP() }, opts)
    end)
    if okAsync then
        return true, "teleport_async"
    end

    local ok, err = pcall(function()
        TeleportService:TeleportToPlaceInstance(placeId, jobId, getLP(), "", teleportData)
    end)
    if not ok then
        return false, tostring(errAsync or err)
    end
    return true, "teleport_to_place_instance"
end

local function hopToServer(placeId, jobId, fromJobId)
    placeId = tonumber(placeId) or game.PlaceId
    jobId = tostring(jobId or "")
    fromJobId = tostring(fromJobId or game.JobId or "")

    if jobId == "" then return false, "jobId_empty" end

    local td = {
        __gag2_autohop = true,
        fromJobId = fromJobId,
        targetJobId = jobId,
        nonce = tostring(os.time()) .. "_" .. tostring(math.random(100000, 999999)),
    }

    local PR = rawget(_G, "PSReconnect") or rawget((getgenv and getgenv()) or _G, "PSReconnect")
    if type(PR) == "table" and type(PR.HopToServer) == "function" then
        local ok, res = PR.HopToServer(placeId, jobId, td)
        if ok then return true, res end
        dprint("psreconnect hop failed -> fallback", tostring(res))
    end

    return teleportToJob(placeId, jobId, td)
end

----------------------------------------------------------------
-- TeleportData confirm (visited only when really moved)
----------------------------------------------------------------
local _teleDataApplied = false
local function applyTeleportDataOnce()
    if _teleDataApplied then return end
    _teleDataApplied = true

    local data = nil
    pcall(function()
        data = TeleportService:GetLocalPlayerTeleportData()
    end)

    dprint("TPDATA type", typeof(data))
    if type(data) == "table" then
        dprint("TPDATA keys",
            tostring(data.__gag2_autohop),
            tostring(data.fromJobId),
            tostring(data.targetJobId),
            "here="..tostring(game.JobId)
        )
    end

    if type(data) ~= "table" then return end
    if data.__gag2_autohop ~= true then return end

    local targetJob = tostring(data.targetJobId or "")
    local fromJob   = tostring(data.fromJobId or "")
    local hereJob   = tostring(game.JobId or "")

    if targetJob ~= "" and hereJob == targetJob and hereJob ~= fromJob then
        pushVisitedConfirmed(hereJob)
        dprint("teleport confirmed from", fromJob, "to", hereJob)
    else
        dprint("teleportData ignored target", targetJob, "here", hereJob, "from", fromJob)
    end
end

----------------------------------------------------------------
-- Hop Scheduler (no spam)
----------------------------------------------------------------
local _running = false
local _thread  = nil

local _lastHopSuccessAt = 0
local _lastHopTryAt     = 0
local _cooldownHopSec   = 12
local SESSION_FAIL_COOLDOWN = 18

local _lockUntil = 0

local _session = nil
local WATCHDOG_SEC = 12
local _hopThresholdMetAt = 0

local function sessionReset()
    _session = nil
end

local function sessionActive()
    return type(_session) == "table" and _session.active == true
end

local function shouldHop(cfg)
    if not cfg or cfg.enabled ~= true then
        return false, "disabled"
    end

    if rawget(_G, "__GAG2_AUTO_HOP_NOW") == true then
        return true, "manual_flag"
    end

    local currentCount = getLocalPlayerCount()
    local currentMax = clampCurrentPlayers(cfg.currentPlayers)
    local targetMax = clampNum(cfg.targetPlayers, 1, 100, 1)
    local delaySec = clampNum(cfg.teleportDelay, 0, 600, 30)
    local mode = getHopMode(currentMax, targetMax)

    if mode == "leave_crowded" then
        if currentCount < currentMax then
            _hopThresholdMetAt = 0
            _lastStatus = ("Waiting crowded " .. currentCount .. "/" .. currentMax)
            return false, _lastStatus
        end
    elseif mode == "leave_quiet" then
        if currentCount > currentMax then
            _hopThresholdMetAt = 0
            _lastStatus = ("Waiting quieter " .. currentCount .. "/" .. currentMax)
            return false, _lastStatus
        end
    else
        if currentCount < currentMax then
            _hopThresholdMetAt = 0
            _lastStatus = ("Waiting players " .. currentCount .. "/" .. currentMax)
            return false, _lastStatus
        end
    end

    if delaySec <= 0 then
        local why
        if mode == "leave_crowded" then
            why = ("crowd_reached (" .. currentCount .. ">=" .. currentMax .. " -> " .. targetMax .. ")")
        elseif mode == "leave_quiet" then
            why = ("too_quiet (" .. currentCount .. "<=" .. currentMax .. " -> " .. targetMax .. ")")
        else
            why = ("player_threshold (" .. currentCount .. ">=" .. currentMax .. ")")
        end
        return true, why
    end

    if _hopThresholdMetAt <= 0 then
        _hopThresholdMetAt = now()
        _lastStatus = ("Delay " .. math.ceil(delaySec) .. "s before hop")
        return false, "delay_armed"
    end

    local elapsed = now() - _hopThresholdMetAt
    if elapsed < delaySec then
        local left = math.ceil(delaySec - elapsed)
        _lastStatus = ("Delay " .. left .. "s before hop")
        return false, ("delay_wait (" .. left .. "s)")
    end

    if mode == "leave_crowded" then
        return true, ("crowd_delayed (" .. currentCount .. ">=" .. currentMax .. " -> " .. targetMax .. ")")
    elseif mode == "leave_quiet" then
        return true, ("quiet_delayed (" .. currentCount .. "<=" .. currentMax .. " -> " .. targetMax .. ")")
    end
    return true, ("player_threshold_delayed (" .. currentCount .. ">=" .. currentMax .. ")")
end

local function sessionStart(reason)
    local cfg = getCfg()
    if cfg.enabled ~= true then
        _lastStatus = "disabled"
        return false, "disabled"
    end
    local lp = getLP()
    if not lp then
        _lastStatus = "no_localplayer"
        return false, "no_localplayer"
    end
    if sessionActive() then
        return false, "session_already_active"
    end

    local t = now()
    if (t - (_lastHopTryAt or 0)) < _cooldownHopSec then
        _lastStatus = "Hop cooldown"
        return false, "hop_cooldown"
    end

    local placeId   = game.PlaceId
    local fromJobId = tostring(game.JobId)

    local visitedSet = buildSetFromArray(cfg.AH.visited)
    do
        local vfile = cacheGetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers)
        for _, jid in ipairs(vfile) do
            visitedSet[tostring(jid)] = true
        end
    end
    visitedSet[fromJobId] = true

    local function tryBuild()
        return buildCandidates(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, visitedSet, fromJobId)
    end

    local candidates, err = tryBuild()
    if (type(candidates) ~= "table" or #candidates == 0) and #ensureArray(cfg.AH.visited) > 0 then
        cfg.AH.visited = {}
        cacheSetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, cfg.AH.visited)
        cacheSave(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, { ts = 0, scanCursor = {} })
        _persistState()
        visitedSet = { [fromJobId] = true }
        candidates, err = tryBuild()
    end

    if type(candidates) ~= "table" or #candidates == 0 then
        local detail = ("pages=%d srv=%d limit=%d"):format(
            _lastScanPages or 0, _lastScanServers or 0, API_PAGE_LIMIT
        )
        _lastSessionErr = (err or "no_candidates") .. " (" .. detail .. ")"
        _lastStatus = tostring(_lastSessionErr)
        if tostring(err or ""):find("429") then
            apiBackoff(35, "no_candidates_429")
        end
        return false, err or "no_candidates"
    end

    _lastHopTryAt = t
    pushVisitedPreHop(fromJobId)
    _hopThresholdMetAt = 0

    _session = {
        active = true,
        reason = tostring(reason or ""),
        placeId = placeId,
        fromJobId = fromJobId,
        targetPlayers = cfg.targetPlayers,
        diffServers = cfg.diffServers,
        candidates = ensureArray(candidates),
        idx = 1,
        attemptedSet = {},
        inFlight = false,
        currentJobId = "",
        startedAt = now(),
        nextActionAt = now(),
    }

    dprint("sessionStart", "reason=", _session.reason, "candidates=", #_session.candidates)
    _lastSessionErr = nil
    _lastStatus = "teleporting"
    return true, "session_started"
end

local function sessionFinish(ok, why)
    if rawget(_G, "__GAG2_AUTO_HOP_NOW") == true then
        _G.__GAG2_AUTO_HOP_NOW = false
    end

    if ok then
        _lastHopSuccessAt = now()
        _hopThresholdMetAt = 0
    else
        _lockUntil = math.max(_lockUntil, now() + SESSION_FAIL_COOLDOWN)
    end

    dprint("sessionFinish", ok, tostring(why or ""))
    _lastSessionErr = tostring(why or "")
    _lastStatus = ok and "idle" or tostring(why or "failed")
    sessionReset()
end

local function pickNextCandidate()
    if not sessionActive() then return nil end
    local s = _session

    for i = s.idx, #s.candidates do
        local rec = s.candidates[i] or {}
        local jobId = tostring(rec.id or "")
        s.idx = i + 1

        if jobId ~= ""
            and jobId ~= s.fromJobId
            and not s.attemptedSet[jobId]
            and not isDead(jobId)
            and not isAvoided(jobId)
            and not isRecent(jobId)
        then
            s.attemptedSet[jobId] = true
            return rec, jobId
        end
    end

    return nil
end

local function startWatchdog(attemptJobId, fromJobId)
    task.delay(WATCHDOG_SEC, function()
        if not sessionActive() then return end
        local s = _session
        if s.inFlight ~= true then return end
        if s.currentJobId ~= tostring(attemptJobId) then return end

        if tostring(game.JobId) == tostring(fromJobId) then
            dprint("WATCHDOG timeout -> treat as stuck, try next")
            markAvoid(attemptJobId, AVOID_TTL_SEC)
            markRecent(attemptJobId, RECENT_TRIED_TTL)
            s.inFlight = false
            s.currentJobId = ""
            s.nextActionAt = now() + 1.0
        end
    end)
end

----------------------------------------------------------------
-- TeleportInitFailed hook (core anti spam)
----------------------------------------------------------------
local _tpFailConn = nil
local function ensureTeleportFailHook()
    if _tpFailConn then return end

    _tpFailConn = TeleportService.TeleportInitFailed:Connect(function(player, result, errMsg)
        local lp = getLP()
        if lp and player ~= lp then return end
        if not sessionActive() then return end

        local s = _session
        if s.inFlight ~= true then return end

        local msg = tostring(errMsg or "")
        local lm  = low(msg)
        local r   = tostring(result)

        dprint("TeleportInitFailed", r, msg)

        local jobId = tostring(s.currentJobId or "")
        if jobId ~= "" then
            if lm:find("gameended")
                or lm:find("could not find requested game instance")
                or lm:find("requested game instance")
            then
                markDead(jobId, AVOID_TTL_DEAD)
                markAvoid(jobId, AVOID_TTL_DEAD)
                markRecent(jobId, math.max(RECENT_TRIED_TTL, AVOID_TTL_DEAD))
                s.nextActionAt = now() + 0.8

            elseif r:find("IsTeleporting") or lm:find("previous teleport") or lm:find("in processing") then
                _lockUntil = math.max(_lockUntil, now() + 12)
                s.nextActionAt = _lockUntil + 0.2

            else
                markAvoid(jobId, AVOID_TTL_FULL)
                markRecent(jobId, RECENT_TRIED_TTL)
                s.nextActionAt = now() + 0.6
            end
        end

        s.inFlight = false
        s.currentJobId = ""
    end)
end

----------------------------------------------------------------
-- Session Tick (state machine)
----------------------------------------------------------------
local function sessionTick()
    if not sessionActive() then return end
    local s = _session

    if now() < (_lockUntil or 0) then
        return
    end

    if now() < (s.nextActionAt or 0) then
        return
    end

    if s.inFlight == true then
        return
    end

    local rec, jobId = pickNextCandidate()
    if not rec then
        sessionFinish(false, "candidates_exhausted")
        return
    end

    markRecent(jobId, RECENT_TRIED_TTL)

    s.currentJobId = jobId
    s.inFlight = true
    _lastStatus = "teleporting"

    dprint(("Hop -> job=%s playing=%s target=%s from=%s"):format(
        jobId, tostring(rec.playing or "?"), tostring(s.targetPlayers), tostring(s.fromJobId)
    ))

    local ok, res = hopToServer(s.placeId, jobId, s.fromJobId)
    if not ok then
        dprint("teleport call failed (pcall)", tostring(res))
        s.inFlight = false
        s.currentJobId = ""
        markAvoid(jobId, AVOID_TTL_SEC)
        s.nextActionAt = now() + 0.6
        return
    end

    startWatchdog(jobId, s.fromJobId)
end

----------------------------------------------------------------
-- Apply TeleportData once per server join
----------------------------------------------------------------
local function tryApplyTeleportDataAndSyncVisited()
    applyTeleportDataOnce()

    -- also sync visited file -> STATE (so UI consistent)
    local cfg = getCfg()
    local placeId = game.PlaceId

    local vfile = cacheGetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers)
    if #vfile > 0 and type(cfg.AH.visited) == "table" then
        local set = buildSetFromArray(cfg.AH.visited)
        local changed = false
        for _, jid in ipairs(vfile) do
            jid = tostring(jid or "")
            if jid ~= "" and not set[jid] then
                table.insert(cfg.AH.visited, jid)
                set[jid] = true
                changed = true
            end
        end
        if changed then
            _persistState()
        end
    end
end

----------------------------------------------------------------
-- Main loop
----------------------------------------------------------------
local function loop()
    while _running do
        local ok, err = pcall(function()
            tryApplyTeleportDataAndSyncVisited()

            local cfg = getCfg()
            local doHop, why = shouldHop(cfg)

            if doHop and not sessionActive() then
                local okS, rs = sessionStart(why)
                dprint("startHop", okS, rs)
                if not okS then
                    _lastStatus = tostring(rs or "start_failed")
                end
            end

            if not sessionActive() and not doHop then
                -- shouldHop already sets _lastStatus with mode-aware message
            end

            if sessionActive() then
                sessionTick()
            end
        end)

        if not ok then
            dprint("loop error", err)
        end

        task.wait(0.6)
    end
end

----------------------------------------------------------------
-- Public API
----------------------------------------------------------------
function M.IsRunning()
    return _running == true
end

function M.GetStatus()
    local cfg = getCfg()
    local pc = getLocalPlayerCount()
    local delaySec = clampNum(cfg.teleportDelay, 0, 600, HOP_TELEPORT_DELAY_DEFAULT)
    local delayLeft = 0
    if _hopThresholdMetAt > 0 and delaySec > 0 then
        delayLeft = math.max(0, math.ceil(delaySec - (now() - _hopThresholdMetAt)))
    end
    local primarySort, fallbackSort = getSortOrdersForHop(cfg.currentPlayers, cfg.targetPlayers)
    local hopMode = getHopMode(cfg.currentPlayers, cfg.targetPlayers)
    local st = {
        running = (_running == true),
        sessionActive = sessionActive(),
        inFlight = sessionActive() and _session.inFlight == true,
        playerCount = pc,
        currentMax = cfg.currentPlayers,
        targetMax = cfg.targetPlayers,
        hopMode = hopMode,
        sortOrder = primarySort .. ">" .. fallbackSort,
        sortPrimary = primarySort,
        sortFallback = fallbackSort,
        triggerHint = getHopTriggerHint(cfg.currentPlayers, cfg.targetPlayers),
        joinableHint = (cfg.targetPlayers >= GAME_SERVER_MAX)
            and ("< " .. tostring(GAME_SERVER_MAX) .. " player (not full)")
            or nil,
        teleportDelay = delaySec,
        delayRemaining = delayLeft,
        status = _lastStatus or "idle",
        lastError = _lastSessionErr,
        scanPages = _lastScanPages,
        scanServers = _lastScanServers,
        pageLimit = API_PAGE_LIMIT,
        candidateCount = sessionActive() and #ensureArray(_session.candidates) or 0,
    }
    return st
end

function M.SetDebug(on)
    _debug = (on == true)
end

function M.ShouldHop()
    return shouldHop(getCfg())
end

function M.ForceHopNow(reason)
    if sessionActive() then
        return false, "session_active"
    end
    local okS, rs = sessionStart(reason or "manual_force")
    return okS, rs
end

function M.Start()
    if _running then return end
    _running = true
    ensureTeleportFailHook()
    tryApplyTeleportDataAndSyncVisited()
    _thread = task.spawn(loop)
    dprint("Start()")
end

function M.Stop()
    _running = false
    _hopThresholdMetAt = 0
    sessionReset()
    dprint("Stop()")
end

function M.SetCurrentPlayer(n)
    local _, AH = _getState()
    AH.current_player = clampCurrentPlayers(n)
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_CURRENT_PLAYER = AH.current_player
    _G.AUTO_HOP_CURRENT_PLAYER = AH.current_player
    return AH.current_player
end

function M.SetTeleportDelay(sec)
    local _, AH = _getState()
    AH.teleport_delay = clampNum(sec, 0, 600, HOP_TELEPORT_DELAY_DEFAULT)
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_TELEPORT_DELAY = AH.teleport_delay
    _G.AUTO_HOP_TELEPORT_DELAY = AH.teleport_delay
    return AH.teleport_delay
end

M.setTeleportDelay = M.SetTeleportDelay

function M.SetMaxPlayer(n)
    local _, AH = _getState()
    AH.max_player = clampNum(n, 1, 100, 1)
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_MAX_PLAYER = AH.max_player
    _G.AUTO_HOP_MAX_PLAYER = AH.max_player
    return AH.max_player
end

function M.SetEnabled(on)
    on = (on == true)
    local _, AH = _getState()
    AH.enabled = on
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_ENABLED = on
    _G.AUTO_HOP_ENABLED = on
    if on then
        M.Start()
    else
        M.Stop()
    end
    return on
end

function M.SyncFromGlobals()
    local G = (getgenv and getgenv()) or _G
    local enabled = (G.AUTO_HOP_ENABLED == true)
    local curP = tonumber(G.AUTO_HOP_CURRENT_PLAYER)
    local maxP = tonumber(G.AUTO_HOP_MAX_PLAYER)
    local delayP = tonumber(G.AUTO_HOP_TELEPORT_DELAY)
    if curP then
        M.SetCurrentPlayer(curP)
    end
    if maxP then
        M.SetMaxPlayer(maxP)
    end
    if delayP ~= nil then
        M.SetTeleportDelay(delayP)
    end
    M.SetEnabled(enabled)
end

M.syncFromGlobals = M.SyncFromGlobals

----------------------------------------------------------------
-- Export
----------------------------------------------------------------
local G = (getgenv and getgenv()) or _G
G.AutoHopServer = M
G.AutoHopServerModule = M
_G.AutoHopServer = M
_G.AutoHopServerModule = M
G.__GAG2_SYNC_AUTO_HOP = function()
    local applyFn = G.applyAutoHopModule or _G.applyAutoHopModule
    if type(applyFn) == "function" then
        pcall(applyFn)
    else
        M.SyncFromGlobals()
    end
end
_G.__GAG2_SYNC_AUTO_HOP = G.__GAG2_SYNC_AUTO_HOP

return M
 end,         required = false },
    { key = "WeatherPredict",  name = "Weather Predict",  factory = function() -- WeatherPredict.lua — Grow A Garden 2
-- Live cycle + moon/map weather prediction overlay

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local COLOR_BG     = Color3.fromRGB(8, 8, 12)
local COLOR_PANEL  = Color3.fromRGB(14, 14, 20)
local COLOR_YELLOW = Color3.fromRGB(255, 211, 0)
local COLOR_LIVE   = Color3.fromRGB(120, 255, 175)
local COLOR_MUTED  = Color3.fromRGB(175, 178, 190)
local COLOR_MOON   = {
    ["Rainbow Moon"] = Color3.fromRGB(255, 140, 220),
    ["Goldmoon"]     = Color3.fromRGB(255, 210, 90),
    ["Bloodmoon"]    = Color3.fromRGB(255, 95, 95),
}

local running      = false
local overlayGui   = nil
local overlayGen   = 0
local initDone     = false

local cycle        = { phases = {}, cycleSec = 600, nightIdx = 3, nightPhase = nil }
local weatherRows  = {}

local function _enabled()
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" and type(MAIN.misc) == "table"
        and type(MAIN.misc.weather_predict) == "table"
        and MAIN.misc.weather_predict.enabled == true then
        return true
    end
    return G.WEATHER_PREDICT_ENABLED == true or rawget(_G, "WEATHER_PREDICT_ENABLED") == true
end

local function _writeEnabled(on)
    on = (on == true)
    G.WEATHER_PREDICT_ENABLED = on
    _G.WEATHER_PREDICT_ENABLED = on

    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" then
        MAIN.misc = MAIN.misc or {}
        MAIN.misc.weather_predict = MAIN.misc.weather_predict or {}
        MAIN.misc.weather_predict.enabled = on
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end

    local STATE = G.STATE or rawget(_G, "STATE")
    if type(STATE) == "table" then
        STATE.weather_predict = STATE.weather_predict or {}
        STATE.weather_predict.enabled = on
    end
