end

local function fmtSec(sec)
    sec = math.max(0, math.floor(tonumber(sec) or 0))
    local h = math.floor(sec / 3600)
    local m = math.floor((sec % 3600) / 60)
    local s = sec % 60
    if h > 0 then return string.format("%dh%02dm", h, m) end
    if m > 0 then return string.format("%dm%02ds", m, s) end
    return string.format("%ds", s)
end

local function fmtClock(unixTs)
    unixTs = math.floor(tonumber(unixTs) or 0)
    if unixTs <= 0 then return "?" end
    return os.date("%H:%M", unixTs)
end

-- Semua timing ikut server game (bukan os.time() lokal — bisa selisih ~10 menit)
local function now()
    return workspace:GetServerTimeNow()
end

local function serverNow()
    return now()
end

local function activePhase()
    return workspace:GetAttribute("ActivePhase")
end

local function activeWeather()
    return workspace:GetAttribute("ActiveWeather")
end

local function loadModule(name)
    local SM = ReplicatedStorage:FindFirstChild("SharedModules")
    if not SM then return nil end
    local ok, mod = pcall(function() return require(SM:WaitForChild(name, 5)) end)
    if not ok then return nil end
    return mod
end

local function buildPhases(tcd)
    if not tcd or type(tcd.Data) ~= "table" then return nil end
    local phases = {}
    for phaseName, entry in pairs(tcd.Data) do
        if type(entry) == "table" then
            phases[#phases + 1] = {
                name = phaseName,
                duration = entry.Lasts or 0,
                order = entry.StartOrder or 99,
                weathers = entry.Weathers or {},
            }
        end
    end
    table.sort(phases, function(a, b) return a.order < b.order end)
    local cycleSec = 0
    for _, p in ipairs(phases) do cycleSec = cycleSec + p.duration end
    local nightIdx, nightPhase = nil, nil
    for i, p in ipairs(phases) do
        if p.name == "Night" then nightIdx, nightPhase = i, p break end
    end
    return { phases = phases, cycleSec = cycleSec, nightIdx = nightIdx, nightPhase = nightPhase }
end

local function rollPhaseWeather(phase, rng)
    if not phase or not phase.weathers then return nil end
    local total = 0
    for _, w in pairs(phase.weathers) do
        if type(w) == "table" and w.Chance then total = total + w.Chance end
    end
    if total <= 0 then return nil end
    local roll = rng:NextNumber() * total
    local acc = 0
    for wName, w in pairs(phase.weathers) do
        if type(w) == "table" and w.Chance then
            acc = acc + w.Chance
            if roll <= acc then return wName end
        end
    end
    for wName in pairs(phase.weathers) do return wName end
    return nil
end

local function getPhaseByName(name)
    for i, p in ipairs(cycle.phases) do
        if p.name == name then return p, i end
    end
    return nil, nil
end

local function getCycleState()
    local phaseName = activePhase()
    local phaseEnd = workspace:GetAttribute("PhaseDuration")
    if not phaseName or type(phaseEnd) ~= "number" then return nil end

    local remaining = math.max(0, phaseEnd - serverNow())
    local phase, phaseIdx = getPhaseByName(phaseName)
    if not phase then return nil end

    return {
        phaseIndex = phaseIdx,
        phaseName = phaseName,
        phase = phase,
        weather = activeWeather(),
        remaining = remaining,
        elapsed = math.max(0, phase.duration - remaining),
        phaseEnd = phaseEnd,
    }
end

local function cycleIndex()
    local st = getCycleState()
    if not st or not cycle.phases or #cycle.phases == 0 then
        return math.floor(serverNow() / math.max(cycle.cycleSec, 1))
    end

    local elapsed = 0
    for i, p in ipairs(cycle.phases) do
        if i < st.phaseIndex then
            elapsed = elapsed + p.duration
        elseif i == st.phaseIndex then
            elapsed = elapsed + math.max(0, p.duration - st.remaining)
            break
        end
    end

    local cycleStart = serverNow() - elapsed
    return math.floor(cycleStart / math.max(cycle.cycleSec, 1))
end

local function predictNightWeather(cycleIdx)
    if not cycle.nightPhase or not cycle.nightIdx then return nil end
    return rollPhaseWeather(cycle.nightPhase, Random.new(cycleIdx * 1000 + cycle.nightIdx))
end

local function phaseRemaining()
    local st = getCycleState()
    return st and st.remaining or nil
end

local function dur(name, fallback)
    local p = getPhaseByName(name)
    return p and p.duration or fallback
end

local function secondsUntilNightCycle(offset)
    offset = offset or 0
    local st = getCycleState()
    if not st then return 0 end

    local rem = st.remaining
    local cur = st.phaseName
    local nightIdx = cycle.nightIdx

    if offset == 0 then
        if cur == "Night" then return 0 end
        if cur == "Sunset" then return rem end
        if cur == "Day" then return rem + dur("Sunset", 30) end
        return rem
    end

    local toCycleEnd = rem
    for i = st.phaseIndex + 1, #cycle.phases do
        toCycleEnd = toCycleEnd + cycle.phases[i].duration
    end

    local beforeNight = 0
    if nightIdx and nightIdx > 1 then
        for i = 1, nightIdx - 1 do
            beforeNight = beforeNight + (cycle.phases[i].duration or 0)
        end
    else
        beforeNight = dur("Day", 450) + dur("Sunset", 30)
    end

    return toCycleEnd + (offset - 1) * cycle.cycleSec + beforeNight
end

local function findNextMoon(moonName, maxCycles)
    maxCycles = maxCycles or 60
    local now = serverNow()
    local ci = cycleIndex()
    local cur = activePhase()
    local weather = activeWeather()

    for offset = 0, maxCycles do
        if predictNightWeather(ci + offset) ~= moonName then
            -- skip
        elseif offset == 0 and cur == "Night" then
            if weather == moonName then
                return { inSec = 0, cycleIdx = ci, live = true }
            end
        else
            local sec = secondsUntilNightCycle(offset)
            return { inSec = sec, cycleIdx = ci + offset, at = now + sec }
        end
    end
    return nil
end

local function readMapWeather(name)
    local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
    if not WeatherValues then
        return { playing = false, endsIn = nil, endsAt = nil }
    end
    local playing = WeatherValues:GetAttribute(name .. "_Playing")
    local endTime = WeatherValues:GetAttribute(name .. "_EndTime")
    local startTime = WeatherValues:GetAttribute(name .. "_StartTime")
    local duration = WeatherValues:GetAttribute(name .. "_Duration")
    local now = serverNow()

    local endsIn = nil
    if playing == true then
        if type(startTime) == "number" and startTime > 1e9
            and type(duration) == "number" and duration > 0 then
            endsIn = math.max(0, (startTime + duration) - now)
        elseif type(endTime) == "number" and endTime > 1e9 then
            endsIn = math.max(0, endTime - now)
        elseif type(endTime) == "number" and endTime > 0 and endTime < 1e6 then
            endsIn = math.max(0, endTime)
        end
    end

    return {
        playing = playing == true,
        endsIn = endsIn,
        endsAt = (endsIn ~= nil) and fmtClock(now + endsIn) or nil,
    }
end

local function loadWeatherEventRows(wd)
    local rows = {}
    if wd and type(wd.Data) == "table" and wd.Data[1] then
        for _, entry in ipairs(wd.Data) do
            if type(entry) == "table" then rows[#rows + 1] = entry end
        end
    end
    return rows
end

local function ensureInit()
    if initDone then return true end

    local built = buildPhases(loadModule("TimeCycleData"))
    if built then cycle = built end
    weatherRows = loadWeatherEventRows(loadModule("WeatherData"))
    initDone = true
    return true
end

function M.GetLines()
    ensureInit()
    local lines = {}
    local st = getCycleState()
    local rem = st and st.remaining or phaseRemaining()
    local cur = activePhase()
    local weather = activeWeather()

    if cur then
        lines[#lines + 1] = {
            text = string.format("%s · %s", cur, weather or "?"),
            sub = fmtSec(rem or 0) .. " left",
            live = true,
            kind = "cycle",
        }
    else
        lines[#lines + 1] = {
            text = "Waiting ActivePhase...",
            sub = "join server cycle",
            live = false,
            kind = "info",
        }
    end

    local nextOff = (cur == "Night") and 1 or 0
    local nightIn = secondsUntilNightCycle(nextOff)
    local nextMoon = predictNightWeather(cycleIndex() + nextOff)
    lines[#lines + 1] = {
        text = "Next Night",
        sub = string.format("%s → %s", fmtSec(nightIn), nextMoon or "?"),
        live = false,
        kind = "night",
    }

    for _, moon in ipairs({ "Rainbow Moon", "Goldmoon", "Bloodmoon" }) do
        local hit = findNextMoon(moon, 60)
        if hit then
            if hit.live then
                lines[#lines + 1] = {
                    text = moon,
                    sub = "LIVE NOW",
                    live = true,
                    kind = "moon",
                    moon = moon,
                }
            else
                lines[#lines + 1] = {
                    text = moon,
                    sub = string.format("%s · ~%s", fmtSec(hit.inSec), fmtClock(hit.at)),
                    live = false,
                    kind = "moon",
                    moon = moon,
                }
            end
        end
    end

    lines[#lines + 1] = {
        text = string.format("Cycle %s · idx %d", fmtSec(cycle.cycleSec), cycleIndex()),
        sub = "Tonight ~" .. tostring(predictNightWeather(cycleIndex()) or "?"),
        live = false,
        kind = "meta",
    }

    lines[#lines + 1] = { text = "Map Weather", sub = "", live = false, kind = "divider" }

    for _, entry in ipairs(weatherRows) do
        local n = entry.Name
        if type(n) == "string" then
            local row = readMapWeather(n)
            if row.playing then
                lines[#lines + 1] = {
                    text = n,
                    sub = string.format("LIVE %s · %s", row.endsAt or "?", fmtSec(row.endsIn)),
                    live = true,
                    kind = "map",
                }
            else
                lines[#lines + 1] = {
                    text = n,
                    sub = type(entry.Occurrence) == "number" and ("Occ " .. entry.Occurrence) or "idle",
                    live = false,
                    kind = "map",
                }
            end
        end
    end

    return lines
end

function M.GetSnapshot()
    local st = getCycleState()
    return {
        running = running,
        phase = st and st.phaseName or activePhase(),
        weather = st and st.weather or activeWeather(),
        remaining = st and st.remaining or phaseRemaining(),
        lines = M.GetLines(),
    }
end

local function destroyOverlay()
    overlayGen += 1

    local pg = LP and LP:FindFirstChild("PlayerGui")
    if pg then
        local old = pg:FindFirstChild("GAG2_WX_PRED")
        if old then
            pcall(function() old:Destroy() end)
        end
    end

    if overlayGui then
        pcall(function() overlayGui:Destroy() end)
        overlayGui = nil
    end
end

local function lineColor(line)
    if line.live then return COLOR_LIVE end
    if line.kind == "moon" and line.moon and COLOR_MOON[line.moon] then
        return COLOR_MOON[line.moon]
    end
    if line.kind == "divider" then return COLOR_YELLOW end
    return COLOR_MUTED
end

local function createOverlay()
    local myGen = overlayGen

    local pg = LP:FindFirstChild("PlayerGui") or LP:WaitForChild("PlayerGui", 5)
    if not pg then return false end

    local gui = Instance.new("ScreenGui")
    gui.Name = "GAG2_WX_PRED"
    gui.ResetOnSpawn = false
    gui.IgnoreGuiInset = true
    gui.Enabled = true
    gui.DisplayOrder = 10050
    gui.Parent = pg
    overlayGui = gui

    local frame = Instance.new("Frame")
    frame.Name = "Panel"
    frame.Size = UDim2.fromOffset(340, 200)
    frame.Position = UDim2.new(0, 14, 0.24, 0)
    frame.BackgroundColor3 = COLOR_BG
    frame.BackgroundTransparency = 0.08
    frame.BorderSizePixel = 0
    frame.Parent = gui
    Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 10)

    local stroke = Instance.new("UIStroke")
    stroke.Color = COLOR_YELLOW
    stroke.Thickness = 1.2
    stroke.Transparency = 0.35
    stroke.Parent = frame

    local accent = Instance.new("Frame")
    accent.Size = UDim2.new(1, 0, 0, 3)
    accent.BackgroundColor3 = COLOR_YELLOW
    accent.BorderSizePixel = 0
    accent.Parent = frame
    Instance.new("UICorner", accent).CornerRadius = UDim.new(0, 10)

    local header = Instance.new("TextLabel")
    header.Size = UDim2.new(1, -16, 0, 22)
    header.Position = UDim2.fromOffset(10, 8)
    header.BackgroundTransparency = 1
    header.Font = Enum.Font.GothamBold
    header.TextSize = 13
    header.TextXAlignment = Enum.TextXAlignment.Left
    header.TextColor3 = COLOR_YELLOW
    header.Text = "WEATHER PREDICT"
    header.Parent = frame

    local badge = Instance.new("TextLabel")
    badge.Size = UDim2.fromOffset(52, 16)
    badge.Position = UDim2.new(1, -60, 0, 10)
    badge.BackgroundColor3 = Color3.fromRGB(25, 55, 35)
    badge.BackgroundTransparency = 0.2
    badge.Font = Enum.Font.GothamBold
    badge.TextSize = 9
    badge.Text = "LIVE"
    badge.TextColor3 = COLOR_LIVE
    badge.Parent = frame
    Instance.new("UICorner", badge).CornerRadius = UDim.new(0, 6)

    local list = Instance.new("ScrollingFrame")
    list.Name = "List"
    list.Size = UDim2.new(1, -12, 1, -38)
    list.Position = UDim2.fromOffset(6, 34)
    list.BackgroundTransparency = 1
    list.BorderSizePixel = 0
    list.ScrollBarThickness = 3
    list.ScrollBarImageColor3 = COLOR_YELLOW
    list.CanvasSize = UDim2.new()
    list.AutomaticCanvasSize = Enum.AutomaticSize.Y
    list.Parent = frame

    local layout = Instance.new("UIListLayout")
    layout.Padding = UDim.new(0, 4)
    layout.SortOrder = Enum.SortOrder.LayoutOrder
    layout.Parent = list

    local rows = {}

    local function render()
        if myGen ~= overlayGen or not overlayGui or overlayGui ~= gui or not gui.Parent then
            return
        end
        local lines = M.GetLines()
        local yPad = 0

        for i, line in ipairs(lines) do
            local row = rows[i]
            if not row then
                row = Instance.new("Frame")
                row.BackgroundColor3 = COLOR_PANEL
                row.BackgroundTransparency = line.kind == "divider" and 1 or 0.35
                row.BorderSizePixel = 0
                row.Size = UDim2.new(1, -4, 0, line.kind == "divider" and 18 or 34)
                row.Parent = list
                Instance.new("UICorner", row).CornerRadius = UDim.new(0, 6)

                local title = Instance.new("TextLabel")
                title.Name = "Title"
                title.BackgroundTransparency = 1
                title.Position = UDim2.fromOffset(8, 4)
                title.Size = UDim2.new(1, -12, 0, 14)
                title.Font = Enum.Font.GothamMedium
                title.TextSize = 11
                title.TextXAlignment = Enum.TextXAlignment.Left
                title.Parent = row

                local sub = Instance.new("TextLabel")
                sub.Name = "Sub"
                sub.BackgroundTransparency = 1
                sub.Position = UDim2.fromOffset(8, 18)
                sub.Size = UDim2.new(1, -12, 0, 12)
                sub.Font = Enum.Font.Gotham
                sub.TextSize = 10
                sub.TextXAlignment = Enum.TextXAlignment.Left
                sub.TextColor3 = COLOR_MUTED
                sub.Parent = row

                rows[i] = { frame = row, title = title, sub = sub }
            end

            local r = rows[i]
            if not r or not r.title or not r.title.Parent then
                -- overlay destroyed mid-render
            else
            r.frame.Visible = true
            r.frame.LayoutOrder = i
            r.frame.Size = UDim2.new(1, -4, 0, line.kind == "divider" and 18 or 34)

            local col = lineColor(line)
            r.title.Text = line.text or ""
            r.title.TextColor3 = col
            r.sub.Text = line.sub or ""
            r.sub.Visible = (line.sub or "") ~= ""
            if line.kind == "divider" then
                r.title.Text = "— " .. (line.text or "") .. " —"
                r.sub.Visible = false
            end
            yPad += r.frame.AbsoluteSize.Y + 4
            end
        end

        for i = #lines + 1, #rows do
            if rows[i] then rows[i].frame.Visible = false end
        end
    end

    render()

    task.spawn(function()
        while myGen == overlayGen and overlayGui == gui and gui.Parent do
            task.wait(1)
            if myGen ~= overlayGen or overlayGui ~= gui or not gui.Parent then
                break
            end
            render()
        end
    end)

    return true
end

function M.Start()
    ensureInit()
    running = true
    _G.GAG2_WEATHER_STOP = false
    destroyOverlay()

    local ok = createOverlay()
    if not ok or not overlayGui or not overlayGui.Parent then
        running = false
        return false
    end

    G.GAG2_WEATHER = {
        cycle = cycle,
        state = getCycleState,
        predictNight = predictNightWeather,
        nextMoon = findNextMoon,
        nextNightIn = function(offset) return secondsUntilNightCycle(offset or 0) end,
        readMap = readMapWeather,
        GetLines = M.GetLines,
    }
    _G.GAG2_WEATHER = G.GAG2_WEATHER
    return true
end

M.start = M.Start

function M.Stop()
    running = false
    _G.GAG2_WEATHER_STOP = true
    destroyOverlay()
end

M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.SetEnabled(on)
    on = (on == true)
    _writeEnabled(on)
    if on then
        return M.Start()
    end
    M.Stop()
    return on
end

function M.EnsureRunning()
    if _enabled() then
        M.Start()
    else
        M.Stop()
    end
end

M.ensureRunning = M.EnsureRunning

function M.SyncFromGlobals()
    M.EnsureRunning()
end

M.syncFromGlobals = M.SyncFromGlobals

G.__GAG2_SYNC_WEATHER_PREDICT = function()
    M.SyncFromGlobals()
end
_G.__GAG2_SYNC_WEATHER_PREDICT = G.__GAG2_SYNC_WEATHER_PREDICT

return M
 end,        required = false },
    { key = "ReduceFPS",       name = "Reduce FPS",       factory = function() -- ReduceFPS.lua — Grow A Garden 2
-- Event-driven: hide garden lain + plant/buah sendiri. Tanpa sweep berat tiap detik.

local Players           = game:GetService("Players")
local CollectionService = game:GetService("CollectionService")
local Lighting          = game:GetService("Lighting")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local HARVEST_TAG      = "HarvestPrompt"
local MARK_ATTR        = "_GAG2FPS"
local PARKED_ATTR      = "_GAG2FPS_PARK"
local PLOT_CACHE_SEC   = 5.0
local BATCH_YIELD_EVERY = 250
local VOID_POS         = Vector3.new(0, -8000, 0)

local running      = false
local conns        = {}
local plotConns    = {}
local cachedPlot   = nil
local cachedPlotAt = 0
local renderApplied = false
local statsCache = {
    plot = nil,
    otherPlots = 0,
    harvestPrompts = 0,
}

local function _cfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local perf = MAIN and MAIN.misc and MAIN.misc.perf
    perf = type(perf) == "table" and perf or {}

    local enabled = (G.REDUCE_FPS_ENABLED == true)
        or (rawget(_G, "REDUCE_FPS_ENABLED") == true)
        or (perf.enabled == true)

    local hideOthers = perf.hide_others
    if hideOthers == nil then hideOthers = G.REDUCE_FPS_HIDE_OTHERS end
    if hideOthers == nil then hideOthers = rawget(_G, "REDUCE_FPS_HIDE_OTHERS") end
    if hideOthers == nil then
        hideOthers = perf.delete_others
        if hideOthers == nil then hideOthers = G.REDUCE_FPS_DELETE_OTHERS end
        if hideOthers == nil then hideOthers = rawget(_G, "REDUCE_FPS_DELETE_OTHERS") end
    end
    if hideOthers == nil then hideOthers = true end

    local hideOwn = perf.hide_own
    if hideOwn == nil then hideOwn = G.REDUCE_FPS_HIDE_OWN end
    if hideOwn == nil then hideOwn = rawget(_G, "REDUCE_FPS_HIDE_OWN") end
    if hideOwn == nil then hideOwn = true end

    local render = perf.render
    if render == nil then render = G.REDUCE_FPS_RENDER end
    if render == nil then render = rawget(_G, "REDUCE_FPS_RENDER") end
    if render == nil then render = true end

    return {
        enabled = enabled,
        hideOthers = hideOthers ~= false,
        hideOwn = hideOwn ~= false,
        render = render ~= false,
    }
end

local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or v == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("OwnerUserId")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local byId = gardens:FindFirstChild("Plot" .. tostring(plotId))
        if byId then
            cachedPlot = byId
            cachedPlotAt = now
            statsCache.plot = byId.Name
            return byId
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            statsCache.plot = plot.Name
            return plot
        end
    end

    local byName = gardens:FindFirstChild("Plot" .. LP.Name)
    cachedPlot = byName
    cachedPlotAt = now
    statsCache.plot = byName and byName.Name or nil
    return byName
end

local function _countOtherPlots()
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        statsCache.otherPlots = 0
        return 0
    end
    local mine = getPlayerPlot()
    local n = 0
    for _, p in ipairs(gardens:GetChildren()) do
        if p ~= mine and not _plotOwnedByLocal(p) then
            n += 1
        end
    end
    statsCache.otherPlots = n
    return n
end

local function _isHarvestPrompt(inst)
    return inst:IsA("ProximityPrompt") and CollectionService:HasTag(inst, HARVEST_TAG)
end

local function _isEssentialPart(inst)
    if not inst or not inst:IsA("BasePart") then return false end
    local n = inst.Name:lower()
    if n == "spawn" or n == "spawnlocation" or n == "spawnpoint" or n == "can_plant" then
        return true
    end
    if CollectionService:HasTag(inst, "PlantArea") then return true end
    return false
end

local function _mustKeepOwn(inst)
    if not inst then return true end
    if _isHarvestPrompt(inst) then return true end
    if inst:IsA("ProximityPrompt") then return true end
    if _isEssentialPart(inst) then return true end
    return false
end

local function _alreadyMarked(inst)
    if not inst then return true end
    local ok, v = pcall(function()
        return inst:GetAttribute(MARK_ATTR)
    end)
    return ok and v == true
end

local function _hideVisual(inst, keepFn)
    if not inst or not inst.Parent then return false end
    if keepFn and keepFn(inst) then return false end
    if _alreadyMarked(inst) then return false end

    pcall(function() inst:SetAttribute(MARK_ATTR, true) end)

    if inst:IsA("BasePart") then
        pcall(function()
            inst.Transparency = 1
            inst.LocalTransparencyModifier = 1
            inst.CastShadow = false
            inst.CanCollide = false
            inst.CanTouch = false
            inst.CanQuery = false
            inst.Material = Enum.Material.SmoothPlastic
        end)
        return true
    end

    if inst:IsA("Decal") or inst:IsA("Texture") then
        pcall(function() inst.Transparency = 1 end)
        return true
    end

    if inst:IsA("ParticleEmitter") or inst:IsA("Trail") or inst:IsA("Beam") or inst:IsA("Light") then
        pcall(function() inst.Enabled = false end)
        return true
    end

    if inst:IsA("Highlight") then
        pcall(function()
            inst.Enabled = false
            inst.FillTransparency = 1
            inst.OutlineTransparency = 1
        end)
        return true
    end

    if inst:IsA("BillboardGui") or inst:IsA("SurfaceGui") then
        pcall(function() inst.Enabled = false end)
        return true
    end

    return false
end

local function _walkDescendants(root, keepFn, onDone)
    if not root or not root.Parent then
        if onDone then onDone(0) end
        return
    end

    task.spawn(function()
        local changed = 0
        local batch = 0
        local list = root:GetDescendants()
        for i = 1, #list do
            if not running then break end
            if _hideVisual(list[i], keepFn) then
                changed += 1
            end
            batch += 1
            if batch >= BATCH_YIELD_EVERY then
                batch = 0
                task.wait()
            end
        end
        if running then
            _hideVisual(root, keepFn)
        end
        if onDone then onDone(changed) end
    end)
end

local function _plotParked(plot)
    if not plot then return true end
    local ok, v = pcall(function()
        return plot:GetAttribute(PARKED_ATTR)
    end)
    return ok and v == true
end

local function _parkOtherPlot(plot)
    if not plot or _plotParked(plot) then return end
    pcall(function() plot:SetAttribute(PARKED_ATTR, true) end)

    _walkDescendants(plot, nil, function()
        pcall(function()
            if plot:IsA("Model") then
                plot:PivotTo(CFrame.new(VOID_POS))
            elseif plot:IsA("BasePart") then
                plot.CFrame = CFrame.new(VOID_POS)
            end
        end)
    end)
end

local function _hideOtherGardens()
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return 0 end

    local myPlot = getPlayerPlot()
    local n = 0
    for _, plot in ipairs(gardens:GetChildren()) do
        if plot ~= myPlot and not _plotOwnedByLocal(plot) then
            _parkOtherPlot(plot)
            n += 1
        end
    end
    statsCache.otherPlots = n
    return n
end

local function _hideOwnGarden(plot)
    if not plot or not plot.Parent then return end
    _walkDescendants(plot, _mustKeepOwn)
end

local function _applyRenderingOnce()
    if renderApplied then return end
    renderApplied = true

    pcall(function()
        Lighting.GlobalShadows = false
        Lighting.FogEnd = 9e9
        local atm = Lighting:FindFirstChildOfClass("Atmosphere")
        if atm then atm.Density = 0 end
    end)

    pcall(function()
        local r = settings().Rendering
        r.QualityLevel = Enum.QualityLevel.Level01
        r.MeshPartDetailLevel = Enum.MeshPartDetailLevel.Level01
    end)

    pcall(function()
        local gs = UserSettings():GetService("UserGameSettings")
        gs.SavedQualityLevel = Enum.SavedQualitySetting.QualityLevel1
    end)
end

local function _refreshHarvestCount(plot)
    if not plot then
        statsCache.harvestPrompts = 0
        return
    end
    local n = 0
    for _, d in ipairs(plot:GetDescendants()) do
        if _isHarvestPrompt(d) and not d:GetAttribute("Collected") then
            n += 1
        end
    end
    statsCache.harvestPrompts = n
end

function M.RunOnce()
    local cfg = _cfg()
    local stats = { hiddenOthers = 0, hiddenOwn = 0 }

    if cfg.render then _applyRenderingOnce() end
    if cfg.hideOthers then stats.hiddenOthers = _hideOtherGardens() end
    if cfg.hideOwn then
        local plot = getPlayerPlot()
        if plot then
            _hideOwnGarden(plot)
            _refreshHarvestCount(plot)
        end
    end
    return stats
end

local function _disconnectPlotConns()
    for _, c in ipairs(plotConns) do
        pcall(function() c:Disconnect() end)
    end
    table.clear(plotConns)
end

local function _disconnectAll()
    for _, c in ipairs(conns) do
        pcall(function() c:Disconnect() end)
    end
    table.clear(conns)
    _disconnectPlotConns()
end

local function _bindGardens(gardens)
    if not gardens then return end

    table.insert(conns, gardens.ChildAdded:Connect(function(child)
        task.defer(function()
            if not running or not _cfg().hideOthers then return end
            if child ~= getPlayerPlot() and not _plotOwnedByLocal(child) then
                _parkOtherPlot(child)
                _countOtherPlots()
            end
        end)
    end))
end

local function _bindOwnPlot(plot)
    _disconnectPlotConns()
    if not plot then return end

    table.insert(plotConns, plot.DescendantAdded:Connect(function(desc)
        if not running or not _cfg().hideOwn then return end
        task.defer(function()
            _hideVisual(desc, _mustKeepOwn)
            if _isHarvestPrompt(desc) and not desc:GetAttribute("Collected") then
                statsCache.harvestPrompts = (statsCache.harvestPrompts or 0) + 1
            end
        end)
    end))

    table.insert(plotConns, plot.DescendantRemoving:Connect(function(desc)
        if _isHarvestPrompt(desc) and not desc:GetAttribute("Collected") then
            statsCache.harvestPrompts = math.max(0, (statsCache.harvestPrompts or 0) - 1)
        end
    end))
end

function M.SetEnabled(on)
    on = (on == true)
    G.REDUCE_FPS_ENABLED = on
    _G.REDUCE_FPS_ENABLED = on
    if on then M.Start() else M.Stop() end
end

function M.IsEnabled()
    return running
end

function M.Start()
    if running then
        return true
    end

    running = true

    G.REDUCE_FPS_ENABLED = true
    _G.REDUCE_FPS_ENABLED = true

    _disconnectAll()

    local cfg = _cfg()
    if cfg.render then _applyRenderingOnce() end
    if cfg.hideOthers then _hideOtherGardens() end
    if cfg.hideOwn then
        local plot = getPlayerPlot()
        if plot then
            _hideOwnGarden(plot)
            task.defer(function()
                if running then _refreshHarvestCount(plot) end
            end)
        end
    end

    local gardens = workspace:FindFirstChild("Gardens") or workspace:WaitForChild("Gardens", 15)
    if gardens then _bindGardens(gardens) end
    _bindOwnPlot(getPlayerPlot())

    table.insert(conns, LP:GetAttributeChangedSignal("PlotId"):Connect(function()
        cachedPlot = nil
        cachedPlotAt = 0
        if not running then return end
        task.defer(function()
            local cfgNow = _cfg()
            local plot = getPlayerPlot()
            if cfgNow.hideOthers then _hideOtherGardens() end
            if cfgNow.hideOwn and plot then
                _hideOwnGarden(plot)
                _refreshHarvestCount(plot)
            end
            _bindOwnPlot(plot)
        end)
    end))

    return true
end

function M.Stop()
    running = false
    _disconnectAll()
    renderApplied = false
    G.REDUCE_FPS_ENABLED = false
    _G.REDUCE_FPS_ENABLED = false
end

function M.SyncFromGlobals()
    local cfg = _cfg()
    G.REDUCE_FPS_ENABLED = cfg.enabled
    _G.REDUCE_FPS_ENABLED = cfg.enabled
    G.REDUCE_FPS_HIDE_OTHERS = cfg.hideOthers
    _G.REDUCE_FPS_HIDE_OTHERS = cfg.hideOthers
    G.REDUCE_FPS_HIDE_OWN = cfg.hideOwn
    _G.REDUCE_FPS_HIDE_OWN = cfg.hideOwn
    G.REDUCE_FPS_RENDER = cfg.render
    _G.REDUCE_FPS_RENDER = cfg.render

    if cfg.enabled then
        M.Start()
    else
        M.Stop()
    end
    return cfg
end

function M.GetStats()
    local plot = getPlayerPlot()
    return {
        enabled = running,
        plot = plot and plot.Name or statsCache.plot,
        otherPlots = statsCache.otherPlots,
        harvestPrompts = statsCache.harvestPrompts,
        voidPos = VOID_POS,
    }
end

G.ReduceFPS = M
_G.ReduceFPS = M

return M
 end,             required = false },
    { key = "PetFinder",       name = "Pet Finder",       factory = function() -- PetFinder.lua — Grow A Garden 2
-- Scan wild pet lokal → sync ke DB → browse global list → hop server

local M = {}

local Players         = game:GetService("Players")
local HttpService     = game:GetService("HttpService")
local TeleportService = game:GetService("TeleportService")
local RS              = game:GetService("ReplicatedStorage")
local LP              = Players.LocalPlayer

local DEFAULT_API_BASE = "https://golas.co.id/grow_a_garden2"
local DEFAULT_API_KEY  = "8jdfsklldks09382304k"  -- set di sini saja, tidak disimpan ke save file

local SYNC_SCAN_INTERVAL_SEC  = 1
local HOP_FETCH_INTERVAL_SEC  = 1
local LIST_REFRESH_INTERVAL_SEC = 8
local UI_TICK_INTERVAL_SEC    = 1
local LIST_LIMIT          = 50
local LIST_FETCH_LIMIT    = 50
local AUTO_HOP_COOLDOWN_SEC = 20
local SYNC_MIN_RARITY     = "Rare"
local AVOID_JOB_TTL_FULL  = 30
local AVOID_JOB_TTL_DEAD  = 30
local AVOID_JOB_TTL_BUSY  = 30

-- Fallback rank jika PetListView belum load (min Rare = 3)
local FALLBACK_RARITY_RANK = {
    common = 1,
    uncommon = 2,
    rare = 3,
    epic = 4,
    legendary = 5,
    mythic = 6,
    divine = 7,
    secret = 8,
}

local COLOR_ACCENT  = Color3.fromRGB(255, 211, 0)
local COLOR_CARD    = Color3.fromRGB(18, 18, 22)
local COLOR_CARD_HI = Color3.fromRGB(26, 26, 32)
local COLOR_MUTED   = Color3.fromRGB(145, 148, 162)
local COLOR_TEXT    = Color3.fromRGB(235, 237, 245)

local _cfg = {
    filter_rarities   = {},
    auto_refresh_list = true,
    auto_hop          = false,
    target_pets       = {},
}

local _lastScan = nil
local _lastListRaw = {}
local _lastList = {}
local _lastSyncOk = nil
local _lastSyncMsg = ""
local _lastListErr = ""
local _autoSyncToken = 0
local _autoRefreshToken = 0
local _autoHopFetchToken = 0
local _lastSyncFingerprint = ""
local _uiRefreshers = {}
local _hopInFlight = false
local _lastAutoHopAt = 0
local _lastAutoHopJobId = ""
local _pendingHopJobId = ""
local _avoidJobs = {}
local _tpFailConn = nil

----------------------------------------------------------------
-- Utils
----------------------------------------------------------------
local function getG()
    return (getgenv and getgenv()) or _G
end

local function cleanSelectedMap(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true and tostring(k) ~= "" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function mapToArray(map)
    local arr = {}
    if type(map) ~= "table" then return arr end
    for k, v in pairs(map) do
        if v == true then
            arr[#arr + 1] = tostring(k)
        end
    end
    table.sort(arr)
    return arr
end

local function arrayToMap(arr)
    local out = {}
    if type(arr) ~= "table" then return out end
    for _, v in ipairs(arr) do
        if type(v) == "string" and v ~= "" then
            out[v] = true
        end
    end
    return out
end

local function shortSpawnId(uuid)
    uuid = tostring(uuid or ""):gsub("%s+", "")
    if uuid == "" then return "------" end
    if #uuid >= 6 then
        return uuid:sub(-6):upper()
    end
    return uuid:upper()
end

local function getPetListView()
    local G = getG()
    return G.PetListView or _G.PetListView
end

local function collectSeenRarities()
    local seen = {}
    local out = {}

    local function add(r)
        r = tostring(r or "")
        if r == "" or seen[r] then return end
        seen[r] = true
        out[#out + 1] = r
    end

    for _, row in ipairs(_lastListRaw or {}) do
        add(row.rarity)
    end

    if type(_lastScan) == "table" and type(_lastScan.pets) == "table" then
        for _, pet in ipairs(_lastScan.pets) do
            add(pet.rarity)
        end
    end

    return out
end

local function getRarityItems()
    local extra = collectSeenRarities()
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.buildRarityItems) == "function" then
        return PLV.buildRarityItems(extra)
    end

    table.sort(extra)
    local out = {}
    for _, rarity in ipairs(extra) do
        out[#out + 1] = { key = rarity, name = rarity }
    end
    return out
end

local function normalizeRarityKey(name)
    return tostring(name or ""):lower():gsub("[%s_%-]+", "")
end

local function getRarityRank(name)
    name = tostring(name or "")
    if name == "" then return 0 end

    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.getRarityRank) == "function" then
        local r = PLV.getRarityRank(name)
        if type(r) == "number" and r > 0 then
            return r
        end
    end

    local key = normalizeRarityKey(name)
    return FALLBACK_RARITY_RANK[key] or 0
end

local function getRarityColor(name)
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.getRarityColor) == "function" then
        return PLV.getRarityColor(name)
    end
    return COLOR_ACCENT
end

local function countSelected(map)
    local n = 0
    if type(map) ~= "table" then return 0 end
    for _, v in pairs(map) do
        if v == true then n += 1 end
    end
    return n
end

local function normalizePetKey(name)
    return tostring(name or ""):lower():gsub("[%s_%-]+", "")
end

local function getPetTypeItems()
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.buildPetItems) == "function" then
        return PLV.buildPetItems() or {}
    end
    return {}
end

local function buildPetAliasLookup()
    local lookup = {}
    for _, item in ipairs(getPetTypeItems()) do
        local key = tostring(item.key or item.name or "")
        if key ~= "" then
            lookup[normalizePetKey(key)] = key
            local display = tostring(item.name or "")
            if display ~= "" then
                lookup[normalizePetKey(display)] = key
            end
        end
    end
    return lookup
end

local function resolvePetCanonicalName(petName, aliasLookup)
    petName = tostring(petName or "")
    if petName == "" then return "" end
    aliasLookup = aliasLookup or buildPetAliasLookup()
    return aliasLookup[normalizePetKey(petName)] or petName
end

local function rowMatchesTargetPet(row, aliasLookup)
    local selected = _cfg.target_pets
    if countSelected(selected) <= 0 then return false end

    local canonical = resolvePetCanonicalName(row and row.pet_name, aliasLookup)
    if canonical ~= "" and selected[canonical] == true then
        return true
    end

    local norm = normalizePetKey(row and row.pet_name)
    for key, on in pairs(selected) do
        if on == true and normalizePetKey(key) == norm then
            return true
        end
    end
    return false
end

local function isSameServerJob(jobId)
    jobId = tostring(jobId or ""):gsub("%s+", "")
    if jobId == "" then return true end
    return jobId:lower() == tostring(game.JobId):lower()
end

local function getSheckles()
    local v = tonumber(LP:GetAttribute("Sheckles"))
    if type(v) == "number" then return v end

    local ls = LP:FindFirstChild("leaderstats")
    if ls then
        for _, name in ipairs({ "Sheckles", "Money", "Cash", "Coins" }) do
            local obj = ls:FindFirstChild(name)
            if obj and (obj:IsA("IntValue") or obj:IsA("NumberValue")) then
                return tonumber(obj.Value)
            end
        end
    end

    return nil
end

local function canAffordPrice(price)
    price = tonumber(price)
    if not price or price <= 0 then return true end
    local money = getSheckles()
    if type(money) ~= "number" then return true end
    return money >= price
end

local function markAvoidJob(jobId, ttlSec)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    if jobId == "" then return end
    _avoidJobs[jobId] = os.clock() + math.max(5, tonumber(ttlSec) or AVOID_JOB_TTL_FULL)
end

local function isAvoidedJob(jobId)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    local untilAt = _avoidJobs[jobId]
    if not untilAt then return false end
    if os.clock() >= untilAt then
        _avoidJobs[jobId] = nil
        return false
    end
    return true
end

local function classifyTeleportFail(result, errMsg)
    local msg = string.lower(tostring(errMsg or ""))
    local r = string.lower(tostring(result or ""))
    if msg:find("gameended", 1, true)
        or msg:find("game full", 1, true)
        or msg:find("could not find requested game instance", 1, true)
        or msg:find("requested game instance", 1, true)
        or msg:find("instance has shutdown", 1, true)
    then
        return "dead_or_full", AVOID_JOB_TTL_DEAD
    end
    if r:find("isteleporting", 1, true)
        or msg:find("previous teleport", 1, true)
        or msg:find("in processing", 1, true)
    then
        return "busy", AVOID_JOB_TTL_BUSY
    end
    return "other", AVOID_JOB_TTL_FULL
end

function M.ensureTeleportFailHook()
    if _tpFailConn then return end
    _tpFailConn = TeleportService.TeleportInitFailed:Connect(function(player, result, errMsg)
        if LP and player ~= LP then return end

        local failedJob = _pendingHopJobId
        if failedJob == "" then return end

        _hopInFlight = false
        _pendingHopJobId = ""

        local _, ttl = classifyTeleportFail(result, errMsg)
        markAvoidJob(failedJob, ttl)

        if _cfg.auto_hop then
            _lastAutoHopAt = os.clock() - AUTO_HOP_COOLDOWN_SEC
            task.defer(function()
                M.tryAutoHop(true)
            end)
        end
    end)
end

local function countSelectedRarities(map)
    return countSelected(map)
end

local function passesRarityFilter(row)
    local selected = _cfg.filter_rarities
    if countSelectedRarities(selected) <= 0 then
        return true
    end
    local rarity = tostring(row.rarity or "")
    return selected[rarity] == true
end

local function getMinSyncRarityRank()
    for _, name in ipairs({ SYNC_MIN_RARITY, "Rare", "RARE", "rare" }) do
        local r = getRarityRank(name)
        if r > 0 then return r end
    end
    return FALLBACK_RARITY_RANK.rare or 3
end

-- Sync ke API/DB: selalu Rare+ saja (UI filter tidak mempengaruhi sync).
local function passesSyncRarityFilter(row)
    local minRank = getMinSyncRarityRank()
    return getRarityRank(row and row.rarity) >= minRank
end

function M.rebuildDisplayList()
    local rows = {}
    for _, row in ipairs(_lastListRaw or {}) do
        if passesRarityFilter(row) then
            rows[#rows + 1] = row
        end
    end

    table.sort(rows, function(a, b)
        local ra = getRarityRank(a.rarity)
        local rb = getRarityRank(b.rarity)
        if ra ~= rb then return ra > rb end
        local pa = tonumber(a.price) or 0
        local pb = tonumber(b.price) or 0
        if pa ~= pb then return pa > pb end
        local ea = tonumber(a.expires_at) or 0
        local eb = tonumber(b.expires_at) or 0
        return ea < eb
    end)

    if LIST_LIMIT > 0 and #rows > LIST_LIMIT then
        local trimmed = {}
        for i = 1, LIST_LIMIT do
            trimmed[i] = rows[i]
        end
        rows = trimmed
    end

    _lastList = rows
end

local function getRequestFn()
    return (syn and syn.request)
        or (http and http.request)
        or http_request
        or (fluxus and fluxus.request)
        or request
end

local function buildHeaders()
    local h = {
        ["Content-Type"] = "application/json",
        ["Accept"] = "application/json",
    }
    if DEFAULT_API_KEY ~= "" then
        h["X-Api-Key"] = DEFAULT_API_KEY
    end
    return h
end

local function apiUrl()
    return tostring(DEFAULT_API_BASE):gsub("/+$", "") .. "/pet_finder_api.php"
end

local function stripNil(tbl)
    local out = {}
    for k, v in pairs(tbl) do
        if v ~= nil then
            out[k] = v
        end
    end
    return out
end

local function syncUrl()
    return apiUrl()
end

local function listUrl()
    return apiUrl()
end

local function gameNow()
    local ok, t = pcall(function()
        return workspace:GetServerTimeNow()
    end)
    if ok and type(t) == "number" then
        return math.floor(t)
    end
    return os.time()
end

local function computeSecondsLeft(row)
    if type(row) ~= "table" then return 0 end
    local expiresAt = tonumber(row.expires_at) or 0
    if expiresAt > 0 then
        return math.max(0, expiresAt - gameNow())
    end
    return math.max(0, math.ceil(tonumber(row.seconds_left) or 0))
end

local function fmtTimeLeft(secondsLeft)
    secondsLeft = math.max(0, math.ceil(tonumber(secondsLeft) or 0))
    if secondsLeft >= 3600 then
        return string.format("%dh %dm", math.floor(secondsLeft / 3600), math.floor((secondsLeft % 3600) / 60))
    end
    if secondsLeft >= 60 then
        return string.format("%dm %ds", math.floor(secondsLeft / 60), secondsLeft % 60)
    end
    return string.format("%ds", secondsLeft)
end

local function fmtPrice(n)
    n = math.floor(tonumber(n) or 0)
    local negative = n < 0
    local s = tostring(math.abs(n))
    while true do
        local k
        s, k = s:gsub("^(%d+)(%d%d%d)", "%1,%2")
        if k == 0 then break end
    end
    if negative then s = "-" .. s end
    return s
end

local function attr(inst, key, default)
    if not inst then return default end
    local v = inst:GetAttribute(key)
    if v == nil then return default end
    return v
end

local function num(v, default)
    v = tonumber(v)
    if v == nil then return default end
    return v
end

local function str(v, default)
    if v == nil then return default end
    v = tostring(v)
    if v == "" then return default end
    return v
end

local SharedData  = RS:FindFirstChild("SharedData")
local PetTypesMod = SharedData and SharedData:FindFirstChild("PetTypes")
local PetTypes    = PetTypesMod and PetTypesMod:IsA("ModuleScript") and (function()
    local ok, mod = pcall(require, PetTypesMod)
    return ok and mod or nil
end)() or nil

local function extractUuid(refName)
    refName = tostring(refName or "")
    local uuid = refName:match("(%x%x%x%x%x%x%x%x%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x%x%x%x%x%x%x%x%x)$")
    return uuid or refName
end

local function resolvePetType(raw)
    if raw == nil then return nil end
    if type(raw) == "string" then return raw end
    if type(raw) == "number" and PetTypes then
        for name, val in pairs(PetTypes) do
            if val == raw then return name end
        end
    end
    return tostring(raw)
end

local function getWildRefFolder()
    local map = workspace:FindFirstChild("Map")
    if not map then return nil end
    local ref = map:FindFirstChild("WildPetRef")
    return (ref and ref:IsA("Folder")) and ref or nil
end

local function getWildSpawnsFolder()
    local map = workspace:FindFirstChild("Map")
    if not map then return nil end
    local spawns = map:FindFirstChild("WildPetSpawns")
    return (spawns and spawns:IsA("Folder")) and spawns or nil
end

local function findSpawnModel(refPart, spawnsFolder)
    if not refPart or not spawnsFolder then return nil end
    local refName = refPart.Name
    local petName = attr(refPart, "PetName", "")
    local expect = "WildPet_" .. tostring(petName) .. "_" .. refName
    local direct = spawnsFolder:FindFirstChild(expect)
    if direct then return direct end
    for _, child in ipairs(spawnsFolder:GetChildren()) do
        if child:IsA("Model") and child.Name:find(refName, 1, true) then
            return child
        end
    end
    return nil
end

local function isOwnedBySelf(ownerUserId)
    return type(ownerUserId) == "number" and ownerUserId == LP.UserId
end

local function isOwnedByOther(ownerUserId)
    if ownerUserId == nil or ownerUserId == 0 then return false end
    if type(ownerUserId) ~= "number" then return false end
    return ownerUserId ~= LP.UserId
end

-- Bisa di-tame: belum ada owner (harga normal) ATAU sudah di-claim orang lain (outbid/steal ~2x).
-- Tidak bisa: sudah milik kamu sendiri.
local function canTameWildPet(ownerUserId)
    if isOwnedBySelf(ownerUserId) then return false end
    return true
end

local function isAvailable(ownerUserId)
    return canTameWildPet(ownerUserId)
end

local function isWildPetAlive(pet, now)
    if type(pet) ~= "table" then return false end
    now = now or gameNow()
    local expiresAt = tonumber(pet.expires_at) or 0
    if expiresAt > 0 and expiresAt <= now then return false end
    return true
end

-- Auto hop: stay selama pet target masih ada di WildPetRef (wandering / taming / jalan ke garden).
-- Beda dengan canTameWildPet — setelah kamu beli, owner = kamu tapi ref masih di map.
local function isWildTargetPresent(pet, aliasLookup, now)
    if not rowMatchesTargetPet(pet, aliasLookup) then return false end
    return isWildPetAlive(pet, now)
end

local function getLocalStayTag(pet)
    if type(pet) ~= "table" then return "" end
    if isOwnedBySelf(pet.owner_user_id) then
        local st = string.lower(tostring(pet.state or ""))
        if st:find("garden", 1, true) or st:find("home", 1, true)
            or st:find("walk", 1, true) or st:find("tame", 1, true)
        then
            return " · going to garden"
        end
        return " · taming"
    end
    if pet.steal == true or pet.owned_by_other == true then
        return " · steal 2x"
    end
    return ""
end

local function buildServerMeta()
    return {
        place_id = game.PlaceId,
        game_id = game.GameId,
        job_id = game.JobId,
        player_count = #Players:GetPlayers(),
        scanned_at = gameNow(),
        reporter_user_id = LP.UserId,
        reporter_name = LP.Name,
    }
end

local function scanOneRef(refPart, spawnsFolder, now)
    local petName = str(attr(refPart, "PetName", nil), nil)
    if not petName then return nil end

    local spawnedAt = num(attr(refPart, "SpawnedAt", nil), nil)
    local lifetime = num(attr(refPart, "Lifetime", nil), nil)
    local expiresAt = (spawnedAt and lifetime) and (spawnedAt + lifetime) or nil
    local secondsLeft = expiresAt and (expiresAt - now) or nil
    local pos = refPart.Position
    local ownerUserId = attr(refPart, "OwnerUserId", nil)
    local spawnModel = findSpawnModel(refPart, spawnsFolder)

    return {
        spawn_uuid = extractUuid(refPart.Name),
        ref_name = refPart.Name,
        model_name = spawnModel and spawnModel.Name or nil,
        pet_name = petName,
        rarity = str(attr(refPart, "Rarity", nil), nil),
        pet_type = resolvePetType(attr(refPart, "PetType", nil)),
        pet_size = str(attr(refPart, "PetSize", nil), nil),
        price = num(attr(refPart, "Price", nil), nil),
        owner_user_id = ownerUserId,
        owned_by_other = isOwnedByOther(ownerUserId),
        steal = isOwnedByOther(ownerUserId),
        available = canTameWildPet(ownerUserId),
        state = str(attr(refPart, "State", nil), nil),
        spawned_at = spawnedAt,
        lifetime = lifetime,
        expires_at = expiresAt,
        seconds_left = secondsLeft,
        time_left_text = secondsLeft and fmtTimeLeft(secondsLeft) or nil,
        pos_x = math.floor(pos.X * 10 + 0.5) / 10,
        pos_y = math.floor(pos.Y * 10 + 0.5) / 10,
        pos_z = math.floor(pos.Z * 10 + 0.5) / 10,
    }
end

function M.Scan()
    local folder = getWildRefFolder()
    local spawns = getWildSpawnsFolder()
    local now = gameNow()
    local pets = {}

    if not folder then
        _lastScan = {
            ok = false,
            error = "WildPetRef folder not found",
            server = buildServerMeta(),
            pets = {},
            count = 0,
        }
        return _lastScan
    end

    for _, child in ipairs(folder:GetChildren()) do
        if child:IsA("BasePart") then
            local rec = scanOneRef(child, spawns, now)
            if rec then
                pets[#pets + 1] = rec
            end
        end
    end

    table.sort(pets, function(a, b)
        local pa, pb = a.price or 0, b.price or 0
        if pa ~= pb then return pa > pb end
        return tostring(a.pet_name) < tostring(b.pet_name)
    end)

    local availableCount = 0
    for _, p in ipairs(pets) do
        if p.available then availableCount += 1 end
    end

    _lastScan = {
        ok = true,
        server = buildServerMeta(),
        pets = pets,
        count = #pets,
        available_count = availableCount,
    }
    return _lastScan
end

function M.findLocalTargetPets()
    if countSelected(_cfg.target_pets) <= 0 then
        return {}
    end

    local scan = _lastScan
    if not scan or scan.ok ~= true or type(scan.pets) ~= "table" then
        scan = M.Scan()
    end

    local aliasLookup = buildPetAliasLookup()
    local now = gameNow()
    local found = {}

    for _, pet in ipairs(scan.pets or {}) do
        if isWildTargetPresent(pet, aliasLookup, now) then
            found[#found + 1] = pet
        end
    end

    table.sort(found, function(a, b)
        local ra = getRarityRank(a.rarity)
        local rb = getRarityRank(b.rarity)
        if ra ~= rb then return ra > rb end
        local pa = tonumber(a.price) or 0
        local pb = tonumber(b.price) or 0
        if pa ~= pb then return pa > pb end
        local ea = tonumber(a.expires_at) or 0
        local eb = tonumber(b.expires_at) or 0
        return ea < eb
    end)

    return found
end

function M.hasLocalTargetPet()
    local found = M.findLocalTargetPets()
    if #found > 0 then
        return true, found[1], #found
    end
    return false, nil, 0
end

function M.GetLastScan()
    return _lastScan
end

function M.GetLastList()
    return _lastList
end

function M.GetConfig()
    return {
        filter_rarities = cleanSelectedMap(_cfg.filter_rarities),
        auto_refresh_list = (_cfg.auto_refresh_list == true),
        auto_hop = (_cfg.auto_hop == true),
        target_pets = cleanSelectedMap(_cfg.target_pets),
    }
end

function M.pickAutoHopTarget()
    if not _cfg.auto_hop or countSelected(_cfg.target_pets) <= 0 then
        return nil
    end

    local aliasLookup = buildPetAliasLookup()
    local candidates = {}

    for _, row in ipairs(_lastListRaw or {}) do
        if rowMatchesTargetPet(row, aliasLookup) and not isSameServerJob(row.job_id) then
            local expiresAt = tonumber(row.expires_at) or 0
            if expiresAt <= 0 or expiresAt > gameNow() then
                candidates[#candidates + 1] = row
            end
        end
    end

    if #candidates == 0 then
        return nil
    end

    table.sort(candidates, function(a, b)
        local ra = getRarityRank(a.rarity)
        local rb = getRarityRank(b.rarity)
        if ra ~= rb then return ra > rb end
        local pa = tonumber(a.price) or 0
        local pb = tonumber(b.price) or 0
        if pa ~= pb then return pa > pb end
        local ea = tonumber(a.expires_at) or 0
        local eb = tonumber(b.expires_at) or 0
        return ea < eb
    end)

    for _, row in ipairs(candidates) do
        if not isAvoidedJob(row.job_id) and canAffordPrice(row.price) then
            return row
        end
    end
    return nil
end

function M.tryAutoHop(forceRetry)
    M.ensureTeleportFailHook()
    if not _cfg.auto_hop or _hopInFlight then
        return false, "disabled_or_in_flight"
    end
    if countSelected(_cfg.target_pets) <= 0 then
        return false, "no_target_pets"
    end

    M.Scan()
    local hasLocal = M.hasLocalTargetPet()
    if hasLocal then
        return false, "local_target_present"
    end

    if not forceRetry and (os.clock() - _lastAutoHopAt) < AUTO_HOP_COOLDOWN_SEC then
        return false, "cooldown"
    end

    local target = M.pickAutoHopTarget()
    if not target then
        return false, "no_match"
    end

    local jobId = tostring(target.job_id or "")
    if not forceRetry
        and jobId == _lastAutoHopJobId
        and (os.clock() - _lastAutoHopAt) < (AUTO_HOP_COOLDOWN_SEC * 2)
    then
        return false, "recent_same_job"
    end

    _hopInFlight = true
    _lastAutoHopAt = os.clock()
    _lastAutoHopJobId = jobId

    local ok, err = M.HopToJob(jobId, target.place_id, target.price)
    if not ok then
        _hopInFlight = false
        if err ~= "insufficient_sheckles" then
            markAvoidJob(jobId, AVOID_JOB_TTL_BUSY)
            if _cfg.auto_hop then
                task.defer(function()
                    M.tryAutoHop(true)
                end)
            end
        end
        return false, err
    end

    task.delay(30, function()
        if _pendingHopJobId ~= "" then
            _hopInFlight = false
            _pendingHopJobId = ""
        end
    end)
    return true, target
end

local function buildDbPayload(fullPayload)
    local pets = {}
    for _, p in ipairs(fullPayload.pets or {}) do
        if p.spawn_uuid and p.pet_name and p.expires_at and passesSyncRarityFilter(p) then
            pets[#pets + 1] = {
                spawn_uuid = p.spawn_uuid,
                pet_name = p.pet_name,
                rarity = p.rarity,
                price = p.price,
                lifetime = p.lifetime,
                expires_at = p.expires_at,
            }
        end
    end
    return {
        server = fullPayload.server,
        pets = pets,
    }
end

local function buildSyncFingerprint(dbPayload)
    dbPayload = type(dbPayload) == "table" and dbPayload or {}
    local parts = {}
    local server = dbPayload.server or {}
    parts[#parts + 1] = tostring(server.job_id or "")

    local pets = dbPayload.pets or {}
    local sorted = {}
    for _, p in ipairs(pets) do
        sorted[#sorted + 1] = p
    end
    table.sort(sorted, function(a, b)
        return tostring(a.spawn_uuid or "") < tostring(b.spawn_uuid or "")
    end)

    for _, p in ipairs(sorted) do
        parts[#parts + 1] = string.format(
            "%s|%s|%s|%s|%s",
            tostring(p.spawn_uuid or ""),
            tostring(p.pet_name or ""),
            tostring(p.rarity or ""),
            tostring(p.price or ""),
            tostring(p.expires_at or "")
        )
    end

    return table.concat(parts, "\n")
end

local function httpPost(url, bodyTbl)
    local reqFn = getRequestFn()
    if not reqFn then
        return false, "HTTP request not supported"
    end

    local okJson, body = pcall(function()
        return HttpService:JSONEncode(bodyTbl)
    end)
    if not okJson then
        return false, "JSON encode failed"
    end

    local ok, res = pcall(function()
        return reqFn({
            Url = url,
            Method = "POST",
            Headers = buildHeaders(),
            Body = body,
        })
    end)
    if not ok then
        return false, tostring(res)
    end

    local status = res.StatusCode or res.status or 0
    local text = res.Body or res.body or ""
    if status < 200 or status >= 300 then
        return false, ("HTTP %s: %s"):format(tostring(status), tostring(text):sub(1, 300))
    end

    local parsed = nil
    if text ~= "" then
        pcall(function()
            parsed = HttpService:JSONDecode(text)
        end)
    end
    return true, parsed or text
end

function M.Sync(payload)
    payload = payload or _lastScan or M.Scan()
    if not payload or not payload.ok then
        _lastSyncOk = false
        _lastSyncMsg = payload and payload.error or "scan failed"
        return false, _lastSyncMsg
    end

    local dbPayload = buildDbPayload(payload)
    local fingerprint = buildSyncFingerprint(dbPayload)
    if fingerprint == _lastSyncFingerprint then
        _lastSyncOk = true
        _lastSyncMsg = "cached (no pet changes)"
        return true, "skipped"
    end

    local ok, result = httpPost(syncUrl(), stripNil({
        action = "sync",
        server = dbPayload.server,
        pets = dbPayload.pets,
    }))
    _lastSyncOk = ok
    if ok then
        _lastSyncFingerprint = fingerprint
        _lastSyncMsg = "OK"
        if type(result) == "table" and type(result.data) == "table" then
            local d = result.data
            _lastSyncMsg = string.format("upsert=%s stale=%s", tostring(d.upserted), tostring(d.deleted_stale))
        end
    else
        _lastSyncMsg = tostring(result)
    end
    M._notifyUi()
    return ok, result
end

function M.FetchList(overrideFilters, opts)
    opts = type(opts) == "table" and opts or {}
    local filters = overrideFilters or {
        place_id = game.PlaceId,
        limit = LIST_FETCH_LIMIT,
    }

    local ok, result = httpPost(listUrl(), stripNil({
        action = "list",
        place_id = filters.place_id,
        limit = filters.limit,
    }))
    if not ok then
        _lastListErr = tostring(result)
        _lastListRaw = {}
        _lastList = {}
        M._notifyUi()
        return false, result
    end

    if type(result) == "table" and type(result.data) == "table" then
        _lastListRaw = result.data
        _lastListErr = ""
        M.rebuildDisplayList()
        if opts.skipAutoHop ~= true then
            M.tryAutoHop()
        end
    else
        _lastListRaw = {}
        _lastList = {}
        _lastListErr = "invalid response"
    end
    M._notifyUi()
    return true, _lastList
end

function M.HopToJob(jobId, placeId, requiredPrice)
    M.ensureTeleportFailHook()
    jobId = tostring(jobId or ""):gsub("%s+", "")
    placeId = tonumber(placeId) or game.PlaceId
    if jobId == "" then return false, "job_id empty" end
    if isSameServerJob(jobId) then
        return false, "already on server"
    end
    if isAvoidedJob(jobId) then
        return false, "server_avoided"
    end
    if not canAffordPrice(requiredPrice) then
        return false, "insufficient_sheckles"
    end

    local td = {
        __gag2_petfinder = true,
        targetJobId = jobId,
        nonce = tostring(os.time()) .. "_" .. tostring(math.random(100000, 999999)),
    }

    _pendingHopJobId = jobId:lower()

    local PR = rawget(_G, "PSReconnect") or getG().PSReconnect
    if type(PR) == "table" and type(PR.HopToServer) == "function" then
        local ok, res = PR.HopToServer(placeId, jobId, td)
        if ok then return true, res end
    end

    local opts = Instance.new("TeleportOptions")
    pcall(function() opts:SetTeleportData(td) end)
    pcall(function() opts.ServerInstanceId = jobId end)

    local okAsync, errAsync = pcall(function()
        TeleportService:TeleportAsync(placeId, { LP }, opts)
    end)
    if okAsync then
        return true, "teleporting"
    end

    local okLegacy, errLegacy = pcall(function()
        TeleportService:TeleportToPlaceInstance(placeId, jobId, LP, "", td)
    end)
    if not okLegacy then
        _pendingHopJobId = ""
        return false, tostring(errAsync or errLegacy)
    end
    return true, "teleporting"
end

function M.ScanAndSync()
    local payload = M.Scan()
    return M.Sync(payload)
end

function M.StopAutoSync()
    _autoSyncToken += 1
end

function M.StartAutoSync()
    _autoSyncToken += 1
    local token = _autoSyncToken
    task.spawn(function()
        while token == _autoSyncToken do
            M.ScanAndSync()
            task.wait(SYNC_SCAN_INTERVAL_SEC)
        end
    end)
end

function M.StopAutoHopFetch()
    _autoHopFetchToken += 1
end

function M.StartAutoHopFetch()
    M.StopAutoHopFetch()
    if not _cfg.auto_hop then return end
    _autoHopFetchToken += 1
    local token = _autoHopFetchToken
    task.spawn(function()
        while token == _autoHopFetchToken and _cfg.auto_hop do
            M.FetchList(nil, { skipAutoHop = false })
            task.wait(HOP_FETCH_INTERVAL_SEC)
        end
    end)
end

function M.StopAutoRefreshList()
    _autoRefreshToken += 1
end

local function waitWithUiTick(token, intervalSec, shouldRun)
    local t0 = os.clock()
    while token and shouldRun() and (os.clock() - t0) < intervalSec do
        M._notifyUi()
        task.wait(UI_TICK_INTERVAL_SEC)
    end
end

function M.StartAutoRefreshList()
    _autoRefreshToken += 1
    local token = _autoRefreshToken
    task.spawn(function()
        while token == _autoRefreshToken and _cfg.auto_refresh_list do
            if not _cfg.auto_hop then
                M.FetchList(nil, { skipAutoHop = true })
            end
            waitWithUiTick(token, LIST_REFRESH_INTERVAL_SEC, function()
                return token == _autoRefreshToken and _cfg.auto_refresh_list == true
            end)
        end
    end)
end

function M.ApplyConfig(cfg)
    if type(cfg) ~= "table" then return end
    if cfg.filter_rarities ~= nil then
        _cfg.filter_rarities = cleanSelectedMap(cfg.filter_rarities)
    end
    if cfg.auto_refresh_list ~= nil then
        _cfg.auto_refresh_list = (cfg.auto_refresh_list == true)
    end
    if cfg.auto_hop ~= nil then
        _cfg.auto_hop = (cfg.auto_hop == true)
    end
    if cfg.target_pets ~= nil then
        _cfg.target_pets = cleanSelectedMap(cfg.target_pets)
    end

    M.rebuildDisplayList()

    if _cfg.auto_hop then
        M.StartAutoHopFetch()
    else
        M.StopAutoHopFetch()
    end

    if _cfg.auto_refresh_list then
        M.StartAutoRefreshList()
    else
        M.StopAutoRefreshList()
    end
end

function M.SyncFromGlobals()
    local G = getG()
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    local pf = (type(MAIN) == "table" and type(MAIN.misc) == "table" and type(MAIN.misc.pet_finder) == "table")
        and MAIN.misc.pet_finder or {}

    local rarityMap = arrayToMap(pf.filter_rarities)
    if countSelectedRarities(rarityMap) <= 0 and pf.filter_rarity and pf.filter_rarity ~= "" then
        rarityMap = { [tostring(pf.filter_rarity)] = true }
    end
    if countSelectedRarities(rarityMap) <= 0 and type(G.PET_FINDER_FILTER_RARITIES) == "table" then
        rarityMap = arrayToMap(G.PET_FINDER_FILTER_RARITIES)
    end

    local targetMap = arrayToMap(pf.target_pets)
    if countSelected(targetMap) <= 0 and type(G.PET_FINDER_TARGET_PETS) == "table" then
        targetMap = arrayToMap(G.PET_FINDER_TARGET_PETS)
    end

    M.ApplyConfig({
        filter_rarities = rarityMap,
        auto_refresh_list = pf.auto_refresh_list ~= false,
        auto_hop = pf.auto_hop == true,
        target_pets = targetMap,
    })
end

function M.WriteGlobals(cfg)
    cfg = cfg or M.GetConfig()
    local G = getG()
    local rarityArr = mapToArray(cfg.filter_rarities)
    local targetArr = mapToArray(cfg.target_pets)
    local payload = {
        filter_rarities = rarityArr,
        auto_refresh_list = (cfg.auto_refresh_list == true),
        auto_hop = (cfg.auto_hop == true),
        target_pets = targetArr,
    }

    local State = G.__GAG2_STATE
    if type(State) == "table" and type(State.patchMisc) == "function" then
        pcall(State.patchMisc, "pet_finder", payload, { noSync = true })
    end

    G.PET_FINDER_FILTER_RARITIES = rarityArr
    G.PET_FINDER_AUTO_REFRESH_LIST = payload.auto_refresh_list
    G.PET_FINDER_AUTO_HOP = payload.auto_hop
    G.PET_FINDER_TARGET_PETS = targetArr
    _G.PET_FINDER_FILTER_RARITIES = rarityArr
    _G.PET_FINDER_AUTO_REFRESH_LIST = G.PET_FINDER_AUTO_REFRESH_LIST
    _G.PET_FINDER_AUTO_HOP = G.PET_FINDER_AUTO_HOP
    _G.PET_FINDER_TARGET_PETS = targetArr

    G.MAIN = G.MAIN or {}
    G.MAIN.misc = G.MAIN.misc or {}
    G.MAIN.misc.pet_finder = payload
    _G.MAIN = G.MAIN
end

function M._notifyUi()
    for _, fn in ipairs(_uiRefreshers) do
        pcall(fn)
    end
end

function M.RegisterUI(ui, STATE, autoSave)
    autoSave = autoSave or function() end
    local G = getG()
    local State = G.__GAG2_STATE
    if type(State) == "table" and type(State.registerFlush) == "function" then
        pcall(State.registerFlush, "pet_finder", function()
            M.WriteGlobals(M.GetConfig())
        end)
    end

    ui:RegisterSubTab("misc", "petfinder", "Pet Finder", function()
        ui:ClearSubContent()
        _uiRefreshers = {}

        local cfg = M.GetConfig()

        local function commitCfg(partial)
            local nextCfg = M.GetConfig()
            if type(partial) == "table" then
                for k, v in pairs(partial) do
                    nextCfg[k] = v
                end
            end
            M.ApplyConfig(nextCfg)
            M.WriteGlobals(nextCfg)
            autoSave()
        end

        local bodyHop = ui:CreateSection("Auto Hop", true)

        local petTypeRow = ui:CreateRowDropdown(bodyHop, {
            label       = "Pet Type",
            placeholder = "Select target pets",
            mode        = "multi",
            getItems    = function() return getPetTypeItems() end,
            initial     = cfg.target_pets,
            onChanged   = function(_, selectedMap)
                commitCfg({ target_pets = cleanSelectedMap(selectedMap) })
            end,
        })
        if petTypeRow then petTypeRow.LayoutOrder = 1 end

        ui:CreateRowToggle(bodyHop, "Auto Hop", cfg.auto_hop == true, function(on)
            commitCfg({ auto_hop = (on == true) })
        end, 2)

        local _, hopStatusLbl = ui:CreateRowLabel(bodyHop, "Select pet type(s) to auto hop.", nil, 3, "info")

        local bodyList = ui:CreateSection("Pet List", true)

        local rarityRow = ui:CreateRowDropdown(bodyList, {
            label       = "Rarity",
            placeholder = "All Rarities",
            mode        = "multi",
            getItems    = function() return getRarityItems() end,
            initial     = cfg.filter_rarities,
            onChanged   = function(_, selectedMap)
                commitCfg({ filter_rarities = cleanSelectedMap(selectedMap) })
                M._notifyUi()
            end,
        })
        if rarityRow then rarityRow.LayoutOrder = 1 end

        ui:CreateRowToggle(bodyList, "Auto Refresh List", cfg.auto_refresh_list == true, function(on)
            commitCfg({ auto_refresh_list = (on == true) })
        end, 2)

        local _, listStatusLbl = ui:CreateRowLabel(bodyList, "Loading...", nil, 3, "info")

        local listHost = Instance.new("Frame")
        listHost.Name = "PetFinderListHost"
        listHost.BackgroundTransparency = 1
        listHost.Size = UDim2.new(1, 0, 0, 240)
        listHost.LayoutOrder = 4
        listHost.Parent = bodyList

        local listScroll = Instance.new("ScrollingFrame")
        listScroll.Name = "Scroll"
        listScroll.BackgroundColor3 = Color3.fromRGB(10, 10, 12)
        listScroll.BorderSizePixel = 0
        listScroll.Size = UDim2.new(1, 0, 1, 0)
        listScroll.CanvasSize = UDim2.new(0, 0, 0, 0)
