            priceLbl.BackgroundTransparency = 1
            priceLbl.AnchorPoint = Vector2.new(1, 0)
            priceLbl.Position = UDim2.new(1, -62, 0, 5)
            priceLbl.Size = UDim2.fromOffset(78, 15)
            priceLbl.Font = Enum.Font.GothamMedium
            priceLbl.TextSize = 10
            priceLbl.TextXAlignment = Enum.TextXAlignment.Right
            priceLbl.TextColor3 = COLOR_ACCENT
            priceLbl.Parent = frame

            local metaLbl = Instance.new("TextLabel")
            metaLbl.BackgroundTransparency = 1
            metaLbl.Position = UDim2.fromOffset(13, 24)
            metaLbl.Size = UDim2.new(1, -72, 0, 14)
            metaLbl.Font = Enum.Font.Gotham
            metaLbl.TextSize = 9
            metaLbl.TextXAlignment = Enum.TextXAlignment.Left
            metaLbl.TextTruncate = Enum.TextTruncate.AtEnd
            metaLbl.TextColor3 = COLOR_MUTED
            metaLbl.Parent = frame

            local hopBtn = Instance.new("TextButton")
            hopBtn.BackgroundColor3 = COLOR_ACCENT
            hopBtn.BorderSizePixel = 0
            hopBtn.AnchorPoint = Vector2.new(1, 0.5)
            hopBtn.Position = UDim2.new(1, -6, 0.5, 0)
            hopBtn.Size = UDim2.fromOffset(50, 24)
            hopBtn.Font = Enum.Font.GothamBold
            hopBtn.TextSize = 9
            hopBtn.TextColor3 = Color3.fromRGB(12, 12, 12)
            hopBtn.Text = "Hop"
            hopBtn.AutoButtonColor = false
            hopBtn.Parent = frame
