            local card = {
                frame = frame,
                accent = accent,
                badge = badge,
                nameLbl = nameLbl,
                priceLbl = priceLbl,
                metaLbl = metaLbl,
                hopBtn = hopBtn,
                _jobId = "",
                _placeId = game.PlaceId,
                _price = 0,
            }

