    { key = "UpdateNewServer", name = "UpdateNewServer",  factory = function() -- UpdateNewServer.lua
-- Source of truth:
--   1) STATE.rejoin.update_new_server / update_new_server_minute
--   2) fallback global UPDATE_NEW_SERVER_ENABLED / UPDATE_NEW_SERVER_MINUTE
-- Interval habis -> kick kosong + sembunyikan prompt disconnect

local Players    = game:GetService("Players")
local Workspace  = game:GetService("Workspace")
local CoreGui    = game:GetService("CoreGui")
local GuiService = game:GetService("GuiService")
local TeleportService = game:GetService("TeleportService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G

local MODULE_VER = 5
if G.__UPDATE_NEW_SERVER_VER == MODULE_VER and type(G.UpdateNewServer) == "table" then
    return G.UpdateNewServer
end
G.__UPDATE_NEW_SERVER_VER = MODULE_VER
G.__UPDATE_NEW_SERVER_LOADED = true

local M = {}
M._running = false
M._thread = nil
M._nextKickAt = nil
M._lastKickStamp = nil
M.DEBUG = false

local __antiPromptStarted = false

local function dprint(...)
    if M.DEBUG ~= true then return end
    print("[UpdateNewServer]", ...)
end

local function dwarn(...)
     if M.DEBUG ~= true then return end
    warn("[UpdateNewServer]", ...)
end

local function clampMinute(n)
    n = tonumber(n) or 30
    n = math.floor(n)
    if n < 1 then n = 1 end
    if n > 300 then n = 300 end
    return n
end

local function truthy(v)
    return (v == true) or (v == 1) or (v == "true") or (v == "1")
end

local function getState()
    local STATE = G.STATE
    if type(STATE) ~= "table" then
        return nil
    end
    return STATE
end

local function ensureState()
    G.STATE = (type(G.STATE) == "table") and G.STATE or {}
    G.STATE.rejoin = (type(G.STATE.rejoin) == "table") and G.STATE.rejoin or {}
    return G.STATE
end

local function getMainRejoin()
    local main = G.MAIN or _G.MAIN
    if type(main) == "table" and type(main.misc) == "table" and type(main.misc.rejoin) == "table" then
        return main.misc.rejoin
    end
    return nil
end

local function getCfg()
    local enabled, minute

    local rjMain = getMainRejoin()
    if type(rjMain) == "table" then
        if rjMain.update_new_server ~= nil then
            enabled = truthy(rjMain.update_new_server)
        end
        if rjMain.update_new_server_minute ~= nil then
            minute = rjMain.update_new_server_minute
        end
    end

    local STATE = getState()
    if type(STATE) == "table" and type(STATE.rejoin) == "table" then
        local rj = STATE.rejoin
        if enabled == nil and rj.update_new_server ~= nil then
            enabled = truthy(rj.update_new_server)
        end
        if minute == nil and rj.update_new_server_minute ~= nil then
            minute = rj.update_new_server_minute
        end
    end

    if type(G.__UNS_SAVED) == "table" then
        if enabled == nil and G.__UNS_SAVED.enabled ~= nil then
            enabled = truthy(G.__UNS_SAVED.enabled)
        end
        if minute == nil and G.__UNS_SAVED.minute ~= nil then
            minute = G.__UNS_SAVED.minute
        end
    end

    if enabled == nil then
        enabled = (G.UPDATE_NEW_SERVER_ENABLED == true)
    end
    if minute == nil then
        minute = G.UPDATE_NEW_SERVER_MINUTE
    end

    enabled = (enabled == true)
    minute  = clampMinute(minute)

    G.UPDATE_NEW_SERVER_ENABLED = enabled
    G.UPDATE_NEW_SERVER_MINUTE  = minute
    _G.UPDATE_NEW_SERVER_ENABLED = enabled
    _G.UPDATE_NEW_SERVER_MINUTE  = minute

    if type(STATE) == "table" then
        STATE.rejoin = type(STATE.rejoin) == "table" and STATE.rejoin or {}
        STATE.rejoin.update_new_server        = enabled
        STATE.rejoin.update_new_server_minute = minute
    end

    return enabled, minute, "global"
end

local function syncFromState()
    local enabled, minute, path = getCfg()

    G.UPDATE_NEW_SERVER_ENABLED = enabled
    G.UPDATE_NEW_SERVER_MINUTE  = minute

    local STATE = ensureState()
    STATE.rejoin.update_new_server = enabled
    STATE.rejoin.update_new_server_minute = minute

    dprint(
        "SyncFromState:",
        "path =", path,
        "enabled =", enabled,
        "minute =", minute
    )

    return enabled, minute, path
end

local function getServerNow()
    local ok, v = pcall(function()
        return Workspace:GetServerTimeNow()
    end)
    if ok and type(v) == "number" then
        return v
    end

    local fallback = os.time()
    dprint("GetServerTimeNow failed, fallback os.time =", fallback)
    return fallback
end

local function fmtClock(sec)
    sec = math.floor(tonumber(sec) or 0)
    return os.date("!%H:%M:%S", sec)
end

local function fmtRemain(sec)
    sec = math.max(0, math.floor(tonumber(sec) or 0))
    local m = math.floor(sec / 60)
    local s = sec % 60
    return string.format("%02d:%02d", m, s)
end

local function computeNextBoundary(now, minute)
    local intervalSec = clampMinute(minute) * 60
    local bucket = math.floor(now / intervalSec)
    local nextAt = (bucket + 1) * intervalSec
    return nextAt, bucket, intervalSec
end

local function reschedule(reason)
    local enabled, minute, path = syncFromState()

    if not enabled then
        M._nextKickAt = nil
        dprint("Reschedule:", tostring(reason or "-"), "| disabled | path =", path)
        return
    end

    local now = getServerNow()
    local nextAt, bucket, intervalSec = computeNextBoundary(now, minute)
    M._nextKickAt = nextAt

    dprint(
        "Reschedule:",
        tostring(reason or "-"),
        "| path =", path,
        "| minute =", minute,
        "| now =", fmtClock(now),
        "| bucket =", bucket,
        "| intervalSec =", intervalSec,
        "| nextKick =", fmtClock(nextAt),
        "| remain =", fmtRemain(nextAt - now)
    )
end

local function hideDisconnectPrompt()
    pcall(function()
        GuiService:ClearError()
    end)

    pcall(function()
        local gui = CoreGui:FindFirstChild("RobloxPromptGui")
        if not gui then
            return
        end

        gui.Enabled = false

        for _, v in ipairs(gui:GetDescendants()) do
            if v:IsA("GuiObject") then
                v.Visible = false
            end
        end
    end)
end

local function startAntiPrompt()
    if __antiPromptStarted then
        return
    end
    __antiPromptStarted = true

    task.spawn(function()
        while true do
            hideDisconnectPrompt()
            task.wait(0.05)
        end
    end)
end

local function doKick(reason)
    reason = tostring(reason or "interval")
    dwarn("KICK NOW:", reason)
    dprint("CURRENT JOBID:", game.JobId)

    G.__UPDATE_NEW_SERVER_REJOIN_PENDING = true
    _G.__UPDATE_NEW_SERVER_REJOIN_PENDING = true

    startAntiPrompt()
    hideDisconnectPrompt()
    task.wait(0.15)
    hideDisconnectPrompt()

    local ok, err = pcall(function()
        LP:Kick("")
        task.wait(7)
        TeleportService:Teleport(game.PlaceId, LP)
    end)

    if not ok then
        dwarn("Kick failed:", tostring(err))
    end

    task.defer(hideDisconnectPrompt)

    return ok
end

function M.KickNow(reason)
    return doKick(reason)
end

function M.RejoinNow(reason)
    return doKick(reason)
end

function M.IsRunning()
    return M._running == true
end

function M.SyncFromState()
    reschedule("SyncFromState")
end

function M.Apply(selfOrEnabled, maybeEnabled, maybeMinute)
    local enabled, minute

    if selfOrEnabled == M then
        enabled = maybeEnabled
        minute  = maybeMinute
    else
        enabled = selfOrEnabled
        minute  = maybeEnabled
    end

    enabled = truthy(enabled)
    minute  = clampMinute(minute)

    local prevEnabled, prevMinute = getCfg()

    G.UPDATE_NEW_SERVER_ENABLED = enabled
    G.UPDATE_NEW_SERVER_MINUTE  = minute
    _G.UPDATE_NEW_SERVER_ENABLED = enabled
    _G.UPDATE_NEW_SERVER_MINUTE  = minute
    G.__UNS_SAVED = { enabled = enabled, minute = minute }

    local STATE = ensureState()
    STATE.rejoin.update_new_server        = enabled
    STATE.rejoin.update_new_server_minute = minute

    if enabled ~= prevEnabled or minute ~= prevMinute then
        dprint(("Apply: enabled=%s minute=%d"):format(tostring(enabled), minute))
    end

    if enabled then
        startAntiPrompt()
        M._ensureRunning(minute)
    elseif M._running then
        M.Stop("disabled")
    end
end

function M.SetEnabled(on)
    M.Apply((on == true), G.UPDATE_NEW_SERVER_MINUTE)
end

function M.SetMinute(minute)
    M.Apply((G.UPDATE_NEW_SERVER_ENABLED == true), minute)
end

function M.GetInfo()
    local enabled, minute, path = getCfg()
    local now = getServerNow()
    local nextAt, bucket, intervalSec = computeNextBoundary(now, minute)
    local remain = math.max(0, math.floor(nextAt - now))

    return {
        enabled = enabled,
        minute = minute,
        path = path,
        serverNow = now,
        remainSec = remain,
        remainFmt = fmtRemain(remain),
        nextBucketAt = nextAt,
        bucket = bucket,
        intervalSec = intervalSec,
        nextKickAt = M._nextKickAt,
        nextRejoinAt = M._nextKickAt,
        jobId = tostring(game.JobId or ""),
        running = M._running,
    }
end

function M._ensureRunning(minute)
    minute = clampMinute(minute)

    G.UPDATE_NEW_SERVER_ENABLED = true
    G.UPDATE_NEW_SERVER_MINUTE  = minute
    _G.UPDATE_NEW_SERVER_ENABLED = true
    _G.UPDATE_NEW_SERVER_MINUTE  = minute

    if M._running then
        reschedule("Apply")
        return
    end

    M._running = true
    M._lastKickStamp = nil
    M._nextKickAt = nil

    startAntiPrompt()
    dprint(("Started | kick interval = %d minute(s)"):format(minute))

    reschedule("Start")

    M._thread = task.spawn(function()
        task.wait(2)

        while M._running do
            local enabled = (G.UPDATE_NEW_SERVER_ENABLED == true)
            minute = clampMinute(G.UPDATE_NEW_SERVER_MINUTE)

            if enabled then
                local now = getServerNow()

                if M._nextKickAt == nil then
                    local nextAt = computeNextBoundary(now, minute)
                    M._nextKickAt = nextAt
                    dprint("Tick -> nextKickAt nil, rebuilt =", fmtClock(nextAt))
                end

                local remain = math.max(0, math.floor((M._nextKickAt or now) - now))

                dprint(
                    "Tick |",
                    "| serverNow =", fmtClock(now),
                    "| minute =", minute,
                    "| nextKick =", M._nextKickAt and fmtClock(M._nextKickAt) or "nil",
                    "| remain =", fmtRemain(remain)
                )

                if M._nextKickAt and now >= M._nextKickAt then
                    local kickStamp = math.floor(M._nextKickAt)

                    if M._lastKickStamp ~= kickStamp then
                        M._lastKickStamp = kickStamp
                        doKick(("boundary reached @ every %d minute"):format(minute))
                    else
                        dprint("Skip duplicate kick at", fmtClock(kickStamp))
                    end

                    local nextAt = computeNextBoundary(now, minute)
                    M._nextKickAt = nextAt
                    dprint("Post-kick reschedule ->", fmtClock(nextAt))
                end
            else
                M._nextKickAt = nil
            end

            task.wait(1)
        end
    end)
end

function M.Start()
    local enabled, minute = getCfg()
    if enabled ~= true then
        dprint("Start aborted: disabled")
        return
    end
    M._ensureRunning(minute)
end

function M.Stop(reason)
    if M._running ~= true then
        return
    end
    M._running = false
    M._thread = nil
    M._nextKickAt = nil
    dprint("Stop:", tostring(reason or "manual"))
end

G.UpdateNewServer = M
_G.UpdateNewServer = M

return M
