    if menu then
        local lbl = menu:FindFirstChild("SkipTxt", true)
        if lbl and lbl:IsA("TextLabel") then return lbl end
    end
    for _, inst in ipairs(workspace:GetDescendants()) do
        if inst.Name == "SkipTxt" and inst:IsA("TextLabel") then
            return inst
        end
    end
    return nil
end

local function findPressTxt()
    local menu = workspace:FindFirstChild("LoadingScreenMenu")
    if menu then
        local lbl = menu:FindFirstChild("PressAnyTxt", true)
        if lbl and lbl:IsA("TextLabel") then return lbl end
