        end
    end
    return nil
end

local function textHas(txt, word)
    if not txt or txt == "" then return false end
    return string.find(string.lower(txt), string.lower(word), 1, true) ~= nil
end

local function labelVisible(lbl)
    if not lbl then return false end
    if lbl.Visible == false then return false end
    local p = lbl
    while p do
        if p:IsA("GuiObject") and p.Visible == false then
            return false
        end
        p = p.Parent
    end
    return true
end

local function isLoadingActive()
    return LP:GetAttribute("LoadingScreenActive") == true
end

local function isLoadingDone()
    return LP:GetAttribute("LoadingScreenDone") == true
end

local function getLoadingPhase()
    if isLoadingDone() then
        return "done"
    end

    local pressTxt = findPressTxt()
    if labelVisible(pressTxt) then
        local t = pressTxt.Text or ""
        if textHas(t, "press any key") or textHas(t, "tap anywhere") or textHas(t, "fully loaded") then
            return "play"
        end
    end

    local skipTxt = findSkipTxt()
    if labelVisible(skipTxt) then
        local t = skipTxt.Text or ""
        if textHas(t, "click to skip") then
            return "skip"
        end
    end

    local menu = workspace:FindFirstChild("LoadingScreenMenu")
    if menu then
        for _, inst in ipairs(menu:GetDescendants()) do
            if inst:IsA("TextLabel") or inst:IsA("TextButton") then
                local t = string.lower(tostring(inst.Text or ""))
                if t:find("press any", 1, true) or t:find("tap anywhere", 1, true) then
                    return "play"
                end
                if t:find("click to skip", 1, true) then
                    return "skip"
                end
            end
        end
    end

    if isLoadingActive() then
        if pressTxt then return "play" end
        if skipTxt then return "skip_done" end
        return "loading"
    end

    return "idle"
end

local function softDismissLoading()
    if isLoadingDone() then return end
    if isTeleportBusy() then
        dprint("soft dismiss skipped: teleport busy")
        return
    end
    dprint("soft dismiss")

    local menu = workspace:FindFirstChild("LoadingScreenMenu")
    local loadingGui = menu and menu:FindFirstChild("LoadingGui", true)

    pcall(function()
        local blur = require(game:GetService("ReplicatedStorage").ClientModules.Blur)
        if type(blur.SetBlur) == "function" then blur.SetBlur(0, 0) end
    end)

    ProximityPromptService.Enabled = true

    if loadingGui and loadingGui:IsA("ScreenGui") then
        pcall(function() loadingGui.Enabled = false end)
    end

    pcall(function()
        LP:SetAttribute("LoadingScreenActive", false)
        LP:SetAttribute("LoadingScreenDone", true)
    end)
end

local function forceDismissLoading()
    if isLoadingDone() then return end
    if isTeleportBusy() then
        dprint("force dismiss blocked: teleport/hop active")
        return
    end
    softDismissLoading()
end

local function runLoadingSkipLoop()
    if M._loadingSkipStarted then return end
    if isLoadingDone() then return end
    M._loadingSkipStarted = true

    task.spawn(function()
        dprint("loading skip start")
        local t0 = os.clock()

        while getLoadingPhase() == "idle" and os.clock() - t0 < 60 do
            task.wait(0.15)
        end

        if getLoadingPhase() == "done" then
            M._loadingSkipStarted = false
            return
        end

        t0 = os.clock()
        local lastInput = 0

        while os.clock() - t0 < LOADING_SKIP_TIMEOUT do
            if isTeleportBusy() then
                dprint("loading skip pause: teleport busy")
                task.wait(0.5)
            else
                local phase = getLoadingPhase()
                if phase == "done" or phase == "idle" then
                    break
                end

                local now = os.clock()

                -- Phase "loading" = ProgressBar masih jalan; jangan spam input / jangan destroy UI.
                if phase == "skip" and now - lastInput >= 0.5 then
                    dprint("phase skip")
                    sendLoadingSkipInput()
                    lastInput = now
                elseif phase == "play" and now - lastInput >= 0.5 then
                    dprint("phase play")
                    sendLoadingSkipInput()
                    lastInput = now
                elseif phase == "skip_done" and now - lastInput >= 0.6 then
                    dprint("phase skip_done")
                    sendLoadingSkipInput()
                    lastInput = now
                end

                if isLoadingDone() then
                    break
                end
            end

            task.wait(0.2)
        end

        if not isLoadingDone() and not isTeleportBusy()
            and isLoadingActive() and os.clock() - t0 >= LOADING_FORCE_TIMEOUT then
            sendLoadingSkipInput()
            task.wait(1)
            if isLoadingActive() and not isLoadingDone() and not isTeleportBusy() then
                softDismissLoading()
            end
        end

        M._loadingSkipStarted = false
        dprint("loading skip end")
    end)
end

function M.Start()
