 end,               required = false, early = true },
    { key = "PSReconnect",     name = "PSReconnect",      factory = function() -- PSReconnect.lua (FULL, DEBUG + HARD GATE)
-- ✅ Rejoin (PS-safe) + optional auto reconnect
-- ✅ Auto Exec STRICT dari save file: autohatch/<username>.json -> rejoin.auto_exec
-- ✅ queue_on_teleport hanya dipanggil jika auto_exec true
-- ✅ QTP chunk cek file lagi di server baru (OFF => skip)
-- ✅ QTP chunk nulis marker file + --warn() (biar kebukti jalan / gak jalan)
-- ✅ Kalau auto_exec ON tapi QTP gagal -> CANCEL teleport (biar gak rejoin tanpa autoexec)
-- ✅ Export ke _G/getgenv: _G.PSReconnect selalu ada
-- ✅ Debounce anti spam prompt

--------------------------------------------------
-- SERVICES
--------------------------------------------------
local Players         = game:GetService("Players")
local TeleportService = game:GetService("TeleportService")
local CoreGui         = game:GetService("CoreGui")
local HttpService     = game:GetService("HttpService")

local LP = Players.LocalPlayer
local M  = {}

--------------------------------------------------
-- PREVENT MULTI LOAD (module ini)
--------------------------------------------------
local G = (getgenv and getgenv()) or _G
if G.__PSRECONNECT_LOADED then
    return G.PSReconnect or M
end
G.__PSRECONNECT_LOADED = true

--------------------------------------------------
-- CONFIG
--------------------------------------------------
local SCRIPT_URL                 = "https://golaspay.net/scv/uA55bVTKKYY3f?psreconnect=1&key=xzlncM2dOhQLfeTe"
local SAVE_DIR                   = "growagarden2"
local REJOIN_DELAY_SEC           = 50
local UPDATE_NEW_SERVER_DELAY_SEC = 30
local SHUTDOWN_REJOIN_DELAY_SEC  = 50
local DEBUG_PSRECONNECT          = false

local function dprint(...)
    if not DEBUG_PSRECONNECT then return end
    print("[PSReconnect]", ...)
end
-- debounce
local _rejoinInFlight       = false
local _shutdownRejoinBusy   = false
local _lastRejoinT          = 0
local MIN_REJOIN_INTERVAL   = 6

--------------------------------------------------
-- FLAGS (runtime)
--------------------------------------------------
local TELEPORT_BLOCKED       = false
local AUTO_RECONNECT_ENABLED = true

--------------------------------------------------
-- FILE HELPERS
--------------------------------------------------
local CAN_FS = (type(readfile)=="function" and type(isfile)=="function")

local function safeName(s)
    s = tostring(s or "player")
    s = s:gsub("[^%w%-_.]", "_")
    s = s:gsub("_+", "_")
    return s:sub(1, 48)
end

local function getSaveFile()
    if not LP then return nil end
    return (SAVE_DIR .. "/" .. safeName(LP.Name) .. ".json")
end

-- return: autoReconnect(bool), autoExec(bool)
local function readFlagsFromFile()
    local DEFAULT_RECONNECT = true
    local DEFAULT_EXEC      = false

    if not CAN_FS then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local f = getSaveFile()
    if not f or not isfile(f) then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local ok, txt = pcall(readfile, f)
    if not ok or type(txt) ~= "string" or txt == "" then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local ok2, data = pcall(HttpService.JSONDecode, HttpService, txt)
    if not ok2 or type(data) ~= "table" then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local r = {}
    if type(data.rejoin) == "table" then
        r = data.rejoin
    elseif type(data.main) == "table"
        and type(data.main.misc) == "table"
        and type(data.main.misc.rejoin) == "table" then
        r = data.main.misc.rejoin
    elseif type(data.state) == "table" and type(data.state.rejoin) == "table" then
        r = data.state.rejoin
    end

    local autoReconnect = (r.auto_reconnect == true)
    local autoExec      = (r.auto_exec == true)

    return autoReconnect, autoExec
end

--------------------------------------------------
-- QTP RESOLVER
--------------------------------------------------
local function getQTP()
    return queue_on_teleport
        or (syn and syn.queue_on_teleport)
        or (fluxus and fluxus.queue_on_teleport)
        or queueteleport
        or queueonteleport
end

--------------------------------------------------
-- LOADER GUARD RESET (cegah loader skip)
--------------------------------------------------
local function resetLoaderGuards()
    local GG = (getgenv and getgenv()) or _G
    GG.__NODEHUB_LOADED = nil
    GG.__NODEHUB_LOADED_SESSION = nil
    GG.__NODEHUB_AUTOEXECED = nil
    GG.__MAINUI_LOADED = nil
    GG.__UI_LOADED = nil
    GG.__GROWAGARDEN2_RUNNING = nil
end

--------------------------------------------------
-- QUEUE ON TELEPORT (STRICT GATED + DEBUG MARKER)
--------------------------------------------------
local function QueueAutoExecIfEnabled()
    local _, autoExec = readFlagsFromFile()
    if autoExec ~= true then
        return false, "auto_exec=false"
    end

    local qtp = getQTP()
    if not qtp then
        return false, "qtp not found"
    end

    local template = [[
        task.wait(3)

        local url = "__URL__"
        local SAVE_DIR = "__SAVE_DIR__"

        local Players = game:GetService("Players")
        local HttpService = game:GetService("HttpService")

        --warn("[QTP] running | SAVE_DIR=", SAVE_DIR, "| url=", url)
        --warn("[QTP] fs types:", type(readfile), type(isfile), type(writefile), type(makefolder))

        local function safeName(s)
            s = tostring(s or "player")
            s = s:gsub("[^%w%-_.]", "_")
            s = s:gsub("_+", "_")
            return s:sub(1, 48)
        end

        local function readAutoExecAndFile()
            if type(readfile)~="function" or type(isfile)~="function" then
                return false, nil
            end
            local lp = Players.LocalPlayer
            if not lp then return false, nil end

            local f = (SAVE_DIR .. "/" .. safeName(lp.Name) .. ".json")
            local ex = isfile(f)
            --warn("[QTP] file=", f, "exists=", ex)

            if not ex then return false, f end

            local ok, txt = pcall(readfile, f)
            if not ok or type(txt)~="string" or txt=="" then
                return false, f
            end

            local ok2, data = pcall(HttpService.JSONDecode, HttpService, txt)
            if not ok2 or type(data)~="table" then
                return false, f
            end

            local r
            if type(data.rejoin)=="table" then
                r = data.rejoin
            elseif type(data.state)=="table" and type(data.state.rejoin)=="table" then
                r = data.state.rejoin
            else
                r = {}
            end

            return (r.auto_exec == true), f
        end

        local enabled, fpath = readAutoExecAndFile()

        -- marker: buktiin chunk jalan
        pcall(function()
            if type(writefile)=="function" then
                -- coba bikin folder kalau belum ada
                if type(makefolder)=="function" and type(isfolder)=="function" then
                    if not isfolder(SAVE_DIR) then pcall(makefolder, SAVE_DIR) end
                end
                writefile(SAVE_DIR .. "/_qtp_ran.txt", "ran@"..os.time().."\nfile="..tostring(fpath).."\nenabled="..tostring(enabled))
            end
        end)

        if enabled ~= true then
            --warn("[QTP] auto_exec OFF in new server -> skip load")
            return
        end

        -- reset guard supaya loader tidak skip
        local G = (getgenv and getgenv()) or _G
        G.__NODEHUB_LOADED = nil
        G.__NODEHUB_LOADED_SESSION = nil
        G.__NODEHUB_AUTOEXECED = nil
        G.__MAINUI_LOADED = nil
        G.__UI_LOADED = nil

        local src
        for i=1,5 do
            local ok, res = pcall(function() return game:HttpGet(url) end)
            if ok and type(res)=="string" and #res>0 then
                src = res
                break
            end
            --warn("[QTP] HttpGet fail #"..i, res)
            task.wait(1.5)
        end

        if not src then
            --warn("[QTP] no src -> abort")
            return
        end

        local ok3, err3 = pcall(function()
            loadstring(src)()
        end)

        --warn("[QTP] load result:", ok3, err3)
    ]]

    local chunk = template
        :gsub("__URL__", tostring(SCRIPT_URL))
        :gsub("__SAVE_DIR__", tostring(SAVE_DIR))

    local ok, err = pcall(function()
        qtp(chunk)
    end)

    if not ok then
        return false, tostring(err)
    end
    return true, "queued"
end

--------------------------------------------------
-- TELEPORT BLOCK (private/restricted)
--------------------------------------------------
TeleportService.TeleportInitFailed:Connect(function(player, result, errMsg)
    if player ~= LP then return end
    local m = string.lower(errMsg or "")
    if result == Enum.TeleportResult.Unauthorized
        or m:find("restricted")
        or m:find("private")
        or m:find("not authorized") then
        TELEPORT_BLOCKED = true
    end
end)

--------------------------------------------------
-- REJOIN CORE
--------------------------------------------------
local function doTeleport()
    if TELEPORT_BLOCKED then return false, "blocked" end
    local ok, err = pcall(function()
        TeleportService:Teleport(game.PlaceId, LP)
    end)
    if not ok then return false, tostring(err) end
    return true
end

local function canTriggerRejoin()
    local now = os.clock()
    if _rejoinInFlight then return false end
    if (now - _lastRejoinT) < MIN_REJOIN_INTERVAL then return false end
    _lastRejoinT = now
    return true
end

local function tryRejoin()
    if not canTriggerRejoin() then return end
    _rejoinInFlight = true

    local pendingUNS = (G.__UPDATE_NEW_SERVER_REJOIN_PENDING == true)
    local fileAutoReconnect = select(1, readFlagsFromFile())
    if not pendingUNS and not (fileAutoReconnect == true and AUTO_RECONNECT_ENABLED == true) then
        _rejoinInFlight = false
        return
    end
    if TELEPORT_BLOCKED then
        _rejoinInFlight = false
        return
    end

    local delaySec = pendingUNS and UPDATE_NEW_SERVER_DELAY_SEC or REJOIN_DELAY_SEC

    task.delay(delaySec, function()
        if pendingUNS then
            G.__UPDATE_NEW_SERVER_REJOIN_PENDING = nil
            _G.__UPDATE_NEW_SERVER_REJOIN_PENDING = nil
        end

        local okQ, reasonQ = QueueAutoExecIfEnabled()
        dprint("queue (auto) =>", okQ, reasonQ)

        if okQ then task.wait(0.8) end
        doTeleport()

        task.delay(2, function()
            _rejoinInFlight = false
        end)
    end)
end

local function tryShutdownRejoin()
    if _shutdownRejoinBusy then
        dprint("shutdown rejoin skipped: already busy")
        return
    end

    local fileAutoReconnect = select(1, readFlagsFromFile())
    if not (fileAutoReconnect == true and AUTO_RECONNECT_ENABLED == true) then
        dprint("shutdown rejoin skipped: auto reconnect OFF")
        return
    end

    if TELEPORT_BLOCKED then
        dprint("shutdown rejoin skipped: teleport blocked")
        return
    end

    _shutdownRejoinBusy = true
    dprint("shutdown prompt detected -> wait", SHUTDOWN_REJOIN_DELAY_SEC, "sec")

    task.delay(SHUTDOWN_REJOIN_DELAY_SEC, function()
        local _, ax = readFlagsFromFile()

        if ax == true then
            local okQ, reasonQ = QueueAutoExecIfEnabled()
            dprint("shutdown queue =>", okQ, reasonQ)

            -- HARD GATE: kalau auto_exec ON tapi queue gagal, cancel teleport
            if not okQ then
                dprint("shutdown teleport CANCEL: QTP failed while auto_exec ON:", reasonQ)
                _shutdownRejoinBusy = false
                return
            end

            task.wait(0.8)
        end

        local okTp, errTp = doTeleport()
        dprint("shutdown teleport result =>", okTp, errTp)

        task.delay(2, function()
            _shutdownRejoinBusy = false
        end)
    end)
end
--------------------------------------------------
-- DISCONNECT DETECTION
--------------------------------------------------
local function normText(s)
    s = tostring(s or "")
    s = s:gsub("%s+", " ")
    s = s:gsub("^%s+", "")
    s = s:gsub("%s+$", "")
    return s
end

local function isShutdownText(t)
    t = string.lower(normText(t))
    return t:find("server telah dimatikan", 1, true)
        or t:find("kode error: 288", 1, true)
        or t:find("server has shut down", 1, true)
        or t:find("error code: 288", 1, true)
end

local function isUpdateNewServerKickText(t)
    t = string.lower(normText(t))
    return t:find("updatenewserver", 1, true) ~= nil
        or t:find("interval reached", 1, true) ~= nil
end

local function isDisconnectText(t)
    t = string.lower(normText(t))
    return t:find("error", 1, true)
        or t:find("disconnected", 1, true)
        or t:find("lost connection", 1, true)
        or t:find("kicked", 1, true)
        or t:find("dikeluarkan", 1, true)
        or t:find("reconnect", 1, true)
        or t:find("koneksi terputus", 1, true)
        or t:find("hubungkan kembali", 1, true)
end

local function hookPrompt()
    task.spawn(function()
        local gui = CoreGui:WaitForChild("RobloxPromptGui", 30)
        if not gui then
            dprint("RobloxPromptGui not found")
            return
        end

        local overlay = gui:WaitForChild("promptOverlay", 30)
        if not overlay then
            dprint("promptOverlay not found")
            return
        end

        dprint("prompt hook attached")

        local function scan()
            for _, v in ipairs(overlay:GetDescendants()) do
                if v:IsA("TextLabel") then
                    local txt = tostring(v.Text or "")
                    if txt ~= "" then
                        dprint("label:", txt)
                    end

                    -- PRIORITAS 1: shutdown / server dimatikan / error 288
                    if isShutdownText(txt) then
                        tryShutdownRejoin()
                        return
                    end

                    -- PRIORITAS 2: kick UpdateNewServer
                    if isUpdateNewServerKickText(txt) then
                        G.__UPDATE_NEW_SERVER_REJOIN_PENDING = true
                        _G.__UPDATE_NEW_SERVER_REJOIN_PENDING = true
                        tryRejoin()
                        return
                    end

                    -- PRIORITAS 3: disconnect umum
                    if isDisconnectText(txt) then
                        tryRejoin()
                        return
                    end
                end
            end
        end

        scan()
        overlay.DescendantAdded:Connect(function(obj)
            dprint("DescendantAdded:", obj.ClassName, obj.Name)
            task.wait(0.2)
            scan()
        end)

        while true do
            task.wait(1)
            scan()
        end
    end)
end

hookPrompt()

--------------------------------------------------
-- INIT (ikuti file)
--------------------------------------------------
do
    local fileAutoReconnect = select(1, readFlagsFromFile())
    AUTO_RECONNECT_ENABLED = (fileAutoReconnect == true)
end

--------------------------------------------------
-- API FOR UI
--------------------------------------------------
function M.SetEnabled(on)
    AUTO_RECONNECT_ENABLED = (on == true)
end

function M.SetDelay(sec)
    REJOIN_DELAY_SEC = tonumber(sec) or REJOIN_DELAY_SEC
end

function M.TryRejoinNow()
    tryRejoin()
end

function M.RejoinOnce(delaySec)
    delaySec = tonumber(delaySec) or 0
    task.delay(math.max(0, delaySec), function()
        tryRejoin()
    end)
end

function M.RejoinNow()
    local _, ax = readFlagsFromFile()

    if ax == true then
        local okQ, reasonQ = QueueAutoExecIfEnabled()
        --warn("[PSReconnect] queue (manual) =>", okQ, reasonQ)

        -- ✅ keras: kalau auto_exec ON tapi QTP gagal, jangan teleport
