local function isLoadedModule(mod)
    return type(mod) == "table" and next(mod) ~= nil
end

local function hasUnreplacedShortcode(s)
    return tostring(s or ""):find("%%%[%[%[") ~= nil
end

local function httpRequest(url)
    local req =
        (syn and syn.request) or
        (http and http.request) or
        http_request or
        (fluxus and fluxus.request) or
        request

    if req then
        local res = req({ Url = url, Method = "GET" })
        if not res then error("no response") end
        return res.Body or res.body or ""
    end
    return game:HttpGet(url)
end

local function callMethod(mod, names, ...)
    if type(mod) ~= "table" then return false, "module not table" end
    for _, name in ipairs(names) do
        local fn = mod[name]
        if type(fn) == "function" then
            local ok, res = pcall(fn, mod, ...)
            if ok then return true, res end
            ok, res = pcall(fn, ...)
            if ok then return true, res end
            return false, res
        end
    end
    return false, "method not found"
end

local function moduleStart(mod, ...)
    if type(mod) ~= "table" then return false end
    if type(mod.IsRunning) == "function" then
        local ok, v = pcall(mod.IsRunning, mod)
        if ok and v == true then return true end
    end
    if mod.running == true then return true end
    local ok = callMethod(mod, { "Start", "start" }, ...)
    return ok == true
end

local function resolveFactoryResult(res, def)
    if type(res) == "table" then
        return true, res
    end
    if type(res) == "function" then
        local ok2, res2 = pcall(res)
        if ok2 and type(res2) == "table" then
            return true, res2
        end
    end
    if def and def.key == "antiafk" then
        local cached = G.AntiAFK or G.antiafk or rawget(_G, "AntiAFK")
        if type(cached) == "table" then
            return true, cached
        end
    end
    return false, "factory result bukan table"
end

local function runFactory(def)
    local okRun, res = pcall(def.factory)
    if not okRun then
        return false, "factory error: " .. tostring(res)
    end
    return resolveFactoryResult(res, def)
end

local function registerAutoSprinklerSectionLate(uiRef)
    if type(uiRef) ~= "table" then return end

    local ctx = G.__GAG2_AUTO_TAB_CTX or rawget(_G, "__GAG2_AUTO_TAB_CTX")
    if type(ctx) ~= "table" and type(uiRef) == "table" then
        local State = G.__GAG2_STATE or rawget(_G, "__GAG2_STATE")

        local function saveNow()
            if G.__GAG2_RESETTING == true then return end
            if type(State) == "table" and type(State.saveFromUi) == "function" then
                pcall(State.saveFromUi)
            elseif uiRef and type(uiRef.SaveState) == "function" then
                pcall(function() uiRef:SaveState() end)
            end
        end

        local function getAuto(key)
            if type(State) == "table" and type(State.getAuto) == "function" then
                local ok, result = pcall(State.getAuto, key)
                if ok and type(result) == "table" then return result end
            end
            local m = rawget(_G, "MAIN") or G.MAIN
            if type(m) == "table" and type(m.auto) == "table" then
                return m.auto[key] or {}
            end
            return {}
        end

        local function patchAuto(key, partial, syncFn)
            if type(State) == "table" and type(State.patchAuto) == "function" then
                pcall(State.patchAuto, key, partial)
            else
                local m = rawget(_G, "MAIN") or G.MAIN
                if type(m) == "table" and type(partial) == "table" then
                    m.auto = m.auto or {}
                    local cur = type(m.auto[key]) == "table" and m.auto[key] or {}
                    for k, v in pairs(partial) do cur[k] = v end
                    m.auto[key] = cur
                    G.MAIN = m
                    _G.MAIN = m
                end
            end
            if syncFn then pcall(syncFn) end
            saveNow()
        end

        local function patchAutoOnly(key, partial)
            if type(State) == "table" and type(State.patchAuto) == "function" then
                pcall(State.patchAuto, key, partial, { noSync = true })
            else
                local m = rawget(_G, "MAIN") or G.MAIN
                if type(m) == "table" and type(partial) == "table" then
                    m.auto = m.auto or {}
                    local cur = type(m.auto[key]) == "table" and m.auto[key] or {}
                    for k, v in pairs(partial) do cur[k] = v end
                    m.auto[key] = cur
                    G.MAIN = m
                    _G.MAIN = m
                end
            end
        end

        local function registerFlush(id, fn)
            if type(State) == "table" and type(State.registerFlush) == "function" then
                pcall(State.registerFlush, id, fn)
            end
        end

        local function toggleApiGet(apiKey)
            local api = G[apiKey] or rawget(_G, apiKey)
            if type(api) == "table" and type(api.get) == "function" then
                return api.get() == true
            end
            return nil
        end

        local function cleanSelectedMap(selectedMap)
            local out = {}
            if type(selectedMap) ~= "table" then return out end
            for k, v in pairs(selectedMap) do
                if v == true then
                    out[tostring(k)] = true
                elseif type(k) == "number" and (type(v) == "string" or type(v) == "number") then
                    local s = tostring(v)
                    if s ~= "" then out[s] = true end
                elseif type(k) == "string" and type(v) == "table" then
                    out[tostring(k)] = true
                end
            end
            return out
        end

        local function mapToArray(map)
            local arr = {}
            if type(map) == "table" then
                for k, v in pairs(map) do
                    if v == true then arr[#arr + 1] = tostring(k) end
                end
            end
            table.sort(arr)
            return arr
        end

        local function arrayToMap(arr)
            local m = {}
            if type(arr) == "table" then
                for _, v in ipairs(arr) do
                    if v ~= nil and tostring(v) ~= "" then m[tostring(v)] = true end
                end
            end
            return m
        end

        ctx = {
            ui               = uiRef,
            getAuto          = getAuto,
            patchAuto        = patchAuto,
            patchAutoOnly    = patchAutoOnly,
            registerFlush    = registerFlush,
            cleanSelectedMap = cleanSelectedMap,
            arrayToMap       = arrayToMap,
            mapToArray       = mapToArray,
            toggleApiGet     = toggleApiGet,
        }
    end

    local Sec = G.SectionAutoSprinkler or rawget(_G, "SectionAutoSprinkler")
    if type(ctx) ~= "table" or type(Sec) ~= "table" or type(Sec.Register) ~= "function" then
        warnlog("Auto Sprinkler section skip: module/ctx missing")
        return
    end
    local ok, err = pcall(Sec.Register, ctx)
    if ok then
        G.__GAG2_AUTO_SPRINKLER_UI_DONE = true
        _G.__GAG2_AUTO_SPRINKLER_UI_DONE = true
    else
        warnlog("Auto Sprinkler section error:", tostring(err))
    end
end

