local function _normalizeBuyItems(items)
    if type(items) ~= "table" then return {} end

    local arr = {}
    for _, v in ipairs(items) do
        if v ~= nil and tostring(v) ~= "" then
            arr[#arr + 1] = tostring(v)
        end
    end
    if #arr > 0 then
        table.sort(arr)
        return arr
    end

    for k, v in pairs(items) do
        if v == true or v == 1 or v == "true" then
            arr[#arr + 1] = tostring(k)
        end
    end
    table.sort(arr)
    return arr
end

local function _normalizeBuyCategory(cat)
    cat = type(cat) == "table" and cat or { enabled = false, items = {} }
    cat.enabled = (cat.enabled == true)
    cat.items = _normalizeBuyItems(cat.items)
    return cat
end

local function _normalizeAutoBuyState(buy)
    buy = type(buy) == "table" and buy or _deepCopy(DEFAULT_AUTO.buy)
    buy.delay = nil
    buy.seed = _normalizeBuyCategory(buy.seed)
    buy.gear = _normalizeBuyCategory(buy.gear)
    buy.props = _normalizeBuyCategory(buy.props)
    buy.pet = _normalizeBuyCategory(buy.pet)
    buy.pet.auto_tame = (buy.pet.auto_tame == true)
    local mult = tonumber(buy.pet.max_price_mult)
    buy.pet.max_price_mult = (mult and mult >= 1) and mult or 2
    return buy
end

