--------------------------------------------------
-- Auto Gift globals
--------------------------------------------------
local function _giftCategoryKeysFromState(st)
    local keys = {}
    local seen = {}
    local function add(key)
        key = tostring(key or "")
        if key ~= "" and not seen[key] then
            keys[#keys + 1] = key
            seen[key] = true
        end
    end
    for _, key in ipairs(_giftCatalogKeys()) do
        add(key)
    end
    if type(st) == "table" then
        if type(st.categories) == "table" then
            for key in pairs(st.categories) do
                if not seen[key] then
                    keys[#keys + 1] = key
                    seen[key] = true
                end
            end
        end
        if type(st.selected) == "table" then
            for key in pairs(st.selected) do
                if not seen[key] then
                    keys[#keys + 1] = key
                    seen[key] = true
                end
            end
        end
    end
    return keys
end

local function _migrateLegacyGiftKeys(st)
    if type(st) ~= "table" then return end
    st.categories = type(st.categories) == "table" and st.categories or {}
    st.selected = type(st.selected) == "table" and st.selected or {}
    st.send_totals = type(st.send_totals) == "table" and st.send_totals or {}
    local aliases = { Tools = "Pets", EmptyPots = "DustyPots", InstyPots = "DustyPots" }
    for legacy, canon in pairs(aliases) do
        if st.categories[legacy] == true then
            st.categories[canon] = true
            st.categories[legacy] = false
        end
        if type(st.selected[legacy]) == "table" and next(st.selected[legacy]) then
            st.selected[canon] = st.selected[canon] or {}
            for k, v in pairs(_normalizeBuyItems(st.selected[legacy])) do
                if v == true then st.selected[canon][k] = true end
            end
            st.selected[legacy] = {}
        end
        if st.send_totals[legacy] ~= nil and st.send_totals[canon] == nil then
            st.send_totals[canon] = st.send_totals[legacy]
        end
    end
end

local function _normalizeAutoGiftState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.gift)
    _migrateLegacyGiftKeys(st)
    st.enabled = (st.enabled == true)
    st.auto_send = (st.auto_send == true)
    st.auto_claim_mail = (st.auto_claim_mail == true)
    st.auto_accept_gift = (st.auto_accept_gift == true)
    st.recipient_username = tostring(st.recipient_username or "")
    st.recipient_user_id = math.floor(tonumber(st.recipient_user_id) or 0)
    st.recipient_display = tostring(st.recipient_display or "")
    st.skip_equipped = (st.skip_equipped ~= false)
    st.max_per_batch = math.floor(math.max(1, math.min(20, tonumber(st.max_per_batch) or 20)))
    st.note = tostring(st.note or "")
    st.delay_sec = tonumber(st.delay_sec) or 1
    if st.delay_sec == 3 or st.delay_sec == 6 or st.delay_sec == 8 then st.delay_sec = 1 end
    if st.delay_sec < 1 then st.delay_sec = 1 end
    if st.delay_sec > 120 then st.delay_sec = 120 end

    st.categories = type(st.categories) == "table" and st.categories or {}
    local catKeys = _giftCategoryKeysFromState(st)
    for _, key in ipairs(catKeys) do
        st.categories[key] = (st.categories[key] == true)
    end

    st.selected = type(st.selected) == "table" and st.selected or {}
    for _, key in ipairs(catKeys) do
        st.selected[key] = _normalizeBuyItems(st.selected[key])
    end

    st.send_totals = type(st.send_totals) == "table" and st.send_totals or {}
    for _, key in ipairs(catKeys) do
        local n = math.floor(tonumber(st.send_totals[key]) or 20)
        if n < 1 then n = 1 end
        st.send_totals[key] = n
    end

    st.category_mode = tostring(st.category_mode or "single"):lower()
    if st.category_mode ~= "multi" then st.category_mode = "single" end

    local slm = tostring(st.send_list_mode or "loop"):lower():gsub("%s+", "")
    if slm == "sendtotal" or slm == "send_total" or slm == "total" then
        st.send_list_mode = "send_total"
    else
        st.send_list_mode = "loop"
    end

    st.send_total = math.floor(tonumber(st.send_total) or 20)
    if st.send_total < 1 then st.send_total = 1 end

    st.after_send_mode = tostring(st.after_send_mode or "keep"):lower()
    if st.after_send_mode ~= "reset" then st.after_send_mode = "keep" end

    return st
end

local function _normalizeAutoNormalGiftState(st)
    st = type(st) == "table" and st or _deepCopy(DEFAULT_AUTO.normalGift)
    st.target_user_id = math.floor(tonumber(st.target_user_id) or 0)
    st.target_name = tostring(st.target_name or "")
    local cat = tostring(st.category or "Seeds")
    if cat == "" then cat = "Seeds" end
    st.category = cat
    st.selected = _normalizeBuyItems(st.selected)
    st.send_total = math.floor(math.max(1, math.min(50, tonumber(st.send_total) or 1)))
    return st
end

local function _giftSelectedMapsFromMain(gift)
    local out = {}
    gift = type(gift) == "table" and gift or {}
    local sel = type(gift.selected) == "table" and gift.selected or {}
    local catKeys = _giftCategoryKeysFromState(gift)
    for _, key in ipairs(catKeys) do
        out[key] = _arrayToMap(sel[key])
    end
    return out
end

local function _giftSelectedArraysFromMaps(maps)
    local out = {}
    maps = type(maps) == "table" and maps or {}
    local catKeys = _giftCategoryKeysFromState({ selected = maps })
    for _, key in ipairs(catKeys) do
        out[key] = _mapToArray(maps[key])
    end
    return out
end

local function _replaceGiftStoreFromMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.gift = _normalizeAutoGiftState(MAIN.auto.gift)
    local st = MAIN.auto.gift

    G.__GAG2_AUTO_GIFT = {
        enabled = st.enabled,
        auto_send = st.auto_send,
        auto_claim_mail = st.auto_claim_mail,
        recipient_username = st.recipient_username,
        recipient_user_id = st.recipient_user_id,
        recipient_display = st.recipient_display,
        categories = _deepCopy(st.categories),
        selected = _giftSelectedMapsFromMain(st),
        skip_equipped = st.skip_equipped,
        max_per_batch = st.max_per_batch,
        note = st.note,
        delay_sec = st.delay_sec,
        send_totals = _deepCopy(st.send_totals),
        category_mode = st.category_mode,
        send_list_mode = st.send_list_mode,
        send_total = st.send_total,
        after_send_mode = st.after_send_mode,
        _hydrated = true,
    }
    _G.__GAG2_AUTO_GIFT = G.__GAG2_AUTO_GIFT
    G.__GAG2_GIFT_STORE_EPOCH = (tonumber(G.__GAG2_GIFT_STORE_EPOCH) or 0) + 1
    _G.__GAG2_GIFT_STORE_EPOCH = G.__GAG2_GIFT_STORE_EPOCH

    G.AUTO_GIFT_ENABLED = st.enabled
    _G.AUTO_GIFT_ENABLED = st.enabled
    G.AUTO_GIFT_AUTO_SEND = st.auto_send
    _G.AUTO_GIFT_AUTO_SEND = st.auto_send
    STATE.auto_gift = _deepCopy(st)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function syncAutoGiftGlobalsFromMain()
    local mainRef = _getMainRef()
    if mainRef ~= MAIN then MAIN = mainRef end

    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.gift = _normalizeAutoGiftState(MAIN.auto.gift)
    local st = MAIN.auto.gift

    if type(G.__GAG2_AUTO_GIFT) ~= "table" then
        G.__GAG2_AUTO_GIFT = {}
    end
    local store = G.__GAG2_AUTO_GIFT

    store.enabled = (st.enabled == true)
    store.auto_send = (st.auto_send == true)
    store.auto_claim_mail = (st.auto_claim_mail == true)
    store.auto_accept_gift = (st.auto_accept_gift == true)

    if st.recipient_username ~= "" then
        store.recipient_username = st.recipient_username
    elseif store.recipient_username == nil then
        store.recipient_username = ""
    end
    if (tonumber(st.recipient_user_id) or 0) > 0 then
        store.recipient_user_id = math.floor(tonumber(st.recipient_user_id))
    elseif store.recipient_user_id == nil then
        store.recipient_user_id = 0
    end
    if st.recipient_display ~= "" then
        store.recipient_display = st.recipient_display
    elseif store.recipient_display == nil then
        store.recipient_display = ""
    end

    if st.note ~= nil and tostring(st.note) ~= "" then
        store.note = tostring(st.note)
    elseif store.note == nil then
        store.note = ""
    end
    if tonumber(st.delay_sec) then
        store.delay_sec = tonumber(st.delay_sec)
    elseif store.delay_sec == nil then
        store.delay_sec = 1
    end
    if tonumber(st.max_per_batch) then
        store.max_per_batch = tonumber(st.max_per_batch)
    elseif store.max_per_batch == nil then
        store.max_per_batch = 20
    end
    if st.skip_equipped ~= nil then
        store.skip_equipped = (st.skip_equipped == true)
    elseif store.skip_equipped == nil then
        store.skip_equipped = true
    end

    store.send_totals = type(store.send_totals) == "table" and store.send_totals or {}
    local catKeys = _giftCategoryKeysFromState(st)
    if type(st.send_totals) == "table" then
        for _, key in ipairs(catKeys) do
            store.send_totals[key] = st.send_totals[key]
        end
    end

    store.categories = type(store.categories) == "table" and store.categories or {}
    for _, key in ipairs(catKeys) do
        store.categories[key] = (st.categories[key] == true)
    end

    store.selected = type(store.selected) == "table" and store.selected or {}
    local fromMain = _giftSelectedMapsFromMain(st)
    for _, key in ipairs(catKeys) do
        local cur = _arrayToMap(store.selected[key])
        if next(fromMain[key]) then
            store.selected[key] = fromMain[key]
        elseif next(cur) then
            store.selected[key] = cur
        else
            store.selected[key] = {}
        end
    end

    store.category_mode = st.category_mode
    store.send_list_mode = st.send_list_mode
    store.send_total = st.send_total
    store.after_send_mode = st.after_send_mode

    store._hydrated = true
    _G.__GAG2_AUTO_GIFT = store

    local enabled = store.enabled == true
    local autoSend = store.auto_send == true

    G.AUTO_GIFT_ENABLED = enabled
    _G.AUTO_GIFT_ENABLED = enabled
    G.AUTO_GIFT_AUTO_SEND = autoSend
    _G.AUTO_GIFT_AUTO_SEND = autoSend

    st.enabled = enabled
    st.auto_send = autoSend
    MAIN.auto.gift = _normalizeAutoGiftState(st)
    STATE.auto_gift = _deepCopy(MAIN.auto.gift)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function syncNormalGiftGlobalsFromMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.normalGift = _normalizeAutoNormalGiftState(MAIN.auto.normalGift)
    local st = MAIN.auto.normalGift

    G.__GAG2_NORMAL_GIFT = {
        target_user_id = st.target_user_id,
        target_name = st.target_name,
        category = st.category,
        selected = _arrayToMap(st.selected),
        send_total = st.send_total,
        _hydrated = true,
    }
    _G.__GAG2_NORMAL_GIFT = G.__GAG2_NORMAL_GIFT

    STATE.auto_normal_gift = _deepCopy(st)
    G.MAIN = MAIN
    _G.MAIN = MAIN

    local ng = G.NormalGift or G.NormalGiftModule or rawget(_G, "NormalGift")
    if type(ng) == "table" and type(ng.ApplyConfig) == "function" then
        pcall(ng.ApplyConfig, ng, G.__GAG2_NORMAL_GIFT)
    end
end

