            auto_claim_mail = (store.auto_claim_mail == true),
            auto_accept_gift = (store.auto_accept_gift == true),
            recipient_username = store.recipient_username,
            recipient_user_id = store.recipient_user_id,
            recipient_display = store.recipient_display,
