    if type(G.__GAG2_AUTO_GIFT) ~= "table" then
        G.__GAG2_AUTO_GIFT = {}
    end
    G.__GAG2_AUTO_GIFT.enabled = MAIN.auto.gift.enabled
    G.__GAG2_AUTO_GIFT.auto_send = MAIN.auto.gift.auto_send
    G.__GAG2_AUTO_GIFT.auto_claim_mail = MAIN.auto.gift.auto_claim_mail
    G.__GAG2_AUTO_GIFT.auto_accept_gift = MAIN.auto.gift.auto_accept_gift
    G.__GAG2_AUTO_GIFT.recipient_username = MAIN.auto.gift.recipient_username
