local function _snapshotPetFinderForSave(pf)
    pf = (type(pf) == "table") and pf or {}
    local rarities = pf.filter_rarities
    if type(rarities) ~= "table" then
        rarities = {}
    end
    if #rarities == 0 and pf.filter_rarity and pf.filter_rarity ~= "" then
        rarities = { tostring(pf.filter_rarity) }
    end
    local cleaned = {}
    for _, v in ipairs(rarities) do
        if type(v) == "string" and v ~= "" then
            cleaned[#cleaned + 1] = v
        end
    end
    table.sort(cleaned)
    local pets = pf.target_pets
    if type(pets) ~= "table" then
        pets = {}
    end
    local cleanedPets = {}
    for _, v in ipairs(pets) do
        if type(v) == "string" and v ~= "" then
            cleanedPets[#cleanedPets + 1] = v
        end
    end
    table.sort(cleanedPets)
    return {
        filter_rarities = cleaned,
        auto_refresh_list = (pf.auto_refresh_list ~= false),
        auto_hop = (pf.auto_hop == true),
        target_pets = cleanedPets,
    }
end

