local function applyReduceFpsModule()
    local RF = G.ReduceFPS or rawget(_G, "ReduceFPS")
    if type(RF) ~= "table" then return end
    if type(RF.SyncFromGlobals) == "function" then
        pcall(RF.SyncFromGlobals, RF)
    elseif type(RF.SetEnabled) == "function" then
        pcall(RF.SetEnabled, RF, REDUCE_FPS_ENABLED == true)
    end
end

G.applyReduceFpsModule = applyReduceFpsModule
