local function syncAutoBuyGlobalsToMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.buy = MAIN.auto.buy or _deepCopy(DEFAULT_AUTO.buy)
    local buy = MAIN.auto.buy

    local seedOn = G.AUTO_BUY_SEED_ENABLED
    if seedOn == nil then seedOn = rawget(_G, "AUTO_BUY_SEED_ENABLED") end
    if seedOn ~= nil then buy.seed = buy.seed or {}; buy.seed.enabled = (seedOn == true) end

    local gearOn = G.AUTO_BUY_GEAR_ENABLED
    if gearOn == nil then gearOn = rawget(_G, "AUTO_BUY_GEAR_ENABLED") end
    if gearOn ~= nil then buy.gear = buy.gear or {}; buy.gear.enabled = (gearOn == true) end

    local propsOn = G.AUTO_BUY_PROPS_ENABLED
    if propsOn == nil then propsOn = rawget(_G, "AUTO_BUY_PROPS_ENABLED") end
    if propsOn ~= nil then buy.props = buy.props or {}; buy.props.enabled = (propsOn == true) end

    local store = G.__GAG2_BUY_PET or _G.__GAG2_BUY_PET
    buy.pet = buy.pet or {}
    local mainPet = buy.pet
    local storeOn = type(store) == "table" and store.enabled == true
    local mainOn = mainPet.enabled == true
    local globOn = G.AUTO_BUY_PET_ENABLED == true or rawget(_G, "AUTO_BUY_PET_ENABLED") == true
    local tameStore = type(store) == "table" and store.auto_tame == true
    local tameMain = mainPet.auto_tame == true
    local tameGlob = G.AUTO_TAME_PET_ENABLED == true or rawget(_G, "AUTO_TAME_PET_ENABLED") == true

    if type(store) == "table" then
        buy.pet.enabled = storeOn or mainOn or globOn
        buy.pet.auto_tame = tameStore or tameMain or tameGlob
        local sm = tonumber(store.max_price_mult) or tonumber(mainPet.max_price_mult) or 2
        buy.pet.max_price_mult = (sm >= 1) and sm or 2
        if type(store.selected) == "table" and next(store.selected) then
            buy.pet.items = _mapToArray(store.selected)
        elseif type(mainPet.items) == "table" and next(mainPet.items) then
            buy.pet.items = _normalizeBuyItems(mainPet.items)
        else
            local petMap = G.BUY_PET_SELECTED or rawget(_G, "BUY_PET_SELECTED")
            if type(petMap) == "table" then
                buy.pet.items = _mapToArray(petMap)
            end
        end
    else
        local petOn = G.AUTO_BUY_PET_ENABLED
        if petOn == nil then petOn = rawget(_G, "AUTO_BUY_PET_ENABLED") end
        if petOn ~= nil then buy.pet = buy.pet or {}; buy.pet.enabled = (petOn == true) end

        local tameOn = G.AUTO_TAME_PET_ENABLED
        if tameOn == nil then tameOn = rawget(_G, "AUTO_TAME_PET_ENABLED") end
        if tameOn ~= nil then buy.pet = buy.pet or {}; buy.pet.auto_tame = (tameOn == true) end

        local mult = G.AUTO_BUY_PET_MAX_PRICE_MULT
        if mult == nil then mult = rawget(_G, "AUTO_BUY_PET_MAX_PRICE_MULT") end
        if mult ~= nil then
            mult = tonumber(mult) or 2
            buy.pet = buy.pet or {}
            buy.pet.max_price_mult = (mult >= 1) and mult or 2
        end

        local petMap = G.BUY_PET_SELECTED or rawget(_G, "BUY_PET_SELECTED")
        if type(petMap) == "table" then buy.pet = buy.pet or {}; buy.pet.items = _mapToArray(petMap) end
    end

    local seedMap = G.BUY_SEED_SELECTED or rawget(_G, "BUY_SEED_SELECTED")
    if type(seedMap) == "table" then buy.seed = buy.seed or {}; buy.seed.items = _mapToArray(seedMap) end

    local gearMap = G.BUY_GEAR_SELECTED or rawget(_G, "BUY_GEAR_SELECTED")
    if type(gearMap) == "table" then buy.gear = buy.gear or {}; buy.gear.items = _mapToArray(gearMap) end

    local propsMap = G.BUY_PROPS_SELECTED or rawget(_G, "BUY_PROPS_SELECTED")
    if type(propsMap) == "table" then buy.props = buy.props or {}; buy.props.items = _mapToArray(propsMap) end

    MAIN.auto.buy = _normalizeAutoBuyState(buy)

    if type(G.__GAG2_BUY_PET) ~= "table" then
        G.__GAG2_BUY_PET = {}
    end
    G.__GAG2_BUY_PET.enabled = MAIN.auto.buy.pet.enabled
    G.__GAG2_BUY_PET.auto_tame = MAIN.auto.buy.pet.auto_tame
    G.__GAG2_BUY_PET.max_price_mult = MAIN.auto.buy.pet.max_price_mult
    G.__GAG2_BUY_PET.selected = _arrayToMap(MAIN.auto.buy.pet.items)
    G.__GAG2_BUY_PET._hydrated = true
    _G.__GAG2_BUY_PET = G.__GAG2_BUY_PET

    G.MAIN = MAIN
    _G.MAIN = MAIN
end

