    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.claimSeed = MAIN.auto.claimSeed or _deepCopy(DEFAULT_AUTO.claimSeed)

    local mainOn = MAIN.auto.claimSeed.enabled == true

    local store = G.__GAG2_CLAIM_SEED or _G.__GAG2_CLAIM_SEED
    local storeOn = type(store) == "table" and store.enabled == true

    local on = G.AUTO_CLAIM_SEED_ENABLED
    if on == nil then on = rawget(_G, "AUTO_CLAIM_SEED_ENABLED") end
    if on == nil then on = AUTO_CLAIM_SEED_ENABLED end
    local globOn = (on == true)

    MAIN.auto.claimSeed.enabled = (mainOn == true) or (storeOn == true) or (globOn == true)

    MAIN.auto.claimSeed = _normalizeAutoClaimSeedState(MAIN.auto.claimSeed)

    if type(G.__GAG2_CLAIM_SEED) ~= "table" then
        G.__GAG2_CLAIM_SEED = { enabled = MAIN.auto.claimSeed.enabled }
    else
        G.__GAG2_CLAIM_SEED.enabled = MAIN.auto.claimSeed.enabled
    end
    _G.__GAG2_CLAIM_SEED = G.__GAG2_CLAIM_SEED

    G.MAIN = MAIN
    _G.MAIN = MAIN
end

-- __GAG2_FLUSH_TO_MAIN di-assign setelah _prepareMainForSave() didefinisikan.

--------------------------------------------------
-- UpdateNewServer helpers
--------------------------------------------------
local function __clampUpdateNewServerMinute(n)
    n = tonumber(n) or 30
    n = math.floor(n + 0.5)
    if n < 1 then n = 1 end
    if n > 300 then n = 300 end
    return n
end

local function __truthy(v)
    return (v == true) or (v == 1) or (v == "true") or (v == "1")
end

local __unsApplied = { enabled = nil, minute = nil }

local function readUpdateNewServerGlobals()
    local enabled, minute

    if type(MAIN.misc) == "table" and type(MAIN.misc.rejoin) == "table" then
        local rj = MAIN.misc.rejoin
        if rj.update_new_server ~= nil then
            enabled = __truthy(rj.update_new_server)
        end
        if rj.update_new_server_minute ~= nil then
            minute = rj.update_new_server_minute
        end
    end

    if type(G.__UNS_SAVED) == "table" then
        if enabled == nil and G.__UNS_SAVED.enabled ~= nil then
            enabled = __truthy(G.__UNS_SAVED.enabled)
        end
        if minute == nil and G.__UNS_SAVED.minute ~= nil then
            minute = G.__UNS_SAVED.minute
        end
    end

    local env = (getgenv and getgenv()) or _G
    if enabled == nil then
        enabled = rawget(env, "UPDATE_NEW_SERVER_ENABLED")
        if enabled == nil then enabled = rawget(_G, "UPDATE_NEW_SERVER_ENABLED") end
    end
    if minute == nil then
        minute = rawget(env, "UPDATE_NEW_SERVER_MINUTE")
        if minute == nil then minute = rawget(_G, "UPDATE_NEW_SERVER_MINUTE") end
    end

    enabled = (enabled == true)
    minute  = __clampUpdateNewServerMinute(minute)

    env.UPDATE_NEW_SERVER_ENABLED = enabled
    _G.UPDATE_NEW_SERVER_ENABLED  = enabled
    G.UPDATE_NEW_SERVER_ENABLED   = enabled
    env.UPDATE_NEW_SERVER_MINUTE  = minute
    _G.UPDATE_NEW_SERVER_MINUTE   = minute
    G.UPDATE_NEW_SERVER_MINUTE    = minute

    return enabled, minute
end

local function writeUpdateNewServerGlobals(enabled, minute)
    local env = (getgenv and getgenv()) or _G
    enabled = (enabled == true)
    minute  = __clampUpdateNewServerMinute(minute)

    env.UPDATE_NEW_SERVER_ENABLED = enabled
    _G.UPDATE_NEW_SERVER_ENABLED  = enabled
    G.UPDATE_NEW_SERVER_ENABLED   = enabled
    UPDATE_NEW_SERVER_ENABLED     = enabled

    env.UPDATE_NEW_SERVER_MINUTE = minute
    _G.UPDATE_NEW_SERVER_MINUTE  = minute
    G.UPDATE_NEW_SERVER_MINUTE   = minute
    UPDATE_NEW_SERVER_MINUTE       = minute

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    MAIN.misc.rejoin.update_new_server        = enabled
    MAIN.misc.rejoin.update_new_server_minute = minute
    G.MAIN = MAIN
    _G.MAIN = MAIN

    STATE.rejoin = type(STATE.rejoin) == "table" and STATE.rejoin or {}
    STATE.rejoin.update_new_server        = enabled
    STATE.rejoin.update_new_server_minute = minute

    G.__UNS_SAVED = { enabled = enabled, minute = minute }
    __unsApplied.enabled = nil
    __unsApplied.minute  = nil
end

local function applyUpdateNewServerModule(forcedEnabled, forcedMinute)
    local enabled, minute
    if forcedEnabled ~= nil then
        enabled = __truthy(forcedEnabled)
        minute  = __clampUpdateNewServerMinute(forcedMinute)
    else
        enabled, minute = readUpdateNewServerGlobals()
    end

    local UNS = G.UpdateNewServer or _G.UpdateNewServer
    if type(UNS) ~= "table" then return end

    if forcedEnabled == nil and forcedMinute == nil
        and __unsApplied.enabled == enabled
        and __unsApplied.minute == minute then
        return
    end

    if type(UNS.Apply) == "function" then
        pcall(function() UNS:Apply(enabled, minute) end)
        __unsApplied.enabled = enabled
        __unsApplied.minute  = minute
        return
    end

    pcall(function() UNS:SetEnabled(enabled) end)
    pcall(function() UNS:SetMinute(minute) end)
    if enabled == true then
        if type(UNS.Start) == "function" then pcall(function() UNS:Start() end) end
    elseif type(UNS.Stop) == "function" then
        pcall(function() UNS:Stop("disabled") end)
    end

    __unsApplied.enabled = enabled
    __unsApplied.minute  = minute
end

local function publishUpdateNewServer()
    local enabled, minute = readUpdateNewServerGlobals()
    writeUpdateNewServerGlobals(enabled, minute)
    applyUpdateNewServerModule()
end

G.readUpdateNewServerGlobals   = readUpdateNewServerGlobals
_G.readUpdateNewServerGlobals  = readUpdateNewServerGlobals
G.writeUpdateNewServerGlobals  = writeUpdateNewServerGlobals
_G.writeUpdateNewServerGlobals = writeUpdateNewServerGlobals
G.applyUpdateNewServerModule   = applyUpdateNewServerModule
_G.applyUpdateNewServerModule  = applyUpdateNewServerModule
G.publishUpdateNewServer       = publishUpdateNewServer
_G.publishUpdateNewServer      = publishUpdateNewServer

local __autoHopApplied = { enabled = nil, current = nil, max = nil, delay = nil }

local function readAutoHopGlobals()
    local enabled, current, max, delay

    if type(MAIN.misc) == "table" and type(MAIN.misc.rejoin) == "table" then
        local ah = MAIN.misc.rejoin.auto_hop
        if type(ah) == "table" then
            if ah.enabled ~= nil then enabled = (ah.enabled == true) end
            if tonumber(ah.current_player) ~= nil then current = tonumber(ah.current_player) end
            if tonumber(ah.max_player) ~= nil then max = tonumber(ah.max_player) end
            if tonumber(ah.teleport_delay) ~= nil then delay = tonumber(ah.teleport_delay) end
        end
    end

    if type(G.__AUTO_HOP_SAVED) == "table" then
        if enabled == nil and G.__AUTO_HOP_SAVED.enabled ~= nil then
            enabled = (G.__AUTO_HOP_SAVED.enabled == true)
        end
        if current == nil and tonumber(G.__AUTO_HOP_SAVED.current) ~= nil then
            current = tonumber(G.__AUTO_HOP_SAVED.current)
        end
        if max == nil and tonumber(G.__AUTO_HOP_SAVED.max) ~= nil then
            max = tonumber(G.__AUTO_HOP_SAVED.max)
        end
        if delay == nil and tonumber(G.__AUTO_HOP_SAVED.delay) ~= nil then
            delay = tonumber(G.__AUTO_HOP_SAVED.delay)
        end
    end

    local env = (getgenv and getgenv()) or _G
    if enabled == nil then
        enabled = rawget(env, "AUTO_HOP_ENABLED")
        if enabled == nil then enabled = rawget(_G, "AUTO_HOP_ENABLED") end
    end
    if current == nil then
        current = rawget(env, "AUTO_HOP_CURRENT_PLAYER")
        if current == nil then current = rawget(_G, "AUTO_HOP_CURRENT_PLAYER") end
    end
    if max == nil then
        max = rawget(env, "AUTO_HOP_MAX_PLAYER")
        if max == nil then max = rawget(_G, "AUTO_HOP_MAX_PLAYER") end
    end
    if delay == nil then
        delay = rawget(env, "AUTO_HOP_TELEPORT_DELAY")
        if delay == nil then delay = rawget(_G, "AUTO_HOP_TELEPORT_DELAY") end
    end

    enabled = (enabled == true)
    current = math.floor(math.max(2, math.min(100, tonumber(current) or 2)))
    max = math.floor(math.max(1, math.min(100, tonumber(max) or 1)))
    delay = math.floor(math.max(0, math.min(600, tonumber(delay) or 60)))

    env.AUTO_HOP_ENABLED = enabled
    _G.AUTO_HOP_ENABLED = enabled
    G.AUTO_HOP_ENABLED = enabled
    AUTO_HOP_ENABLED = enabled

    env.AUTO_HOP_CURRENT_PLAYER = current
    _G.AUTO_HOP_CURRENT_PLAYER = current
    G.AUTO_HOP_CURRENT_PLAYER = current
    AUTO_HOP_CURRENT_PLAYER = current

    env.AUTO_HOP_MAX_PLAYER = max
    _G.AUTO_HOP_MAX_PLAYER = max
    G.AUTO_HOP_MAX_PLAYER = max
    AUTO_HOP_MAX_PLAYER = max

    env.AUTO_HOP_TELEPORT_DELAY = delay
    _G.AUTO_HOP_TELEPORT_DELAY = delay
    G.AUTO_HOP_TELEPORT_DELAY = delay

    return enabled, current, max, delay
end

local function writeAutoHopGlobals(enabled, current, max, delay)
    local env = (getgenv and getgenv()) or _G
    enabled = (enabled == true)
    current = math.floor(math.max(2, math.min(100, tonumber(current) or 2)))
    max = math.floor(math.max(1, math.min(100, tonumber(max) or 1)))
    delay = math.floor(math.max(0, math.min(600, tonumber(delay) or 60)))

    env.AUTO_HOP_ENABLED = enabled
    _G.AUTO_HOP_ENABLED = enabled
    G.AUTO_HOP_ENABLED = enabled
    AUTO_HOP_ENABLED = enabled

    env.AUTO_HOP_CURRENT_PLAYER = current
    _G.AUTO_HOP_CURRENT_PLAYER = current
    G.AUTO_HOP_CURRENT_PLAYER = current
    AUTO_HOP_CURRENT_PLAYER = current

    env.AUTO_HOP_MAX_PLAYER = max
    _G.AUTO_HOP_MAX_PLAYER = max
    G.AUTO_HOP_MAX_PLAYER = max
    AUTO_HOP_MAX_PLAYER = max

    env.AUTO_HOP_TELEPORT_DELAY = delay
    _G.AUTO_HOP_TELEPORT_DELAY = delay
    G.AUTO_HOP_TELEPORT_DELAY = delay

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local ah = type(MAIN.misc.rejoin.auto_hop) == "table"
        and MAIN.misc.rejoin.auto_hop
        or _deepCopy(DEFAULT_MISC.rejoin.auto_hop)
    local visited = ah.visited
    ah.enabled = enabled
    ah.current_player = current
    ah.max_player = max
    ah.teleport_delay = delay
    if type(visited) == "table" then ah.visited = visited end
    MAIN.misc.rejoin.auto_hop = ah
    G.MAIN = MAIN
    _G.MAIN = MAIN

    STATE.rejoin = type(STATE.rejoin) == "table" and STATE.rejoin or {}
    STATE.rejoin.auto_hop = _deepCopy(ah)

    G.__AUTO_HOP_SAVED = { enabled = enabled, current = current, max = max, delay = delay }
    __autoHopApplied.enabled = nil
    __autoHopApplied.current = nil
    __autoHopApplied.max = nil
    __autoHopApplied.delay = nil
end

local function applyAutoHopModule(forcedEnabled, forcedCurrent, forcedMax, forcedDelay)
    local enabled, current, max, delay
    if forcedEnabled ~= nil then
        enabled = (forcedEnabled == true)
        current = math.floor(math.max(2, math.min(100, tonumber(forcedCurrent) or 2)))
        max = math.floor(math.max(1, math.min(100, tonumber(forcedMax) or 1)))
        delay = math.floor(math.max(0, math.min(600, tonumber(forcedDelay) or 60)))
    else
        enabled, current, max, delay = readAutoHopGlobals()
    end

    local AH = G.AutoHopServer or _G.AutoHopServer
    if type(AH) ~= "table" then return end

    if forcedEnabled == nil and forcedCurrent == nil and forcedMax == nil and forcedDelay == nil
        and __autoHopApplied.enabled == enabled
        and __autoHopApplied.current == current
        and __autoHopApplied.max == max
        and __autoHopApplied.delay == delay then
        return
    end

    if type(AH.SetCurrentPlayer) == "function" then
        pcall(AH.SetCurrentPlayer, AH, current)
    end
    if type(AH.SetMaxPlayer) == "function" then
        pcall(AH.SetMaxPlayer, AH, max)
    end
    if type(AH.SetTeleportDelay) == "function" then
        pcall(AH.SetTeleportDelay, AH, delay)
    end
    if enabled then
        if type(AH.Start) == "function" then pcall(AH.Start, AH) end
    elseif type(AH.Stop) == "function" then
        pcall(AH.Stop, AH)
    end

    __autoHopApplied.enabled = enabled
    __autoHopApplied.current = current
    __autoHopApplied.max = max
    __autoHopApplied.delay = delay
end

G.readAutoHopGlobals   = readAutoHopGlobals
_G.readAutoHopGlobals  = readAutoHopGlobals
G.writeAutoHopGlobals  = writeAutoHopGlobals
_G.writeAutoHopGlobals = writeAutoHopGlobals
G.applyAutoHopModule   = applyAutoHopModule
_G.applyAutoHopModule  = applyAutoHopModule

local function _normalizeAutoHopState(ah)
    ah = type(ah) == "table" and ah or _deepCopy(DEFAULT_MISC.rejoin.auto_hop)
    ah.enabled = (ah.enabled == true)
    ah.current_player = math.floor(math.max(2, math.min(100, tonumber(ah.current_player) or 2)))
    ah.max_player = math.floor(math.max(1, math.min(100, tonumber(ah.max_player) or 1)))
    ah.teleport_delay = math.floor(math.max(0, math.min(600, tonumber(ah.teleport_delay) or 60)))
    ah.minutes = math.floor(math.max(1, math.min(1440, tonumber(ah.minutes) or 8)))
    ah.diff_servers = math.floor(math.max(1, math.min(200, tonumber(ah.diff_servers) or 5)))
    if type(ah.visited) ~= "table" then ah.visited = {} end
    return ah
end

local function syncRejoinGlobalsFromMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local rj = MAIN.misc.rejoin

    AUTO_RECONNECT_ENABLED = (rj.auto_reconnect == true)
    AUTO_START_ON_REJOIN = (rj.auto_exec == true)
    G.AUTO_RECONNECT_ENABLED = AUTO_RECONNECT_ENABLED
    G.AUTO_START_ON_REJOIN = AUTO_START_ON_REJOIN
    _G.AUTO_RECONNECT_ENABLED = AUTO_RECONNECT_ENABLED
    _G.AUTO_START_ON_REJOIN = AUTO_START_ON_REJOIN

    rj.auto_hop = _normalizeAutoHopState(rj.auto_hop)
    local ah = rj.auto_hop
    AUTO_HOP_ENABLED = ah.enabled
    AUTO_HOP_CURRENT_PLAYER = ah.current_player
    AUTO_HOP_MAX_PLAYER = ah.max_player
    G.AUTO_HOP_ENABLED = AUTO_HOP_ENABLED
    G.AUTO_HOP_CURRENT_PLAYER = AUTO_HOP_CURRENT_PLAYER
    G.AUTO_HOP_MAX_PLAYER = AUTO_HOP_MAX_PLAYER
    G.AUTO_HOP_TELEPORT_DELAY = ah.teleport_delay
    _G.AUTO_HOP_ENABLED = AUTO_HOP_ENABLED
    _G.AUTO_HOP_CURRENT_PLAYER = AUTO_HOP_CURRENT_PLAYER
    _G.AUTO_HOP_MAX_PLAYER = AUTO_HOP_MAX_PLAYER
    _G.AUTO_HOP_TELEPORT_DELAY = ah.teleport_delay

    STATE.rejoin = _deepCopy(rj)
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function syncRejoinGlobalsToMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local rj = MAIN.misc.rejoin

    rj.auto_reconnect = (AUTO_RECONNECT_ENABLED == true)
    rj.auto_exec      = (AUTO_START_ON_REJOIN == true)

    -- auto_hop: MAIN is source of truth — never overwrite from stale globals on save
    rj.auto_hop = _normalizeAutoHopState(rj.auto_hop)
    syncRejoinGlobalsFromMain()

    STATE.rejoin = STATE.rejoin or {}
    STATE.rejoin.auto_reconnect = rj.auto_reconnect
    STATE.rejoin.auto_exec      = rj.auto_exec
    STATE.rejoin.update_new_server        = rj.update_new_server
    STATE.rejoin.update_new_server_minute = rj.update_new_server_minute
    STATE.rejoin.auto_hop = _deepCopy(rj.auto_hop)

    G.MAIN = MAIN
    _G.MAIN = MAIN
end

--------------------------------------------------
-- FILE SAVE
--------------------------------------------------
-- Persist (save/load file) — satu pintu untuk semua fitur
-- UI/tabs: tulis ke G.__GAG2_* store + MAIN, lalu panggil G.__GAG2_STATE_SAVE()
-- Boot: loadSelectionsFromFile() -> restore*FromData() -> sync*FromMain()
--------------------------------------------------
local CAN_FS = (typeof(writefile) == "function" and typeof(readfile) == "function"
    and typeof(isfile) == "function" and typeof(makefolder) == "function")

local SAVE_DIR = "growagarden2"

local function _safeName(s)
    s = tostring(s or "player")
    s = s:gsub("[^%w%-_.]", "_"):gsub("_+", "_")
    return s:sub(1, 48)
end

local SAVE_FILE = ("%s/%s.json"):format(SAVE_DIR, _safeName(LP.Name))

local function _ensureFolder()
    if not CAN_FS then return false end
    if not isfolder(SAVE_DIR) then pcall(makefolder, SAVE_DIR) end
    return isfolder(SAVE_DIR)
end

local AUTO_PERSIST_KEYS = {
    "collect", "plant", "sprinkler", "sell", "buy", "claimSeed", "autoTele", "gift",
}

local function _adoptLiveMain()
    local live = G.MAIN or _G.MAIN
    if type(live) ~= "table" then return end

    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    if type(live.auto) == "table" then
        for _, key in ipairs(AUTO_PERSIST_KEYS) do
            if type(live.auto[key]) == "table" then
                MAIN.auto[key] = _deepCopy(live.auto[key])
            end
        end
    end

    if type(live.misc) == "table" then
        MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
        if type(live.misc.rejoin) == "table" then
            MAIN.misc.rejoin = _deepCopy(live.misc.rejoin)
        end
        if type(live.misc.weather_predict) == "table" then
            MAIN.misc.weather_predict = _deepCopy(live.misc.weather_predict)
        end
        if type(live.misc.pet_finder) == "table" then
            MAIN.misc.pet_finder = _deepCopy(live.misc.pet_finder)
        end
        if type(live.misc.perf) == "table" then
            MAIN.misc.perf = _deepCopy(live.misc.perf)
        end
    end

    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _pullUiStoresIntoMain()
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)

    local tele = G.__GAG2_AUTO_TELE or _G.__GAG2_AUTO_TELE
    if type(tele) == "table" then
        MAIN.auto.autoTele = _normalizeAutoTeleState({
            enabled = (tele.enabled == true),
            delay = tele.delay,
            selectedLocation = tele.selectedLocation,
        })
    end

    local gift = G.__GAG2_AUTO_GIFT or _G.__GAG2_AUTO_GIFT
    if type(gift) == "table" then
        local maps = {}
        if type(gift.selected) == "table" then
            for _, key in ipairs(_giftCategoryKeysFromState(gift)) do
                maps[key] = _arrayToMap(gift.selected[key])
            end
        end
        MAIN.auto.gift = _normalizeAutoGiftState({
            enabled = (gift.enabled == true),
            auto_send = (gift.auto_send == true),
            auto_claim_mail = (gift.auto_claim_mail == true),
            auto_accept_gift = (gift.auto_accept_gift == true),
            recipient_username = gift.recipient_username,
            recipient_user_id = gift.recipient_user_id,
            recipient_display = gift.recipient_display,
            categories = type(gift.categories) == "table" and _deepCopy(gift.categories) or {},
            selected = _giftSelectedArraysFromMaps(maps),
            skip_equipped = gift.skip_equipped,
            max_per_batch = gift.max_per_batch,
            note = gift.note,
            delay_sec = gift.delay_sec,
            send_totals = type(gift.send_totals) == "table" and _deepCopy(gift.send_totals) or {},
            category_mode = gift.category_mode,
            send_list_mode = gift.send_list_mode,
            send_total = gift.send_total,
            after_send_mode = gift.after_send_mode,
        })
    end

    local ng = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
    if type(ng) == "table" then
        MAIN.auto.normalGift = _normalizeAutoNormalGiftState({
            target_user_id = ng.target_user_id,
            target_name = ng.target_name,
            category = ng.category,
            selected = _mapToArray(ng.selected),
            send_total = ng.send_total,
        })
    end

    local claim = G.__GAG2_CLAIM_SEED or _G.__GAG2_CLAIM_SEED
    if type(claim) == "table" then
        MAIN.auto.claimSeed = _normalizeAutoClaimSeedState({
            enabled = (claim.enabled == true),
        })
    end

    local petStore = G.__GAG2_BUY_PET or _G.__GAG2_BUY_PET
    local buySnap = G.__GAG2_AUTO_BUY or _G.__GAG2_AUTO_BUY
    if type(buySnap) == "table" then
        MAIN.auto.buy = _normalizeAutoBuyState(_deepCopy(buySnap))
    end
    if type(petStore) == "table" then
        MAIN.auto.buy = MAIN.auto.buy or _deepCopy(DEFAULT_AUTO.buy)
        local pet = MAIN.auto.buy.pet or _deepCopy(DEFAULT_AUTO.buy.pet)
        pet.enabled = (petStore.enabled == true)
        pet.auto_tame = (petStore.auto_tame == true)
        pet.max_price_mult = tonumber(petStore.max_price_mult) or pet.max_price_mult or 2
        if type(petStore.selected) == "table" then
            pet.items = _mapToArray(petStore.selected)
        end
        MAIN.auto.buy.pet = pet
        MAIN.auto.buy = _normalizeAutoBuyState(MAIN.auto.buy)
    end

    local col = G.__GAG2_AUTO_COLLECT or _G.__GAG2_AUTO_COLLECT
    if type(col) == "table" then
        MAIN.auto.collect = _normalizeAutoCollectState({
            enabled = (col.enabled == true),
            delay = col.delay,
            fruits = col.fruits,
            mutations = col.mutations,
            kg = col.kg,
            kgMode = col.kgMode,
            kgRule = col.kgRule,
            priority = col.priority,
        })
    end

    local pl = G.__GAG2_AUTO_PLANT or _G.__GAG2_AUTO_PLANT
    if type(pl) == "table" then
        MAIN.auto.plant = _normalizeAutoPlantState({
            enabled = (pl.enabled == true),
            seeds = pl.seeds,
            positions = pl.positions,
            mode = pl.mode,
            delay = pl.delay,
            autoManual = pl.autoManual,
            selectedPosition = pl.selectedPosition,
            savePosition = pl.savePosition,
        })
    end

    local sl = G.__GAG2_AUTO_SELL or _G.__GAG2_AUTO_SELL
    if type(sl) == "table" then
        MAIN.auto.sell = _normalizeAutoSellState({
            enabled = (sl.enabled == true),
            minCount = sl.minCount,
            delay = sl.delay,
            sellWhenFull = sl.sellWhenFull,
        })
    end

    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeMainAutoForSave()
    MAIN.auto.collect = _normalizeAutoCollectState(MAIN.auto.collect)
    MAIN.auto.plant = _normalizeAutoPlantState(MAIN.auto.plant)
    MAIN.auto.sprinkler = _normalizeAutoSprinklerState(MAIN.auto.sprinkler)
    MAIN.auto.sell = _normalizeAutoSellState(MAIN.auto.sell)
    MAIN.auto.buy = _normalizeAutoBuyState(MAIN.auto.buy)
    MAIN.auto.claimSeed = _normalizeAutoClaimSeedState(MAIN.auto.claimSeed)
    MAIN.auto.autoTele = _normalizeAutoTeleState(MAIN.auto.autoTele)
    MAIN.auto.gift = _normalizeAutoGiftState(MAIN.auto.gift)
