    _G.__GAG2_BUY_PET = G.__GAG2_BUY_PET
    G.__GAG2_AUTO_TELE = _deepCopy(DEFAULT_AUTO.autoTele)
    _G.__GAG2_AUTO_TELE = G.__GAG2_AUTO_TELE
    G.__GAG2_SHOVEL = { enabled = false, plants = {} }
