local function restoreAutoBuyFromData(data)
    if type(data) ~= "table" then return end

    local src = {}
    local function mergeBuy(from)
        if type(from) ~= "table" then return end
        for k, v in pairs(from) do
            if type(v) == "table" and type(src[k]) == "table" then
                local dst = src[k]
                for kk, vv in pairs(v) do
                    dst[kk] = vv
                end
                src[k] = dst
            else
                src[k] = v
            end
        end
    end

    mergeBuy(type(data.auto_buy) == "table" and data.auto_buy or nil)
    mergeBuy(type(data.auto) == "table" and data.auto.buy or nil)
    mergeBuy(type(data.main) == "table" and type(data.main.auto) == "table" and data.main.auto.buy or nil)

    if next(src) == nil then return end

    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.auto.buy = MAIN.auto.buy or _deepCopy(DEFAULT_AUTO.buy)
    for k, v in pairs(src) do
        if type(v) == "table" and type(MAIN.auto.buy[k]) == "table" then
            for kk, vv in pairs(v) do
                MAIN.auto.buy[k][kk] = vv
            end
        else
            MAIN.auto.buy[k] = v
        end
    end

    syncAutoBuyGlobalsFromMain()
end

