    for k, v in pairs(src) do
        MAIN.misc.weather_predict[k] = v
    end

    syncWeatherPredictGlobalsFromMain()
end

local function restorePetFinderFromData(data)
    if type(data) ~= "table" then return end

    local src = {}
    local function merge(from)
        if type(from) ~= "table" then return end
        for k, v in pairs(from) do src[k] = v end
    end

    merge(type(data.pet_finder) == "table" and data.pet_finder or nil)
    merge(type(data.main) == "table" and type(data.main.misc) == "table" and data.main.misc.pet_finder or nil)

    if next(src) == nil then return end

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    local pf = _snapshotPetFinderForSave(MAIN.misc.pet_finder)
    local allowed = {
        filter_rarities = true,
        filter_rarity = true,
        auto_refresh_list = true,
        auto_hop = true,
        target_pets = true,
    }
    for k, v in pairs(src) do
        if allowed[k] then
            pf[k] = v
        end
    end
    MAIN.misc.pet_finder = _snapshotPetFinderForSave(pf)

    syncPetFinderGlobalsFromMain()
end

local function restorePerfFromData(data)
    if type(data) ~= "table" then return end

    local src = {}
    local function merge(from)
        if type(from) ~= "table" then return end
        for k, v in pairs(from) do src[k] = v end
    end

    merge(type(data.perf) == "table" and data.perf or nil)
    merge(type(data.main) == "table" and type(data.main.misc) == "table" and data.main.misc.perf or nil)

    if next(src) == nil then return end

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.perf = _normalizePerfState(MAIN.misc.perf)
    for k, v in pairs(src) do
        MAIN.misc.perf[k] = v
    end
    MAIN.misc.perf = _normalizePerfState(MAIN.misc.perf)

    syncReduceFpsGlobalsFromMain()
end

local function loadSelectionsFromFile()
    if not CAN_FS or not isfile(SAVE_FILE) then return end

    local ok, text = pcall(readfile, SAVE_FILE)
    if not ok or type(text) ~= "string" or #text == 0 then return end

    local ok2, data = pcall(function()
        return HttpService:JSONDecode(text)
    end)
    if not ok2 or type(data) ~= "table" then return end

    if type(data.running) == "boolean" then
        STATE.scriptRunning = data.running
        G.scriptRunning = STATE.scriptRunning
    end

    restoreRejoinFromData(data)
    restoreAutoCollectFromData(data)
    restoreAutoPlantFromData(data)
    restoreAutoSprinklerFromData(data)
    restoreAutoSellFromData(data)
    restoreAutoBuyFromData(data)
    restoreAutoClaimSeedFromData(data)
    restoreAutoTeleFromData(data)
    restoreAutoGiftFromData(data)
    restoreNormalGiftFromData(data)
    restoreWeatherPredictFromData(data)
    restorePetFinderFromData(data)
    restorePerfFromData(data)
    syncAutoTeleGlobalsFromMain()
    syncAutoGiftGlobalsFromMain()
    syncNormalGiftGlobalsFromMain()
end

loadSelectionsFromFile()
syncRejoinGlobalsFromMain()
applyAutoHopModule()
syncAutoCollectGlobalsFromMain()
syncAutoPlantGlobalsFromMain()
syncAutoSprinklerGlobalsFromMain()
syncAutoSellGlobalsFromMain()
syncAutoBuyGlobalsFromMain()
syncAutoClaimSeedGlobalsFromMain()
syncAutoTeleGlobalsFromMain()
syncAutoGiftGlobalsFromMain()
syncNormalGiftGlobalsFromMain()
