-- STATE API — satu pintu untuk UI & save/load
-- UI: State.patchAuto("collect", { enabled = false }) → State.saveFromUi()
--------------------------------------------------
local State = {}

local _UI_FLUSH = {}

local AUTO_NORMALIZERS = {
    collect   = _normalizeAutoCollectState,
    plant     = _normalizeAutoPlantState,
    sprinkler = _normalizeAutoSprinklerState,
    sell      = _normalizeAutoSellState,
    buy       = _normalizeAutoBuyState,
    claimSeed = _normalizeAutoClaimSeedState,
    autoTele  = _normalizeAutoTeleState,
    gift      = _normalizeAutoGiftState,
    normalGift = _normalizeAutoNormalGiftState,
}

local AUTO_SYNC_FROM_MAIN = {
    collect   = syncAutoCollectGlobalsFromMain,
    plant     = syncAutoPlantGlobalsFromMain,
    sprinkler = syncAutoSprinklerGlobalsFromMain,
    sell      = syncAutoSellGlobalsFromMain,
    buy       = syncAutoBuyGlobalsFromMain,
    claimSeed = syncAutoClaimSeedGlobalsFromMain,
    autoTele  = syncAutoTeleGlobalsFromMain,
    gift      = syncAutoGiftGlobalsFromMain,
    normalGift = syncNormalGiftGlobalsFromMain,
}

local function _mergePartialInto(target, partial)
    if type(target) ~= "table" or type(partial) ~= "table" then return target end
    for k, v in pairs(partial) do
        if type(v) == "table" and type(target[k]) == "table" and v[1] == nil and target[k][1] == nil then
            _mergePartialInto(target[k], v)
        else
            target[k] = (type(v) == "table") and _deepCopy(v) or v
        end
    end
    return target
end

local function _applyAutoPatch(key, partial)
    if type(key) ~= "string" or type(partial) ~= "table" then return end
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    local cur = type(MAIN.auto[key]) == "table" and _deepCopy(MAIN.auto[key]) or _deepCopy(DEFAULT_AUTO[key] or {})
    _mergePartialInto(cur, partial)
    local norm = AUTO_NORMALIZERS[key]
    MAIN.auto[key] = norm and norm(cur) or cur
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local MISC_SYNC_FROM_MAIN = {
    rejoin          = syncRejoinGlobalsFromMain,
    weather_predict = syncWeatherPredictGlobalsFromMain,
    pet_finder      = syncPetFinderGlobalsFromMain,
    perf            = syncReduceFpsGlobalsFromMain,
}

local function _applyMiscPatch(key, partial)
    if type(key) ~= "string" or type(partial) ~= "table" then return end
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    if key == "rejoin" then
        local cur = _deepCopy(MAIN.misc.rejoin or DEFAULT_MISC.rejoin)
        _mergePartialInto(cur, partial)
        if type(cur.auto_hop) == "table" then
            cur.auto_hop = _normalizeAutoHopState(cur.auto_hop)
        end
        MAIN.misc.rejoin = cur
    elseif key == "weather_predict" then
        local cur = _deepCopy(MAIN.misc.weather_predict or DEFAULT_MISC.weather_predict)
        _mergePartialInto(cur, partial)
        cur.enabled = (cur.enabled == true)
        MAIN.misc.weather_predict = cur
    elseif key == "pet_finder" then
        local cur = _deepCopy(MAIN.misc.pet_finder or DEFAULT_MISC.pet_finder)
        _mergePartialInto(cur, partial)
        MAIN.misc.pet_finder = _snapshotPetFinderForSave(cur)
    elseif key == "perf" then
        local cur = _deepCopy(MAIN.misc.perf or DEFAULT_MISC.perf)
        _mergePartialInto(cur, partial)
        MAIN.misc.perf = _normalizePerfState(cur)
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

function State.getMisc(key)
    if type(key) ~= "string" then return nil end
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    if key == "rejoin" then return MAIN.misc.rejoin end
    if key == "weather_predict" then return MAIN.misc.weather_predict end
    if key == "pet_finder" then return MAIN.misc.pet_finder end
    if key == "perf" then return MAIN.misc.perf end
    return nil
end

function State.patchMisc(key, partial, opts)
    opts = type(opts) == "table" and opts or {}
    if type(key) ~= "string" or type(partial) ~= "table" then
        return State.getMisc(key)
    end
    _applyMiscPatch(key, partial)
    if not opts.noSync then
        local sync = MISC_SYNC_FROM_MAIN[key]
        if sync then sync() end
    end
    return State.getMisc(key)
end

function State.getMain()
    G.MAIN = MAIN
    _G.MAIN = MAIN
    return MAIN
end

function State.getAuto(key)
    if type(key) ~= "string" then return nil end
    _applyAutoPatch(key, {})
    return MAIN.auto[key]
end

function State.patchAuto(key, partial, opts)
    opts = type(opts) == "table" and opts or {}
    if type(key) ~= "string" or type(partial) ~= "table" then
        return State.getAuto(key)
    end
    _applyAutoPatch(key, partial)
    if not opts.noSync then
        local sync = AUTO_SYNC_FROM_MAIN[key]
        if sync then sync() end
    end
    return MAIN.auto[key]
end

function State.registerFlush(id, fn)
    if type(id) == "string" and id ~= "" and type(fn) == "function" then
        _UI_FLUSH[id] = fn
    end
end

function State.unregisterFlush(id)
    if type(id) == "string" then
        _UI_FLUSH[id] = nil
    end
end

function State.flushUi()
    if G.__GAG2_RESETTING == true then
        return
    end
    for _, fn in pairs(_UI_FLUSH) do
        pcall(fn)
    end
    _normalizeMainAutoForSave()
end

function State.syncAllMisc()
    syncRejoinGlobalsFromMain()
    syncWeatherPredictGlobalsFromMain()
    syncPetFinderGlobalsFromMain()
    syncReduceFpsGlobalsFromMain()
end

function State.syncAllAuto()
    _syncAllRuntimeFromMain()
end

function State.save()
    saveSelectionsToFile()
end

function State.saveFromUi()
    State.flushUi()
    State.syncAllMisc()
    _syncAllRuntimeFromMain()
    saveSelectionsToFile()
end

function State.load()
    loadSelectionsFromFile()
    syncRejoinGlobalsToMain()
    applyAutoHopModule()
    syncAutoCollectGlobalsFromMain()
    syncAutoPlantGlobalsFromMain()
    syncAutoSprinklerGlobalsFromMain()
    syncAutoSellGlobalsFromMain()
    syncAutoBuyGlobalsFromMain()
    syncAutoClaimSeedGlobalsFromMain()
    syncAutoTeleGlobalsFromMain()
    syncAutoGiftGlobalsFromMain()
    syncWeatherPredictGlobalsFromMain()
    syncPetFinderGlobalsFromMain()
    syncReduceFpsGlobalsFromMain()
    applyReduceFpsModule()
    G.STATE = STATE
    _G.STATE = STATE
    return STATE
end

function State.reset()
    G.__GAG2_RESETTING = true
    _G.__GAG2_RESETTING = true
    resetAllToDefaults()
    applyResetRuntime()
    if type(G.__GAG2_APPLY_UI_DEFAULTS) == "function" then
        pcall(G.__GAG2_APPLY_UI_DEFAULTS)
    end
    if type(G.__GAG2_ON_STATE_RESET) == "function" then
        pcall(G.__GAG2_ON_STATE_RESET)
    end
    G.__GAG2_RESETTING = nil
    _G.__GAG2_RESETTING = nil
    return true
end

G.__GAG2_STATE = State
_G.__GAG2_STATE = State

G.__GAG2_RESET_STATE = function()
    return State.reset()
end
_G.__GAG2_RESET_STATE = G.__GAG2_RESET_STATE

G.__GAG2_STATE_SAVE = function()
    State.saveFromUi()
end
_G.__GAG2_STATE_SAVE = G.__GAG2_STATE_SAVE

G.__GAG2_FLUSH_TO_MAIN = function()
    State.flushUi()
    _syncAllRuntimeFromMain()
end
_G.__GAG2_FLUSH_TO_MAIN = G.__GAG2_FLUSH_TO_MAIN

return State
 end)()
    end)
    if okFac then
        local ok, mod, state = stateFromModule(modOrErr)
        if ok then
            debuglog("STATE_OK_INLINE")
            return true, mod, state
        end
    end

    -- 2) HTTP fallback via LINK_GAG2_STATE
    if not hasUnreplacedShortcode(STATE_URL) then
        local okBody, bodyOrErr = pcall(httpRequest, STATE_URL)
        if okBody and type(bodyOrErr) == "string" and bodyOrErr ~= "" then
            local chunk, err = loadstring(bodyOrErr)
            if type(chunk) == "function" then
                local okRun, modOrErr = pcall(chunk)
                if okRun then
                    local ok, mod, state = stateFromModule(modOrErr)
                    if ok then
                        debuglog("STATE_OK_HTTP")
                        return true, mod, state
                    end
                    return false, state
                end
                return false, "state run failed: " .. tostring(modOrErr)
            end
            return false, "state loadstring: " .. tostring(err)
        end
        return false, "state http failed: " .. tostring(bodyOrErr)
    end

    return false, "GAG2_STATE inline & LINK_GAG2_STATE gagal"
end

